 /** <pre> 2021-02-24
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnWrkMgtjmMtlNew2 
  --크레인작업관리 스케줄조회  
WITH TEMP_TABLE AS (  
            SELECT A.YD_CRN_SCH_ID  
                 , A.YD_WORD_DT  
                 , A.YD_WBOOK_ID  
                 , A.YD_SCH_CD  
                 , A.YD_EQP_ID  
                 , SUBSTR(A.YD_UP_WO_LOC, 2, 5) || TO_NUMBER(A.YD_UP_WO_LYR) ||  SUBSTR(A.YD_UP_WO_LOC, 7, 2) AS YD_UP_WO_LOC2  
                 , SUBSTR(A.YD_DN_WO_LOC, 2, 5) || TO_NUMBER(A.YD_DN_WO_LYR) ||  SUBSTR(A.YD_DN_WO_LOC, 7, 2) AS YD_DN_WO_LOC2  
                 , YD_DN_WO_LOC || YD_DN_WO_LYR AS YD_DN_LOC  
                 , NVL(YD_UP_WR_LOC , YD_UP_WO_LOC ) AS YD_UP_WO_LOC  
                 , NVL(YD_UP_WR_LYR, YD_UP_WO_LYR) AS YD_UP_WO_LYR  
                 , YD_DN_WO_LOC  
                 , YD_DN_WO_LYR  
                 , YD_EQP_WRK_SH  
                 , YD_EQP_WRK_WT  
                 , YD_EQP_WRK_STAT
                 , DECODE (A.YD_WRK_PROG_STAT, '1' , '권상'
                                 , '2' , '권하'
                                 , 'C' , '보류'
                                 , 'S' , '대기'
                                 ,' ') AS YD_WRK_PROG_STAT_NM
                 , A.YD_WRK_PROG_STAT
                 , A.YD_SCH_PRIOR  
                 , B.STL_NO  
                 , A.YD_GP  
                 , A.YD_TO_LOC_DCSN_MTD   
                 , TO_CHAR(A.YD_UP_CMPL_DT,'DD/ HH24:MI:SS') AS YD_UP_CMPL_DT  
                 , (SELECT COUNT(*) FROM TB_YF_CRNSCH WHERE YD_WBOOK_ID = A.YD_WBOOK_ID AND DEL_YN = 'N') AS STL_CNT  
                 , (CASE WHEN B.YD_AID_WRK_YN = 'Y' THEN '보조' ELSE '주' END ) AS YD_AID_WRK_YN  
                 , B.YD_AID_WRK_YN AS MAIN_CHK  
                 , SUBSTR(A.YD_UP_WO_LOC, 1, 1) AS DN_WO_LOC_YD  
                 , A.YD_L2_REQUEST_STAT  
                 , A.YD_WRK_PROG_REQ_MSG  
                 , A.YD_WRK_PARTY AS YD_SCH_ST_GP  
                 , MIN(A.YD_WRK_PROG_STAT||A.YD_CRN_SCH_ID) OVER (PARTITION BY A.YD_WBOOK_ID ) AS CHK  
                 , A.YD_UP_WO_LOC_XAXIS  
                 , A.YD_UP_WO_LOC_YAXIS  
                 , A.YD_UP_WO_LOC_ZAXIS  
                 , A.YD_DN_WO_LOC_XAXIS  
                 , A.YD_DN_WO_LOC_YAXIS  
                 , A.YD_DN_WO_LOC_ZAXIS  
                 , CASE WHEN B.YD_AID_WRK_YN = 'Y'  THEN '' 
                    ELSE (SELECT CASE WHEN CARD_NO IN ('9990','9991','9992','9993','9994') THEN CARD_NO  
                                WHEN CAR_NO IS NOT NULL THEN CAR_NO || '[' || CARD_NO || ']'  
                                ELSE TRN_EQP_CD END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = A.YD_WBOOK_ID
                   ) END AS CAR_CARD_NO  
                 , (SELECT CASE WHEN CARD_NO IN ('9990','9991','9992','9993','9994') THEN CARD_NO  
                                WHEN CAR_NO IS NOT NULL THEN CAR_NO || '[' || CARD_NO || ']'  
                                ELSE TRN_EQP_CD END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = A.YD_WBOOK_ID
                   ) AS CAR_CARD_NO_ 
                 , B.REG_DDTT AS SCH_CRE_DT              
                 , P.CURR_PROG_CD
                 , P.COIL_T   AS YD_MTL_T
                 , P.COIL_W   AS YD_MTL_W
                 , P.COIL_LEN AS YD_MTL_L
                 , CASE WHEN SUBSTR(B.STL_NO,1,1) = 'S' THEN A.YD_EQP_WRK_WT
                        ELSE P.COIL_WT END  AS YD_MTL_WT
                 , P.COIL_OUTDIA AS YD_MTL_OUTDIA
                 , P.ORD_NO || '-' || P.ORD_DTL AS ORD_NO_DTL
                 , P.COIL_GP
                 , P.STL_APPEAR_GP
                 , (SELECT CASE WHEN REGISTER = 'AUTO_MVSTK' THEN 'Y' ELSE 'N' END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = A.YD_WBOOK_ID) AS AUTO_YN
                 , CASE 
                        WHEN B.YD_ROUTE_GP IS NOT NULL THEN B.YD_ROUTE_GP
                    ELSE 
                        CASE 
                            WHEN W.YD_TO_LOC_DCSN_MTD = 'F' OR LENGTH(W.YD_TO_LOC_GUIDE) >= 4 THEN 'GD' -- 지정
                            WHEN W.YD_TO_LOC_DCSN_MTD = 'W' THEN 'MM' -- 동내 
                            ELSE 'GN'
                        END -- YD_TO_LOC_DCSN_MTD :: 
                        
                    END AS YD_ROUTE_GP
                 , CASE WHEN  W.YD_AIM_BAY_GP IS NOT NULL THEN W.YD_AIM_BAY_GP 
                    ELSE SUBSTR(A.YD_DN_WO_LOC,2,1) END AS YD_AIM_BAY_GP
              FROM TB_YF_CRNSCH    A  
                 , TB_YF_CRNWRKMTL B  
                 , VW_YF_COILCOMM  P
                 , TB_YF_STOCK S
                 , TB_YF_WRKBOOK W
             WHERE A.YD_CRN_SCH_ID=B.YD_CRN_SCH_ID  
               AND A.DEL_YN = 'N'  
               AND B.DEL_YN = 'N'  
               AND B.STL_NO      = P.COIL_NO(+)
               AND B.STL_NO      = S.STL_NO
               AND A.YD_WBOOK_ID = W.YD_WBOOK_ID
               AND A.YD_EQP_ID LIKE :V_YD_CRN_ID||'%'  
)  
SELECT BB.* 
      ,(SELECT DTL_ITEM1
          FROM TB_YF_RULE Z
         WHERE Z.REPR_CD_GP = 'SCHRGB'
           AND Z.CD_GP = :V_MODIFIER
           AND Z.ITEM LIKE  SUBSTR(BB.YD_SCH_CD,1,1) || '_' || SUBSTR(BB.YD_SCH_CD,3)) AS SCH_COLOR
      ,(SELECT REPR_CD_CONTENTS 
        FROM   USRYFA.TB_YF_RULE R,  VW_YF_GETCONDENSATIONLOC V 
        WHERE  R.REPR_CD_GP='YM6001' 
        AND    R.DEL_YN='N'
        AND    R.ITEM=V.YD_ZONE_GP
        AND    V.COIL_NO = BB.STL_NO) AS BZ_COIL
FROM ( 
        SELECT ROWNUM AS RNUM  --전체 SEQ
             , AA.*  
             , CASE WHEN AA.PASS_CAR_TM >= 20 THEN 'Y' ELSE 'N' END AS  PASS_CAR_TM_YN
          FROM (  
                SELECT COUNT(*) OVER() AS TOTALCOUNT  
                     , ROW_NUMBER() OVER( PARTITION BY D.YD_EQP_ID ORDER BY DECODE(D.YD_WRK_PROG_STAT,'W',99, 'S', 98, D.YD_WRK_PROG_STAT), D.YD_SCH_PRIOR, D.YD_CRN_SCH_ID) AS WRK_SEQ --작업예약별 작업순서
                     , D.YD_SCH_PRIOR  
                     , D.YD_SCH_PRIOR AS YD_SCH_PRIOR_ORG
                     , CASE WHEN F.YD_EQP_AUTO_CRN_MODE = '4' OR F.YD_EQP_AUTO_CRN_MODE = '5'  
                            THEN F.YD_EQP_NAME||'[정지]'  
                            ELSE F.YD_EQP_NAME  
                            END YD_EQP_NAME  
                     , E.CD_CONTENTS||DECODE(D.AUTO_YN, 'Y', '-A', '') AS YD_SCH_CD_NM  
                     , D.YD_CRN_SCH_ID  
                     , D.YD_WBOOK_ID  
                     , D.YD_AID_WRK_YN  
                     , D.STL_NO  
                     , D.YD_DN_LOC  
                     , D.YD_UP_WO_LOC  
                     , D.YD_UP_WO_LYR  
                     , D.YD_UP_WO_LOC || D.YD_UP_WO_LYR AS YD_UP_WO_LOC_LYR  
                     , D.YD_DN_WO_LOC  
                     , D.YD_DN_WO_LYR
                     , D.YD_DN_WO_LOC||D.YD_DN_WO_LYR  AS YD_DN_WO_LOC_ORG
                     , D.YD_EQP_WRK_SH  
                     , D.YD_EQP_WRK_WT  
                     , TO_CHAR(D.YD_WORD_DT, 'DD/ HH24:MI:SS') AS YD_WORD_DT  
                     , CASE WHEN D.YD_WRK_PROG_STAT NOT IN ('W', 'S') THEN 
                       TRUNC(TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')) ||'/ ' ||  
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')),1)*24), 2, '0') || ':' ||  
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24,1)*60), 2, '0') ||':'||  
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24*60,1)*60), 2, '0')  
                       ELSE NULL END AS PASS_HR  
                     , D.YD_TO_LOC_DCSN_MTD  
                     , D.YD_EQP_WRK_STAT  
                     , D.YD_WRK_PROG_STAT_NM  
                     , D.YD_WRK_PROG_STAT
                     , D.YD_UP_CMPL_DT  
                     , D.YD_EQP_ID  
                     , SUBSTR(D.YD_EQP_ID, 5, 6) AS YD_EQP_NM  
                     , F.YD_EQP_WRK_MODE2 -- 야드설비운전모드   
                     , D.YD_SCH_CD  
                     , D.STL_CNT  
                     , D.MAIN_CHK  
                     , D.DN_WO_LOC_YD  
                     , D.YD_L2_REQUEST_STAT  
                     , D.YD_WRK_PROG_REQ_MSG AS YD_WRK_PROG_REQ_MSG  
                     , D.YD_SCH_ST_GP  
                     , D.YD_UP_WO_LOC_XAXIS  
                     , D.YD_UP_WO_LOC_YAXIS  
                     , D.YD_UP_WO_LOC_ZAXIS  
                     , D.YD_DN_WO_LOC_XAXIS  
                     , D.YD_DN_WO_LOC_YAXIS  
                     , D.YD_DN_WO_LOC_ZAXIS  
                     , D.CAR_CARD_NO  
                     , CASE WHEN D.CAR_CARD_NO IS NOT NULL THEN TRUNC((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.SCH_CRE_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24*60) ELSE NULL
                       END AS PASS_CAR_TM                                         
                     , D.CURR_PROG_CD
                     , D.YD_MTL_T
                     , D.YD_MTL_W
                     , D.YD_MTL_L
                     , D.YD_MTL_WT
                     , D.YD_MTL_OUTDIA
                     , D.ORD_NO_DTL         
                     , E.ADV_CRN_PRIOR
                     , D.YD_ROUTE_GP
                     , D.YD_AIM_BAY_GP
                     ,(CASE WHEN D.COIL_GP = 'HR' THEN '열연'
                       WHEN D.COIL_GP ='CR' AND D.STL_APPEAR_GP ='E' THEN '냉연(재공품)'
                       WHEN D.COIL_GP ='CR' AND D.STL_APPEAR_GP ='Y' THEN '냉연(제품)'
                           END) AS COIL_GP
                  FROM TEMP_TABLE D
                     , TB_YF_SCHRULE E  
                     , TB_YF_EQP F  
                 WHERE D.YD_SCH_CD = E.YD_SCH_CD(+)  
                   AND D.YD_EQP_ID = F.YD_EQP_ID(+)  
                 ORDER BY WRK_SEQ
                        , F.YD_EQP_NAME
                        , E.CD_CONTENTS
                        , D.YD_WRK_PROG_STAT_NM DESC
                        , D.YD_SCH_PRIOR
                        , CASE WHEN D.YD_SCH_CD LIKE '1_DC01LM' THEN  TO_NUMBER(D.YD_CRN_SCH_ID) * -1
                               ---WHEN D.YD_SCH_CD LIKE '1EKD02LM' THEN  TO_NUMBER(D.YD_CRN_SCH_ID) * -1
                               ELSE TO_NUMBER(D.YD_CRN_SCH_ID) END
       ) AA
WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE 
) BB  
WHERE RNUM >= (( :V_PAGE_NO - 1 )* :V_PAGE_SIZE )+1
 </pre> */
public final static String getbtCrnWrkMgtjmMtlNew2 = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnWrkMgtjmMtlNew2";

 /** <pre> 2019-11-28
--yf.common.YfCommon.getClassCode
WITH PARAM AS (
    SELECT :V_TYPE_CD   AS TYPE_CD
          ,:V_CLASS1_CD AS CLASS1_CD
          ,:V_CLASS2_CD AS CLASS2_CD
          ,:V_CLASS3_CD AS CLASS3_CD
          ,:V_CLASS4_CD AS CLASS4_CD
      FROM DUAL)

SELECT A.*
  FROM (SELECT A.TYPE_CD
              ,A.CLASS1_CD
              ,A.CLASS1_NAME1
              ,A.CLASS1_NAME2
              ,A.CLASS1_CONTENTS
              ,B.CLASS2_CD
              ,B.CLASS2_NAME1
              ,B.CLASS2_NAME2
              ,B.CLASS2_CONTENTS
              ,C.CLASS3_CD
              ,C.CLASS3_NAME1
              ,C.CLASS3_NAME2
              ,C.CLASS3_CONTENTS
              ,D.CLASS4_CD
              ,D.CLASS4_NAME1
              ,D.CLASS4_NAME2
              ,D.CLASS4_CONTENTS
          FROM TB_CM_CDCLASS1 A
              ,TB_CM_CDCLASS2 B
              ,TB_CM_CDCLASS3 C
              ,TB_CM_CDCLASS4 D
              ,PARAM P
         WHERE A.TYPE_CD = P.TYPE_CD
           AND A.CLASS1_CD = P.CLASS1_CD
           AND B.TYPE_CD(+)    = A.TYPE_CD
           AND B.CLASS1_CD(+)  = A.CLASS1_CD
           AND C.TYPE_CD(+)    = B.TYPE_CD
           AND C.CLASS1_CD(+)  = B.CLASS1_CD
           AND C.CLASS2_CD(+)  = B.CLASS2_CD
           AND D.TYPE_CD(+)    = C.TYPE_CD
           AND D.CLASS1_CD(+)  = C.CLASS1_CD
           AND D.CLASS2_CD(+)  = C.CLASS2_CD
           AND D.CLASS3_CD(+)  = C.CLASS3_CD ) A
        ,PARAM P
  WHERE A.TYPE_CD = P.TYPE_CD
    AND A.CLASS1_CD = NVL(P.CLASS1_CD,A.CLASS1_CD)
    AND (   ( P.CLASS2_CD IS NULL AND A.CLASS2_CD = A.CLASS2_CD)
         OR ( P.CLASS2_CD IS NOT NULL AND A.CLASS2_CD = P.CLASS2_CD) 
         OR   A.CLASS2_CD IS NULL)
    AND (   ( P.CLASS3_CD IS NULL AND A.CLASS3_CD = A.CLASS3_CD)
         OR ( P.CLASS3_CD IS NOT NULL AND A.CLASS3_CD = P.CLASS3_CD) 
         OR   A.CLASS3_CD IS NULL)
    AND (   ( P.CLASS4_CD IS NULL AND A.CLASS4_CD = A.CLASS4_CD)
         OR ( P.CLASS4_CD IS NOT NULL AND A.CLASS4_CD = P.CLASS4_CD) 
         OR   A.CLASS4_CD IS NULL)
 </pre> */
public final static String getClassCode = "yf.common.YfCommon.getClassCode";

