 /** <pre> 2020-12-03
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getAcoilMtlErrorCommbo 
SELECT
    A.*
FROM
(
    SELECT 
        'ALL' AS CD_VAL
        , '이상적치내역 전체조회' AS CD_NM
    FROM DUAL
UNION ALL
    SELECT 
        '1LYR_NO' AS CD_VAL
        , '2단 적치코일 중 1단의 좌우 재료가 없는 건' AS CD_NM
    FROM DUAL
UNION ALL
    SELECT 
        'LOC_PT_ERROR' AS CD_VAL
        , '코일공통과 위치정보가 다른 건' AS CD_NM
    FROM DUAL
UNION ALL
    SELECT
        'END_COIL' AS CD_VAL
        , '종료된 코일' AS CD_NM
    FROM DUAL
UNION ALL
    SELECT
        'YARD_NO_COIL' AS CD_VAL
        , '코일공통엔 있고 야드에 없는 코일' AS CD_NM
    FROM DUAL
UNION ALL
    SELECT
        'DIFF_YF_PT_DM' AS CD_VAL
        , '출하, 야드, 코일공통 저장위치가 다른것들' AS CD_NM
    FROM DUAL
UNION ALL
    SELECT
        'END_DM_YD' AS CD_VAL
        , '출하가 되었는데 야드에 있는 코일' AS CD_NM
    FROM DUAL 
) A
 </pre> */
public final static String getAcoilMtlErrorCommbo = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getAcoilMtlErrorCommbo";

 /** <pre> 2021-04-01
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getAcoilMtlErrorInqjlList_PIDEV 
WITH V_DATA AS
(
    SELECT
        A.YD_STK_BED_NO,
        A.STL_NO,
        A.YD_STK_COL_GP,
        A.YD_STK_LYR_NO,
        A.YD_STK_LYR_STAT,
        A.YD_STK_LYR_ACTIVE_STAT,
        A.YD_STK_LYR_YD_STK_LOT_NO2
    FROM
        TB_YF_STKLYR A, TB_YF_STKCOL B
    WHERE 1=1
    AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
    AND B.SECT_GP BETWEEN '01' AND '99'
    AND B.YD_GP = '1'
    AND A.STL_NO IS NOT NULL
),
V_PARAM AS
(
    SELECT
        :V_ERROR_GB AS V_ERROR_GB
    FROM
        DUAL
),
V_ERRORMSG AS
(
    SELECT
        'ALL' AS CD_VAL,
        '이상적치내역 전체조회' AS CD_NM
    FROM
        DUAL

    UNION ALL

    SELECT
        '1LYR_NO' AS CD_VAL,
        '2단 적치코일 중 1단의 좌우 재료가 없는 건' AS CD_NM
    FROM
        DUAL

    UNION ALL

    SELECT
        'LOC_PT_ERROR' AS CD_VAL,
        '코일공통과 위치정보가 다른 건' AS CD_NM
    FROM
        DUAL

    UNION ALL

    SELECT
        'END_COIL' AS CD_VAL,
        '종료된 코일' AS CD_NM
    FROM
        DUAL

    UNION ALL

    SELECT
        'YARD_NO_COIL' AS CD_VAL,
        '코일공통엔 있고 야드에 없는 코일' AS CD_NM
    FROM
        DUAL

    UNION ALL

    SELECT
        'DIFF_YF_PT_DM' AS CD_VAL,
        '출하, 야드, 코일공통 저장위치가 다른것들' AS CD_NM
    FROM
        DUAL

    UNION ALL

    SELECT
        'END_DM_YD' AS CD_VAL,
        '출하가 되었는데 야드에 있는 코일' AS CD_NM
    FROM
        DUAL
)
SELECT --+ NO_MERGE(A) 
    T1.*,
    ROW_NUMBER() OVER(ORDER BY T1.STL_NO) AS RNUM
FROM
    (
        SELECT
            '야드' AS YD_LOC_GB,
            A.YD_STK_COL_GP,
            A.YD_STK_BED_NO,
            A.YD_STK_LYR_NO,
            A.STL_NO,
            A.YD_STK_COL_GP || A.YD_STK_BED_NO || A.YD_STK_LYR_NO AS YD_STR_LOC,
            (SELECT CD_NM FROM V_ERRORMSG WHERE CD_VAL = 'END_COIL') AS ERROR_MSG
        FROM
            V_DATA A,
            V_PARAM
        WHERE 1=1
        -- 종료된코일
        AND ('END_COIL' = V_ERROR_GB OR 'ALL' = V_ERROR_GB )
        AND NOT EXISTS
        (
            SELECT
                *
            FROM
                VW_YF_COILCOMM S
            WHERE S.COIL_NO = A.STL_NO
            AND
            (
                S.CURR_PROG_CD IN ('M', 'P', '8', '9') --출하완료(M), 인도완료(P), 소재이송출고완료(8), 소재이송인도완료(9)
                OR
                S.RECORD_PROG_STAT IN('1','2')
            )
            AND ( A.STL_NO NOT LIKE 'S%' OR A.STL_NO NOT LIKE 'BD%' )
        )

        UNION ALL

        SELECT
            '야드' AS YD_LOC_GB,
             A.YD_STK_COL_GP,
             A.YD_STK_BED_NO,
             A.YD_STK_LYR_NO,
             A.STL_NO,
             A.YD_STK_COL_GP || A.YD_STK_BED_NO || A.YD_STK_LYR_NO AS YD_STR_LOC,
            (SELECT CD_NM FROM V_ERRORMSG WHERE CD_VAL = 'LOC_PT_ERROR') AS ERROR_MSG
        FROM
            V_DATA A,
            V_PARAM
        WHERE 1=1
        --코일공통 위치가 다른 건
        AND
        (
            ('LOC_PT_ERROR' = V_ERROR_GB OR 'ALL' = V_ERROR_GB )
            AND EXISTS
            (
                SELECT
                    *
                FROM
                    VW_YF_COILCOMM S
                WHERE 1=1
                AND S.COIL_NO = A.STL_NO
                AND ( S.YD_STR_LOC <> A.YD_STK_COL_GP || A.YD_STK_BED_NO||A.YD_STK_LYR_NO )
                AND A.YD_STK_LYR_STAT IN ('C','U', 'S')
            )
        )

        UNION ALL

        SELECT
            '야드' AS YD_LOC_GB,
            A.YD_STK_COL_GP,
            A.YD_STK_BED_NO,
            A.YD_STK_LYR_NO,
            A.STL_NO,
            A.YD_STK_COL_GP || A.YD_STK_BED_NO || A.YD_STK_LYR_NO AS YD_STR_LOC,
            (SELECT CD_NM FROM V_ERRORMSG WHERE CD_VAL = '1LYR_NO') AS ERROR_MSG
        FROM
            V_DATA A,
            V_PARAM
        WHERE 1=1
        -- 2단 적치 CASE 좌우 코일 없으면 오류
        AND
        (
            ( '1LYR_NO' = V_ERROR_GB OR 'ALL' = V_ERROR_GB )
            AND A.YD_STK_LYR_NO = '02'
            AND  2 <
            (
                SELECT
                    COUNT(*)
                FROM
                    V_DATA S
                WHERE 1=1
                AND S.YD_STK_COL_GP = A.YD_STK_COL_GP
                AND
                (
                    S.YD_STK_BED_NO = A.YD_STK_BED_NO
                    OR
                    S.YD_STK_BED_NO = LPAD(1+TO_NUMBER(A.YD_STK_BED_NO),2,'0')
                )
                AND S.YD_STK_LYR_NO = '01'
                AND S.STL_NO IS NULL
            )
        )

        UNION ALL

        SELECT
            '야드' AS YD_LOC_GB,
            A.YD_STK_COL_GP,
            A.YD_STK_BED_NO,
            A.YD_STK_LYR_NO,
            A.STL_NO,
            A.YD_STK_COL_GP || A.YD_STK_BED_NO || A.YD_STK_LYR_NO AS YD_STR_LOC,
            (SELECT CD_NM FROM V_ERRORMSG WHERE CD_VAL = 'END_DM_YD') AS ERROR_MSG
        FROM
            V_DATA A,
            V_PARAM
        WHERE 1=1
        --출하가 되었는데 야드에 있는 코일
        AND ('END_DM_YD' = V_ERROR_GB OR 'ALL' = V_ERROR_GB )
        AND EXISTS
        (
            SELECT
                *
            FROM
                TB_PT_COILCOMM S
            WHERE 1=1
            AND S.COIL_NO = A.STL_NO
            AND S.CURR_PROG_CD IN ('M', 'P', '8', '9') --출하완료(M), 인도완료(P), 소재이송출고완료(8), 소재이송인도완료(9)
        )

        UNION ALL

        --코일공통에 있지만 우리 야드에 없는 코일정보
        SELECT --+ INDEX(A IX_PT_COILCOMM_21) 
            '코일공통' AS YD_LOC_GB,
            SUBSTR(A.YD_STR_LOC,1,6) AS YD_STK_COL_GP,
            SUBSTR(A.YD_STR_LOC,7,2) AS YD_STK_BED_NO,
            SUBSTR(A.YD_STR_LOC,9,2) AS YD_STK_LYR_NO,
            A.COIL_NO AS STL_NO,
            A.YD_STR_LOC AS YD_STR_LOC,
            (SELECT CD_NM FROM V_ERRORMSG WHERE CD_VAL = 'YARD_NO_COIL') AS ERROR_MSG
        FROM
            TB_PT_COILCOMM A,
            V_PARAM
        WHERE 1=1
        AND ('YARD_NO_COIL' =  V_ERROR_GB OR 'ALL' = V_ERROR_GB )
        AND A.RECORD_PROG_STAT IN('1','2') -- 살아있는코일
        AND A.CURR_PROG_CD NOT IN ('M', 'P', '8', '9') --출하완료(M), 인도완료(P), 소재이송출고완료(8), 소재이송인도완료(9)
        AND ( A.COIL_NO NOT LIKE 'S%' OR A.COIL_NO NOT LIKE 'BD%' )
        AND A.YD_STR_LOC LIKE '1%'
        AND SUBSTR(A.YD_STR_LOC,3,2) BETWEEN '01' AND '99'
        AND NOT EXISTS
        (
            SELECT
                1
            FROM
                TB_YF_STKLYR
            WHERE 1=1
            AND STL_NO = A.COIL_NO
        )

        UNION ALL

        --출하, 박판열연, 코일공통 저장위치가 다른것들
        SELECT DISTINCT --+ DRIVING_SITE(D) 
            '야드' AS YD_LOC_GB,
            B.YD_STK_COL_GP,
            B.YD_STK_BED_NO,
            B.YD_STK_LYR_NO,
            B.STL_NO,
            '야드: ' || B.YD_STK_COL_GP || B.YD_STK_BED_NO || B.YD_STK_LYR_NO || ', 공통-'||A.YD_STR_LOC||', 출하-' || D.STORE_LOC_CD  AS YD_STR_LOC,
            (SELECT CD_NM FROM V_ERRORMSG WHERE CD_VAL = 'DIFF_YF_PT_DM') AS ERROR_MSG
        FROM
            TB_PT_COILCOMM A,
            TB_YF_STKLYR B,
            TB_YF_STKCOL C,
            VW_LM_P_GOODSPROG D,
            V_PARAM
        WHERE 1=1
        AND ('DIFF_YF_PT_DM' =  V_ERROR_GB OR 'ALL' = V_ERROR_GB )
        AND A.COIL_NO = B.STL_NO
        AND
        (
            A.YD_STR_LOC <> B.YD_STK_COL_GP || B.YD_STK_BED_NO||B.YD_STK_LYR_NO
            OR
            A.YD_STR_LOC <> D.STORE_LOC_CD
        )
        AND B.YD_STK_COL_GP = C.YD_STK_COL_GP
        AND C.SECT_GP BETWEEN '01' AND '99'
        AND B.YD_STK_LYR_STAT IN ( 'C')
        AND A.COIL_NO = D.GOODS_NO
    ) T1
ORDER BY T1.STL_NO, T1.YD_STK_COL_GP, T1.YD_STK_BED_NO, T1.YD_STK_LYR_NO
 </pre> */
public final static String getAcoilMtlErrorInqjlList = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getAcoilMtlErrorInqjlList_PIDEV";

