 /** <pre> 2019-08-05
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSchRuleList 
-- 스케줄코드
SELECT YD_SCH_CD         AS CD_VAL
     , YD_SCH_CD||' ['||CD_CONTENTS||']'       AS CD_NM
     , YD_BAY_GP         AS YD_BAY_GP
  FROM TB_YF_SCHRULE
 WHERE YD_GP     LIKE  :V_YD_GP || '%'
   AND YD_BAY_GP LIKE  :V_YD_BAY_GP || '%'
   AND DEL_YN = 'N'
 ORDER BY YD_BAY_GP, CD_CONTENTS    
 </pre> */
