 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListFrtoStl_CoilNewA
WITH TEMP_TABLE AS
(
    SELECT
        AA.*
    FROM
        (
            SELECT
                D1.NEXT_PROC,                                           --구내차공정우선순위
                DECODE(A.MTL_UGNT_GP,'Y','1','N','2') AS MTL_UGNT_GP,   --긴급재순위
                (CASE WHEN D7.CNT = 0 AND A.GP = 'CM' THEN 1 ELSE D7.CNT END) AS CAR_CNT,   --차량갯수
                SEQ_NO,
                DECODE(A.GP,'CG',' ',D3.SCH_RULE_VAL) AS SCH_RULE_VAL,  --야드차공정우선순위
                A.YD_STK_COL_GP,
                A.YD_STK_BED_NO,
                A.YD_STK_LYR_NO,
                A.GP,
                A.CUR_DONG,                                             --제품현재동
                A.CG_AIM,                                               --제품목표동
                A.CM_AIM,                                               --소재차공정
                A.STL_NO,
                A.SPOS_WLOC_CD,                                         --발지개소
                A.ARR_WLOC_CD,                                          --착지개소
                A.HCR_GP,                                               --HCR구분
                A.STK_WT,                                               --중량
                A.COIL_W,
                SUBSTR(A.YD_STK_COL_GP,1,1) AS YD_GP,
                SUBSTR(A.YD_STK_COL_GP,2,1) AS BAY_GP,
                SUBSTR(A.YD_STK_COL_GP,3,2) AS SECT_GP
            FROM
                (
                    SELECT
                        DECODE(C.STL_APPEAR_GP, 'Y', 'CG', 'CM') AS GP,
                        DECODE(C.STL_APPEAR_GP, 'Y', SUBSTR(B.ARR_YD_PNT_CD, 2, 1), 'X') AS CG_AIM,
                        DECODE(C.STL_APPEAR_GP, 'Y', 'XX', C.NEXT_PROC) AS CM_AIM,
                        SUBSTR(A.YD_STK_COL_GP, 2, 1) AS CUR_DONG,
                        C.NEXT_PROC,
                        B.TRN_WRK_MTL_GP,
                        A.STL_NO,
                        A.YD_STK_COL_GP,
                        A.YD_STK_BED_NO,
                        A.YD_STK_LYR_NO,
                        B.SPOS_WLOC_CD,         --발지개소
                        B.ARR_WLOC_CD,          --착지개소
                        B.MTL_UGNT_GP,          --긴급재구분
                        B.HCR_GP,               --HCR구분
                        C.COIL_WT AS STK_WT,    --중량
                        C.COIL_W,
                        B.SEQ_NO
                    FROM
                        TB_YF_STKLYR A,
                        TB_TS_MATL_FTMV_WO B,
                        VW_YF_COILCOMM C
                    WHERE 1=1
                    AND A.STL_NO = B.STL_NO
                    AND A.STL_NO = C.COIL_NO
                    AND A.YD_STK_LYR_STAT IN ('L', 'C')     --적치중
                    AND C.CURR_PROG_CD LIKE (CASE WHEN B.TRN_WRK_MTL_GP = 'H' THEN 'E' ELSE '%' END)
                    AND SUBSTR(A.YD_STK_COL_GP, 3, 2) BETWEEN '00' AND '99'
                    AND B.SPOS_WLOC_CD              = :V_WLOC_CD
                    AND B.TS_MATL_FTMV_STAT_GP      = '1'
                    AND B.MATL_FTMV_WO_NML_HD_YN    = 'Y'
                    AND B.TRANSWORD_SEQNO =
                    (
                        SELECT
                            MAX(TRANSWORD_SEQNO)
                        FROM
                            TB_TS_MATL_FTMV_WO D
                        WHERE 1=1
                        AND D.STL_NO = B.STL_NO
                        AND ROWNUM <= 1
                    )
                    AND B.TRN_WRK_MTL_GP LIKE
                    (
                        SELECT
                            NVL(TRN_WRK_MTL_GP,'H')
                        FROM
                            TB_TS_TRN_EQP_OPRN_PLN
                        WHERE 1=1
                        AND SYSDATE BETWEEN CARASGN_ST_DT AND CARASGN_END_DT
                        AND TRN_EQP_CD = :V_TRN_EQP_CD
                        AND DEL_YN = 'N'
                        AND ROWNUM <= 1
                    ) ||'%'
                ) A,
                (
                    SELECT
                        NEXT_PROC
                    FROM
                        TB_TS_TRN_EQP_OPRN_PLN
                    WHERE 1=1
                    AND SYSDATE BETWEEN CARASGN_ST_DT AND CARASGN_END_DT
                    AND TRN_EQP_CD = :V_TRN_EQP_CD
                    AND DEL_YN = 'N'
                    AND ROWNUM <= 1
                ) D1,       --구내차공정우선순위
                (
                    SELECT
                        DTL_ITEM2 AS SCH_RULE_VAL,  --우선순위
                        ITEM AS SCH_CD              --차공정구분
                    FROM
                        TB_YF_RULE
                    WHERE 1=1
                    AND REPR_CD_GP = 'YM08'
                    AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN NVL(DTL_ITEM3, '19010101000000') AND NVL(DTL_ITEM4, '99991231235959')
                    AND CD_GP = '1'
                    UNION ALL
                    
                    SELECT
                        '1' AS SCH_RULE_VAL,
                        'XX' AS SCH_CD
                    FROM
                        DUAL
                ) D3,       --야드차공정우선순위
                (
                    SELECT
                        BAY_GP AS DONG,
                        NVL(COUNT(CAR_CARD_NO),0)+NVL(COUNT(CARD_NO),0)+ NVL(COUNT(TRN_EQP_CD),0) AS CNT
                    FROM
                        TB_YF_STKCOL
                    WHERE 1=1
                    AND WLOC_CD =  :V_WLOC_CD
                    AND SECT_GP = 'PT'
                    GROUP BY BAY_GP
                ) D7        --차량위치체크
            WHERE 1=1
            AND A.CM_AIM    = D3.SCH_CD(+)      --**** 이부분이 getListFrtoStl_CoilNewB 과 다르다****
            AND A.NEXT_PROC = D1.NEXT_PROC(+)
            AND A.CUR_DONG  = D7.DONG(+)
        ) AA
    ORDER BY
        AA.NEXT_PROC,       --구내차공정우선순위
        AA.MTL_UGNT_GP,     --긴급재순위
        AA.CAR_CNT,         --차량갯수
        AA.SEQ_NO,
        (CASE WHEN AA.GP = 'CM' THEN 1 ELSE LENGTH(AA.STL_NO) END),
        AA.SCH_RULE_VAL,    --야드차공정우선순위
        AA.YD_STK_COL_GP,
        AA.YD_STK_LYR_NO DESC,
        AA.YD_STK_BED_NO,
        AA.COIL_W
)
SELECT
    *
FROM
    TEMP_TABLE AA
WHERE 1=1
AND
(
    (GP = 'CM' AND (CM_AIM, SUBSTR(YD_STK_COL_GP, 1, 2)) = (SELECT CM_AIM, SUBSTR(YD_STK_COL_GP, 1, 2) FROM TEMP_TABLE WHERE ROWNUM <= 1 ))
    OR
    (GP = 'CG' AND (SEQ_NO) = (SELECT SEQ_NO FROM TEMP_TABLE WHERE ROWNUM <= 1 ))
)
ORDER BY
    AA.NEXT_PROC,       --구내차공정우선순위
    AA.MTL_UGNT_GP,     --긴급재순위
    AA.CAR_CNT,         --차량갯수
    AA.SEQ_NO,
    (CASE WHEN AA.GP = 'CM' THEN 1 ELSE LENGTH(AA.STL_NO) END),
    AA.SCH_RULE_VAL,    --야드차공정우선순위
    AA.YD_STK_COL_GP,
    AA.YD_STK_LYR_NO DESC,
    AA.YD_STK_BED_NO,
    AA.COIL_W
 </pre> */
public final static String getListFrtoStl_CoilNewA = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListFrtoStl_CoilNewA";

