 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListCOILGPTrackingByHFLSPMEQL_PIDEV 

SELECT  ROWNUM AS RNUM 
      , AA.*
      , CASE WHEN AA.CURR_PROG_CD IS NOT NULL THEN
            ('[' || AA.CURR_PROG_CD || '] ' || ( SELECT CD_MNNG FROM BRE.VW_CM_CODES WHERE CD_EN_ID = 'PROG_CD' AND CD_CAT_ID = 'HS0000' AND CD_VAL = AA.CURR_PROG_CD ) )
        END AS CURR_PROG_CD_NM
      , CASE WHEN AA.NEXT_PROC IS NOT NULL THEN
            ('[' || AA.NEXT_PROC || '] ' || ( SELECT CD_MNNG FROM BRE.VW_CM_CODES WHERE CD_EN_ID = 'NEXT_PROC' AND CD_CAT_ID = 'HS0000' AND CD_VAL = AA.NEXT_PROC ) )
        END AS NEXT_PROC_NM
      , CASE WHEN AA.CUST_CD IS NOT NULL THEN
            ('[' || AA.CUST_CD || '] ' || ( SELECT NAME_ORG1 FROM USRCOM.TB_COM_BP_MASTER WHERE PARTNER = AA.CUST_CD ) )
        END AS CUST_NM
      , CASE WHEN AA.CUST_CD IS NOT NULL THEN
            ( SELECT NAME_ORG1 FROM USRCOM.TB_COM_BP_MASTER WHERE PARTNER = AA.CUST_CD ) 
        END AS CUST_NM2
  FROM  (  
                SELECT  A.PROC_GP
                  , DECODE(A.PROC_GP,'F','HFL','K','SPM','Q','EQL','???') AS PROC_GP_NM
                  --, D.YD_EQP_GP 
                  , A.STL_NO
                  , A.YD_EQP_NM
                  , A.PROC_GP || '_' || SUBSTR(A.YD_STK_COL_GP,2,1) || ROW_NUMBER() OVER( PARTITION BY A.YD_GP, A.PROC_GP, SUBSTR(A.YD_STK_COL_GP,2,1)  ORDER BY A.SORT_SEQ)  AS EQUIP_ID
                  , C.COIL_T -- 두께
                  , C.COIL_W -- 폭
                  , C.COIL_OUTDIA -- 외경
                  , C.COIL_WT -- 중량
                  , C.COIL_T AS COIL_T2
                  , TRIM(TO_CHAR(C.COIL_W,'9,999,999'))  AS COIL_W2
                  , TRIM(TO_CHAR(C.COIL_OUTDIA,'9,999,999')) AS COIL_OUTDIA2
                  , TRIM(TO_CHAR(C.COIL_WT,'9,999,999')) AS COIL_WT2
                  , C.STL_APPEAR_GP
                  , C.SPEC_ABBSYM
                  , C.ITEMNAME_CD
                  , C.CURR_PROG_CD
                  , CASE 
                        WHEN C.SKINPASS_YN IN('A', 'E')  AND C.SCRAP_CAUSE_CD IS  NULL AND C.CURR_PROG_CD NOT IN ('G','F','H')
                        THEN 'D'
                        WHEN C.SCRAP_CAUSE_CD IS NOT NULL AND C.CURR_PROG_CD <> 'C' AND A.PROC_GP <> 'F'
                        THEN 'S'
                        WHEN C.NEXT_PROC = '9S' AND C.CURR_PROG_CD <> 'C'
                        THEN 'I'
                        WHEN C.NEXT_PROC = '9C' AND C.CURR_PROG_CD = 'D'
                        THEN 'H'
                        ELSE DECODE(C.CURR_PROG_CD
                                 , '2', 'H'
                                 , '3', 'D'
                                 , '4', 'E'
                                 , '6', 'L'
                                 , '7', 'K'
                                 , '8', 'M'
                                 , '9', 'P'
                                 , C.CURR_PROG_CD)
                   END AS CURR_PROG_CD_IMG
                  , C.NEXT_PROC
                  , C.CUST_CD
                  , A.LOC_NO
                  , A.SKID_NO
                  , A.YD_STK_COL_GP
                  , A.YD_STK_BED_NO
                  , NVL((SELECT 'S' FROM TB_YF_WRKBOOKMTL WM WHERE WM.STL_NO = A.STL_NO AND WM.DEL_YN = 'N' AND ROWNUM = 1),D.YD_STK_LYR_STAT) AS YD_STK_LYR_STAT
                  , COUNT(A.STL_NO) OVER() AS TOTALCOUNT
                  , SUM(C.COIL_WT) OVER() AS TOTAL_WT  
                  , A.YD_BAY_GP
                  , SR.SHEAR_WORK_DT -- 정정일시
                  , NVL(CASE WHEN A.PROC_GP = 'F' THEN 'Y' ELSE CASE WHEN SR.STEP_NO IS NULL THEN 'N' ELSE 'Y' END END,'N') AS IS_SHEAR_RST -- 정정실적 발생여부
                  , CASE WHEN NVL(SR.GOODS_DIVIDE_QNTY,0)>1 THEN 'Y' ELSE 'N' END AS IS_DCOIL -- 코일생성구분(자코일)
                  , (
                        SELECT R.REPR_CD_CONTENTS
                        FROM VW_YF_CONDENSATIONLOC VW, TB_YF_RULE R
                        WHERE VW.COIL_NO = A.STL_NO
                        AND R.REPR_CD_GP = 'YM6001'
                        AND R.CD_GP = '1'
                        AND R.DEL_YN = 'N'
                        AND VW.YD_ZONE_GP = R.ITEM
                  ) AS YD_ZONE_GP
                  , C.USAGE_CD 
                  , CASE WHEN A.STL_NO LIKE 'S%' THEN 'Y' ELSE 'N' END AS IS_SCRAP
                  , CASE WHEN
                        (
                            --정정 실적 처리된 항목 중 최근 실적이 재작업인 경우 추출.
                            SELECT
                                COUNT(*)
                            FROM
                                TB_HR_C_SHEARWOWR SR
                            WHERE 1=1
                            AND SR.STEP_NO =
                            (
                                SELECT --+ INDEX_DESC(A PK_HR_C_SHEARWOWR)
                                    MAX(STEP_NO)
                                FROM
                                    TB_HR_C_SHEARWOWR A
                                WHERE 1=1
                                AND COIL_NO = SR.COIL_NO
                                AND WORK_STAT = '*'
                                AND ROWNUM<=1
                            )
                            AND SR.COIL_NO = A.STL_NO
                            AND SR.RECEIPT_HOLD_SCRAP_CAUSE_GP in('J', 'Q')
                        ) = 1 THEN 'Y'
                        WHEN
                        (
                            SELECT
                                COUNT(*)
                            FROM
                                VW_YF_COILCOMM B
                            WHERE 1=1
                            AND B.COIL_NO = A.STL_NO
                            AND ((B.REMAIN_PROC1='1K' AND B.REMAIN_PROC2='1Q') OR B.REMAIN_PROC1='1Q')
                        ) = 1 THEN 'Y'
                        WHEN
                        (
                            SELECT
                                COUNT(*)
                            FROM
                                VW_YF_COILCOMM B
                            WHERE 1=1
                            AND B.COIL_NO = A.STL_NO
                            AND B.CURR_PROG_CD = 'F'
                            AND B.HOLD_CAUSE_CD = '43'  --판정보류 : '43'
                        ) = 1 THEN 'Y'
                  ELSE 'N' END AS IS_RESKCAPING
                    --
                  , NVL((CASE   WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%1K%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%5K%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%6K%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%HK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%EK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%CK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%BK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%AK%' THEN 'Y'
                            ELSE 'N' END),'N') AS IS_RESKCAPING
                   
              FROM  TB_YF_EQPTRACKING A
                  , VW_YF_COILCOMM C
                  , TB_YF_STKLYR D 
                  , TB_HR_C_SHEARWOWR SR
             WHERE  A.YD_GP = '1'
               AND  A.PROC_GP IN ('F', 'K', 'Q')
               AND  A.PROC_GP LIKE :V_PROC_GP || '%' --F:HFL,K:SPM,Q:EQL
               AND  A.STL_NO = C.COIL_NO(+)
               AND  A.STL_NO = SR.COIL_NO(+)
               AND  NVL(SR.STEP_NO,0) = ( SELECT NVL(MAX(X.STEP_NO),0) FROM TB_HR_C_SHEARWOWR X WHERE X.COIL_NO = A.STL_NO)
               AND  A.YD_STK_COL_GP = D.YD_STK_COL_GP(+)
               AND  A.YD_STK_BED_NO = D.YD_STK_BED_NO(+)
               AND  D.YD_STK_LYR_NO(+) = '01' 
             ORDER BY A.YD_GP, A.PROC_GP, A.SORT_SEQ 
) AA
 </pre> */
public final static String getListCOILGPTrackingByHFLSPMEQL = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListCOILGPTrackingByHFLSPMEQL_PIDEV";

 /** <pre> 2019-12-16
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMonitor
-- 크레인 작업 모니터링 조회
WITH PARAM AS (
    SELECT :V_YD_GP   AS P_YD_GP        -- 야드구분
         , :V_BAY_GP  AS P_BAY_GP       -- 동구분
      FROM DUAL
)
SELECT    Y.YD_EQP_ID              -- 설비(크레인)구분
        , Y.YD_EQP_ID2
        , Y.CRN_WRK_PROC_STAT     -- 설비상태  (L2기준)
        , Y.CRN_WRK_PROC_STAT_NM  -- 설비상태명(L2기준)
        --, DECODE(Y.CRN_WRK_PROC_STAT_NM,'고장',Y.YD_EQP_PROG_STAT_NM,Y.CRN_WRK_PROC_STAT_NM ) AS CRN_WRK_PROC_STAT_NM

        , Y.YD_EQP_PROG_STAT            -- 설비상태  (L3기준)
        , Y.YD_EQP_PROG_STAT_NM         -- 설비상태명(L3기준) -- 화면 JSP 표기
        , Y.YD_CRN_SCH_ID         -- 스케쥴ID
        , Y.YD_CRN_SCH_NM         -- 스케쥴코드명
        , Y.CURR_XAXIS            -- 현재위치 X좌표
        , Y.START_X_AXIS          -- 야드 시작 X좌표
        , Y.END_X_AXIS            -- 야드 끝   X좌표
        , Y.YD_DIR_GP             -- 이동방향
        , Y.CRN_WRK_X_AXIS_MIN
        , Y.CRN_WRK_X_AXIS_MAX
        , Y.FROM_XAXIS            -- 시작위치 X좌표
        , Y.TO_XAXIS              -- 목표위치 X좌표
        
        -- 간섭거리 계산 : 좌우 +24000 , 상태 W[대기]일땐 0으로 변경
        , CASE WHEN INTERF_FROM_XAXIS < 0          OR YD_EQP_PROG_STAT  = 'W' THEN 0 ELSE INTERF_FROM_XAXIS END AS INTERF_FROM_XAXIS
        , CASE WHEN YD_EQP_PROG_STAT = 'W'                                    THEN 0              -- 대기면 무조건 0
               WHEN INTERF_TO_XAXIS   > END_X_AXIS AND YD_EQP_PROG_STAT <>'W' THEN END_X_AXIS     -- 동 X좌표를 초과하면 동의 마지막 X좌표
                                                                        ELSE INTERF_TO_XAXIS END          AS INTERF_TO_XAXIS
        , STL_NO
        , YD_AID_WRK_YN  -- 주,보조 작업여부
        , Y.YD_UP_WO_LOC || Y.YD_UP_WO_LYR AS YD_UP_WO_LOC -- 권상지시위치
        , Y.YD_DN_WO_LOC || Y.YD_DN_WO_LYR AS YD_DN_WO_LOC -- 권하지시위치
        
        , Y.YD_EQP_WRK_MODE_NM -- 설비작업모드
        
        -- 고도화 적용여부
        , (
            SELECT DTL_ITEM1
            FROM TB_YF_RULE R, PARAM P 
            WHERE R.REPR_CD_GP = 'APP100'
              AND R.CD_GP  = P.P_YD_GP
              AND R.ITEM   = P.P_BAY_GP
              AND R.DEL_YN = 'N'
          ) AS YD_AVD_YN
        
  FROM
        (
            SELECT 
                  X.YD_EQP_ID            -- 설비(크레인)구분
                , SUBSTR(X.YD_EQP_ID, 5, 2) AS YD_EQP_ID2
                , X.CRN_WRK_PROC_STAT   -- 설비상태(L2기준)
                , DECODE(X.CRN_WRK_PROC_STAT, '00', '작업대기'
                                            , '01', '권상위치 이동중'
                                            , '02', '권상위치 HoistDown'
                                            , '03', '권상위치 Coil_PickUp'
                                            , '04', '권상위치 HoistUp'
                                            , '05', '권상실적 발생후HoistUp'
                                            , '06', '권하위치 이동가능Ready'
                                            , '07', '권하위치 이동중'
                                            , '08', '권하위치 HoistDown'
                                            , '09', '권하위치 CoilPlace'
                                            , '10', '권하위치 HoistUp'
                                            , '11', '권하실적 발생후HoistUp'
                                            , '12', '초기화중 (INITIAL)'
                                            , '13', '일시정지중 (STOP)'
                                            , '14', '비상정지중 (E-STOP)'
                                            , '15', '단순이동중'
                                            , '99', '유인'
                                                  , '기타'    ) AS CRN_WRK_PROC_STAT_NM  -- 설비상태명(L2기준)
                , X.YD_EQP_PROG_STAT              -- 설비상태(L3기준)
                , DECODE(X.YD_EQP_PROG_STAT       , 'B', '고장'
                                            , 'W', '대기'
                                            , 'S', '대기'
                                            , '1', '선택'
                                            , '2', '권상'
                                            , '3', '권상'
                                            , '4', '대기'
                                            , '기타'      ) AS YD_EQP_PROG_STAT_NM  -- 설비상태명(L3기준)

                , X.YD_CRN_SCH_NM
                , X.CURR_XAXIS          -- 현재위치  X좌표
                , X.FROM_XAXIS          -- 시작위치  X좌표
                , X.TO_XAXIS            -- 목표위치  X좌표
                , X.START_X_AXIS        -- 야드 시작 X좌표
                , X.END_X_AXIS          -- 야드 끝   X좌표
                , CASE WHEN TO_NUMBER(X.FROM_XAXIS) < TO_NUMBER(X.TO_XAXIS) THEN 'R'
                       WHEN TO_NUMBER(X.FROM_XAXIS) = TO_NUMBER(X.TO_XAXIS) THEN 'C'
                                                                            ELSE 'L' END AS YD_DIR_GP -- 이동방향
                -- 간섭거리 계산
                , CASE WHEN TO_NUMBER(INTERF_FROM_XAXIS) <= TO_NUMBER(INTERF_TO_XAXIS) THEN (INTERF_FROM_XAXIS - 24000)
                                                                                       ELSE (INTERF_FROM_XAXIS + 24000) END AS INTERF_FROM_XAXIS -- 간섭거리 포함 앞쪽 좌표
                , CASE WHEN TO_NUMBER(INTERF_FROM_XAXIS) <= TO_NUMBER(INTERF_TO_XAXIS) THEN (INTERF_TO_XAXIS   + 24000)
                                                                                       ELSE (INTERF_TO_XAXIS   - 24000) END AS INTERF_TO_XAXIS   -- 간섭거리 포함 뒤쪽 좌표
                
                -- 크레인 작업범위
                , (
                    SELECT MIN(B.YD_STK_LYR_X_AXIS)
                      FROM TB_YF_RULE       A
                         , TB_YF_STKLYR B
                     WHERE 1=1
                       AND A.ITEM           = B.YD_STK_COL_GP
                       AND A.REPR_CD_GP     = 'CR0001'
--                       AND A.REPR_CD_GP     = 'CR0003' 
                       AND B.YD_STK_BED_NO   = '01'  -- 1번 BED
                       AND B.YD_STK_LYR_NO = '01'  -- 1단
                       AND B.YD_STK_LYR_X_AXIS > 0 -- 0은 없는 설비,SPAN
                       AND NVL(A.DEL_YN, 'N') = 'N'
                       AND NVL(B.DEL_YN, 'N') = 'N'
                       AND A.CD_GP          = X.YD_EQP_ID
                ) AS CRN_WRK_X_AXIS_MIN
                
                , (
                    SELECT MAX(B.YD_STK_LYR_X_AXIS)
                      FROM TB_YF_RULE       A
                         , TB_YF_STKLYR B
                     WHERE 1=1
                       AND A.ITEM           = B.YD_STK_COL_GP
                       AND A.REPR_CD_GP     = 'CR0001'
--                       AND  A.REPR_CD_GP   = 'CR0003' 
                       AND B.YD_STK_BED_NO   = '01'  -- 1번 BED
                       AND B.YD_STK_LYR_NO = '01'  -- 1단
                       AND B.YD_STK_LYR_X_AXIS > 0 -- 0은 없는 설비,SPAN
                       AND NVL(A.DEL_YN, 'N') = 'N'
                       AND NVL(B.DEL_YN, 'N') = 'N'
                       AND A.CD_GP          = X.YD_EQP_ID
                ) AS CRN_WRK_X_AXIS_MAX
                , X.YD_CRN_SCH_ID
                
                , (SELECT STL_NO      FROM TB_YF_CRNWRKMTL WHERE YD_CRN_SCH_ID = X.YD_CRN_SCH_ID AND DEL_YN = 'N') AS STL_NO      -- 코일
                , (SELECT YD_AID_WRK_YN FROM TB_YF_CRNWRKMTL WHERE YD_CRN_SCH_ID = X.YD_CRN_SCH_ID AND DEL_YN = 'N') AS YD_AID_WRK_YN -- 주,보조 작업여부
                , X.YD_UP_WO_LOC
                , X.YD_UP_WO_LYR
                , X.YD_DN_WO_LOC
                , X.YD_DN_WO_LYR
                , X.YD_EQP_WRK_MODE2 -- 설비작업모드
                , DECODE(X.YD_EQP_WRK_MODE2 , 'A', '자동'
                                            , 'R', '리모컨'
                                            , 'E', '정비'
                                            , 'M', '유인'   ) AS YD_EQP_WRK_MODE_NM  -- 설비상태명(L3기준)
                        
              FROM
            (
                SELECT CR.EQUIP_GP AS YD_EQP_ID          -- 설비(크레인)구분
                     , CR.YD_GP             -- 야드구분
                     , CR.BAY_GP            -- 동구분
                     , CR.CRN_WRK_PROC_STAT -- 크레인 상태
                     , CR.CURR_XAXIS        -- 현재위치 X좌표
                     
                     , DECODE(EQ.YD_EQP_PROG_STAT, 'W', 0, CR.FROM_XAXIS) AS FROM_XAXIS         -- 시작위치 X좌표
                     , DECODE(EQ.YD_EQP_PROG_STAT, 'W', 0, CR.TO_XAXIS  ) AS TO_XAXIS           -- 목표위치 X좌표
                     
                     , DECODE(EQ.YD_EQP_PROG_STAT, 'W', 0, CASE WHEN CR.FROM_XAXIS < CR.TO_XAXIS THEN CR.FROM_XAXIS ELSE CR.TO_XAXIS END  ) AS INTERF_FROM_XAXIS         -- 시작위치 X좌표
                     , DECODE(EQ.YD_EQP_PROG_STAT, 'W', 0, CASE WHEN CR.FROM_XAXIS < CR.TO_XAXIS THEN CR.TO_XAXIS ELSE CR.FROM_XAXIS END  ) AS INTERF_TO_XAXIS           -- 목표위치 X좌표
                     , EQ.YD_EQP_PROG_STAT
                     --*****************************************************************
                     -- YD_EQP_PROG_STAT (크레인 현재 상태_L3 기준)
                     고장     : B
                     정상     : N
                     복구     : R
                     대기     : W
                     권상지시 : 1
                     권상     : 2
                     권하지시 : 3
                     권하     : 4
                     *****************************************************************
                     
                     --야드 동의 시작지점과 끝지점 X좌표
                    , 0 AS START_X_AXIS
                    , 342811 AS END_X_AXIS
                    , (
                        SELECT CSH.CD_CONTENTS||DECODE(SC.AUTO_YN, 'Y', '-A', '')||' ['||SC.YD_SCH_CD||']'
                          FROM TB_YF_SCHRULE CSH
                         WHERE 1=1
                           AND SC.YD_SCH_CD     = CSH.YD_SCH_CD
                           AND CSH.DEL_YN       = 'N'
                      ) AS YD_CRN_SCH_NM
                    , SC.YD_CRN_SCH_ID
                    , NVL(SC.YD_UP_WR_LOC   , SC.YD_UP_WO_LOC   ) AS YD_UP_WO_LOC   -- 권상지시위치
                    , NVL(SC.YD_UP_WR_LYR , SC.YD_UP_WO_LYR ) AS YD_UP_WO_LYR
                    , NVL(SC.YD_DN_WR_LOC   , SC.YD_DN_WO_LOC   ) AS YD_DN_WO_LOC   -- 권하지시위치
                    , NVL(SC.YD_DN_WR_LYR , SC.YD_DN_WO_LYR ) AS YD_DN_WO_LYR
                    , EQ.YD_EQP_WRK_MODE2 -- 설비작업모드
                    
                    
              FROM TB_YM_CRANEEQUIP CR --BHCYD.TB_AY_CRN_STA_L3@DL_BHCYDL2 CR -- TB_YM_CRANEEQUIP CR
                 , TB_YF_EQP      EQ
                 , (SELECT SC.*
                         , (SELECT CASE WHEN REGISTER = 'AUTO_MVSTK' THEN 'Y' ELSE 'N' END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = SC.YD_WBOOK_ID) AS AUTO_YN
                      FROM TB_YF_CRNSCH SC
                     WHERE SC.YD_WRK_PROG_STAT <> 'W' 
                       AND SC.DEL_YN = 'N'
                       AND SC.YD_CRN_SCH_ID IN (SELECT MAX(YD_CRN_SCH_ID) FROM  TB_YF_CRNSCH
                                                 WHERE DEL_YN = 'N'
                                                   AND YD_EQP_ID LIKE '1%' 
                                                   AND YD_WRK_PROG_STAT <> 'W' 
                                                 GROUP BY YD_EQP_ID )) SC
                 , PARAM
             WHERE CR.EQUIP_GP        = EQ.YD_EQP_ID
               AND CR.EQUIP_GP        = SC.YD_EQP_ID(+)
               AND 'N' = SC.DEL_YN(+)
               AND CR.YD_GP           = PARAM.P_YD_GP     -- 야드구분 >> 2 : SLAB , 3 : COIL
               AND CR.BAY_GP          = PARAM.P_BAY_GP    -- 동구분
               -- 무인 크레인만 조회
               AND CR.EQUIP_GP IN (
                                        SELECT YD_EQP_ID
                                          FROM TB_YF_EQP
                                         WHERE YD_GP = '1'
                                           AND YD_EQP_GP = 'CR'
                                           AND YD_BAY_GP IN ('A', 'C', 'E')
                                  )
            ) X
          ORDER BY YD_EQP_ID
        ) Y
 </pre> */
public final static String getCrnWrkMonitor = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMonitor";

