 /** <pre> 2020-12-08
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcCRDMJ018_PIDEV
SELECT
    'CRDMJ018'                              AS JMS_TC_CD,           --JMSTC코드
    TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')     AS JMS_TC_CREATE_DDTT,  --JMSTC생성일시
    'CRDMJ018'                              AS TC_CODE,             --IF구분코드
    TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')     AS TC_CREATE_DDTT,      --TC생성일시
    CR_YD_GP_FR,                                                    --출발냉연야드
    --'LD00'                                  AS CR_YD_GP_TO,         --도착냉연야드
    'DC0C'                                  AS CR_YD_GP_TO,         --도착냉연야드
    CAR_NO,                                                         --차량번호
    CR_CAR_NO,                                                      --냉연차량번호
    CARLD_SH,                                                       --상차매수
    MAX(DECODE(RNK,1,DD.STL_NO,''))         AS GOODS_NO1,           --제품번호1
    MAX(DECODE(RNK,1,DD.COIL_RMW_WGT,''))   AS GOODS_WT1,           --제품중량1
    MAX(DECODE(RNK,2,DD.STL_NO,''))         AS GOODS_NO2,           --제품번호2
    MAX(DECODE(RNK,2,DD.COIL_RMW_WGT,''))   AS GOODS_WT2,           --제품중량2
    MAX(DECODE(RNK,3,DD.STL_NO,''))         AS GOODS_NO3,           --제품번호3
    MAX(DECODE(RNK,3,DD.COIL_RMW_WGT,''))   AS GOODS_WT3,           --제품중량3
    MAX(DECODE(RNK,4,DD.STL_NO,''))         AS GOODS_NO4,           --제품번호4
    MAX(DECODE(RNK,4,DD.COIL_RMW_WGT,''))   AS GOODS_WT4,           --제품중량4
    MAX(DECODE(RNK,5,DD.STL_NO,''))         AS GOODS_NO5,           --제품번호5
    MAX(DECODE(RNK,5,DD.COIL_RMW_WGT,''))   AS GOODS_WT5,           --제품중량5
    MAX(DECODE(RNK,6,DD.STL_NO,''))         AS GOODS_NO6,           --제품번호6
    MAX(DECODE(RNK,6,DD.COIL_RMW_WGT,''))   AS GOODS_WT6,           --제품중량6
    MAX(DECODE(RNK,7,DD.STL_NO,''))         AS GOODS_NO7,           --제품번호7
    MAX(DECODE(RNK,7,DD.COIL_RMW_WGT,''))   AS GOODS_WT7,           --제품중량7
    MAX(DECODE(RNK,8,DD.STL_NO,''))         AS GOODS_NO8,           --제품번호8
    MAX(DECODE(RNK,8,DD.COIL_RMW_WGT,''))   AS GOODS_WT8,           --제품중량8
    MAX(DECODE(RNK,9,DD.STL_NO,''))         AS GOODS_NO9,           --제품번호9
    MAX(DECODE(RNK,9,DD.COIL_RMW_WGT,''))   AS GOODS_WT9,           --제품중량9
    MAX(DECODE(RNK,10,DD.STL_NO,''))        AS GOODS_NO10,          --제품번호10
    MAX(DECODE(RNK,10,DD.COIL_RMW_WGT,''))  AS GOODS_WT10,          --제품중량10
    MAX(DECODE(RNK,11,DD.STL_NO,''))        AS GOODS_NO11,          --제품번호11
    MAX(DECODE(RNK,11,DD.COIL_RMW_WGT,''))  AS GOODS_WT11,          --제품중량11
    MAX(DECODE(RNK,12,DD.STL_NO,''))        AS GOODS_NO12,          --제품번호12
    MAX(DECODE(RNK,12,DD.COIL_RMW_WGT,''))  AS GOODS_WT12,          --제품중량12
    MAX(DECODE(RNK,13,DD.STL_NO,''))        AS GOODS_NO13,          --제품번호13
    MAX(DECODE(RNK,13,DD.COIL_RMW_WGT,''))  AS GOODS_WT13,          --제품중량13
    MAX(DECODE(RNK,14,DD.STL_NO,''))        AS GOODS_NO14,          --제품번호14
    MAX(DECODE(RNK,14,DD.COIL_RMW_WGT,''))  AS GOODS_WT14,          --제품중량14
    MAX(DECODE(RNK,15,DD.STL_NO,''))        AS GOODS_NO15,          --제품번호15
    MAX(DECODE(RNK,15,DD.COIL_RMW_WGT,''))  AS GOODS_WT15,          --제품중량15
    CARLD_CMPL_DT,                                                  --상차완료일시
    CARUD_CMPL_DT                                                   --하차완료일시
FROM
    (
        SELECT
            RANK() OVER(ORDER BY B.YD_STK_BED_NO ASC) AS RNK,
            COUNT(*) OVER() AS CARLD_SH,
            CASE
            WHEN SUBSTR(A.SPOS_WLOC_CD, 1, 2) = 'DX' THEN 'LB00'    --1냉연
            WHEN SUBSTR(A.SPOS_WLOC_CD, 1, 2) = 'DY' THEN 'LC00'    --2냉연
            ELSE 'LA00'                                             --순천
            END AS CR_YD_GP_FR,
            NVL(A.TRN_EQP_CD, A.CAR_NO) AS CAR_NO,
            A.CARD_NO AS CR_CAR_NO,
            B.STL_NO,
            C.COIL_RMW_WGT,
            TO_CHAR(A.REG_DDTT, 'YYYYMMDDHH24MISS') AS CARLD_CMPL_DT,
            TO_CHAR(NVL(A.YD_CARUD_CMPL_DT, SYSDATE), 'YYYYMMDDHH24MISS') AS CARUD_CMPL_DT
        FROM
            TB_YD_CARSCH A,
            TB_YD_CARFTMVMTL B,
            TB_YF_CR_COILCOMM C
        WHERE 1=1
        AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
        AND B.STL_NO = C.COIL_NO
        AND A.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
    ) DD
GROUP BY CR_YD_GP_FR, CAR_NO, CR_CAR_NO, CARLD_SH, CARLD_CMPL_DT, CARUD_CMPL_DT
 </pre> */
public final static String TcCRDMJ018 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcCRDMJ018_PIDEV";

