 /** <pre> 2019-08-27
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandTrnEqpCd
SELECT YD_STK_COL_GP
     , YD_STK_BED_NO 
     , YD_STK_LYR_NO 
     , YD_MTL_SH 
  FROM
(
SELECT SB.YD_STK_COL_GP
     , SB.YD_STK_BED_NO 
     , SL.YD_STK_LYR_NO 
      ,COUNT(SL.STL_NO) AS YD_MTL_SH
  FROM TB_YF_STKBED SB
      ,TB_YF_STKLYR SL
      ,(SELECT YD_STK_COL_GP AS YD_STK_COL_GP                         
          FROM TB_YD_CARPOINT                          
         WHERE TRN_EQP_CD = :V_TRN_EQP_CD
           AND DEL_YN = 'N' ) SC
 WHERE SB.YD_STK_COL_GP = SL.YD_STK_COL_GP
   AND SB.YD_STK_BED_NO = SL.YD_STK_BED_NO
   AND SB.YD_STK_COL_GP = SC.YD_STK_COL_GP
   AND SB.DEL_YN        = 'N'
   AND SB.YD_STK_BED_ACTIVE_STAT = 'L' --적치가능
   AND SL.YD_STK_LYR_NO='01' --차량위치는 1단만 적치
   AND SB.YD_STK_COL_GP||SB.YD_STK_BED_NO||SL.YD_STK_LYR_NO NOT IN ( SELECT NVL(YD_DN_WO_LOC||YD_DN_WO_LYR,'1') FROM TB_YF_CRNSCH WHERE DEL_YN = 'N')
   AND SL.STL_NO IS NULL
 GROUP BY SB.YD_STK_COL_GP, SB.YD_STK_BED_NO, SL.YD_STK_LYR_NO 
 ORDER BY SB.YD_STK_COL_GP, SB.YD_STK_BED_NO, SL.YD_STK_LYR_NO 
 )
WHERE YD_MTL_SH = 0
   AND ROWNUM = 1
 </pre> */
public final static String getYdStkBedByCarUseGpandTrnEqpCd = "com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandTrnEqpCd";

 /** <pre> 2019-09-24
--yf.common.dao.selectMultyBay
--복수동의 정보를 리턴한다.
SELECT 
    A.*, 
    C.CAR_NO, 
    C.ARR_WLOC_CD, 
    C.YD_PNT_CD3 AS ARR_YD_PNT_CD
FROM 
    (
        SELECT  
            A.STL_NO,
            A.STOCK_ITEM,
            A.CAR_CARD_NO,
            A.TRANS_ORD_DATE,
            A.TRANS_ORD_SEQNO,
            C.FRTOMOVE_EQUIP_GP,
            B.YD_STK_BED_NO,
            B.YD_STK_LYR_NO
        FROM     
            TB_YF_STOCK A,
            TB_YF_STKLYR B,
            TB_YF_STKCOL C
        WHERE 1=1
        AND A.STL_NO = B.STL_NO
        AND B.YD_STK_COL_GP = C.YD_STK_COL_GP
        AND A.CAR_CARD_NO = ?
        AND (SUBSTR(C.FRTOMOVE_EQUIP_GP,3,2) = 'TR' OR SUBSTR(C.FRTOMOVE_EQUIP_GP,3,2) = 'PT')
        AND A.DEL_YN = 'N'
    ) A,
    TB_YD_CARFTMVMTL B,
    TB_YD_CARSCH C
WHERE 1=1
AND A.STL_NO      = B.STL_NO
AND B.YD_CAR_SCH_ID = C.YD_CAR_SCH_ID
AND C.DEL_YN        = 'N'
AND B.DEL_YN        = 'N'
ORDER BY A.YD_STK_BED_NO, A.YD_STK_LYR_NO DESC
 </pre> */
public final static String selectMultyBay = "yf.common.dao.selectMultyBay";

 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListFrtoStl_CoilNewsangcha
WITH TEMP_TABLE AS
(
    SELECT
        AA.*
    FROM
        (
            SELECT
                D1.NEXT_PROC,   --구내차공정우선순위
                DECODE(A.MTL_UGNT_GP, 'Y', '1', 'N', '2') AS MTL_UGNT_GP,   --긴급재순위
                (CASE WHEN D7.CNT=0  AND A.GP ='CM' THEN 1 ELSE D7.CNT END) AS CAR_CNT, --차량갯수
                SEQ_NO,
                DECODE(A.GP,'CG',' ',D3.SCH_RULE_VAL) AS SCH_RULE_VAL,      --야드차공정우선순위
                A.YD_STK_COL_GP,
                A.YD_STK_BED_NO,
                A.YD_STK_LYR_NO,
                A.GP,
                A.CUR_DONG,     --제품현재동
                A.CG_AIM,       --제품목표동
                A.CM_AIM,       --소재차공정
                A.STL_NO,
                A.SPOS_WLOC_CD, --발지개소
                A.ARR_WLOC_CD,  --착지개소
                A.HCR_GP,       --HCR구분
                A.STK_WT,       --중량
                A.COIL_W,
                STL_APPEAR_GP,
                YD_CAR_SCH_ID
            FROM
                (
                    SELECT
                        DECODE(C.STL_APPEAR_GP, 'Y', 'CG', 'CM') AS GP,             --제품CG, 소재CM 구분
                        DECODE(C.STL_APPEAR_GP, 'Y', SUBSTR(B.ARR_YD_PNT_CD,2,1), 'X') AS CG_AIM,  --제품목표동
                        DECODE(C.STL_APPEAR_GP, 'Y', 'XX', C.NEXT_PROC) AS CM_AIM,  --소재차공정
                        SUBSTR(A.YD_STK_COL_GP, 2, 1) AS CUR_DONG,                  --제품현재동
                        C.NEXT_PROC,
                        B.TRN_WRK_MTL_GP,       --운송작업재료구분 C:COIL제품, H:열연COIL, P:후판, S:SLAB, L:냉연COIL ...
                        A.STL_NO,
                        A.YD_STK_COL_GP,
                        A.YD_STK_BED_NO,
                        A.YD_STK_LYR_NO,
                        B.SPOS_WLOC_CD,         --발지개소
                        B.ARR_WLOC_CD,          --착지개소
                        B.MTL_UGNT_GP,          --긴급재구분
                        B.HCR_GP,               --HCR구분
                        C.COIL_WT AS STK_WT,    --중량
                        C.COIL_W,
                        C.STL_APPEAR_GP,
                        (
                            SELECT
                                MAX(YD_CAR_SCH_ID)
                            FROM
                                TB_YD_CARSCH
                            WHERE 1=1
                            AND DEL_YN = 'N'
                            AND TRN_EQP_CD = :V_TRN_EQP_CD  --운송장비코드
                        ) AS YD_CAR_SCH_ID,
                        B.SEQ_NO
                    FROM
                        USRYFA.TB_YF_STKLYR A,
                        TB_TS_MATL_FTMV_WO B,               --TS_소재이송지시(MTP)
                        VW_YF_COILCOMM C,
                        USRYFA.TB_YF_STOCK D
                    WHERE 1=1
                    AND A.STL_NO = B.STL_NO
                    AND A.STL_NO = C.COIL_NO
                    AND A.STL_NO = D.STL_NO
                    AND A.STL_NO NOT IN
                    (
                        SELECT
                            STL_NO
                        FROM
                            TB_YF_WRKBOOKMTL
                        WHERE 1=1
                        AND DEL_YN = 'N'
                    )
                    AND A.YD_STK_LYR_STAT IN ('L', 'C')     --적치중
                    AND SUBSTR(A.YD_STK_COL_GP, 3, 2) BETWEEN '00' AND '99'
                    AND A.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'
                    AND B.SPOS_WLOC_CD = :V_WLOC_CD         --발지개소코드
                    AND B.TS_MATL_FTMV_STAT_GP = '1'        --구내운송소재이송상태구분 1:이송지시완료
                    AND B.MATL_FTMV_WO_NML_HD_YN = 'Y'      --소재이송지시정상처리여부 Y:정상
                    AND B.TRN_WRK_MTL_GP LIKE
                    (
                        SELECT
                            NVL(TRN_WRK_MTL_GP, 'H')
                        FROM
                            TB_TS_TRN_EQP_OPRN_PLN          --TS_장비가동계획
                        WHERE 1=1
                        AND SYSDATE BETWEEN CARASGN_ST_DT AND CARASGN_END_DT --배차시작일시~배차종료일시
                        AND TRN_EQP_CD = :V_TRN_EQP_CD      --운송장비코드
                        AND DEL_YN = 'N'
                        AND ROWNUM <= 1
                    ) ||'%'
                ) A,
                (
                    SELECT
                        NEXT_PROC   --다음공정
                    FROM
                        TB_TS_TRN_EQP_OPRN_PLN              --TS_장비가동계획
                    WHERE 1=1
                    AND SYSDATE BETWEEN CARASGN_ST_DT AND CARASGN_END_DT    --배차시작일시~배차종료일시
                    AND TRN_EQP_CD = :V_TRN_EQP_CD          --운송장비코드
                    AND DEL_YN = 'N'
                    AND ROWNUM <= 1
                ) D1,   --구내차공정우선순위
                (
                    SELECT
                        DTL_ITEM2 AS SCH_RULE_VAL,           --우선순위
                        ITEM AS SCH_CD                      --차공정구분
                    FROM
                        USRYFA.TB_YF_RULE
                    WHERE 1=1
                    AND REPR_CD_GP = 'YM08'
                    AND TO_CHAR(SYSDATE ,'YYYYMMDDHH24MISS') BETWEEN NVL(DTL_ITEM3,'19010101000000') AND NVL(DTL_ITEM4, '99991231235959')
                    AND CD_GP = '1'                         --야드구분

                    UNION ALL

                    SELECT
                        '1' AS SCH_RULE_VAL,
                        'XX' AS SCH_CD
                    FROM
                        DUAL
                ) D3,   -- 야드차공정우선순위
                (
                    SELECT  --+ INDEX(A PK_YF_STACKCOL)
                        BAY_GP AS DONG,
                        NVL(COUNT(CAR_CARD_NO), 0) + NVL(COUNT(CARD_NO), 0) + NVL(COUNT(TRN_EQP_CD), 0) AS CNT
                    FROM
                        TB_YF_STKCOL A
                    WHERE 1=1
                    AND WLOC_CD = :V_WLOC_CD
                    AND YD_STK_COL_GP LIKE '1_PT%'
                    GROUP BY BAY_GP
                )D7     -- 차량위치체크
            WHERE 1=1
            AND A.CM_AIM = D3.SCH_CD
            AND A.NEXT_PROC = D1.NEXT_PROC(+)
            AND A.CUR_DONG = D7.DONG(+)
        )AA
    ORDER
        BY AA.NEXT_PROC,    --구내차공정우선순위
        AA.MTL_UGNT_GP,     --긴급재순위
        AA.YD_STK_LYR_NO DESC,
        AA.CAR_CNT,         --차량갯수
        AA.SEQ_NO,
        (CASE WHEN AA.GP = 'CM' THEN 1 ELSE LENGTH(AA.STL_NO) END),
        AA.SCH_RULE_VAL,    --야드차공정우선순위
        AA.YD_STK_COL_GP,
        AA.YD_STK_BED_NO,
        AA.COIL_W
)
SELECT DISTINCT
    *
FROM
    TEMP_TABLE
WHERE 1=1
AND
(
    ( GP='CM' AND (CM_AIM,SUBSTR(YD_STK_COL_GP, 1, 2)) = (SELECT CM_AIM,SUBSTR(YD_STK_COL_GP, 1, 2) FROM TEMP_TABLE WHERE ROWNUM<=1) )
    OR
    ( GP='CG' AND (SEQ_NO) = (SELECT SEQ_NO FROM TEMP_TABLE WHERE ROWNUM<=1) )
)
ORDER BY
    NEXT_PROC,      --구내차공정우선순위
    MTL_UGNT_GP,    --긴급재순위
    YD_STK_LYR_NO DESC,
    CAR_CNT,        --차량갯수
    SEQ_NO,
    (CASE WHEN GP='CM' THEN 1 ELSE LENGTH(STL_NO) END),
    SCH_RULE_VAL,   --야드차공정우선순위
    YD_STK_COL_GP,
    YD_STK_BED_NO,
    COIL_W
 </pre> */
public final static String getListFrtoStl_CoilNewsangcha = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListFrtoStl_CoilNewsangcha";

