 /** <pre> 2020-06-16
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandCarNoFrto
SELECT YD_STK_COL_GP
     , YD_STK_BED_NO 
     , YD_STK_LYR_NO 
     , YD_MTL_SH 
  FROM
       (
        SELECT SB.YD_STK_COL_GP
             , SB.YD_STK_BED_NO 
             , SL.YD_STK_LYR_NO 
             ,COUNT(SL.STL_NO) AS YD_MTL_SH
          FROM TB_YF_STKBED SB
              ,TB_YF_STKLYR SL
              ,(SELECT YD_STK_COL_GP AS YD_STK_COL_GP                         
                  FROM TB_YD_CARPOINT                          
                 WHERE CAR_NO = :V_CAR_NO ) SC
         WHERE SB.YD_STK_COL_GP = SL.YD_STK_COL_GP
           AND SB.YD_STK_COL_GP = SC.YD_STK_COL_GP
           AND SB.YD_STK_BED_NO = SL.YD_STK_BED_NO
           AND SB.YD_STK_COL_GP LIKE (SELECT SUBSTR(YD_STK_COL_GP,1,2) 
                                        FROM TB_YF_STKLYR 
                                       WHERE STL_NO = :V_STL_NO) || '%'
           AND SB.YD_STK_BED_NO LIKE NVL((SELECT ITEM
                                           FROM TB_YF_RULE 
                                          WHERE REPR_CD_GP = 'YM1001'
                                            AND CD_GP =  (SELECT YD_CAR_UPP_LOC_CD FROM TB_YF_STOCK WHERE STL_NO = :V_STL_NO)
                                    ),'%')    
           AND SB.DEL_YN       = 'N'
           AND SB.YD_STK_BED_ACTIVE_STAT = 'L' --적치가능
           AND SL.YD_STK_LYR_NO='01' --차량위치는 1단만 적치
           AND SB.YD_STK_COL_GP||SB.YD_STK_BED_NO||SL.YD_STK_LYR_NO NOT IN ( SELECT NVL(YD_DN_WO_LOC||YD_DN_WO_LYR,'1') FROM TB_YF_CRNSCH WHERE DEL_YN = 'N')
           AND SL.STL_NO IS NULL
         GROUP BY SB.YD_STK_COL_GP, SB.YD_STK_BED_NO, SL.YD_STK_LYR_NO 
         ORDER BY SB.YD_STK_COL_GP, SB.YD_STK_BED_NO, SL.YD_STK_LYR_NO 
        )
  WHERE YD_MTL_SH = 0
    AND ROWNUM = 1
 </pre> */
public final static String getYdStkBedByCarUseGpandCarNoFrto = "com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandCarNoFrto";

 /** <pre> 2020-11-25
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStklyrAddress
SELECT A.STL_NO AS  STL_NO
     , CASE WHEN A.YD_STK_LYR_ACTIVE_STAT IN ('N') THEN 'N'
            WHEN A.YD_STK_LYR_STAT IN ('E') THEN 'Y' 
            ELSE 'N' 
       END AS STK_ABLE_YN
     , A.YD_STK_LYR_STAT 
     , A.YD_STK_LYR_ACTIVE_STAT
     , LPAD(YD_STK_LYR_X_AXIS, 7, '0')  AS YD_STK_LYR_X_AXIS
     , LPAD(YD_STK_LYR_Y_AXIS, 5, '0')  AS YD_STK_LYR_Y_AXIS
     , LPAD(YD_STK_LYR_Z_AXIS, 5, '0')  AS YD_STK_LYR_Z_AXIS
     , '' AS LYR_STAT_01_CURR
     , '' AS STL_NO_01_CURR
     , '' AS LYR_STAT_01_NEXT
     , '' AS STL_NO_01_NEXT
  FROM TB_YF_STKLYR A 
     , TB_YF_STKBED    B 
 WHERE SUBSTR(A.YD_STK_COL_GP,1,1) ='1' 
   AND A.YD_STK_COL_GP = B.YD_STK_COL_GP  
   AND A.YD_STK_BED_NO = B.YD_STK_BED_NO  
   AND A.YD_STK_COL_GP|| A.YD_STK_BED_NO = :V_YD_DN_WR_LOC
   AND '0'||A.YD_STK_LYR_NO = :V_YD_STK_LYR_NO
   AND A.DEL_YN = 'N' 
   AND B.DEL_YN = 'N'
 </pre> */
public final static String getYdStklyrAddress = "com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStklyrAddress";

