 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getHandlingCnt_PIDEV 
--출하제품핸들링횟수
WITH TEMP_TABLE AS
(
    SELECT
        STL_NO,
        TRANS_ORD_SEQNO
    FROM
        USRYFA.TB_YF_STOCK A
    WHERE 1=1
    AND A.TRANS_ORD_DATE   = :V_TRANS_ORD_DATE
    AND A.TRANS_ORD_SEQNO  = :V_TRANS_ORD_SEQNO
),
TEMP_TABLE2 AS
(
    SELECT
        SUBSTR(YD_CARPNT_CD,1,1)  AS YD_GP,
        YD_CARPNT_CD  AS CARLD_PNT_CD,
        COUNT(STL_NO) AS HANDLING_CNT,
        COIL_GP       AS COIL_GP
    FROM
        (
            SELECT
                SUBSTR(C.YD_CARPNT_CD,1,3) AS YD_CARPNT_CD,
                A.STL_NO,
                TRANS_ORD_SEQNO,
                B.COIL_GP
            FROM
                (
                    SELECT
                        'A' AS CHK,
                        STL_NO,
                        TRANS_ORD_SEQNO
                    FROM
                        TEMP_TABLE

                    UNION

                    SELECT
                        'B',
                        (
                            SELECT
                                STL_NO_LEFT
                            FROM
                                VW_YD_STKLYERSEARCH B
                            WHERE 1=1
                            AND A.STL_NO=B.STL_NO
                        ) AS STL_NO_LEFT,
                        TRANS_ORD_SEQNO
                    FROM
                        TEMP_TABLE A

                    UNION

                    SELECT
                        'B',
                        (
                            SELECT
                                STL_NO_RIGHT
                            FROM
                                VW_YD_STKLYERSEARCH B
                            WHERE 1=1
                            AND A.STL_NO=B.STL_NO
                        ) AS STL_NO_RIGHT,
                        TRANS_ORD_SEQNO
                    FROM
                        TEMP_TABLE A
                ) A,
                VW_YF_COILCOMM B,
                USRYDA.TB_YD_CARPOINT C
            WHERE 1=1
            AND A.STL_NO    = B.COIL_NO
            AND B.YD_GP     = C.YD_GP
            AND B.YD_BAY_GP = C.YD_BAY_GP
            AND B.YD_EQP_GP BETWEEN C.YD_SPAN_FROM AND C.YD_SPAN_TO
            GROUP BY SUBSTR(C.YD_CARPNT_CD,1,3), A.STL_NO ,TRANS_ORD_SEQNO, B.COIL_GP
        )
    GROUP BY YD_CARPNT_CD, COIL_GP
)
SELECT
    *
FROM
    TEMP_TABLE2
WHERE 1=1
AND EXISTS(SELECT 1 FROM TEMP_TABLE2)

UNION ALL

SELECT
    B.YD_GP,
    '',
    COUNT(A.STL_NO) AS HANDLING_CNT,
    B.COIL_GP
FROM
    TEMP_TABLE A,
    VW_YF_COILCOMM B
WHERE 1=1
AND A.STL_NO = B.COIL_NO
AND NOT EXISTS(SELECT 1 FROM TEMP_TABLE2)
GROUP BY B.YD_GP, B.COIL_GP
 </pre> */
public final static String getHandlingCnt = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getHandlingCnt_PIDEV";

