 /** <pre> 2020-04-24
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbcoilWrkBookMtlNoLayer
SELECT STL_NO
     , YD_STK_COL_GP
     -- RULE에 대표 BED가 있으면 사용함       
     , NVL((SELECT DTL_ITEM1
              FROM TB_YF_RULE
             WHERE REPR_CD_GP = 'YMSCH'
               AND A.STL_NO NOT LIKE 'BD%' --분동코일은 FROM 위치 정해져 있음
               AND ITEM       =  SUBSTR(A.YD_STK_COL_GP,3,2)),YD_STK_BED_NO) AS YD_STK_BED_NO      
               
     , YD_STK_LYR_NO
     , '1' AS HANDLING_CNT
     , 'S' AS YD_TO_LOC_DCSN_MTD
     , 'C' AS YD_STK_LYR_STAT
  FROM TB_YF_WRKBOOKMTL A
WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID
  AND DEL_YN = 'N'
 </pre> */
