 /** <pre> 2020-11-10
--com.inisteel.cim.yf.aslab.dao.aSlabDAO.getYdCarschCarGetInWorkByCarNoSlab 
SELECT
    B.STL_NO AS YD_STL_NO,
    A.TRN_EQP_CD AS YD_CAR_NO,
    A.CARD_NO AS YD_CARD_NO,
    (CASE WHEN YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN YD_CARLD_STOP_LOC ELSE YD_CARUD_STOP_LOC END) AS YD_PT_LOAD_LOC,
    TRIM(TO_CHAR(TO_NUMBER(B.YD_STK_LYR_NO), '00')) AS YD_LOAD_LOC_CD,
    LPAD(NVL(SUBSTR(A.TRN_EQP_CD, 2, 2), A.CAR_KIND), 2, ' ') AS YD_PT_CLS,
    A.YD_CAR_WRK_GP,
    A.YD_CAR_PROG_STAT,
    A.YD_CAR_USE_GP,
    A.CAR_KIND,
    A.YD_CAR_SCH_ID,
    (
        CASE 
        WHEN A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN '4'  -- 구내출고(상차)
        WHEN A.YD_CAR_PROG_STAT IN ('A','B','C','D','E') THEN '3'  -- 구내입고(하차)
        END
    ) AS YD_WORK_CLS,
    COUNT(B.STL_NO) OVER() AS YD_WORK_COIL_MAX_CNT,
    (
        CASE 
        WHEN A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN 
        (
            DECODE(SUBSTR(NVL((SELECT YD_STK_COL_GP FROM TB_YF_STKLYR WHERE STL_NO = B.STL_NO AND YD_STK_LYR_STAT = 'C' AND ROWNUM = 1), 'XXXXXX'), 3, 2), 'PT', '*', '0')
        )
        WHEN A.YD_CAR_PROG_STAT IN ('A','B','C','D','E') THEN 
        (
            DECODE(SUBSTR(NVL((SELECT YD_STK_COL_GP FROM TB_YF_STKLYR WHERE STL_NO = B.STL_NO AND YD_STK_LYR_STAT = 'C' AND ROWNUM = 1), 'XXXXXX'), 3, 2), '01', '*', '02', '*', '0')
        )
        ELSE '0' 
        END
    ) AS YD_WORK_STATE  
FROM
    TB_YD_CARSCH A,
    TB_YD_CARFTMVMTL B
WHERE 1=1
AND A.YD_CAR_SCH_ID = 
( 
    SELECT
        MAX(YD_CAR_SCH_ID) AS YD_CAR_SCH_ID
    FROM
        USRYDA.TB_YD_CARSCH
    WHERE 1=1
    AND 
    (
        CASE 
        WHEN YD_CAR_PROG_STAT IN('2','3','4','5') THEN YD_CARLD_STOP_LOC
        ELSE YD_CARUD_STOP_LOC END
    ) = :V_YD_CARUD_STOP_LOC
    AND DEL_YN='N'
    AND YD_CAR_PROG_STAT NOT IN ('1','A')
    AND TRN_EQP_CD = 
    (
        SELECT 
            TRN_EQP_CD
        FROM
            TB_YD_CARPOINT
        WHERE 1=1
        AND YD_STK_COL_GP = :V_YD_CARUD_STOP_LOC
    )
)
AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID(+)
AND A.YD_CAR_USE_GP = 'L'
AND A.DEL_YN        = 'N'
AND B.DEL_YN(+)     = 'N'
AND (A.SPOS_WLOC_CD IN ('D2Y43') OR A.ARR_WLOC_CD IN ('D2Y43'))
ORDER BY B.YD_STK_LYR_NO
 </pre> */
public final static String getYdCarschCarGetInWorkByCarNoSlab = "com.inisteel.cim.yf.aslab.dao.aSlabDAO.getYdCarschCarGetInWorkByCarNoSlab";

 /** <pre> 2019-10-10
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchAxYML007
WITH TMP_TBL AS 
(
SELECT YD_CRN_SCH_ID ,YD_WRK_PROG_STAT,YD_UP_WO_LOC,YD_DN_WO_LOC,YD_SCH_CD,YD_AID_WRK_YN,YD_CTS_RELAY_YN,SEQ1,SEQ3,YD_SCH_PRIOR,CHK ,YD_WBOOK_ID,MAX_YD_CRN_SCH_ID
  FROM
       (
SELECT A.*
  ,(CASE WHEN CHK=1 THEN 1 ELSE SEQ2 END) AS SEQ3
  FROM
       ( SELECT CS.YD_CRN_SCH_ID
              , CS.YD_EQP_ID 
              , CS.YD_WRK_PROG_STAT
              , CS.YD_UP_WO_LOC 
              , CS.YD_DN_WO_LOC 
              , CS.YD_SCH_CD
              , CM.YD_AID_WRK_YN
              , CS.YD_SCH_PRIOR
              , DECODE(CS.YD_WRK_PROG_STAT,'W','0','S','1', CS.YD_WRK_PROG_STAT) AS SEQ1
              , (SELECT YD_CTS_RELAY_YN FROM USRYFA.TB_YF_WRKBOOK  WHERE YD_WBOOK_ID=CS.YD_WBOOK_ID) AS YD_CTS_RELAY_YN
              , CASE WHEN CS.YD_SCH_PRIOR = 0                                                    THEN 0 
                     WHEN CS.YD_SCH_CD    = '1EKE05UM'                                           THEN 0 
                     WHEN CS.YD_CRN_GRAB_USE_RULE_ID = (SELECT YD_CRN_GRAB_USE_RULE_ID 
                                                          FROM TB_YF_CRNSCH 
                                                         WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
                                                           AND SUBSTR(YD_SCH_CD,3,2) = 'PT')     THEN 1  --차량만
                     ELSE 2  END AS SEQ2 -- 이전 
              , (SELECT MAX(C.YD_CRN_SCH_ID) 
                   FROM TB_YF_CRNSCH C
                      , TB_YF_CRNWRKMTL M
                  WHERE C.YD_CRN_SCH_ID    = M.YD_CRN_SCH_ID
                    AND C.DEL_YN    = 'N'
                    AND M.DEL_YN    = 'N'
                    AND C.YD_EQP_ID = CS.YD_EQP_ID
                    AND C.YD_SCH_CD = CS.YD_SCH_CD
                    AND C.YD_WRK_PROG_STAT = 'W' ) AS MAX_YD_CRN_SCH_ID     
              , ( CASE WHEN CS.YD_SCH_PRIOR = 0                                                    THEN 0 
                       WHEN (SELECT YD_CTS_RELAY_YN FROM USRYFA.TB_YF_WRKBOOK  WHERE YD_WBOOK_ID=CS.YD_WBOOK_ID)='Y' 
                            AND CS.YD_SCH_CD LIKE '1_PT%' 
                       THEN 1 ELSE 2 END) AS CHK      
              , cs.YD_WBOOK_ID         
           FROM TB_YF_CRNSCH CS
              , TB_YF_CRNWRKMTL CM
          WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
            AND CS.DEL_YN = 'N'
            AND CM.DEL_YN = 'N'
            AND CS.YD_EQP_ID =  :V_YD_EQP_ID 
       ) A    
 ORDER BY SEQ1 DESC   --작업상태
         --, SEQ3        --차량연속작업 여부
         , YD_SCH_PRIOR
         , CHK         --차량형상측정여부
         , CASE WHEN SUBSTR(YD_SCH_CD,3,2) = 'PT' THEN YD_WBOOK_ID ELSE '0' END --차량이 우선 도착한 대상 우선
         , CASE WHEN YD_SCH_CD LIKE '1CEC02LM' THEN DECODE(SUBSTR(A.YD_UP_WO_LOC, 7, 2),'01',1,'02',2, 3) ELSE 1 END
         , CASE WHEN YD_SCH_CD LIKE '1_DC01LM' THEN TO_NUMBER(YD_CRN_SCH_ID) * -1
                ELSE TO_NUMBER(YD_CRN_SCH_ID) END 
   )      
 WHERE ROWNUM = 1  
)

SELECT YD_CRN_SCH_ID
     , YD_EQP_ID 
     , YD_WRK_PROG_STAT
     , YD_UP_WO_LOC 
     , YD_DN_WO_LOC 
     , YD_SCH_CD
     , YD_SCH_PRIOR      
  FROM TB_YF_CRNSCH 
 WHERE YD_CRN_SCH_ID IN (
                        SELECT CASE WHEN YD_SCH_CD LIKE '1_DC01LM' AND YD_WRK_PROG_STAT = 'W' THEN MAX_YD_CRN_SCH_ID  
                                    WHEN YD_SCH_CD    = '1EKD02LM' AND YD_WRK_PROG_STAT = 'W' THEN MAX_YD_CRN_SCH_ID  
                               ELSE YD_CRN_SCH_ID END AS YD_CRN_SCH_ID
                          FROM TMP_TBL TB
                        )  
 </pre> */
public final static String getCrnSchAxYML007 = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchAxYML007";

 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCoilCommonInfo
SELECT
    (CASE WHEN YD_GP ='1' THEN 'A' ELSE HR_PLNT_GP END) AS PLNT_GP,
    HR_PLNT_GP,     --공장구분
    REPLACE(PASS_PROC1, '6R', '6K') AS PASS_PROC1,
    REPLACE(PASS_PROC2, '6R', '6K') AS PASS_PROC2,
    REPLACE(PASS_PROC3, '6R', '6K') AS PASS_PROC3,
    REPLACE(PASS_PROC4, '6R', '6K') AS PASS_PROC4,
    REPLACE(PASS_PROC5, '6R', '6K') AS PASS_PROC5,
    ORD_NO,         --제작번호
    ORD_DTL,        --제작행번
    COIL_T,         --코일두께
    COIL_W,         --코일폭
    CURR_COIL_LEN,  --코일길이
    COIL_INDIA,     --코일내경
    COIL_OUTDIA,    --코일외경
    DECODE(COIL_WT, 0, NET_CAL_WT, COIL_WT) AS COIL_WT, -- 코일중량
    NEXT_PROC,      --차공정
    PLAN_PROC1,     --계획공정
    BRANCH_CD,      --분기위치코드
    EXTEND_CONVEYOR_BRANCH_CD,  --확장분기위치코드
    HYSCO_TRANS_GP, --HYSCO이송수단
    COOL_METHOD,    --냉각방법
    DECODE(CURR_PROG_CD, '2', 'H', '3', 'D', '4', 'E', '6', 'L', '7', 'K', CURR_PROG_CD) AS CURR_PROG_CD,
    RETURN_GP,
    YD_EQP_GP
FROM
    VW_YF_COILCOMM
WHERE 1=1
AND COIL_NO = :V_COIL_NO    --재료번호
 </pre> */
public final static String getCoilCommonInfo = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCoilCommonInfo";

