 /** <pre> 2020-09-11
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCStkLyr
WITH CSM AS
(
    SELECT
        CM.STL_NO,
        SUBSTR(CS.YD_UP_WO_LOC, 1, 6) AS YD_STK_COL_GP_UP,
        SUBSTR(CS.YD_UP_WO_LOC, 7, 2) AS YD_STK_BED_NO_UP,
        SUBSTR(CS.YD_DN_WO_LOC, 1, 6) AS YD_STK_COL_GP_DN,
        SUBSTR(CS.YD_DN_WO_LOC, 7, 2) AS YD_STK_BED_NO_DN,
        CS.YD_UP_WO_LYR AS YD_STK_LYR_GP,
        CS.YD_CRN_SCH_ID,
        CS.YD_TO_LOC_DCSN_MTD,
        CM.RNUM
    FROM
        TB_YF_CRNSCH CS,
        (
            SELECT
                CS.YD_CRN_SCH_ID,
                CM.STL_NO,
                ROW_NUMBER() OVER(PARTITION BY CM.STL_NO ORDER BY CS.YD_CRN_SCH_ID) AS RNUM
            FROM
                TB_YF_CRNSCH    CS,
                TB_YF_CRNWRKMTL CM
            WHERE 1=1
            AND CM.YD_CRN_SCH_ID  = CS.YD_CRN_SCH_ID
            AND CS.DEL_YN         = 'N'
            AND CM.DEL_YN         = 'N'
            AND CS.YD_WBOOK_ID = :V_YD_WBOOK_ID
        ) CM
    WHERE 1=1
    AND CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
    AND CS.DEL_YN = 'N'
)
SELECT
    YD_STK_COL_GP,
    YD_STK_BED_NO,
    YD_STK_LYR_NO,
    MAX(STL_NO) AS STL_NO,
    MIN(YD_STK_LYR_STAT) AS YD_STK_LYR_STAT
FROM
    (
        --원래위치
        SELECT
            SL.YD_STK_COL_GP,
            SL.YD_STK_BED_NO,
            SL.YD_STK_LYR_NO,
            SL.STL_NO,
            'C' AS YD_STK_LYR_STAT --적치중
        FROM
            TB_YF_STKLYR SL,
            CSM
        WHERE 1=1
        AND SL.STL_NO     = CSM.STL_NO
        AND SL.YD_STK_COL_GP = CSM.YD_STK_COL_GP_UP
        AND SL.YD_STK_LYR_STAT = 'U' --권상대기

        UNION ALL

        --권하지시위치
        SELECT
            SL.YD_STK_COL_GP,
            SL.YD_STK_BED_NO,
            SL.YD_STK_LYR_NO,
            NULL AS STL_NO,
            'E'  AS YD_STK_LYR_STAT --적치가능
        FROM
            TB_YF_STKLYR SL,
            CSM
        WHERE 1=1
        AND SL.STL_NO     = CSM.STL_NO
        AND SL.YD_STK_COL_GP = CSM.YD_STK_COL_GP_DN
        AND SL.YD_STK_BED_NO = CSM.YD_STK_BED_NO_DN
    )
GROUP BY YD_STK_COL_GP, YD_STK_BED_NO, YD_STK_LYR_NO
 </pre> */
public final static String getCrnWrkMgtSCStkLyr = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCStkLyr";

 /** <pre> 2020-12-15
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getMvCarSch  
WITH MVCAR_SCH AS (
    SELECT A.YD_CAR_SCH_ID
          ,A.TRN_EQP_CD
          ,A.YD_CAR_PROG_STAT
          ,A.SPOS_WLOC_CD
          ,A.YD_PNT_CD1
          ,A.YD_CARLD_STOP_LOC
          ,A.ARR_WLOC_CD
          ,A.YD_PNT_CD3
          ,A.YD_CARUD_STOP_LOC
          ,A.FRTOMOVE_PLANT_GP
          ,CASE WHEN A.YD_CAR_PROG_STAT BETWEEN '1' AND '4' THEN A.YD_CARLD_WRK_BOOK_ID 
                WHEN A.YD_CAR_PROG_STAT BETWEEN 'A' AND 'D' THEN A.YD_CARUD_WRK_BOOK_ID 
                ELSE '' END AS CARSCH_YD_WBOOK_ID
          ,(SELECT Z.YD_STK_COL_GP 
              FROM TB_YD_CARPOINT Z
             WHERE Z.TRN_EQP_CD = A.TRN_EQP_CD
               AND Z.DEL_YN = 'N') AS YD_STK_COL_GP 
          ,(SELECT COUNT(Z.STL_NO)
              FROM TB_YD_CARFTMVMTL Z
             WHERE Z.DEL_YN = 'N'
               AND Z.YD_CAR_SCH_ID = A.YD_CAR_SCH_ID) AS ITEM_CNT
     FROM  TB_YD_CARSCH A
    WHERE  A.DEL_YN = 'N'
      AND  A.YD_CAR_USE_GP = 'L'
      AND  ((A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') AND A.SPOS_WLOC_CD IN ('D2Y44','D2Y45')) --박판열연 코일 상차
             OR 
            (A.YD_CAR_PROG_STAT IN ('5','A','B','C','D','E') AND A.ARR_WLOC_CD IN ('D2Y44','D2Y45'))) --박판열연 코일 하차
)
SELECT ROWNUM AS RNUM
      ,A.*
FROM   (
            SELECT MC.YD_CAR_SCH_ID
                  ,MC.TRN_EQP_CD
                  ,MC.YD_CAR_PROG_STAT
                  ,MC.SPOS_WLOC_CD
                  ,MC.YD_PNT_CD1
                  ,MC.YD_CARLD_STOP_LOC
                  ,MC.ARR_WLOC_CD
                  ,MC.YD_PNT_CD3
                  ,MC.YD_CARUD_STOP_LOC
                  ,NVL(MC.FRTOMOVE_PLANT_GP,'CR') AS FRTOMOVE_PLANT_GP
                  ,WB.YD_WBOOK_ID
                  ,WB.YD_SCH_CD
                  ,(SELECT MAX(CD_CONTENTS)
                      FROM TB_YF_SCHRULE
                     WHERE YD_SCH_CD =  WB.YD_SCH_CD) AS YD_SCH_CD_NM
                  ,(SELECT YD_CRN_SCH_ID
                      FROM TB_YF_CRNSCH
                     WHERE YD_WBOOK_ID IN (
                                           SELECT YD_WBOOK_ID 
                                             FROM TB_YF_WRKBOOK
                                            WHERE TRN_EQP_CD = MC.TRN_EQP_CD
                                              AND DEL_YN = 'N'
                                          )
                       AND DEL_YN = 'N'
                       AND ROWNUM = 1 
                   ) AS YD_CRN_SCH_ID
                  ,ROWNUM AS NO
            FROM   MVCAR_SCH MC
                  ,TB_YF_WRKBOOK WB
            WHERE  MC.CARSCH_YD_WBOOK_ID = WB.YD_WBOOK_ID(+)
            AND    WB.DEL_YN(+) = 'N'
            ORDER BY MC.TRN_EQP_CD
       ) A
 </pre> */
public final static String getMvCarSch = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getMvCarSch";

