 /** <pre> 2021-01-06
--com.inisteel.cim.yf.common.dao.YfCommDAO.getWbIdAxYML007   
SELECT *
  FROM (
        SELECT A.YD_WBOOK_ID
             , A.YD_SCH_CD
             , A.YD_SCH_CD_CNT
             , A.YD_SCH_CD_YN
             , A.YD_WRK_PLAN_TCAR
             , A.YD_WRK_PLAN_CRN
          FROM (
                SELECT YD_WBOOK_ID
                     , YD_SCH_CD
                     , SUM(1) OVER(PARTITION BY YD_SCH_CD) AS YD_SCH_CD_CNT 
                     , 'Y'  AS YD_SCH_CD_YN 
                     , YD_WRK_PLAN_TCAR
                     , YD_WRK_PLAN_CRN
                     , SCH_CNCL_YN
                     , (SELECT YD_SCH_AUTO_ST_YN 
                          FROM TB_YF_SCHRULE 
                         WHERE YD_SCH_CD = WB.YD_SCH_CD 
                           AND DEL_YN = 'N') AS YD_SCH_AUTO_ST_YN --스케줄별 자동기동여부 DEFAULT Y
                  FROM TB_YF_WRKBOOK WB
                 WHERE DEL_YN = 'N'
                   AND 1 = CASE --차량 없으면 기동안함
                                WHEN NVL((SELECT 'Y' 
                                        FROM TB_YF_STKCOL 
                                       WHERE CAR_NO = WB.CAR_NO 
                                         AND SUBSTR(YD_STK_COL_GP,2,1) != SUBSTR(WB.YD_SCH_CD,2,1)
                                     ),'N') = 'Y'
                                THEN '2'
                                
                                --차량 없으면 기동안함
                                WHEN NVL((SELECT 'Y' 
                                        FROM TB_YF_STKCOL 
                                       WHERE TRN_EQP_CD = WB.TRN_EQP_CD 
                                         AND SUBSTR(YD_STK_COL_GP,2,1) != SUBSTR(WB.YD_SCH_CD,2,1)
                                     ),'N') = 'Y'
                                THEN '2'
                                
                                --형상 존재하면 기동 안함
                                WHEN SUBSTR(YD_SCH_CD, 3, 2) = 'PT' AND SUBSTR(YD_SCH_CD,6,1) IN ('1') 
                                     AND (SELECT NVL(MAX(YD_FRM_YN),'N') AS YD_FRM_YN 
                                            FROM TB_YD_CARPOINT 
                                           WHERE YD_STK_COL_GP IN (SUBSTR(YD_SCH_CD, 1, 2)||'PT01', SUBSTR(YD_SCH_CD, 1, 2)||'PT02')
                                         ) = 'Y'
                                THEN '2'
                                
                                --형상 존재하면 기동 안함 1BPT32UM
                                WHEN SUBSTR(YD_SCH_CD, 3, 2) = 'PT' AND SUBSTR(YD_SCH_CD,6,1) NOT IN ('1') 
                                     AND (SELECT NVL(MAX(YD_FRM_YN),'N') AS YD_FRM_YN 
                                            FROM TB_YD_CARPOINT 
                                           WHERE YD_STK_COL_GP IN (SUBSTR(YD_SCH_CD, 1, 2)||'PT03', SUBSTR(YD_SCH_CD, 1, 2)||'PT04')
                                         ) = 'Y'
                                THEN '2'
                                
                                ELSE '1' END 
                   AND TRN_EQP_CD       IS NULL
                   AND YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
                                             FROM TB_YF_CRNSCH
                                            WHERE DEL_YN = 'N')
                   AND (NVL(YD_WRK_PLAN_CRN, :V_YD_EQP_ID ) = :V_YD_EQP_ID 
                         OR YD_SCH_CD IN
                            (SELECT YD_SCH_CD --고장난 크레인 없으면 자기 스케줄만, 고장난게 있으면 모든 스케줄
                               FROM TB_YF_SCHRULE
                              WHERE (YD_WRK_CRN IN (SELECT YD_EQP_ID
                                                      FROM TB_YF_EQP 
                                                     WHERE YD_EQP_ID LIKE CASE WHEN (SELECT COUNT(CASE WHEN YD_EQP_PROG_STAT = 'B' THEN  YD_EQP_ID END)
                                                                                       FROM TB_YF_EQP 
                                                                                      WHERE YD_EQP_ID LIKE SUBSTR(:V_YD_EQP_ID,1,4) AND YD_EQP_GP ='CR') = 0
                                                                               THEN :V_YD_EQP_ID                       --동일 동에 고장난 크레인이 없으면 해당크레인
                                                                               ELSE SUBSTR(:V_YD_EQP_ID,1,4)||'%' END) --동일 동에 고장난 크레인이 있으면 두크레인 모두 가져온다
                                                   
                                AND DEL_YN      = 'N')
                            ))
                    AND SUBSTR(WB.YD_SCH_CD,1,2) = SUBSTR(:V_YD_EQP_ID,1,2)
                  ORDER BY (CASE WHEN YD_WRK_PLAN_CRN=:V_YD_EQP_ID  THEN 1 ELSE 2 END ),YD_SCH_PRIOR, YD_WBOOK_ID     
               ) A
         WHERE YD_SCH_CD_YN = 'Y'
--           AND SCH_CNCL_YN IS NULL --사용자취소 스케줄은 수동으로 진행한다.
           AND YD_SCH_AUTO_ST_YN = 'Y'  
       )
   WHERE ROWNUM = 1
 </pre> */
public final static String getWbIdAxYML007 = "com.inisteel.cim.yf.common.dao.YfCommDAO.getWbIdAxYML007";

