 /** <pre> 2019-09-24
--yf.common.dao.selectCarArrival
--차량 상차 저장품 정보를 리턴한다.
SELECT
    WBOOK.YD_SCH_CD,
    STOCK.STL_NO,         --저장품ID
    STOCK.YD_WBOOK_ID,         --작업예약ID,
    STOCK.STOCK_ITEM,
    STOCK.CAR_CARD_NO,      --차량CARD번호
    STOCK.CAR_NO,
    SUBSTR(STOCK.TRANS_WORD_NO, 1, 8) AS TRANS_WORD_DATE,
    DECODE(LENGTH(STOCK.TRANS_WORD_NO), 10, SUBSTR(STOCK.TRANS_WORD_NO, 9, 100), SUBSTR(STOCK.TRANS_WORD_NO, 9, 100)) AS TRANS_WORD_SEQNO,
    DECODE(LENGTH(STOCK.TRANS_WORD_NO), 10, STOCK.TRANS_WORD_NO, SUBSTR(STOCK.TRANS_WORD_NO, 1, 8) || '0' || SUBSTR(STOCK.TRANS_WORD_NO, 9,1)) AS TRANS_WORD_DATE_NO,   --운송지시번호
    STOCK.STOCK_MOVE_TERM,  --저장품이동조건
    DECODE(STOCK.STOCK_ITEM, 'CG', DECODE(STOCK.STOCK_MOVE_TERM, 'LG', '1', '2'), DECODE(STOCK.STOCK_ITEM, 'CM', '3', DECODE(STOCK.STOCK_ITEM, 'SM', '4'))) AS MATERIAL_GOODS,
    SUBSTR(LAYER.YD_STK_COL_GP, 1, 2) AS CURR_STOCK_LOC,
    LAYER.YD_STK_LYR_NO,
    LAYER.YD_STK_BED_NO,
    LAYER.YD_STK_COL_GP || LAYER.YD_STK_BED_NO || LAYER.YD_STK_LYR_NO AS UP_LOC,
    FTMV.ARR_WLOC_CD,
    FTMV.ARR_YD_PNT_CD
FROM
    (
        SELECT
            A.STL_NO,
            B.YD_WBOOK_ID,
            A.STOCK_ITEM,
            A.CAR_CARD_NO,
            A.STOCK_MOVE_TERM,
            MIN(TRANS_ORD_DATE || TRANS_ORD_SEQNO) AS TRANS_WORD_NO,
            CAR_NO
        FROM
            TB_YF_STOCK A,
            TB_YF_WRKBOOKMTL B
        WHERE 1=1
        AND A.STL_NO = B.STL_NO
        AND A.DEL_YN = 'N'
        AND A.CAR_CARD_NO = ?
        GROUP BY A.STL_NO, B.YD_WBOOK_ID, STOCK_ITEM, CAR_CARD_NO, STOCK_MOVE_TERM, CAR_NO
    ) STOCK,
    TB_YF_WRKBOOK WBOOK,
    TB_YF_STKLYR LAYER,
    TB_TS_MATL_FTMV_WO FTMV
WHERE 1=1
AND STOCK.YD_WBOOK_ID   = WBOOK.YD_WBOOK_ID
AND STOCK.STL_NO        = FTMV.STL_NO(+)
AND STOCK.STL_NO        = LAYER.STL_NO
AND LAYER.YD_STK_LYR_STAT IN ('S', 'L', 'U')
AND WBOOK.YD_GP         = ?
AND WBOOK.BAY_GP        = ?
ORDER BY STOCK.YD_WBOOK_ID ASC
 </pre> */
public final static String selectCarArrival = "yf.common.dao.selectCarArrival";

