 /** <pre> 2019-10-10
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCSch
--크레인작업관리 크레인스케줄취소 조회
SELECT
    CS.YD_WRK_PROG_STAT,
    CS.YD_EQP_ID,
    CS.YD_EQP_STAT,
    EQ.YD_EQP_PROG_STAT,
    CASE
    WHEN EQ.YD_EQP_PROG_STAT IN ('B', CS.YD_EQP_STAT) OR EQ.YD_EQP_WRK_MODE != '1' THEN 'N'
    ELSE 'Y' END AS EQP_UPD_YN, --설비상태수정여부
    (
        SELECT
            YD_DN_WO_LOC||YD_DN_WO_LYR
        FROM
            TB_YF_CRNSCH
        WHERE 1=1
        AND YD_CRN_SCH_ID = CS.YD_CRN_SCH_ID
    ) AS TO_LOC
FROM
    TB_YF_EQP EQ,
    (
        SELECT
            MIN(DECODE(YD_CRN_SCH_ID,SC_YD_CRN_SCH_ID,SC_YD_CRN_SCH_ID)) AS YD_CRN_SCH_ID,
            MIN(DECODE(YD_CRN_SCH_ID,SC_YD_CRN_SCH_ID,YD_WRK_PROG_STAT)) AS YD_WRK_PROG_STAT,
            MIN(DECODE(RN,1,DECODE(YD_CRN_SCH_ID, SC_YD_CRN_SCH_ID, 'W', YD_WRK_PROG_STAT))) AS YD_EQP_STAT,
            MIN(DECODE(RN,1,YD_EQP_ID)) AS YD_EQP_ID
        FROM
            (
                SELECT
                    YD_CRN_SCH_ID,
                    YD_WRK_PROG_STAT,
                    YD_EQP_ID,
                    :V_YD_CRN_SCH_ID AS SC_YD_CRN_SCH_ID, --취소 크레인스케줄ID
                    ROW_NUMBER() OVER (ORDER BY YD_CRN_SCH_ID) AS RN
                FROM
                    TB_YF_CRNSCH
                WHERE 1=1
                AND YD_WBOOK_ID = :V_YD_WBOOK_ID
                AND DEL_YN      = 'N'
            )
    ) CS
WHERE 1=1
AND CS.YD_EQP_ID = EQ.YD_EQP_ID(+)
 </pre> */
public final static String getCrnWrkMgtSCSch = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCSch";

