 /** <pre> 2019-09-04
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.selectZoneInStocks_Del
SELECT
    STOCK.STL_NO AS STL_NO,             --저장품ID
    COMM.ORD_YEOJAE_GP,                 --주문여재구분
    NVL(COMM.ORD_NO, '') || NVL(COMM.ORD_DTL, '') AS PRODUC_NO, --제작번호행번
    COMM.SLAB_T,                        --두께
    COMM.SLAB_W,                        --폭
    COMM.SLAB_LEN,                      --길이
    COMM.SLAB_WT,                       --중량
    COMM.COIL_NO,                       --예정COILNO
    COMM.STACK_LOT_NO AS STACK_LOT_CD,  --산적 LOT CODE
    COMM.BUY_SLAB_NO                    --구입슬라브번호
FROM
    TB_YF_STOCK STOCK,
    (
        SELECT
            *
        FROM
            VW_YD_SLABCOMM A,
            TB_QM_BUYSLABINFO B
        WHERE 1=1
        AND A.MSLAB_NO = B.MSLAB_NO(+)
    ) COMM
WHERE 1=1
AND STOCK.CHARGE_LOT_NO IS NOT NULL
AND STOCK.STL_NO = COMM.SLAB_NO
 </pre> */
public final static String selectZoneInStocks_Del = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.selectZoneInStocks_Del";

 /** <pre> 2021-03-03
--com.inisteel.cim.yf.common.dao.YfCommDAO.getAxYML009CarSchLd_PIDEV
SELECT
    YD_CAR_SCH_ID,
    YD_CAR_USE_GP,
    CAR_NO,
    BAY_WRK_CNT,        --해당상차도 작업대상
    BAY_WRK_END_CNT,    --해당 상차도 작업완료
    TRANS_ORD_DATE,
    TRANS_ORD_SEQNO,
    DEST_TEL_NO,
    YD_STK_COL_GP,
    WLOC_CD,
    YD_PNT_CD,
    YD_CAR_WRK_GP,
    YD_CAR_PROG_STAT,   -- 차량진행
    CASE
    WHEN BAY_WRK_CNT <= BAY_WRK_END_CNT THEN 'Y'
    ELSE'N' END AS CAR_LD_CMPL_YN,
    TRANS_EQUIPMENT_TYPE,
    CMBN_CARLD_YN
FROM
    (
        SELECT
            TS.YD_CAR_SCH_ID,
            TS.YD_CAR_USE_GP,
            TS.CAR_NO,
            TS.TRANS_ORD_DATE,
            TS.TRANS_ORD_SEQNO,
            TS.DEST_TEL_NO,
            TS.YD_CAR_PROG_STAT,
            TS.TRANS_EQUIPMENT_TYPE,
            --TS.CMBN_CARLD_YN,
            CASE WHEN TS.CMBN_CARLD_YN = 'S' AND
            (
                SELECT
                    COUNT(A.STL_NO)
                FROM
                    TB_YF_STKLYR A,
                    TB_YD_CARPOINT B
                WHERE 1=1
                AND A.YD_STK_COL_GP LIKE '1%'
                AND A.STL_NO IS NOT NULL
                AND A.YD_STK_COL_GP NOT BETWEEN SUBSTR(B.YD_STK_COL_GP, 1, 2) || B.YD_SPAN_FROM || '00' AND SUBSTR(B.YD_STK_COL_GP, 1, 2) || B.YD_SPAN_TO || '99'
                AND B.YD_STK_COL_GP = TS.YD_CARLD_STOP_LOC
                AND A.STL_NO IN
                (
                    SELECT
                        STL_NO
                    FROM
                        TB_YF_STOCK
                    WHERE 1=1
                    AND TRANS_ORD_DATE = TS.TRANS_ORD_DATE
                    AND TRANS_ORD_SEQNO = TS.TRANS_ORD_SEQNO
                )
            ) <= 0 THEN 'N'
            ELSE TS.CMBN_CARLD_YN
            END AS CMBN_CARLD_YN,
            SC.YD_STK_COL_GP,
            SC.WLOC_CD,
            SC.YD_PNT_CD,
            TS.YD_CAR_WRK_GP,
            -- 해당상차도 작업대상 건수
            CASE
            WHEN SC.YD_CAR_USE_GP = 'L' THEN
                -- 구내운송
                (
                    SELECT
                        COUNT(DISTINCT(A.STL_NO))
                    FROM
                        TB_YF_STOCK A
                    WHERE 1=1
                    AND A.FRTOMOVE_WORD_NO = TS.FRTOMOVE_WORD_NO
                )
            ELSE
                -- 출하
                (
                    SELECT
                        COUNT(DISTINCT(A.STL_NO))
                    FROM
                        TB_YF_STOCK A,
                        TB_YF_WRKBOOKMTL B
                    WHERE 1=1
                    AND A.TRANS_ORD_DATE  = TS.TRANS_ORD_DATE
                    AND A.TRANS_ORD_SEQNO = TS.TRANS_ORD_SEQNO
                    AND A.STL_NO          = B.STL_NO
                    AND B.DEL_YN          = 'N'
                )
            END AS BAY_WRK_CNT,
            -- 해당상차도 작업완료 건수
            CASE
            WHEN SC.YD_CAR_USE_GP = 'L' THEN
                -- 구내운송
                (
                    SELECT
                        COUNT(DISTINCT(A.COIL_NO)) + 1
                    FROM
                        VW_YF_COILCOMM A
                    WHERE 1=1
                    AND SUBSTR(A.YD_STR_LOC,3,2) IN ('PT')
                    AND A.COIL_NO IN 
                    (
                        SELECT
                            B.STL_NO
                        FROM
                            TB_YF_STOCK B
                        WHERE 1=1
                        AND B.FRTOMOVE_WORD_NO = TS.FRTOMOVE_WORD_NO
                    )
                )
            ELSE
                -- 출하
                (
                    SELECT
                        COUNT(DISTINCT(A.COIL_NO)) + 1
                    FROM
                        VW_YF_COILCOMM A
                    WHERE 1=1
                    AND SUBSTR(A.YD_STR_LOC,3,2) IN ('PT')
                    AND A.COIL_NO IN
                    (
                        SELECT
                            B.STL_NO
                        FROM
                            TB_YF_STOCK B,
                            TB_YF_WRKBOOKMTL C
                        WHERE 1=1
                        AND B.TRANS_ORD_DATE  = TS.TRANS_ORD_DATE
                        AND B.TRANS_ORD_SEQNO = TS.TRANS_ORD_SEQNO
                        AND B.STL_NO          = C.STL_NO
                        AND C.DEL_YN          = 'N'
                    )
                )
            END AS BAY_WRK_END_CNT
        FROM
            TB_YF_STKCOL SC,
            USRYDA.TB_YD_CARSCH TS
        WHERE 1=1
        AND SC.YD_STK_COL_GP = :V_YD_STK_COL_GP
        AND SC.YD_CAR_USE_GP = TS.YD_CAR_USE_GP
--추가       
        AND SC.YD_STK_COL_GP = (CASE WHEN TS.YD_CAR_PROG_STAT IN('1','2','3','4','5') THEN  TS.YD_CARLD_STOP_LOC 
                                     ELSE  NVL(TS.YD_CARUD_STOP_LOC,TS.YD_CARLD_STOP_LOC) END) 
--                                     
        AND 
        (
            (SC.YD_CAR_USE_GP = 'L' AND SC.TRN_EQP_CD = TS.TRN_EQP_CD)  --구내운송
            OR
            (SC.YD_CAR_USE_GP = 'G' AND SC.CAR_NO = TS.CAR_NO)    --출하차량
        )
        AND TS.DEL_YN = 'N'
        ORDER BY TS.YD_CAR_SCH_ID DESC
    )
WHERE ROWNUM<=1
 </pre> */
public final static String getAxYML009CarSchLd = "com.inisteel.cim.yf.common.dao.YfCommDAO.getAxYML009CarSchLd_PIDEV";

