 /** <pre> 2020-01-29
--com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPO161
SELECT 'YMPOJ161'                                       AS JMS_TC_CD          --JMSTC코드  
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')              AS JMS_TC_CREATE_DDTT --JMSTC생성일시  
     , 'YMPOJ161'                                       AS TCCODE
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),1,8)  AS TCDATE
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),9,6)  AS TCTIME
     , 'A'                                              AS PLANTGBN
     , SUBSTR(A.TRK_INFO,1,1)                           AS PROCGBN   --S:1SPM,N:2SPM,H:HFL,B:HFL결속장
     , A.STL_NO                                         AS COILNO  
     , SUBSTR(A.TRK_INFO,2,1)                           AS PROCESSID --1:보급,2:보급취소,3:추출,4:Take-Out,5:Take-In
     , TO_CHAR(SYSDATE,'YYYYMMDD')                      AS DOWNDATE
     , TO_CHAR(SYSDATE,'HH24MISS')                      AS DOWNTIME
     , 'D'||SUBSTR(A.TRK_INFO,2,1)                      AS POSITIONNO
     
  FROM (SELECT CASE WHEN SUBSTR(LOC,3,2) IN ('HS') AND SUBSTR(YD_SCH_CD,6,2) IN ('1U') THEN 'B1'  --HFL결속장  보급존 
                    WHEN SUBSTR(LOC,3,2) IN ('HS') AND SUBSTR(YD_SCH_CD,6,2) IN ('2U') THEN 'B5'  --HFL결속장  TAKE IN 
                    ELSE '' END AS TRK_INFO 
            , STL_NO 
         FROM (SELECT :V_YD_DN_WR_LOC  AS LOC  
                    , STL_NO         AS STL_NO
                    , (SELECT YD_SCH_CD FROM TB_YF_CRNSCH WHERE YD_CRN_SCH_ID = C.YD_CRN_SCH_ID) AS YD_SCH_CD
                 FROM TB_YF_CRNWRKMTL C 
                WHERE C.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID) 
       ) A
 </pre> */
public final static String TcYMPO161 = "com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPO161";

