 /** <pre> 2019-09-19
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdRtSlab
--야드 행선
WITH PARAM AS 
(
    SELECT
        :V_YD_GP AS P_YD_GP
    FROM
        DUAL
)
SELECT
    ITEM AS CD_VAL,
    REPR_CD_CONTENTS AS CD_NM
FROM
    TB_YF_RULE
WHERE 1=1
AND REPR_CD_GP = 'YD_RT'
AND SUBSTR(CD_GP, 0, 1) = (SELECT P_YD_GP FROM PARAM)
AND '0' = (SELECT P_YD_GP FROM PARAM)
AND DEL_YN = 'N'
ORDER BY DECODE(SUBSTR(:V_YD_SCH_CD, 2, 1), 'A', DTL_ITEM1, 'D', DTL_ITEM1, DTL_ITEM10), CD_VAL
 </pre> */
