 /** <pre> 2019-09-23
-- yf.facilitystatus.facilityinquiry.CraneSchDAO.getStockInfo_PIDEV
WITH
TEMP_TABLE AS
(
    SELECT
        A.*,
        (
            CASE
            WHEN YD_SCH_CD  IN ('1ATC01UM', '1BTC01UM', '1BTC02UM') THEN CARUNLOAD_LOC      --동간이적상차
            WHEN YD_SCH_CD  IN
            (
                '1APT21LM', '1BPT22LM', '1CPT22LM', '1DPT22LM', '1EPT22LM', '1FPT22LM', '1GPT22LM', '1HPT22LM', '1APT22LM', '1BPT31LM', '1CPT31LM', '1DPT31LM', '1EPT26LM', '1FPT26LM', '1GPT26LM', '1HPT26LM',
                '1APT11LM', '1BPT02LM', '1CPT02LM', '1DPT02LM', '1EPT01LM', '1FPT01LM', '1GPT01LM', '1HPT01LM', '1APT12LM', '1BPT12LM', '1CPT12LM', '1DPT12LM', '1EPT06LM', '1FPT06LM', '1GPT06LM', '1HPT06LM'
            ) THEN MOVE_LOC    --소재/제품이송하차
            WHEN YD_SCH_CD  IN ('1EKD01LM', '1FKD01LM') AND SPM_NEXT_LOC = 'E' THEN SPM_NEXT_LOC    --SPM 추출 재작업 시
            WHEN YD_SCH_CD  IN ('1CFD01LM', '1EKD01LM', '1FKD01LM', '1FQE01LM', '1GQD01LM') AND ZONE_AIMBAY_GP IS NOT NULL THEN ZONE_AIMBAY_GP  --추출 시 존별 목적동
            ELSE NVL(NVL(NVL(CARUNLOAD_LOC, SPM_NEXT_LOC), ZONE_AIMBAY_GP), MOVE_LOC) END
        ) AS CARUNLOAD_PUT_LOC2       --CTS 목적동 가져오기
    FROM
        (
            SELECT
                STL_NO,
                YD_WBOOK_ID,
                YD_MTL_STAT,
                EXPECT_YD_STK_LOC,
                STOCK_MOVE_TERM,
                FRTOMOVE_WORD_NO,
                TRANS_ORD_DATE || TRANS_ORD_SEQNO AS TRANS_WORD_NO,
                CAR_CARD_NO,
                CTS_RELAY_YN,
                CTS_RELAY_BAY,
                CTS_RELAY_SADDLE,
                KEEP_STL_YN,
                REGISTER,
                REG_DDTT,
                MODIFIER,
                MOD_DDTT,
                (
                    CASE
                    -- WHEN TRANS_ORD_SEQNO > 700000 THEN 'N'
                    WHEN TRN_FRTOMOVE_GP IN ('21','23') THEN 'N'
                    ELSE DEL_YN END
                ) AS DEL_YN,
                CAR_NO,
                YD_RULE_PL_RS_GP,
                TRANS_ORD_DATE,
                TRANS_ORD_SEQNO,
                SUBSTR(YD_SCH_CD_LOC, 1, 8) AS YD_SCH_CD,
                (SELECT SLAB_W FROM VW_YD_SLABCOMM WHERE SLAB_NO = A.STL_NO) AS SLAB_W,
                (SELECT SLAB_WT FROM VW_YD_SLABCOMM WHERE SLAB_NO = A.STL_NO) AS SLAB_WT,
                (
                    SELECT
                        'E'
                    FROM
                        TB_PT_COILCOMM B
                    WHERE 1=1
                    AND B.COIL_NO = A.STL_NO
                    AND B.YD_GP = '1'
                    AND B.PASS_PROC1 = '1K'
                    AND (SUBSTR(B.YD_STR_LOC_HIS1, 3, 2) IN ('KE', 'KD') OR SUBSTR(B.YD_STR_LOC, 3, 2) IN ('KE', 'KD'))
                    AND ((B.REMAIN_PROC1 = '1K' AND B.REMAIN_PROC2 = '1Q') OR B.REMAIN_PROC1='1Q')
                ) AS SPM_NEXT_LOC,
                (
                    SELECT
                        (
                            CASE
                            WHEN B.NEXT_PROC ='1Q' THEN 'E'
                            WHEN B.NEXT_PROC ='1K' THEN 'D'
                            WHEN B.NEXT_PROC ='1H' THEN 'B'
                            END
                        )
                    FROM
                        TB_PT_COILCOMM B
                    WHERE 1=1
                    AND B.COIL_NO = A.STL_NO
                ) AS MOVE_LOC,
                '' AS CARUNLOAD_LOC,
                'X' AS ZONE_AIMBAY_GP,
                NVL
                (
                    (
                        SELECT
                            'Y'
                        FROM
                            USRYFA.VW_YF_CONDENSATIONLOC C
                        WHERE 1=1
                        AND C.COIL_NO = A.STL_NO
                        AND YD_ZONE_GP IS NOT NULL
                        AND ROWNUM <= 1
                    ),
                    'N'
                ) AS GOODS_YN,
                (
                    SELECT
                        YD_ZONE_GP
                    FROM
                        USRYFA.VW_YF_CONDENSATIONLOC C
                    WHERE 1=1
                    AND C.COIL_NO = A.STL_NO
                    AND YD_ZONE_GP IS NOT NULL
                    AND ROWNUM <= 1
                ) AS YD_ZONE_GP,
                SUBSTR(YD_SCH_CD_LOC, 6, 1) AS BAY_GP,
                (
                    SELECT
                        NVL(SH.RECEIPT_HOLD_SCRAP_CAUSE_GP, '-')
                    FROM
                        TB_HR_C_SHEARWOWR SH
                    WHERE 1=1
                    AND SH.COIL_NO = A.STL_NO
                    AND SH.STEP_NO = 1
                ) AS RECEIPT_HOLD_SCRAP_YN,
                (
                    SELECT
                        COIL_T
                    FROM
                        TB_PT_COILCOMM CO
                    WHERE 1=1
                    AND CO.COIL_NO = A.STL_NO
                ) AS COIL_T
            FROM
                (
                    SELECT
                        A.*,
                        (
                            SELECT
                                YD_SCH_CD || YD_UP_WO_LOC
                            FROM
                                USRYFA.TB_YF_WRKHIST B
                            WHERE 1=1
                            AND B.STL_NO = A.STL_NO
                            AND B.YD_WRK_HIST_ID =
                            (
                                SELECT
                                    MAX(YD_WRK_HIST_ID)
                                FROM
                                    TB_YF_WRKHIST W
                                WHERE 1=1
                                AND W.STL_NO = B.STL_NO
                            )
                            AND ROWNUM <= 1
                        ) AS YD_SCH_CD_LOC,
                        YD_WBOOK_ID,
                        C.TRANS_FRTOMOVE_GP AS TRN_FRTOMOVE_GP
                    FROM
                         TB_YF_STOCK A
                       , TB_YF_WRKBOOKMTL B
                       , VW_LM_P_TRANSWORDCOMM C
                    WHERE
                    			A.TRANS_ORD_DATE  = C.TRANS_WORD_DATE(+)
                    	AND A.TRANS_ORD_SEQNO = C.TRANS_WORD_SEQNO(+)
                    	AND A.STL_NO = B.STL_NO
                     	AND A.STL_NO = :V_STL_NO
                      AND B.DEL_YN = 'N'
                ) A
        ) A

),
TEMP_ANYDONG AS
(
    SELECT
        SUBSTR(C.YD_STK_COL_GP,2,1) AS YD_BAY_GP
    FROM
        USRYFA.TB_YF_STKLYR C,
        USRYFA.TB_YF_STKCOL D
    WHERE 1=1
    AND C.YD_STK_COL_GP = D.YD_STK_COL_GP
    AND C.YD_STK_COL_GP LIKE '1_S%'
    AND C.YD_STK_LYR_ACTIVE_STAT = 'O'
    AND D.YD_STK_COL_USAGE_CD = 'TS'
    AND C.STL_NO IS NULL
    AND
    (
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('CZ', 'BZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('F', 'G', 'H')   --//B,C존
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('AZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('A', 'B') --//A존
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('DZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('E')      --//부적합존
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('EZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('G', 'H') --//광폭존
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('GZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('E', 'H') --//광폭존
    )
    AND SUBSTR(C.YD_STK_COL_GP, 2, 1) <> (SELECT DISTINCT BAY_GP FROM TEMP_TABLE) --자기동이 아닌경우
    AND SUBSTR(C.YD_STK_COL_GP, 2, 1) NOT IN
    (
        SELECT
            BAY_GP
        FROM
            VW_YF_CONDENSATIONDONGRATE
        WHERE 1=1
        AND 가능수량 = 0
        AND YD_ZONE_GP = (SELECT YD_ZONE_GP FROM TEMP_TABLE)
    )
    ORDER BY SUBSTR(C.YD_STK_COL_GP,2,1) DESC
)
SELECT
    B.*,
    NVL
    (
        (
            CASE
            --SPM재작업재인 경우
            WHEN RECEIPT_HOLD_SCRAP_YN = 'C'
                AND COIL_T <= 6.5  --6.5T 이하
                AND YD_SCH_CD IN ('1CFD01LM') --HFL추출
                THEN 'D' --보류Scrap원인구분 : C인 경우 D동으로 이적
            --X:전체선택 인경우 존별로 목적동 검색
            WHEN CARUNLOAD_PUT_LOC2 IN ('X')
                AND YD_SCH_CD IN 
                (
                    '1CFD01LM', '1EKD01LM', '1FKD01LM', '1FQE01LM', '1GQD01LM',
                    '1AYD01MM', '1AYD11MM', '1AYD21MM',
                    '1BYD01MM', '1BYD05MM', '1BYD11MM', '1BYD12MM', '1BYD21MM', '1BYD25MM', 
                    '1CYD01MM', '1CYD05MM', '1CYD11MM', '1CYD12MM', '1CYD21MM', '1CYD25MM',
                    '1DYD01MM', '1DYD12MM', '1DYD25MM', 
                    '1EYD01MM', '1EYD05MM', '1EYD11MM', '1EYD12MM', '1EYD21MM', '1EYD25MM',
                    '1FYD01MM', '1FYD05MM', '1FYD11MM', '1FYD12MM', '1FYD21MM', '1FYD25MM',
                    '1GYD01MM', '1GYD05MM', '1GYD11MM', '1GYD12MM', '1GYD21MM', '1GYD25MM',
                    '1HYD01MM', '1HYD05MM', '1HYD11MM', '1HYD12MM', '1HYD21MM', '1HYD25MM'
                )   --추출
                AND GOODS_YN = 'Y'    --제품
                AND NOT EXISTS
                (
                    SELECT
                        1
                    FROM
                        USRYFA.TB_YF_STKLYR C,
                        USRYFA.TB_YF_STKCOL D
                    WHERE 1=1
                    AND C.YD_STK_COL_GP = D.YD_STK_COL_GP
                    AND C.YD_STK_COL_GP LIKE '1_S%'
                    AND C.YD_STK_LYR_ACTIVE_STAT = 'O'
                    AND D.YD_STK_COL_USAGE_CD = 'TS'
                    AND C.STL_NO IS NULL
                    AND SUBSTR(C.YD_STK_COL_GP, 2, 1) = B.CARUNLOAD_PUT_LOC2
                    AND ROWNUM <= 1
                )
                THEN (SELECT YD_BAY_GP FROM TEMP_ANYDONG A WHERE ROWNUM <= 1)
            --자기동과 목적동이 같은 경우
            WHEN CARUNLOAD_PUT_LOC2 = (SELECT DISTINCT BAY_GP FROM TEMP_TABLE)
                AND GOODS_YN = 'Y'    --제품
                THEN (SELECT YD_BAY_GP FROM TEMP_ANYDONG A WHERE ROWNUM <= 1)
            ELSE
            (
                CASE
                WHEN CARUNLOAD_PUT_LOC2 NOT IN
                    (
                        SELECT
                            BAY_GP
                        FROM
                            VW_YF_CONDENSATIONDONGRATE
                        WHERE 1=1
                        AND 가능수량 = 0
                        AND YD_ZONE_GP = (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE)
                    )
                    THEN CARUNLOAD_PUT_LOC2
                ELSE (SELECT YD_BAY_GP FROM TEMP_ANYDONG A WHERE ROWNUM <= 1) END
            ) END
        ),
        (
            CASE
            WHEN CARUNLOAD_PUT_LOC2 = 'X' AND YD_ZONE_GP = 'AZ' THEN 'A'
            ELSE 'H' END
        )
    ) AS CARUNLOAD_PUT_LOC
FROM
    TEMP_TABLE B
 </pre> */
public final static String getStockInfo = "yf.facilitystatus.facilityinquiry.CraneSchDAO.getStockInfo_PIDEV";

 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getTakeInCoilList
SELECT B.STL_NO || '[' || B.YD_STK_COL_GP || ']'  AS CD_NM,
            B.STL_NO AS CD_VAL 
  FROM TB_YF_STKLYR B 
      ,TB_YF_STKCOL A
      ,VW_YF_COILCOMM D
 WHERE B.YD_STK_COL_GP LIKE '1C%'
   AND B.YD_STK_COL_GP = A.YD_STK_COL_GP
   AND A.SECT_GP BETWEEN '01' AND '99'
   AND B.YD_STK_LYR_STAT IN ('C')
   AND B.STL_NO = D.COIL_NO
   AND D.STL_APPEAR_GP = 'E'
   AND   SUBSTR(
                CASE 
                    WHEN NVL(D.NEXT_DEMAND_PROC,D.NEXT_PROC) IS NULL THEN D.PLAN_PROC1
                    WHEN NVL(D.NEXT_DEMAND_PROC,D.NEXT_PROC) IS NOT  NULL THEN NVL(D.NEXT_DEMAND_PROC,D.NEXT_PROC)
                END
        ,2,1)  = 'H'
    AND NOT EXISTS (
        SELECT 1
        FROM TB_YF_EQPTRACKING S
        WHERE S.STL_NO = B.STL_NO
    )
 </pre> */
public final static String getTakeInCoilList = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getTakeInCoilList";

 /** <pre> 2020-04-24
--com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdSchCd
--스케줄코드조회
WITH PARAM AS
(
    SELECT
        :V_YD_GP     AS P_YD_GP,
        :V_YD_BAY_GP AS P_YD_BAY_GP
    FROM
        DUAL    
)
SELECT
    CD_VAL,
    CD_NM
FROM
    (
        SELECT
            YD_SCH_CD   AS CD_VAL,
            '[' || YD_SCH_CD || '] ' || CD_CONTENTS AS CD_NM,
            YD_BAY_GP
        FROM
            TB_YF_SCHRULE,
            PARAM
        WHERE 1=1
        AND YD_GP  = P_YD_GP
        AND DEL_YN = 'N'
        
        UNION ALL
        
        SELECT
            '1_PT02UM' AS CD_VAL,
            '이송상차' AS CD_NM,
            '0' AS YD_BAY_GP
        FROM
            PARAM
        WHERE 1=1
        AND P_YD_GP = '1'
        
        UNION ALL
        
        SELECT
            '1_PT02LM' AS CD_VAL,
            '이송하차' AS CD_NM,
            '0' AS YD_BAY_GP
        FROM
            PARAM
        WHERE 1=1
        AND P_YD_GP = '1'
    ),
    PARAM
WHERE 1=1
AND YD_BAY_GP LIKE P_YD_BAY_GP || '%' 
ORDER BY YD_BAY_GP, DECODE(SUBSTR(CD_VAL, 3, 6), 'DC01LM', 1, 'PT02LM', 1, 'EC01LM', 2, 'EC02LM', 3, 99), CD_NM
 </pre> */
public final static String getCodeYdSchCd = "com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdSchCd";

