 /** <pre> 2019-10-02
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbcoilWrkBookMtl
-- 대상재 최신적재위치 READ
SELECT 
    CASE WHEN C.YD_STK_LYR_STAT = 'C' AND B.STL_NO = C.STL_NO 
         THEN ROW_NUMBER() OVER(ORDER BY C.YD_STK_LYR_NO DESC) +100
         WHEN C.YD_STK_LYR_STAT = 'C'
         THEN ROW_NUMBER() OVER(ORDER BY C.YD_STK_LYR_NO DESC)
         ELSE 0 END AS HANDLING_CNT
   ,C.YD_STK_COL_GP
   ,C.YD_STK_BED_NO
   ,C.YD_STK_LYR_NO
   ,C.STL_NO
   ,CASE WHEN B.STL_NO = C.STL_NO THEN 'S' ELSE 'W' END AS YD_TO_LOC_DCSN_MTD --S:주작업 W:더미작업
   ,C.YD_STK_LYR_STAT
   ,A.YD_WBOOK_ID 
   ,A.YD_UP_COLL_SEQ
   ,D.YD_CRN_SCH_ID
   ,D.YD_WRK_PROG_STAT
   ,D.YD_SCH_CD   AS CRNSCH_YD_SCH_CD
   ,D.YD_WBOOK_ID AS CRNSCH_WBOOK_ID
FROM TB_YF_WRKBOOKMTL A
    ,TB_YF_STKLYR B
    ,TB_YF_STKLYR C
    ,TB_YF_CRNSCH D
    ,TB_YF_CRNWRKMTL E
WHERE A.YD_WBOOK_ID        = :V_YD_WBOOK_ID
  AND A.STL_NO             = B.STL_NO
  AND B.YD_STK_COL_GP      = C.YD_STK_COL_GP
  AND C.STL_NO             = E.STL_NO(+)
  AND E.YD_CRN_SCH_ID      = D.YD_CRN_SCH_ID(+)
  AND C.YD_STK_LYR_STAT    IN ('C','U')
  AND A.DEL_YN             = 'N'
  AND D.DEL_YN(+)          = 'N'
  AND E.DEL_YN(+)          = 'N'
  AND (   (B.YD_STK_LYR_NO = '01' AND (C.YD_STK_BED_NO|| C.YD_STK_LYR_NO IN (B.YD_STK_BED_NO||'01' 
                                                                            ,B.YD_STK_BED_NO||'02' 
                                                                            ,TO_CHAR(TO_NUMBER(B.YD_STK_BED_NO) - 1,'FM00') ||'02')))
       OR (B.YD_STK_LYR_NO = '02' AND (C.YD_STK_BED_NO|| C.YD_STK_LYR_NO IN (B.YD_STK_BED_NO||'02'))) 
                                    
      )
 </pre> */
public final static String getbcoilWrkBookMtl = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbcoilWrkBookMtl";

