 /** <pre> 2019-09-24
-- yf.facilitystatus.facilityinquiry.CraneSchDAO.getDmCarInfo_PIDEV 
WITH TEMP_TABLE AS
(
    SELECT
        :V_STL_NO AS STL_NO
    FROM
        DUAL
)
SELECT
    CARD_NO,
    (
        CASE
        -- WHEN A.TRANS_WORD_SEQNO < 700000 THEN
       		 WHEN A.CR_FRTOMOVE_GP <> '81' AND A.TRANS_MEANS_GP = '1' THEN
            (
                SELECT
                    MAX(TRANS_COM_CD)   --//내수
                FROM
                    VW_LM_P_TRANSWORDCOMM C
                WHERE 1=1
                AND C.TRANS_WORD_DATE   = A.TRANS_WORD_DATE
                AND C.TRANS_WORD_SEQNO  = A.TRANS_WORD_SEQNO
            )
       -- WHEN A.TRANS_WORD_SEQNO BETWEEN 700000 AND 799999 THEN
       WHEN A.TRANS_FRTOMOVE_GP = '23' THEN
            (
                SELECT
                    MAX(TRANS_COM_CD)   --//임가공
                FROM
                    VW_LM_P_TRANSWORDCOMM C
                WHERE 1=1
                AND C.TRANS_WORD_DATE    = A.TRANS_WORD_DATE
                AND C.TRANS_WORD_SEQNO   = A.TRANS_WORD_SEQNO
            )
       -- WHEN A.TRANS_WORD_SEQNO >= 800000 THEN
			 WHEN A.TRANS_FRTOMOVE_GP = '21' THEN
            (
                SELECT
                    MAX(TRANS_COM_CD)   --//제품이송
                FROM
                    VW_LM_P_TRANSWORDCOMM C
                WHERE 1=1
                AND C.TRANS_WORD_DATE    = A.TRANS_WORD_DATE
                AND C.TRANS_WORD_SEQNO   = A.TRANS_WORD_SEQNO
            )
        ELSE '' END
    ) AS TRANS_COM_CD,
    CAR_NO,
    CAR_NO_ADDR,
    TRANS_WORD_DATE,
    TRANS_WORD_SEQNO
FROM
    (
        --//출하 ,임가공 , 제품이송
        SELECT
            B.CARD_NO,
            RPAD(B.CAR_NO, 12, ' ') AS CAR_NO,
            SUBSTR(B.CAR_NO, LENGTH(B.CAR_NO) - 3) AS CAR_NO_ADDR,
            A.TRANS_ORD_DATE AS TRANS_WORD_DATE,
            TO_CHAR(A.TRANS_ORD_SEQNO) AS TRANS_WORD_SEQNO,
						C.TRANS_FRTOMOVE_GP,
						C.CR_FRTOMOVE_GP,
						C.TRANS_MEANS_GP
        FROM
            (
                SELECT
                    TRANS_ORD_DATE,
                    TRANS_ORD_SEQNO
                FROM
                    TB_YD_STOCK A
                WHERE 1=1
                AND A.STL_NO = (SELECT STL_NO FROM TEMP_TABLE)

                UNION ALL

                SELECT
                    TRANS_ORD_DATE,
                    TRANS_ORD_SEQNO
                FROM
                    TB_YF_STOCK A
                WHERE 1=1
                AND A.STL_NO =(SELECT STL_NO FROM TEMP_TABLE)
            ) A
            , USRYDA.TB_YD_CARSCH B
            , VW_LM_P_TRANSWORDCOMM C
        WHERE 1=1
        AND A.TRANS_ORD_DATE    = B.TRANS_ORD_DATE
        AND A.TRANS_ORD_SEQNO   = B.TRANS_ORD_SEQNO
        AND B.TRANS_ORD_DATE    = C.TRANS_WORD_DATE(+)
        AND B.TRANS_ORD_SEQNO   = C.TRANS_WORD_SEQNO(+)
        AND ROWNUM <= 1

        UNION ALL

        --//구내운송
        SELECT
            B.TRN_EQP_CD,
            RPAD(NVL(C.CAR_NO, B.TRN_EQP_CD), 12, ' '),
            SUBSTR(NVL(C.CAR_NO, B.TRN_EQP_CD), LENGTH(NVL(C.CAR_NO, B.TRN_EQP_CD)) - 3) AS CAR_NO_ADDR,
            '',
            '',
            '',
            '',
            ''
        FROM
            USRYDA.TB_YD_CARFTMVMTL A,
            USRYDA.TB_YD_CARSCH B,
            USRTSA.TB_TS_CAR_SPEC_RULL C
        WHERE 1=1
        AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
        AND B.TRN_EQP_CD    = C.TRN_EQP_CD(+)
        AND A.STL_NO        = (SELECT STL_NO FROM TEMP_TABLE)
        AND B.YD_CAR_USE_GP = 'L'
        AND A.DEL_YN        = 'N'
        AND C.TRN_EQP_CD IS NOT NULL
        AND ROWNUM <= 1
    ) A
WHERE 1=1
AND ROWNUM <= 1
 </pre> */
public final static String getDmCarInfo = "yf.facilitystatus.facilityinquiry.CraneSchDAO.getDmCarInfo_PIDEV";

