 /** <pre> 2021-01-12
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getRetnTrgtGds_PIDEV 
WITH PARAM AS (
SELECT :V_CAR_NO          AS P_CAR_NO
     , :V_TRANS_ORD_DATE  AS P_TRANS_ORD_DATE
     , :V_TRANS_ORD_SEQNO AS P_TRANS_ORD_SEQNO
  FROM DUAL     
)
SELECT RNUM
     , LPAD(RNUM, 2, '0') AS YD_STK_BED_NO
     , COIL_NO AS STL_NO
     , CURR_PROG_CD
     , ORD_NO
     , ORD_DTL
     , SPEC_ABBSYM
     , COIL_T
     , COIL_W
     , COIL_WT
     , COIL_OUTDIA
     , COIL_LEN
  FROM (
        SELECT CC.*
             , RN
          FROM VW_YF_COILCOMM  CC
             , (
                SELECT ROW_NUMBER() OVER(PARTITION BY YD_CAR_SCH_ID ORDER BY YD_STK_BED_NO) AS RN
                     , CM.STL_NO
                  FROM USRYDA.TB_YD_CARFTMVMTL  CM
                 WHERE YD_CAR_SCH_ID = (
                                         SELECT YD_CAR_SCH_ID
                                           FROM (
                                                 SELECT YD_CAR_SCH_ID
                                                   FROM USRYDA.TB_YD_CARSCH
                                                      , PARAM
                                                  WHERE SPOS_WLOC_CD != 'S0001'
                                                    AND TRANS_ORD_DATE BETWEEN TO_CHAR(SYSDATE-3,'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD')
                                                    AND ((CAR_NO = P_CAR_NO OR SUBSTR(CAR_NO, -4) = P_CAR_NO)  AND P_TRANS_ORD_DATE IS NULL)
                                                     OR (TRANS_ORD_DATE = P_TRANS_ORD_DATE AND TRANS_ORD_SEQNO = P_TRANS_ORD_SEQNO)
                                                  ORDER BY YD_CAR_SCH_ID DESC
                                                )
                                          WHERE ROWNUM = 1       
                                        )
                UNION ALL
                SELECT
                     ROW_NUMBER() OVER(PARTITION BY A.TRANS_WORD_DATE, A.TRANS_WORD_SEQNO ORDER BY A.REG_DDTT) AS RN
                    ,A.GOODS_NO
                FROM VW_LM_P_TRANSWORDGOODS A
                    ,VW_LM_P_TRANSWORDCOMM  B
                    , PARAM
                WHERE  A.TRANS_WORD_DATE  = B.TRANS_WORD_DATE
                 AND A.TRANS_WORD_SEQNO = B.TRANS_WORD_SEQNO
                 AND A.TRANS_WORD_DATE = P_TRANS_ORD_DATE
                 AND A.TRANS_WORD_SEQNO = P_TRANS_ORD_SEQNO
                 AND A.DEL_YN = 'N'
                 AND B.DEL_YN ='N'
               ) MTL
         WHERE CC.COIL_NO = MTL.STL_NO
         AND NOT EXISTS (
                SELECT 1
                FROM TB_YD_CARFTMVMTL S
                WHERE S.STL_NO = CC.COIL_NO
                AND S.DEL_YN = 'N'
         )
       ) A
     , (SELECT ROWNUM AS RNUM
          FROM DUAL
       CONNECT BY LEVEL <= 15
       ) R
 WHERE R.RNUM = A.RN(+)
 </pre> */
public final static String getRetnTrgtGds = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getRetnTrgtGds_PIDEV";

