 /** <pre> 2019-10-10
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCrnSchRuleInqjl.getSchRuleMgtList 
-- 크레인스케줄기준조회 
WITH PARAM AS (
    SELECT :V_YD_GP         AS V_YD_GP
          ,:V_YD_BAY_GP     AS V_YD_BAY_GP
          ,:V_YD_SCH_CD     AS V_YD_SCH_CD
          ,:V_PAGE_NO       AS V_PAGE_NO
          ,:V_PAGE_SIZE     AS V_PAGE_SIZE
      FROM DUAL 
)

SELECT X.RNUM                         AS RNUM                   --RowNum
     , X.TOTAL                        AS TOTALCOUNT             --총라인수  
     , X.YD_SCH_CD                    AS YD_SCH_CD              --스케쥴코드    
     , X.YD_GP                        AS YD_GP                  --야드구분
     , X.YD_BAY_GP                    AS YD_BAY_GP              --동구분    
     , X.YD_SCH_RULE_ACT_STAT         AS YD_SCH_RULE_ACT_STAT   --기준활성화상태               
     , X.CD_CONTENTS                  AS CD_CONTENTS            --스케쥴명      
     , X.YD_SCH_RNG_CD                AS YD_SCH_RNG_CD          --스케쥴범위                
     , X.YD_SCH_WHIO_GP               AS YD_SCH_WHIO_GP         --스케쥴입출고구분            
     , X.YD_WRK_CRN                   AS YD_WRK_CRN             --작업크레인            
     , X.YD_WRK_CRN                   AS YD_WRK_CRN_OLD         --작업크레인            
     , X.YD_ALT_CRN                   AS YD_ALT_CRN             --대체크래인           
     , X.YD_SCH_PROH_EXN              AS YD_SCH_PROH_EXN        --금지해제           
     , X.YD_SCH_DIV_GP                AS YD_SCH_DIV_GP          --스케쥴분할구분           
     , X.YD_WRK_CRN_PRIOR             AS YD_WRK_CRN_PRIOR       --작업크레인작업순위            
     , X.YD_ALT_CRN_YN                AS YD_ALT_CRN_YN          --대체크레인유무            
     , X.YD_ALT_CRN_PRIOR             AS YD_ALT_CRN_PRIOR       --대체크레인작업순위            
     , SUBSTR(X.YD_SCH_RNG_CD, 1, 2)  AS YD_MTL_ITEM            --      
     , SUBSTR(X.YD_SCH_RNG_CD, 3, 2)  AS YD_EQP_GP              --    
     , (SELECT YD_EQP_PROG_STAT FROM TB_YF_EQP WHERE YD_EQP_ID = X.YD_WRK_CRN) AS YD_WRK_EQUIP_STAT
     , (SELECT YD_EQP_PROG_STAT FROM TB_YF_EQP WHERE YD_EQP_ID = X.YD_ALT_CRN) AS YD_ALT_EQUIP_STAT
     , X.DAN_PRIOR
     , X.YD_SCH_AUTO_ST_YN
     , X.ADV_CRN_PRIOR
     , CASE WHEN X.YD_SCH_CD IN ('1EKE02MM','1EKE10UM', '1EYD99MM') THEN 'N' ELSE 'Y' END MODIFY_YN -- 수정불가능한 스케쥴 
  FROM(SELECT ROWNUM AS RNUM
            ,A.TOTAL
            ,A.YD_SCH_CD
            ,A.YD_GP
            ,A.YD_BAY_GP
            ,A.YD_SCH_RULE_ACT_STAT
            ,A.CD_CONTENTS
            ,A.YD_SCH_RNG_CD
            ,A.YD_SCH_WHIO_GP
            ,A.YD_WRK_CRN
            ,A.YD_ALT_CRN
            ,A.YD_SCH_PROH_EXN
            ,A.YD_SCH_DIV_GP   
            ,A.YD_WRK_CRN_PRIOR
            ,A.YD_ALT_CRN_YN   
            ,A.YD_ALT_CRN_PRIOR
            ,A.DAN_PRIOR
            ,A.YD_SCH_AUTO_ST_YN
            ,A.ADV_CRN_PRIOR
        FROM (SELECT COUNT(*) OVER() AS TOTAL
                ,A.YD_SCH_CD
                ,A.YD_GP
                ,A.YD_BAY_GP
                ,A.YD_SCH_RULE_ACT_STAT
                ,A.CD_CONTENTS
                ,A.YD_SCH_RNG_CD
                ,A.YD_SCH_WHIO_GP
                ,A.YD_WRK_CRN
                ,A.YD_ALT_CRN
                ,A.YD_SCH_PROH_EXN
                ,A.YD_SCH_DIV_GP
                ,A.YD_WRK_CRN_PRIOR
                ,A.YD_ALT_CRN_YN
                ,A.YD_ALT_CRN_PRIOR
                ,A.DAN_PRIOR
                ,A.YD_SCH_AUTO_ST_YN
                ,A.ADV_CRN_PRIOR
            FROM TB_YF_SCHRULE A 
                ,PARAM P
            WHERE A.YD_GP     LIKE '%' || P.V_YD_GP || '%'
            AND A.YD_BAY_GP   LIKE '%' || P.V_YD_BAY_GP || '%'
            AND A.YD_SCH_CD   LIKE '%' || P.V_YD_SCH_CD || '%'
            AND A.DEL_YN = 'N'  
           ORDER BY A.YD_WRK_CRN_PRIOR,A.YD_SCH_CD
           )A, PARAM P
    WHERE ROWNUM <= P.V_PAGE_NO * P.V_PAGE_SIZE) X
        ,PARAM P
 WHERE RNUM >= ((P.V_PAGE_NO-1)* P.V_PAGE_SIZE)+1
 </pre> */
public final static String getSchRuleMgtList = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCrnSchRuleInqjl.getSchRuleMgtList";

