 /** <pre> 2021-03-29
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getAcoilRetngdsRethtWrkRegjl_PIDEV 
WITH PARAM AS
(
    SELECT
        :V_CAR_NO          AS P_CAR_NO,
        :V_TRANS_ORD_DATE  AS P_TRANS_ORD_DATE,
        :V_TRANS_ORD_SEQNO AS P_TRANS_ORD_SEQNO,
        :V_RETN_WK_GP      AS P_RETN_WK_GP
    FROM
        DUAL
)
SELECT
    *
FROM
    (
        SELECT
            (
                SELECT
                    TRANS_COM_NAME
                FROM
                    VW_LM_Z_TRANSCOMCD
                WHERE 1=1
                AND TRANS_COM_CD = A.TRANS_COM_CD
            ) AS TRANS_COM_NAME,    --운송사
            A.CAR_NO,               -- 차량번호 
            A.DRIVER_NAME,          -- 운전기사명 
            A.DRIVER_TEL_NO,        -- 운전기사전화번호 
            DECODE(P_RETN_WK_GP, 5, CR_CAR_NO, SUBSTR(A.CAR_NO, -4)) AS CARD_NO
        FROM
            VW_LM_P_TRANSWORDCOMM A,
            PARAM
        WHERE 1=1
        AND TRANS_WORD_DATE BETWEEN TO_CHAR(SYSDATE-3,'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD')
        AND 
        (
            (A.CAR_NO = P_CAR_NO OR SUBSTR(A.CAR_NO, -4) = P_CAR_NO)
            OR 
            (TRANS_WORD_DATE = P_TRANS_ORD_DATE AND TRANS_WORD_SEQNO = P_TRANS_ORD_SEQNO)
        )     
        ORDER BY A.TRANS_WORD_DATE DESC, A.TRANS_WORD_SEQNO DESC
    )        
WHERE 1=1
AND ROWNUM = 1
 </pre> */
