 /** <pre> 2021-02-10
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarPoint3
SELECT
    *
FROM
    (
        SELECT
            CASE
            --크레인설비가 고장이거나 OFF라인이 아님 1순위
            WHEN A.YD_CARPNT_CD != NVL(D.YD_CARPNT_CD, ' ') THEN 1
            --그외는 2순위
            ELSE 2 END AS RNK1,
            CASE
            --하차코일중 복포존코일이 1개이상 1통로 1순위
            WHEN C.BZ_CT > 0 AND SUBSTR(A.YD_CARPNT_CD, 2, 1) = '1' THEN 1
            --하차코일중 복포존코일이 0 + 2통로 1순위
            WHEN C.BZ_CT = 0 AND SUBSTR(A.YD_CARPNT_CD, 2, 1) = '2' THEN 1
            --그외는 2순위
            ELSE 2 END AS RNK2,
            CASE
            WHEN SUBSTR(A.YD_CARPNT_CD, 1, 3) = SUBSTR(:V_YD_CARPNT_CD, 1, 3) THEN 1
            ELSE 2 END AS RNK3,
            SUBSTR(A.YD_STK_COL_GP, 1, 4) || '0' || SUBSTR(A.YD_STK_COL_GP, 6, 1) AS YD_STK_COL_GP2,
            DECODE(A.YD_STK_COL_ACT_STAT, 'R', 'C', A.YD_STK_COL_ACT_STAT) AS YD_STK_COL_ACT_STAT,
            A.YD_CARPNT_CD,
            A.REG_DDTT,
            A.REGISTER,
            A.MOD_DDTT,
            A.MODIFIER,
            A.DEL_YN,
            A.YD_CAR_USETYPE_GP,
            A.YD_GP,
            A.YD_BAY_GP,
            A.YD_STK_COL_GP,
            A.TRN_EQP_CD,
            A.CAR_NO,
            A.CARD_NO,
            A.WLOC_CD,
            A.YD_PNT_CD,
            A.YD_CARPNT_DESC,
            A.YD_SPAN_FROM,
            A.YD_SPAN_TO,
            (
                SELECT
                    ITEM1
                FROM
                    USRYDA.TB_YD_RULE
                WHERE 1=1
                AND REPR_CD_GP = 'J00005'
                AND CD_GP = A.YD_GP
                AND ITEM = '*'
                AND DEL_YN = 'N'
            ) AS MOV_YN
        FROM
            TB_YD_CARPOINT A,
            (
                --하차할 재료중에 복포존들어갈 코일매수
                SELECT
                    NVL(SUM(CASE WHEN YD_ZONE_GP = 'BZ' THEN 1 ELSE 0 END), 0) AS BZ_CT
                FROM
                    VW_YF_GETCONDENSATIONLOC
                WHERE 1=1
                AND COIL_NO IN
                (
                    SELECT
                        SUBSTR
                        (
                            STL,
                            INSTR(STL, ',', 1, LEVEL) + 1,
                            INSTR(STL, ',', 1, LEVEL + 1) - INSTR(STL, ',', 1, LEVEL) -1
                        ) AS STL_NOS
                    FROM
                        (
                            SELECT
                                :V_STL_NOS AS STL
                            FROM
                                DUAL
                        )
                    CONNECT BY LEVEL <= LENGTH(STL) - LENGTH(REPLACE(STL, ',')) - 1
                )
            ) C,
            (
                --크레인이 고장이거나 OFF라인상태인 해당크레인쪽 포인트
                SELECT
                    '1' || SUBSTR(A.YD_EQP_ID, 6, 1) || A.YD_BAY_GP || B.CT AS YD_CARPNT_CD
                FROM
                    TB_YF_EQP A,
                    (
                        SELECT
                            LEVEL AS CT
                        FROM
                            DUAL
                        CONNECT BY LEVEL <= 2
                    ) B
                WHERE 1=1
                AND A.YD_GP = SUBSTR(:V_YD_CARPNT_CD, 1, 1)
                AND A.YD_BAY_GP = SUBSTR(:V_YD_CARPNT_CD, 3, 1)
                AND A.YD_EQP_GP = 'CR'
                AND
                (
                    A.YD_EQP_PROG_STAT  = 'B'   --고장
                    OR
                    A.YD_EQP_WRK_MODE   = '2'   --OFF라인
                )
            ) D
        WHERE 1=1
        AND A.YD_CARPNT_CD = D.YD_CARPNT_CD(+)
        AND A.YD_CARPNT_CD LIKE SUBSTR(:V_YD_CARPNT_CD, 1, 1) || '_' || SUBSTR(:V_YD_CARPNT_CD, 3, 1) || '%'  --해당야드 + 해당동만 조회
        AND A.DEL_YN = 'N'                --삭제된곳 제외
        AND A.YD_STK_COL_ACT_STAT != 'N'  --사용불가인곳 제외
        ORDER BY 1, 2, 3, A.YD_STK_COL_GP
    )
WHERE 1=1
AND ROWNUM = 1
 </pre> */
public final static String getYdCarPoint3 = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarPoint3";

 /** <pre> 2020-09-02
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSchPrfrPrior 
SELECT YD_SCH_CD
     , YD_ROUTE_GP
     , YD_SCH_PRFR_PRIOR
     , A.DEL_YN
     , SUBSTR(YD_SCH_PRFR_PRIOR, 1, 1) AS YARD_PRIOR
     , SUBSTR(YD_SCH_PRFR_PRIOR, 2, 1) AS CAR_PRIOR
     , CASE WHEN YD_SCH_CD = '1EKD02LM' THEN (SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP046' AND CD_GP='1' AND DEL_YN ='N')
            WHEN YD_SCH_CD = '1CYD21MM' THEN (SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP047' AND CD_GP='1' AND DEL_YN ='N' AND ITEM = 'L')
            WHEN YD_SCH_CD = '1CYD25MM' THEN (SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP047' AND CD_GP='1' AND DEL_YN ='N' AND ITEM = 'R')
            ELSE 'N' END AS DTL_ITEM1
     , CASE WHEN YD_SCH_CD = '1EKD02LM' THEN (SELECT DTL_ITEM2 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP046' AND CD_GP='1' AND DEL_YN ='N')
            WHEN YD_SCH_CD = '1CYD21MM' THEN (SELECT DTL_ITEM2 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP047' AND CD_GP='1' AND DEL_YN ='N' AND ITEM = 'L')
            WHEN YD_SCH_CD = '1EYD25MM' THEN (SELECT DTL_ITEM2 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP047' AND CD_GP='1' AND DEL_YN ='N' AND ITEM = 'R')
            ELSE '' END AS DTL_ITEM2        
     , CASE WHEN YD_SCH_CD = '1EKD02LM' THEN (SELECT DTL_ITEM3 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP046' AND CD_GP='1' AND DEL_YN ='N')
            WHEN YD_SCH_CD = '1CYD21MM' THEN (SELECT DTL_ITEM3 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP047' AND CD_GP='1' AND DEL_YN ='N' AND ITEM = 'L')
            WHEN YD_SCH_CD = '1EYD25MM' THEN (SELECT DTL_ITEM3 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP047' AND CD_GP='1' AND DEL_YN ='N' AND ITEM = 'R')
            ELSE '' END AS DTL_ITEM3        
  FROM TB_YF_SCHLOCSRCHPRIOR  A
 WHERE YD_SCH_CD   = :V_YD_SCH_CD
   AND YD_ROUTE_GP = :V_YD_ROUTE_GP
 </pre> */
public final static String getSchPrfrPrior = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSchPrfrPrior";

