 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYFF1L004Scrap
SELECT 'YFF1L004'                          AS JMS_TC_CD          --JMSTC코드
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTC생성일시
      ,'YFF1L004'                                     --전문ID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')         --생성일시
     ||NVL(:V_MSG_GP,'I')                              --전문구분
     ||'0400'                                          --전문길이
     ||RPAD(' ',29,' ')                                --임시
     ||RPAD(NVL(YD_EQP_ID                                   ,' '),6 ,' ') --야드설비ID                 
     ||RPAD(NVL(YD_WRK_PROG_STAT                            ,' '),1 ,' ') --야드작업진행상태           
     ||RPAD(NVL(YD_SCH_CD                                   ,' '),8 ,' ') --야드스케쥴코드             
     ||RPAD(NVL(YD_SCH_NAME                                 ,' '),30,' ') --야드스케줄명               
     ||RPAD(NVL(YD_CRN_SCH_ID                               ,' '),18,' ') --야드크레인스케쥴ID         
     ||RPAD(NVL(YD_CRN_SCH_RMD_CNT                          ,' '),2 ,' ') --야드크레인스케줄잔여회수   
     ||RPAD(NVL(YD_UP_WO_LOC                                ,' '),8 ,' ') --야드권상지시위치           
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_LYR         ,'FM000')    ,'0'),3 ,'0') --야드권상지시단             
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_LOC_XAXIS     ,'FM0000000'),'0'),7 ,'0') --야드권상지시X축            
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_XAXIS_GAP_MAX ,'FM00000'  ),'0'),5 ,'0') --야드권상지시X축오차최대    
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_XAXIS_GAP_MIN ,'FM00000'  ),'0'),5 ,'0') --야드권상지시X축오차최소    
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_LOC_YAXIS     ,'FM00000'  ),'0'),5 ,'0') --야드권상지시Y축            
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_YAXIS_GAP_MAX ,'FM00000'  ),'0'),5 ,'0') --야드권상지시Y축오차최대    
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_YAXIS_GAP_MIN ,'FM00000'  ),'0'),5 ,'0') --야드권상지시Y축오차최소   
     ||RPAD(NVL(YD_UP_WO_LOC_ZAXIS_SYM                      ,' '),1 ,' ') --야드권상지시Z축부호
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_LOC_ZAXIS1    ,'FM00000'  ),'0'),5 ,'0') --야드권상지시Z축            
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_ZAXIS_GAP_MAX ,'FM00000'  ),'0'),5 ,'0') --야드권상지시Z축오차최대    
     ||RPAD(NVL(TO_CHAR(YD_UP_WO_ZAXIS_GAP_MIN ,'FM00000'  ),'0'),5 ,'0') --야드권상지시Z축오차최소    
     ||RPAD(NVL(YD_DN_WO_LOC                                ,' '),8 ,' ') --야드권하지시위치           
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_LYR         ,'FM000')    ,'0'),3 ,'0') --야드권하지시단             
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_LOC_XAXIS     ,'FM0000000'),'0'),7 ,'0') --야드권하지시X축            
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_XAXIS_GAP_MAX ,'FM00000'  ),'0'),5 ,'0') --야드권하지시X축오차최대    
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_XAXIS_GAP_MIN ,'FM00000'  ),'0'),5 ,'0') --야드권하지시X축오차최소    
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_LOC_YAXIS     ,'FM00000'  ),'0'),5 ,'0') --야드권하지시Y축            
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_YAXIS_GAP_MAX ,'FM00000'  ),'0'),5 ,'0') --야드권하지시Y축오차최대    
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_YAXIS_GAP_MIN ,'FM00000'  ),'0'),5 ,'0') --야드권하지시Y축오차최소    
     ||RPAD(NVL(YD_DN_WO_LOC_ZAXIS_SYM                      ,' '),1 ,' ') --야드권하지시Z축부호
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_LOC_ZAXIS1    ,'FM00000'  ),'0'),5 ,'0') --야드권하지시Z축            
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_ZAXIS_GAP_MAX ,'FM00000'  ),'0'),5 ,'0') --야드권하지시Z축오차최대    
     ||RPAD(NVL(TO_CHAR(YD_DN_WO_ZAXIS_GAP_MIN ,'FM00000'  ),'0'),5 ,'0') --야드권하지시Z축오차최소    
     ||RPAD(NVL(GRUSH_COIL_YN                               ,' '),1 ,' ') --짱구코일 여부              
     ||RPAD(NVL(SPM_HFL_YN                                  ,' '),1 ,' ') --SPM/HFL  유무              
     ||RPAD(NVL(CUT_YN                                      ,' '),1 ,' ') --절단재 여부                
     ||RPAD(NVL(YD_EQP_ID2                                  ,' '),6 ,' ') --야드설비ID2                
     ||RPAD(NVL(YD_TC_AIM_BAY_GP                            ,' '),1 ,' ') --야드대차목적동             
     ||RPAD(NVL(YD_CAR_USE_GP                               ,' '),1 ,' ') --야드차량사용구분           
     ||RPAD(NVL(CAR_NO                                      ,' '),15,' ') --차량번호                   
     ||RPAD(NVL(TRN_EQP_CD                                  ,' '),8 ,' ') --운송장비코드               
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_SH          ,'FM00'     ),' '),2 ,' ') --야드설비작업매수           
     ||RPAD(NVL(TO_CHAR(YD_EQP_RMN_SH          ,'FM00'     ),' '),2 ,' ') --야드설비잔량매수           
     ||RPAD(NVL(STL_NO1                                   ,' '),11,' ') --재료번호1                  
     ||RPAD(NVL(TO_CHAR(YD_STL_WT1             ,'FM00000'  ),'0'),5 ,'0') --야드재료중량1              
     ||RPAD(NVL(TO_CHAR(YD_STL_T1              ,'FM000V000'),'0'),6 ,'0') --야드재료두께1              
     ||RPAD(NVL(TO_CHAR(YD_STL_W1              ,'FM0000V0' ),'0'),5 ,'0') --야드재료폭1                
     ||RPAD(NVL(TO_CHAR(YD_STL_L1              ,'FM00000'  ),'0'),7 ,'0') --야드재료길이1              
     ||RPAD(NVL(STL_NO2                                   ,' '),11,' ') --재료번호2                  
     ||RPAD(NVL(TO_CHAR(YD_STL_WT2             ,'FM00000'  ),'0'),5 ,'0') --야드재료중량2              
     ||RPAD(NVL(TO_CHAR(YD_STL_T2              ,'FM000V000'),'0'),6 ,'0') --야드재료두께2              
     ||RPAD(NVL(TO_CHAR(YD_STL_W2              ,'FM0000V0' ),'0'),5 ,'0') --야드재료폭2                
     ||RPAD(NVL(TO_CHAR(YD_STL_L2              ,'FM00000'  ),'0'),7 ,'0') --야드재료길이2              
     ||RPAD(NVL(TO_CHAR(COIL_OUTDIA            ,'FM00000'  ),'0'),5 ,'0') --Coil외경                   
     ||RPAD(NVL(TO_CHAR(COIL_INDIA             ,'FM00000V0' ),'0'),5 ,'0') --Coil내경                   
     ||RPAD(NVL(YD_SCH_CD_NEXT                              ,' '),8 ,' ') --야드스케쥴코드_Next        
     ||RPAD(NVL(YD_SCH_NAME_NEXT                            ,' '),30,' ') --야드스케줄명_NEXT          
     ||RPAD(NVL(YD_UP_WO_LOC_NEXT                           ,' '),8 ,' ') --야드권상지시위치_Next      
     ||RPAD(NVL(YD_UP_WO_LYR_NEXT                         ,' '),3 ,' ') --야드권상지시단_Next        
     ||RPAD(NVL(YD_DN_WO_LOC_NEXT                           ,' '),8 ,' ') --야드권하지시위치_Next      
     ||RPAD(NVL(YD_DN_WO_LYR_NEXT                         ,' '),3 ,' ') --야드권하지시단_Next        
     ||RPAD(NVL(STL_NO_NEXT                               ,' '),11,' ') --재료번호_Next              
     ||RPAD(NVL(TO_CHAR(YD_CRN_WRK_WT_NEXT     ,'FM0000000'),'0'),7 ,'0') --야드크레인작업중량_Next ***   
     ||RPAD(NVL(TO_CHAR(YD_CRN_WRK_T_NEXT      ,'FM000V000'),'0'),6 ,'0') --야드크레인작업총두께_Next  
     ||RPAD(NVL(TO_CHAR(YD_CRN_WRK_MAX_W_NEXT  ,'FM0000V0' ),'0'),5 ,'0') --야드크레인작업최대폭_Next  
     ||RPAD(NVL(TO_CHAR(COIL_OUTDIA_NEXT       ,'FM00000'  ),'0'),5 ,'0') --야드크레인작업코일외경_Next
     ||RPAD(NVL(TO_CHAR(COIL_INDIA_NEXT        ,'FM00000V0' ),'0'),5 ,'0') --야드크레인작업코일내경_Next
     ||RPAD(NVL(TO_CHAR(UP_ROTATION_ANGLE      ,'FM0'      ),' '),1 ,' ') --권상위치 회전각도          
     ||RPAD(NVL(TO_CHAR(DOWN_ROTATION_ANGLE    ,'FM0'      ),' '),1 ,' ') --권하위치 회전각도              
     AS JMS_TC_MESSAGE --JMSTCMessage

FROM 
(
    SELECT K.*
         , CASE WHEN K.YD_UP_WO_LOC_ZAXIS >= 0  THEN '+'
                ELSE '-' END                      AS YD_UP_WO_LOC_ZAXIS_SYM
         , CASE WHEN K.YD_DN_WO_LOC_ZAXIS >= 0  THEN '+'
                ELSE '-' END                      AS YD_DN_WO_LOC_ZAXIS_SYM
         , CASE WHEN K.YD_UP_WO_LOC_ZAXIS < 200 THEN 200
                ELSE K.YD_UP_WO_LOC_ZAXIS END     AS YD_UP_WO_LOC_ZAXIS1                
         , CASE WHEN K.YD_DN_WO_LOC_ZAXIS < 200 THEN 200
                ELSE K.YD_DN_WO_LOC_ZAXIS END     AS YD_DN_WO_LOC_ZAXIS1
      FROM 
    (
        SELECT A.YD_EQP_ID                AS YD_EQP_ID                 --야드설비ID
             , CASE WHEN A.YD_L2_REQUEST_STAT = 'D' THEN '1' 
                    WHEN A.YD_L2_REQUEST_STAT = 'X' THEN 'D'
                    WHEN A.YD_L2_REQUEST_STAT = '5' AND A.YD_WRK_PROG_STAT = '2'  THEN '5' --무인 권하위치변경시 권상전이면 1 권상 후면 5 보내줘야함 20171020 LHJ
                    WHEN A.YD_L2_REQUEST_STAT = '5' AND A.YD_WRK_PROG_STAT != '2' THEN '1'
                    ELSE DECODE(A.YD_WRK_PROG_STAT,'S','1','W','1',A.YD_WRK_PROG_STAT)  END 
                                          AS YD_WRK_PROG_STAT          --야드작업진행상태
             , A.YD_SCH_CD                AS YD_SCH_CD                 --야드스케쥴코드
             , SUBSTRB((SELECT CD_CONTENTS 
                          FROM TB_YF_SCHRULE WHERE YD_SCH_CD = A.YD_SCH_CD)
                      || (CASE WHEN A.YD_AID_WRK_YN='N' THEN '[주]' ELSE '[보조]' END),1,30) AS YD_SCH_NAME
             , A.YD_CRN_SCH_ID            AS YD_CRN_SCH_ID             --야드크레인스케쥴ID
             , DECODE(A.YD_SCH_PRIOR,0,'Y','N')||A.CURR_PROG_CD  AS YD_CRN_SCH_RMD_CNT        --야드크레인스케줄잔여회수
             , A.YD_UP_WO_LOC             AS YD_UP_WO_LOC              --야드권상지시위치
             , A.YD_UP_WO_LYR           AS YD_UP_WO_LYR            --야드권상지시단
             , A.YD_UP_WO_LOC_XAXIS       AS YD_UP_WO_LOC_XAXIS        --야드권상지시X축
             , A.YD_UP_WO_XAXIS_GAP_MAX   AS YD_UP_WO_XAXIS_GAP_MAX    --야드권상지시X축오차최대
             , A.YD_UP_WO_XAXIS_GAP_MIN   AS YD_UP_WO_XAXIS_GAP_MIN    --야드권상지시X축오차최소
             , A.YD_UP_WO_LOC_YAXIS       AS YD_UP_WO_LOC_YAXIS        --야드권상지시Y축
             , A.YD_UP_WO_YAXIS_GAP_MAX   AS YD_UP_WO_YAXIS_GAP_MAX    --야드권상지시Y축오차최대
             , A.YD_UP_WO_YAXIS_GAP_MIN   AS YD_UP_WO_YAXIS_GAP_MIN    --야드권상지시Y축오차최소

             , ROUND(CASE WHEN A.YD_UP_WO_LYR = '02' 
                          THEN SF_YM_WO_LOC_ZAXIS_AUTO_SCR(SUBSTR(YD_UP_WO_LOC,1,6),SUBSTR(YD_UP_WO_LOC,7,2), A.COIL_OUTDIA)
                          ELSE NVL((SELECT YD_STK_LYR_Z_AXIS 
                                      FROM TB_YF_STKLYR SL
                                     WHERE SL.YD_STK_COL_GP   = SUBSTR(A.YD_UP_WO_LOC,1,6) 
                                       AND SL.YD_STK_BED_NO   = SUBSTR(A.YD_UP_WO_LOC,7,2) 
                                       AND SL.YD_STK_LYR_NO = A.YD_UP_WO_LYR
                                       AND ROWNUM<=1 ),0) + ( A.COIL_OUTDIA / 2 )   
                           END )          AS YD_UP_WO_LOC_ZAXIS        --야드권상지시Z축
         
             , A.YD_UP_WO_ZAXIS_GAP_MAX   AS YD_UP_WO_ZAXIS_GAP_MAX    --야드권상지시Z축오차최대
             , A.YD_UP_WO_ZAXIS_GAP_MIN   AS YD_UP_WO_ZAXIS_GAP_MIN    --야드권상지시Z축오차최소

             , (CASE WHEN A.YD_L2_REQUEST_STAT = '5' THEN A.YD_DN_WO_LOC_TO 
                     ELSE NVL(A.YD_DN_WR_LOC, A.YD_DN_WO_LOC) END
               )                          AS YD_DN_WO_LOC              --야드권하지시위치
             , (CASE WHEN A.YD_L2_REQUEST_STAT = '5' THEN A.STK_LYR_NO_TEMP 
                     ELSE NVL(A.YD_DN_WR_LYR, A.YD_DN_WO_LYR) END
               )                          AS YD_DN_WO_LYR            --야드권하지시단
               
             , CASE WHEN A.YD_L2_REQUEST_STAT='5' THEN (SELECT B.YD_STK_LYR_X_AXIS FROM TB_YF_STKLYR B
                                                         WHERE SUBSTR(A.YD_DN_WO_LOC_TO,1,6) = B.YD_STK_COL_GP  
                                                           AND SUBSTR(A.YD_DN_WO_LOC_TO,7,2) = B.YD_STK_BED_NO   
                                                           AND A.STK_LYR_NO_TEMP = B.YD_STK_LYR_NO 
                                                       ) 
                    ELSE NVL(A.YD_DN_WR_XAXIS, (SELECT YD_STK_LYR_X_AXIS FROM TB_YF_STKLYR
                                                 WHERE YD_STK_COL_GP   = SUBSTR(A.YD_DN_WO_LOC,1,6)
                                                   AND YD_STK_BED_NO   = SUBSTR(A.YD_DN_WO_LOC,7,2)
                                                   AND YD_STK_LYR_NO = YD_DN_WO_LYR
                                                )
                            ) 
                END AS YD_DN_WO_LOC_XAXIS        --야드권하지시X축
                                          
                                          
             , DECODE(A.YD_DN_WO_XAXIS_GAP_MAX, '9999', '99999', A.YD_DN_WO_XAXIS_GAP_MAX) AS YD_DN_WO_XAXIS_GAP_MAX    --야드권하지시X축오차최대
             , DECODE(A.YD_DN_WO_XAXIS_GAP_MIN, '9999', '99999', A.YD_DN_WO_XAXIS_GAP_MIN) AS YD_DN_WO_XAXIS_GAP_MIN    --야드권하지시X축오차최소
         
             , CASE WHEN A.YD_L2_REQUEST_STAT='5' THEN (SELECT B.YD_STK_LYR_Y_AXIS FROM TB_YF_STKLYR B
                                                         WHERE SUBSTR(A.YD_DN_WO_LOC_TO,1,6) = B.YD_STK_COL_GP  
                                                           AND SUBSTR(A.YD_DN_WO_LOC_TO,7,2) = B.YD_STK_BED_NO   
                                                           AND A.STK_LYR_NO_TEMP = B.YD_STK_LYR_NO 
                                                        ) 
                    ELSE NVL(A.YD_DN_WR_YAXIS, (SELECT YD_STK_LYR_Y_AXIS FROM TB_YF_STKLYR
                                                 WHERE YD_STK_COL_GP   = SUBSTR(A.YD_DN_WO_LOC,1,6)
                                                   AND YD_STK_BED_NO   = SUBSTR(A.YD_DN_WO_LOC,7,2)
                                                   AND YD_STK_LYR_NO = YD_DN_WO_LYR
                                                )
                            ) 
                END AS YD_DN_WO_LOC_YAXIS        --야드권하지시Y축   
             
             , DECODE(A.YD_DN_WO_YAXIS_GAP_MAX, '9999', '99999', A.YD_DN_WO_YAXIS_GAP_MAX) AS YD_DN_WO_YAXIS_GAP_MAX    --야드권하지시Y축오차최대
             , DECODE(A.YD_DN_WO_YAXIS_GAP_MIN, '9999', '99999', A.YD_DN_WO_YAXIS_GAP_MIN) AS YD_DN_WO_YAXIS_GAP_MIN    --야드권하지시Y축오차최소
             
             , ROUND(CASE WHEN A.YD_L2_REQUEST_STAT = '5' AND A.STK_LYR_NO_TEMP = '02' 
                               THEN SF_YM_WO_LOC_ZAXIS_AUTO_SCR(SUBSTR(A.YD_DN_WO_LOC_TO,1,6),SUBSTR(A.YD_DN_WO_LOC_TO,7,2), A.COIL_OUTDIA)
                          WHEN A.YD_L2_REQUEST_STAT = '5' AND A.STK_LYR_NO_TEMP = '01' 
                               THEN NVL((SELECT YD_STK_LYR_Z_AXIS 
                                      FROM TB_YF_STKLYR SL
                                     WHERE SL.YD_STK_COL_GP   = SUBSTR(A.YD_DN_WO_LOC_TO,1,6) 
                                       AND SL.YD_STK_BED_NO   = SUBSTR(A.YD_DN_WO_LOC_TO,7,2) 
                                       AND SL.YD_STK_LYR_NO = A.STK_LYR_NO_TEMP
                                       AND ROWNUM<=1 ),0) + ( A.COIL_OUTDIA / 2 )
                          WHEN A.YD_DN_WO_LYR = '02' 
                          THEN SF_YM_WO_LOC_ZAXIS_AUTO_SCR(SUBSTR(A.YD_DN_WO_LOC,1,6),SUBSTR(A.YD_DN_WO_LOC,7,2), A.COIL_OUTDIA)
                          ELSE NVL(A.YD_DN_WR_ZAXIS, NVL((SELECT YD_STK_LYR_Z_AXIS 
                                                          FROM TB_YF_STKLYR SL
                                                         WHERE SL.YD_STK_COL_GP   = SUBSTR(A.YD_DN_WO_LOC,1,6) 
                                                           AND SL.YD_STK_BED_NO   = SUBSTR(A.YD_DN_WO_LOC,7,2) 
                                                           AND SL.YD_STK_LYR_NO = A.YD_DN_WO_LYR
                                                           AND ROWNUM<=1 ),0) + ( A.COIL_OUTDIA / 2 ))           
                          END )           AS YD_DN_WO_LOC_ZAXIS        --야드권하지시Z축                           
                          
             , DECODE(A.YD_DN_WO_ZAXIS_GAP_MAX, '9999', '99999', A.YD_DN_WO_ZAXIS_GAP_MAX) AS YD_DN_WO_ZAXIS_GAP_MAX    --야드권하지시Z축오차최대
             , DECODE(A.YD_DN_WO_ZAXIS_GAP_MIN, '9999', '99999', A.YD_DN_WO_ZAXIS_GAP_MIN) AS YD_DN_WO_ZAXIS_GAP_MIN    --야드권하지시Z축오차최소
             , 'Y' AS GRUSH_COIL_YN             --짱구코일 여부
                      

             ,  CASE WHEN A.NEXT_PROC like '%H' THEN 'H'
                     WHEN A.NEXT_PROC like '%K' THEN 'S'  
                     ELSE '' END        AS SPM_HFL_YN                --SPM/HFL  유무
             
             , ''                         AS CUT_YN                    --절단재 여부
             , CASE WHEN SUBSTR(A.YD_SCH_CD, 3, 2) = 'TC' AND YD_AID_WRK_YN = 'N' THEN A.TCAR_GP
                    WHEN SUBSTR(A.YD_SCH_CD, 3, 2) = 'PT' AND YD_AID_WRK_YN = 'N' AND SUBSTR(A.YD_SCH_CD, 7, 2) = 'UM' THEN SUBSTR(YD_DN_WO_LOC, 1, 6)
                    WHEN SUBSTR(A.YD_SCH_CD, 3, 2) = 'PT' AND YD_AID_WRK_YN = 'N' AND SUBSTR(A.YD_SCH_CD, 7, 2) = 'LM' THEN SUBSTR(YD_UP_WO_LOC, 1, 6)
                    ELSE '' END AS YD_EQP_ID2                --야드설비ID2
                     
             , ''            AS YD_TC_AIM_BAY_GP          --야드대차목적동
             , ''            AS YD_CAR_USE_GP             --야드차량사용구분
             , ''            AS CAR_NO                    --차량번호
             , ''            AS TRN_EQP_CD                --운송장비코드(카드번호)
             , A.YD_EQP_WRK_SH            AS YD_EQP_WRK_SH             --야드설비작업매수
             , '00'                       AS YD_EQP_RMN_SH             --야드설비잔량매수
             , A.STL_NO                 AS STL_NO1                 --재료번호1
             , A.YD_MTL_WT                AS YD_STL_WT1                --야드재료중량1
             , A.YD_MTL_T                 AS YD_STL_T1                 --야드재료두께1
             , A.YD_MTL_W                 AS YD_STL_W1                 --야드재료폭1
             , A.YD_MTL_L                 AS YD_STL_L1                 --야드재료길이1
             , ''                         AS STL_NO2                 --재료번호2
             , ''                         AS YD_STL_WT2                --야드재료중량2
             , ''                         AS YD_STL_T2                 --야드재료두께2
             , ''                         AS YD_STL_W2                 --야드재료폭2
             , ''                         AS YD_STL_L2                 --야드재료길이2
             , A.COIL_OUTDIA              AS COIL_OUTDIA               --Coil외경
             , 7620                       AS COIL_INDIA                --Coil내경
             
             , NVL(A.YD_SCH_CD_NEXT, B.YD_SCH_CD) AS YD_SCH_CD_NEXT            --야드스케쥴코드_Next
             , NVL(SUBSTRB((SELECT CD_CONTENTS 
                          FROM TB_YF_SCHRULE WHERE YD_SCH_CD = A.YD_SCH_CD_NEXT)
                      || DECODE(A.YD_SCH_CD_NEXT,NULL,'', (CASE WHEN A.YD_AID_WRK_YN_NEXT='N' THEN '[주]' 
                                                                ELSE '[보조]' END)),1,30)
                 , SUBSTRB((SELECT CD_CONTENTS 
                              FROM TB_YF_SCHRULE WHERE YD_SCH_CD = B.YD_SCH_CD)
                      ,1,30)
                  )
                                          AS YD_SCH_NAME_NEXT          --야드스케줄명_NEXT 
             , NVL(A.YD_UP_WO_LOC_NEXT  , B.YD_STK_COL_GP   )   AS YD_UP_WO_LOC_NEXT         --야드권상지시위치_Next
             , NVL(A.YD_UP_WO_LYR_NEXT  , B.YD_STK_LYR_NO )   AS YD_UP_WO_LYR_NEXT       --야드권상지시단_Next
             , NVL(A.YD_DN_WO_LOC_NEXT    , B.YD_TO_LOC_GUIDE)   AS YD_DN_WO_LOC_NEXT         --야드권하지시위치_Next
             , A.YD_DN_WO_LYR_NEXT          AS YD_DN_WO_LYR_NEXT       --야드권하지시단_Next
             , NVL(A.STL_NO_NEXT        , B.STL_NO       )   AS STL_NO_NEXT             --재료번호_Next
             , NVL(A.YD_CRN_WRK_WT_NEXT   , B.COIL_WT        )   AS YD_CRN_WRK_WT_NEXT        --야드크레인작업중량_Next
             , NVL(A.YD_CRN_WRK_T_NEXT    , B.COIL_T         )   AS YD_CRN_WRK_T_NEXT         --야드크레인작업총두께_Next
             , NVL(A.YD_CRN_WRK_MAX_W_NEXT, B.COIL_W         )   AS YD_CRN_WRK_MAX_W_NEXT     --야드크레인작업최대폭_Next
             , NVL(A.COIL_OUTDIA_NEXT     , B.COIL_OUTDIA    )   AS COIL_OUTDIA_NEXT          --야드크레인작업코일외경_Next
             , 7620                       AS COIL_INDIA_NEXT           --야드크레인작업코일내경_Next
             , A.UP_ROTATION_ANGLE        AS UP_ROTATION_ANGLE         --권상위치 회전각도
             , A.DOWN_ROTATION_ANGLE      AS DOWN_ROTATION_ANGLE       --권하위치 회전각도
        --------------------------------------------------------------------------
             , A.RN                       AS RN
             , A.YD_L2_REQUEST_STAT       AS YD_L2_REQUEST_STAT
         FROM (
                SELECT A.* 
                     , C.WRSLT_REAL_WT  AS YD_MTL_WT --//반품/회송 인 경우 입력한 중량기준
                     , C.WRSLT_REAL_WT  AS NET_WEIGH_WT       
                     , (SELECT MILL_T FROM VW_YF_COILCOMM WHERE COIL_NO = C.COIL_NO) AS YD_MTL_T
                     , (SELECT MILL_W FROM VW_YF_COILCOMM WHERE COIL_NO = C.COIL_NO) AS YD_MTL_W
                     , C.WRSLT_LEN      AS YD_MTL_L       
                     , C.WRSLT_INDIA    AS COIL_INDIA     
                     , C.WRSLT_OUTDIA   AS COIL_OUTDIA 
                     , B.STL_NO 
                     , B.YD_STK_LYR_NO
                     , LEAD(A.YD_SCH_CD)        OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_SCH_CD_NEXT
                     , LEAD(A.YD_UP_WO_LOC)     OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_UP_WO_LOC_NEXT
                     , LEAD(A.YD_UP_WO_LYR)   OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_UP_WO_LYR_NEXT
                     , LEAD(A.YD_DN_WO_LOC)     OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_DN_WO_LOC_NEXT
                     , LEAD(A.YD_DN_WO_LYR)   OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_DN_WO_LYR_NEXT
                     , LEAD(B.STL_NO)         OVER (ORDER BY A.YD_CRN_SCH_ID)  AS STL_NO_NEXT
                     , LEAD(A.YD_EQP_WRK_WT)    OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_CRN_WRK_WT_NEXT
                     , LEAD(A.YD_EQP_WRK_T)     OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_CRN_WRK_T_NEXT
                     , LEAD(A.YD_EQP_WRK_MAX_W) OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_CRN_WRK_MAX_W_NEXT
                     , 0    AS  COIL_OUTDIA_NEXT
                     , 0    AS  COIL_INDIA_NEXT
                     , LEAD(B.YD_AID_WRK_YN)    OVER (ORDER BY A.YD_CRN_SCH_ID)  AS YD_AID_WRK_YN_NEXT
                     , ROW_NUMBER() OVER(PARTITION BY A.YD_WBOOK_ID, A.YD_CRN_SCH_ID ORDER BY A.YD_CRN_SCH_ID ASC, B.YD_STK_LYR_NO DESC) AS RN
                     , B.YD_AID_WRK_YN
                     --짱구CHECK용
                     , '' AS HRMILL_CMPL_DT
                     , '' AS NEXT_PROC
                     , '' AS HR_SPEC_ABBSYM
                     , '' AS CURR_PROG_CD
                     , '' AS TCAR_GP
                     , '1' AS AA
                  FROM TB_YF_CRNSCH A
                     , TB_YF_CRNWRKMTL B
                     , USRPOA.TB_PO_COILSHEARORD_SCRAP C
                 WHERE A.YD_CRN_SCH_ID = B.YD_CRN_SCH_ID
                   AND A.YD_EQP_ID  = (SELECT YD_EQP_ID FROM TB_YF_CRNSCH WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID )
                   AND B.STL_NO   = C.SCRAP_COIL_NO
                   AND C.STEP_NO    = :V_STEP_NO
                   AND A.DEL_YN = 'N'
              ) A
            , (
                SELECT STL_NO, ST.YD_STK_COL_GP||ST.YD_STK_BED_NO AS YD_STK_COL_GP
                     , ST.YD_STK_LYR_NO, YD_SCH_CD, YD_TO_LOC_GUIDE
                     , COIL_WT, COIL_T, COIL_W, COIL_OUTDIA, COIL_INDIA
                     , CD_CONTENTS
                     , '1' AS AA
                  FROM (
                        SELECT *
                          FROM (
                                SELECT CASE WHEN BB.WRK_YD_EQP_PROG_STAT <> 'B' AND BB.WRK_YD_EQP_WRK_MODE = '1' THEN AA.YD_WRK_CRN
                                            WHEN CC.ALT_YD_EQP_WRK_MODE  <> 'B' AND CC.ALT_YD_EQP_WRK_MODE = '1' THEN AA.YD_ALT_CRN
                                            ELSE 'XXXXXX' END AS WRK_CRANE
                                      , AA.*
                                  FROM (
                                        SELECT A1.*, A2.YD_STK_COL_GP, A2.YD_STK_BED_NO, A2.YD_STK_LYR_NO, A2.STL_NO
                                             , NVL(A1.YD_WRK_PLAN_CRN, B1.YD_WRK_CRN) AS YD_WRK_CRN
                                             , B1.YD_ALT_CRN
                                             , B1.YD_WRK_CRN_PRIOR
                                             , B1.CD_CONTENTS
                                          FROM TB_YF_WRKBOOK      A1
                                             , TB_YF_WRKBOOKMTL   A2
                                             , TB_YF_SCHRULE B1
                                         WHERE A1.YD_WBOOK_ID = A2.YD_WBOOK_ID
                                           AND A1.DEL_YN = 'N'  
                                           AND A2.DEL_YN = 'N'  
                                           AND A1.YD_GP = '1'
                                           AND A1.YD_SCH_CD = B1.YD_SCH_CD
                                           AND A1.YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID FROM TB_YF_CRNSCH WHERE DEL_YN = 'N')
                                           AND B1.YD_SCH_AUTO_ST_YN = 'Y'
                                       ) AA
                                     , (SELECT YD_EQP_ID, YD_EQP_PROG_STAT AS WRK_YD_EQP_PROG_STAT,YD_EQP_WRK_MODE AS WRK_YD_EQP_WRK_MODE FROM TB_YF_EQP) BB
                                     , (SELECT YD_EQP_ID, YD_EQP_PROG_STAT AS ALT_YD_EQP_PROG_STAT,YD_EQP_WRK_MODE AS ALT_YD_EQP_WRK_MODE FROM TB_YF_EQP) CC
                                 WHERE AA.YD_WRK_CRN = BB.YD_EQP_ID
                                   AND AA.YD_ALT_CRN = CC.YD_EQP_ID  
                              )
                         WHERE WRK_CRANE = (SELECT YD_EQP_ID FROM TB_YF_CRNSCH WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID)
                         ORDER BY YD_WRK_CRN_PRIOR, YD_WBOOK_ID
                       ) ST
                     , VW_YF_COILCOMM CC
                 WHERE ROWNUM = 1                    
                   AND ST.STL_NO = CC.COIL_NO            
              ) B
        WHERE A.YD_CRN_SCH_ID     = :V_YD_CRN_SCH_ID 
          AND A.AA = B.AA(+)
    ) K          
) SN
 </pre> */
public final static String TcYFF1L004Scrap = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYFF1L004Scrap";

 /** <pre> 2020-03-25
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK2
WITH TEMP_TABLE AS
(
    SELECT
        :V_YD_CARPNT_CD AS V_YD_CARPNT_CD,
        :V_CAR_KIND     AS V_CAR_KIND,
        (
            SELECT
                ITEM1
            FROM
                USRYFA.TB_YF_RULE
            WHERE 1=1
            AND REPR_CD_GP = 'J00002'
            AND CD_GP = '*'
            AND ITEM  = '*'
        ) AS PRE_SUP_YN
    FROM
        DUAL
)
--//TR--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C'   --사용가능
AND B.V_CAR_KIND            = 'TR'
AND A.YD_CAR_USETYPE_GP     IN ('TR', 'RT', 'RA', 'TO')         --트레일러
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//TT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C'   --사용가능
AND B.V_CAR_KIND            = 'TT'
AND A.YD_CAR_USETYPE_GP     IN ('TT', 'AT', 'RT', 'TO')         --TT_CAR
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//PT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C'   --사용가능
AND B.V_CAR_KIND            = 'PT'
AND A.YD_CAR_USETYPE_GP     IN ('PT', 'GT', 'AT', 'RA', 'TO')   --PT
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))
 </pre> */
public final static String getYdCarPointCHK2 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK2";

