 /** <pre> 2021-02-24
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getACoilEqpIdWrkItmInqjl
-- 야드설비별 작업내역 조회 
WITH PARAM AS (
SELECT :V_YD_GP            AS P_YD_GP
     , NVL(:V_DT_CHK, 'N') AS P_DT_CHK
     , :V_DATE_FROM        AS P_DATE_FROM 
     , :V_DATE_TO          AS P_DATE_TO
     , :V_YD_WRK_PARTY     AS P_YD_WRK_PARTY
     , :V_YD_WRK_DUTY      AS P_YD_WRK_DUTY
     , :V_YD_EQP_ID        AS P_YD_EQP_ID
     , :V_YD_GNT_GP        AS P_YD_GNT_GP
     , :V_YD_AID_WRK_YN    AS P_YD_AID_WRK_YN
     , :V_YD_BAY_GP        AS P_YD_BAY_GP
     , NVL(:V_SORT,'X')    AS P_SORT
  FROM DUAL      
),
ARR_STL_NO AS (
SELECT 
    STL_NO
FROM(
 SELECT  
    SUBSTR (AA, INSTR (AA, ',', 1, LEVEL) + 1, INSTR (AA, ',', 1, LEVEL + 1) - INSTR (AA, ',', 1, LEVEL) - 1) AS STL_NO
FROM (SELECT ',' || :V_STL_NO || ',' AA FROM DUAL)
CONNECT BY LEVEL <= LENGTH (AA) - LENGTH (REPLACE (AA, ',')) - 1
) 
WHERE STL_NO IS NOT NULL
)
SELECT *
  FROM (
        SELECT ROWNUM AS RNUM
             , TOTAL
             , TOTAL_WGT
             , DATA_TY
             , STL_NO
             , YD_EQP_NAME
             , YD_WRK_CRN
             , YD_SCH_CD
             , COIL_H_SIZE
             , COIL_OUTDIA
             , COIL_ALLOC_WT
             , STL_PROG_CD
             , YD_UP_WR_LOC
             , YD_DN_WR_LOC
             , YD_UP_CMPL_DT
             , YD_DN_CMPL_DT
             , NEXT_PROC
             , (CASE YD_AID_WRK_YN WHEN 'Y' THEN '보조작업' WHEN 'N' THEN '주작업' ELSE '' END) AS YD_AID_WRK_YN
             , YD_UP_WRK_MODE2
             , YD_DN_WRK_MODE2
             , YD_WBOOK_ID
             , YD_CRN_SCH_ID
             , UP_WO_YN
             , DN_WO_YN
             , YD_TCAR_SCH_ID
             , YD_CAR_SCH_ID  
             , CAR_CARD_NO
             , (SELECT YD_EQP_NAME 
                  FROM TB_YF_EQP    EQ 
                  WHERE EQ.YD_EQP_ID   = XX.TCAR_EQP_ID
               ) AS TCAR_NM
             , WRK_TIME
             , CD_CONTENTS||DECODE(YD_AID_WRK_YN, 'Y', '[보조]', '[주]')||(CASE --WHEN YD_SCH_REQ_GP IN ('A','B','C') THEN '['||YD_SCH_REQ_GP||']'
                                                                                WHEN WB_REGISTER IN('AUTO_MV_A','AUTO_MV_B','AUTO_MV_C') THEN SUBSTR(WB_REGISTER, 9, 1)
                                                                                WHEN WB_MODIFIER IN('AUTO_MV_A','AUTO_MV_B','AUTO_MV_C') THEN SUBSTR(WB_MODIFIER, 9, 1)
                                                                                ELSE '' 
                                                                            END
               ) AS CD_CONTENTS
             , SORT_1
             , SORT_2
             ,(CASE WHEN COIL_GP = 'HR' THEN '열연'
                       WHEN COIL_GP ='CR' AND STL_APPEAR_GP ='E' THEN '냉연(재공품)'
                       WHEN COIL_GP ='CR' AND STL_APPEAR_GP ='Y' THEN '냉연(제품)'
                       END) AS COIL_GP
        FROM (
                SELECT COUNT(*) OVER() AS TOTAL
                     , WR.DATA_TY
                     , ROUND(SUM (WR.YD_MTL_WT) OVER()/1000, 0)  AS TOTAL_WGT
                     , WR.STL_NO
                     , CASE WHEN WR.YD_SCH_CD = '1X9999' THEN '산적위치수정' ELSE E.YD_EQP_NAME END AS YD_EQP_NAME
                     , CASE WHEN WR.YD_SCH_CD = '1X9999' THEN '산적위치수정' ELSE WR.YD_EQP_ID END AS YD_WRK_CRN
                     , WR.YD_SCH_CD
                     , WR.CD_CONTENTS
                     , NVL(WR.YD_SCH_REQ_GP, A.YD_SCH_REQ_GP) AS YD_SCH_REQ_GP
                     , WR.WB_REGISTER
                     , WR.WB_MODIFIER
                     , TO_CHAR(WR.YD_MTL_T,'99.99') || ' X ' || TO_CHAR(WR.YD_MTL_W,'9,999') AS COIL_H_SIZE
                     , WR.COIL_OUTDIA
                     , WR.YD_MTL_WT AS COIL_ALLOC_WT
                     , WR.STL_PROG_CD
                     , NVL(WR.YD_UP_WR_LOC, WR.YD_UP_WO_LOC) AS YD_UP_WR_LOC --권상위치
                     , TO_CHAR(WR.YD_UP_CMPL_DT, 'YYYY/MM/DD HH24:MI:SS')  AS YD_UP_CMPL_DT --권상완료일시
                     , NVL(WR.YD_DN_WR_LOC, WR.YD_DN_WO_LOC) AS YD_DN_WR_LOC  --권하위치
                     , TO_CHAR(WR.YD_DN_CMPL_DT, 'YYYY/MM/DD HH24:MI:SS') AS YD_DN_CMPL_DT --권하완료일시
                     , WR.NEXT_PROC       -- 2019.09.09 작업이력테이블에 다음공정 컬럼 없음
                     , WR.YD_AID_WRK_YN
                     , CASE WHEN WR.YD_SCH_CD = '1X9999' THEN '' ELSE  WR.YD_UP_WRK_MODE2 END AS YD_UP_WRK_MODE2
                     , CASE WHEN WR.YD_SCH_CD = '1X9999' THEN '' ELSE  WR.YD_DN_WRK_MODE2 END AS YD_DN_WRK_MODE2
                     , WR.YD_WBOOK_ID
                     , WR.YD_CRN_SCH_ID
                     , CASE WHEN WR.YD_UP_WO_LOC = WR.YD_UP_WR_LOC THEN 'Y'
                            ELSE 'N' END 
                       AS UP_WO_YN  --권상지시위치와 작업결과위치 비교 같으면 Y 아니면 N
                     , CASE WHEN WR.YD_DN_WO_LOC = WR.YD_DN_WR_LOC THEN 'Y'
                            ELSE 'N' END 
                       AS DN_WO_YN  --권하지시위치와 작업결과위치 비교 같으면 Y 아니면 N
                     , A.YD_CRN_GRAB_USE_RULE_ID --차량스케줄 혹은 대차스케줄
--                     , CASE WHEN SUBSTR(WR.YD_SCH_CD, 3, 2)  IN ('TC', 'DC') THEN  
                                       ,CASE 
                                        WHEN SUBSTR(WR.YD_DN_WR_LOC,3,2) IN ('SR', 'SL') THEN WR.YD_CTS_SCH_ID
                                        WHEN SUBSTR(WR.YD_DN_WR_LOC,3,2) IN ('TC') THEN A.YD_CRN_GRAB_USE_RULE_ID
                                       ELSE '' END AS YD_TCAR_SCH_ID  
--                       END YD_TCAR_SCH_ID  
--                     , CASE WHEN SUBSTR(WR.YD_SCH_CD, 3, 2)  IN ('TC', 'DC') THEN 
                                       ,CASE 
                                            WHEN SUBSTR(WR.YD_DN_WR_LOC,3,2) IN ('SR', 'SL') THEN WR.YD_CTS_EQP_ID
                                            WHEN SUBSTR(WR.YD_DN_WR_LOC,3,2) IN ('TC') THEN '1XTC03'
                                       ELSE '' END AS TCAR_EQP_ID  
--                       END TCAR_EQP_ID  
--                     , DECODE(SUBSTR(WR.YD_SCH_CD, 3, 2), 'TC', A.YD_CRN_GRAB_USE_RULE_ID, NULL) AS YD_TCAR_SCH_ID
                     , WR.YD_CAR_SCH_ID
                     , CASE WHEN WR.CAR_NO IN ('9990','9991','9992','9993','9994') THEN CARD_NO  
                            WHEN WR.CAR_NO IS NOT NULL THEN WR.CAR_NO || '[' || WR.CARD_NO || ']'  
                       ELSE WR.TRN_EQP_CD END AS CAR_CARD_NO                  
                     , TRUNC((WR.YD_DN_CMPL_DT - A.YD_WORD_DT)*60*60*24)  AS WRK_TIME
                     , DENSE_RANK() OVER( PARTITION BY TO_CHAR(WR.YD_DN_CMPL_DT,'YYYYMMDD') ORDER BY WR.STL_NO DESC) AS SORT_1 
                     , ROW_NUMBER() OVER( PARTITION BY TO_CHAR(WR.YD_DN_CMPL_DT,'YYYYMMDD'), WR.STL_NO ORDER BY  A.YD_WORD_DT, WR.YD_DN_CMPL_DT ASC) AS SORT_2
                     ,WR.COIL_GP
                     ,WR.STL_APPEAR_GP
                  FROM ( 
                     SELECT    --+ NO_MERGE  'A' AS DATA_TY
                               , WR.YD_MTL_WT
                               ,WR.STL_NO
                               ,WR.YD_EQP_ID
                               ,WR.YD_SCH_CD
                               ,WR.YD_WBOOK_ID
                               ,WR.YD_MTL_T
                               ,WR.YD_MTL_W
                               ,WR.COIL_OUTDIA 
                               ,WR.STL_PROG_CD 
                               ,WR.YD_UP_CMPL_DT
                               ,WR.YD_DN_CMPL_DT
                               ,WR.YD_AID_WRK_YN
                               ,WR.YD_UP_WRK_MODE2
                               ,WR.YD_DN_WRK_MODE2 
                               ,WR.YD_CRN_SCH_ID
                               ,WR.YD_UP_WO_LOC || WR.YD_UP_WO_LYR AS YD_UP_WO_LOC
                               ,WR.YD_UP_WR_LOC || WR.YD_UP_WR_LYR AS YD_UP_WR_LOC
                               ,WR.YD_DN_WO_LOC || WR.YD_DN_WO_LYR AS YD_DN_WO_LOC
                               ,WR.YD_DN_WR_LOC || WR.YD_DN_WR_LYR AS YD_DN_WR_LOC
                               ,WR.YD_WRK_DUTY
                               ,WR.YD_WRK_PARTY
                               ,'' AS YD_CTS_SCH_ID
                               ,'' AS YD_CTS_EQP_ID
                               , C.CD_CONTENTS 
                               , C.YD_WRK_CRN
                               ,WR.TRANS_ORD_DATE
                               ,WR.SHIPASSIGN_WORD_DATE
                               ,WR.SHIPASSIGN_WORD_SEQNO
                               ,NVL(WR.CAR_NO, CAR.CAR_NO) AS CAR_NO
                               ,NVL(WR.CARD_NO, CAR.CARD_NO) AS CARD_NO
                               ,NVL(WR.TRN_EQP_CD, CAR.TRN_EQP_CD) AS TRN_EQP_CD
                               ,WR.CAR_KIND
                               ,CO.NEXT_PROC
                               ,WR.YD_CAR_SCH_ID
                               ,WR.YD_SCH_REQ_GP
                               ,WB.REGISTER  AS WB_REGISTER
                               ,WB.MODIFIER  AS WB_MODIFIER
                               ,CO.COIL_GP
                               ,CO.STL_APPEAR_GP
                          FROM TB_YF_WRKHIST WR
                                , TB_YF_SCHRULE C
                                , VW_YF_COILCOMM CO
                                , TB_YF_WRKBOOK WB
                                , TB_YD_CARSCH CAR
                                , PARAM
                         WHERE ( (P_DT_CHK = 'Y' AND WR.YD_WRK_HDS_DD  BETWEEN P_DATE_FROM AND P_DATE_TO)    --야드작업계상일자
                                OR (P_DT_CHK = 'N' AND WR.YD_WRK_HIST_ID BETWEEN P_DATE_FROM||'0000000000' AND P_DATE_TO||'9999999999')  )
                           AND WR.YD_GP = '1'    
                           AND WR.DEL_YN = 'N' 
                           AND WR.YD_SCH_CD = C.YD_SCH_CD(+)
                           AND WR.STL_NO = CO.COIL_NO
                           AND WR.YD_WBOOK_ID = WB.YD_WBOOK_ID(+)
                           AND WR.YD_CAR_SCH_ID = CAR.YD_CAR_SCH_ID(+)
                           AND ( 
                                    WR.STL_NO IN ( SELECT STL_NO FROM ARR_STL_NO )
                                OR
                                    NOT EXISTS (SELECT STL_NO FROM ARR_STL_NO)
                            )
                           AND NVL(WR.YD_WRK_PARTY,' ') LIKE P_YD_WRK_PARTY ||'%' --작업조
                           AND NVL(WR.YD_WRK_DUTY ,' ') LIKE P_YD_WRK_DUTY  ||'%' --작업근
                           AND NVL(WR.YD_EQP_ID ,' ') LIKE P_YD_EQP_ID ||'%'  --크레인
                           AND (  (P_YD_GNT_GP = 'YD_IN' AND (WR.YD_SCH_CD LIKE '1_DC__LM' )) --수입
                              OR(P_YD_GNT_GP = 'EQP_IN' AND (WR.YD_SCH_CD LIKE '1_FE__UM' OR WR.YD_SCH_CD LIKE '1_KE__UM' OR WR.YD_SCH_CD LIKE '1_QE__UM')) --보급
                              OR(P_YD_GNT_GP = 'EQP_OUT' AND (WR.YD_SCH_CD LIKE '1_FD__LM' OR WR.YD_SCH_CD LIKE '1_KD__LM' OR WR.YD_SCH_CD LIKE '1_QD__LM' )) --추출
                              
                              OR(P_YD_GNT_GP = 'YD_TRNAS' AND (
                                                                   WR.YD_SCH_CD LIKE '1_YD__MM' 
                                                                OR WR.YD_SCH_CD LIKE '1_PT31%' -- 차량동간
                                                                OR WR.YD_SCH_CD LIKE '1_PT32%' -- 차량동간
                                                                OR WR.YD_SCH_CD LIKE '1_TC%'    -- 대차
                                                                OR WR.YD_SCH_CD LIKE '1_DC41MM' -- 난방코일
                                                               )
                                ) --이적 
                                                                    
                              OR(P_YD_GNT_GP = 'SAME_DONG' AND (WR.YD_SCH_CD LIKE '1_YD__MM')) --동내이적
                              OR(P_YD_GNT_GP = 'DIFF_DONG' AND (
                                                                   WR.YD_SCH_CD LIKE '1_PT31%' -- 차량동간
                                                                OR WR.YD_SCH_CD LIKE '1_PT32%' -- 차량동간
                                                                OR WR.YD_SCH_CD LIKE '1_TC%'   -- 대차
                                                                OR WR.YD_SCH_CD LIKE '1_DC41MM' -- 난방코일
                                                                )
                              ) --동간이적
                              
                              OR(P_YD_GNT_GP = 'TRANS' AND (
                                                                   WR.YD_SCH_CD LIKE '1_PT1_LM' 
                                                                OR WR.YD_SCH_CD LIKE '1_PT1_UM'
                                                           )
                              ) --구내운송
                              
                              OR(P_YD_GNT_GP = 'CAR_OUT' AND (WR.YD_SCH_CD LIKE '1_PT0_UM')) --출하
                              OR(P_YD_GNT_GP = 'CAR_MV_OUT' AND (WR.YD_SCH_CD LIKE '1_PT21UM' OR WR.YD_SCH_CD LIKE '1_PT22UM' OR WR.YD_SCH_CD LIKE '1_PT22LM' OR WR.YD_SCH_CD LIKE '1_PT21LM')) -- 제품이송
                              OR(P_YD_GNT_GP = 'CAR_IN' AND (WR.YD_SCH_CD LIKE '1_PT01LM' OR WR.YD_SCH_CD LIKE '1_PT02LM')) --반품
                              OR(P_YD_GNT_GP = 'ALL' AND (WR.YD_SCH_CD IS NOT NULL))
                              )
                           AND NVL(WR.YD_AID_WRK_YN , ' ') LIKE P_YD_AID_WRK_YN || '%' --보조작업
        --                   AND C.DEL_YN = 'N'
                           AND SUBSTR(NVL(WR.YD_DN_WR_LOC ,' '), 1, 2) LIKE '1'||P_YD_BAY_GP||'%'
                         ) WR 
                     , TB_YF_CRNSCH A  
                     , TB_YF_EQP E 
                     , PARAM
                 WHERE WR.YD_CRN_SCH_ID = A.YD_CRN_SCH_ID(+) 
                   AND WR.YD_EQP_ID    = E.YD_EQP_ID(+)
                 ORDER BY
                      CASE P_SORT WHEN 'STL' THEN TO_DATE(TO_CHAR(WR.YD_DN_CMPL_DT,'YYYYMMDD')) ELSE WR.YD_DN_CMPL_DT END DESC
                    , CASE P_SORT WHEN 'STL' THEN SORT_1 || SORT_2 END DESC 
             ) XX
        WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE 
     ) TT
 WHERE RNUM >= (( :V_PAGE_NO -1)* :V_PAGE_SIZE ) + 1
 </pre> */
public final static String getACoilEqpIdWrkItmInqjl = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getACoilEqpIdWrkItmInqjl";

