 /** <pre> 2019-12-09
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointGD
SELECT
    BB.YD_STK_COL_GP AS YD_STK_COL_GP,
    BB.YD_PNT_CD
FROM
    (
        SELECT
            MIN(A.YD_STK_COL_GP) AS YD_STK_COL_GP,
            A.YD_PNT_CD,
            SUM(A.COUNT) AS COUNT
        FROM
            (
                SELECT
                    YD_STK_COL_GP,
                    YD_PNT_CD,
                    1 AS COUNT
                FROM
                    TB_YF_STKCOL
                WHERE 1=1
                AND SUBSTR(YD_STK_COL_GP, 3, 2) IN ('PT')
                AND WLOC_CD     = :V_WLOC_CD
                AND YD_PNT_CD   LIKE SUBSTR(:V_YD_PNT_CD, 1, 2)||'%'
                AND TRN_EQP_CD  IS NULL --현재차량정지위치
                AND CAR_CARD_NO IS NULL --예약차량정지위치
                AND CARD_NO     IS NULL
            )A
            GROUP BY YD_PNT_CD
    ) AA,
    TB_YD_CARPOINT BB
WHERE 1=1
AND AA.YD_STK_COL_GP = BB.YD_STK_COL_GP
AND BB.YD_CAR_USETYPE_GP IN ('GT','TO')
AND COUNT <= '2'
ORDER BY YD_PNT_CD
 </pre> */
public final static String getListloadStoppointGD = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointGD";

