 /** <pre> 2019-09-19
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getSchScrapInfoWithSchId
SELECT
    STL_NO,
    (
        SELECT
            MAX(STEP_NO)
        FROM
            USRPOA.TB_PO_COILSHEARORD_SCRAP
        WHERE 1=1
        AND SCRAP_COIL_NO = MT.STL_NO
    ) AS STEP_NO
FROM
    TB_YF_CRNSCH     SC,
    TB_YF_CRNWRKMTL  MT
WHERE 1=1
AND SC.YD_CRN_SCH_ID = MT.YD_CRN_SCH_ID
AND SC.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
AND SC.DEL_YN = 'N'
AND MT.DEL_YN = 'N'
 </pre> */
