 /** <pre> 2019-08-27
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListAimBay_CCast2
--YD야드적치열의 YD_STKBED_USG_CD 에 PALLET 조회 화면에서 지정한 목적동 조회
SELECT
    (
        CASE 
        WHEN B.YD_STKBED_USG_CD='D' AND SUBSTR(A.TRN_EQP_CD, 2, 2) ='TR' THEN 'E' 
        ELSE B.YD_STKBED_USG_CD END
    ) AS DEST_BAY,  --목적동
    A.TRN_EQP_CD,
    A.YD_CAR_SCH_ID 
FROM
    TB_YD_CARSCH A,
    TB_YD_STKCOL B
WHERE 1=1
AND A.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
AND A.DEL_YN = 'N'
AND A.YD_CARLD_STOP_LOC = B.YD_STK_COL_GP
AND B.YD_STK_COL_GP LIKE 'A_PT__'
AND B.YD_STKBED_USG_CD IN ('A', 'D', 'E') --A:수출, D:철송, E:주문외
 </pre> */
public final static String getListAimBay_CCast2 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListAimBay_CCast2";

