public final static String getListSchchkYN = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListSchchkYN";

 /** <pre> 2019-08-29
--com.inisteel.cim.ym.bcommon.dao.YmCommDAO.getListSchchkYN 
SELECT 
   *
FROM   TB_YM_CRNSCH
WHERE  YD_WBOOK_ID = :V_YD_WBOOK_ID
AND    DEL_YN = 'N'
 </pre> */
