 /** <pre> 2019-12-12
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListAimBay_CCast
--C연주 SLAB야드에서 이송시 목적동 조회 (첫 번째 ROW 만 사용)
SELECT
    A.RANKING,
    CASE
    WHEN B.MSLAB_HTWRM_SLOWCL_TG_EXN = 'Y' OR CCSLAB_CL_MTD_GP IN ('C', 'D', 'E', 'F') THEN 'A' --//보온뱅크 대상 A동 적치
    WHEN B.SHEAR_CLS_HOLD_RSN_CD IN ('01', '02', '03', '07') THEN 'E'                           --// 정정마감보류사유코드 E동 적치
    ELSE DECODE(B.TRN_EQP_GP, 'TR', DEST_BAY, 'PT', PT_DEST_BAY, PT_DEST_BAY) END AS DEST_BAY   --목적동
FROM
    TB_YF_SLABMOVEBAYRANKING A,
    (
        SELECT
            CASE
            WHEN AA.CLHR = '0' THEN DECODE(AA.HCR_GP, 'C', 'E', 'J')
            ELSE
            (
                CASE
                WHEN ROUND((SYSDATE - AA.SLAB_CREATE_DDTT) * 24) > AA.CLHR
                THEN 'E' ELSE 'J' END
            ) END AS HCR_GP,
            DECODE(AA.ORD_YEOJAE_GP, '1', '1', '0') AS T1,  --1:주문재
            DECODE(AA.ORD_YEOJAE_GP, '2', '2', '0') AS T2,  --2:여재
            DECODE(AA.ITEMNAME_CD, 'CBD', '3', '0') AS T3,  --3:외판재 (CBD:B-Cast정정 Slab)
            DECODE(AA.REAGENT_PICK_TARGET_YN, 'Y', '4', '0') AS T4,     --4:시편재
            DECODE(AA.SCARFING_YN, 'Y',DECODE(AA.SCARFING_DONE_YN, 'N', '5', '3'), '0') AS T5,  --5:스카핑재
            DECODE(AA.INGRHOLD_YN, 'Y', '6', '0') AS T6,    --6:보류재
            AA.ARR_WLOC_CD,
            AA.TRN_EQP_GP,
            AA.SHEAR_CLS_HOLD_RSN_CD,
            AA.MSLAB_HTWRM_SLOWCL_TG_EXN,
            AA.CCSLAB_CL_MTD_GP
        FROM
            (
                SELECT
                    A.ARR_WLOC_CD,                          --착지개소코드
                    SUBSTR(A.TRN_EQP_CD,2,2) AS TRN_EQP_GP, --'TR' or 'PT'
                    C.HCR_GP,                               --HCR구분
                    C.ORD_YEOJAE_GP,                        --주문여재구분
                    C.ITEMNAME_CD,                          --품명코드
                    C.REAGENT_PICK_TARGET_YN,               --시편채취대상여부
                    C.SCARFING_YN,                          --Scarfing대상여부
                    C.SCARFING_DONE_YN,                     --Scarfing완료유무
                    C.INGRHOLD_YN,                          --성분보류유무
                    C.SLAB_CREATE_DDTT,                     --Slab생성일시
                    C.SHEAR_CLS_HOLD_RSN_CD,                --정정마감보류사유코드
                    (
                        SELECT
                            DTL_ITEM1
                        FROM
                            TB_YF_RULE
                        WHERE 1=1
                        AND REPR_CD_GP  = 'CLHR'
                        AND CD_GP       = '0'
                        AND ITEM        = 'C'
                        AND DEL_YN      = 'N'
                    ) AS CLHR,                              --C연주야드 냉각시간
                    NVL(D.MSLAB_HTWRM_SLOWCL_TG_EXN,'N') AS MSLAB_HTWRM_SLOWCL_TG_EXN,  --주편보온서냉대상유무
                    D.CCSLAB_CL_MTD_GP                      --연주주편냉각방법구분
                FROM
                    TB_YD_CARSCH A,
                    TB_YD_CARFTMVMTL B,
                    VW_YD_SLABCOMM C,
                    TB_PT_MSLABCOMMSUB D
                WHERE 1=1
                AND A.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
                AND A.DEL_YN = 'N'
                AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
                AND B.STL_NO = C.SLAB_NO
                AND B.STL_NO = D.MSLAB_NO(+)
            ) AA
    ) B,
    TB_YF_STKCOL C
WHERE 1=1
AND A.ORD_YEOJAE_GP = B.HCR_GP
AND A.SLAB_GP IN (B.T1, B.T2, B.T3, B.T4, B.T5, B.T6)
AND B.ARR_WLOC_CD = C.WLOC_CD
AND (C.CAR_CARD_NO <>'9999' OR C.CAR_CARD_NO IS NULL)
ORDER BY TO_NUMBER(RANKING)
 </pre> */
public final static String getListAimBay_CCast = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListAimBay_CCast";

 /** <pre> 2020-11-20
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getNumberSpanbyLowInfo
WITH 
 PARAM AS (
    SELECT :V_YD_GP         AS V_YD_GP
          ,:V_YD_BAY_GP     AS V_YD_BAY_GP
          ,:V_YD_ZONE_GP    AS V_YD_ZONE_GP
      FROM DUAL
)

,HD_INFO AS (
   SELECT SECT_GP 
    FROM TB_YF_STKCOL
        ,PARAM P
   WHERE YD_GP     = P.V_YD_GP
     AND BAY_GP    LIKE P.V_YD_BAY_GP || '%'
     AND REGEXP_INSTR(SECT_GP,'[^0-9]')   = 0
     AND SECT_GP < '17'
   GROUP BY SECT_GP
   ORDER BY SECT_GP
)

,LOW_CHK AS( 
    SELECT  BAY_GP
          , COL_GP
          , (CASE WHEN HD_INFO.SECT_GP = '01' THEN YD_ZONE_GP ELSE '' END) AS SP01 
          , (CASE WHEN HD_INFO.SECT_GP = '02' THEN YD_ZONE_GP ELSE '' END) AS SP02 
          , (CASE WHEN HD_INFO.SECT_GP = '03' THEN YD_ZONE_GP ELSE '' END) AS SP03 
          , (CASE WHEN HD_INFO.SECT_GP = '04' THEN YD_ZONE_GP ELSE '' END) AS SP04 
          , (CASE WHEN HD_INFO.SECT_GP = '05' THEN YD_ZONE_GP ELSE '' END) AS SP05 
          , (CASE WHEN HD_INFO.SECT_GP = '06' THEN YD_ZONE_GP ELSE '' END) AS SP06 
          , (CASE WHEN HD_INFO.SECT_GP = '07' THEN YD_ZONE_GP ELSE '' END) AS SP07 
          , (CASE WHEN HD_INFO.SECT_GP = '08' THEN YD_ZONE_GP ELSE '' END) AS SP08 
          , (CASE WHEN HD_INFO.SECT_GP = '09' THEN YD_ZONE_GP ELSE '' END) AS SP09 
          , (CASE WHEN HD_INFO.SECT_GP = '10' THEN YD_ZONE_GP ELSE '' END) AS SP10 
          , (CASE WHEN HD_INFO.SECT_GP = '11' THEN YD_ZONE_GP ELSE '' END) AS SP11 
          , (CASE WHEN HD_INFO.SECT_GP = '12' THEN YD_ZONE_GP ELSE '' END) AS SP12 
          , (CASE WHEN HD_INFO.SECT_GP = '13' THEN YD_ZONE_GP ELSE '' END) AS SP13 
          , (CASE WHEN HD_INFO.SECT_GP = '14' THEN YD_ZONE_GP ELSE '' END) AS SP14 
          , (CASE WHEN HD_INFO.SECT_GP = '15' THEN YD_ZONE_GP ELSE '' END) AS SP15 
          , (CASE WHEN HD_INFO.SECT_GP = '16' THEN YD_ZONE_GP ELSE '' END) AS SP16 
          , (CASE WHEN HD_INFO.SECT_GP = '17' THEN YD_ZONE_GP ELSE '' END) AS SP17 
          , (CASE WHEN HD_INFO.SECT_GP = '18' THEN YD_ZONE_GP ELSE '' END) AS SP18 
          , (CASE WHEN HD_INFO.SECT_GP = '19' THEN YD_ZONE_GP ELSE '' END) AS SP19 
          , (CASE WHEN HD_INFO.SECT_GP = '20' THEN YD_ZONE_GP ELSE '' END) AS SP20 
          , (CASE WHEN HD_INFO.SECT_GP = '21' THEN YD_ZONE_GP ELSE '' END) AS SP21 
          , (CASE WHEN HD_INFO.SECT_GP = '22' THEN YD_ZONE_GP ELSE '' END) AS SP22 
          , (CASE WHEN HD_INFO.SECT_GP = '23' THEN YD_ZONE_GP ELSE '' END) AS SP23 
          , (CASE WHEN HD_INFO.SECT_GP = '24' THEN YD_ZONE_GP ELSE '' END) AS SP24 
          , (CASE WHEN HD_INFO.SECT_GP = '25' THEN YD_ZONE_GP ELSE '' END) AS SP25 
          , (CASE WHEN HD_INFO.SECT_GP = '26' THEN YD_ZONE_GP ELSE '' END) AS SP26 
          , (CASE WHEN HD_INFO.SECT_GP = '27' THEN YD_ZONE_GP ELSE '' END) AS SP27 
          , (CASE WHEN HD_INFO.SECT_GP = '28' THEN YD_ZONE_GP ELSE '' END) AS SP28 
          , (CASE WHEN HD_INFO.SECT_GP = '29' THEN YD_ZONE_GP ELSE '' END) AS SP29 
          , (CASE WHEN HD_INFO.SECT_GP = '30' THEN YD_ZONE_GP ELSE '' END) AS SP30 
          , (CASE WHEN HD_INFO.SECT_GP = '31' THEN YD_ZONE_GP ELSE '' END) AS SP31 
          , (CASE WHEN HD_INFO.SECT_GP = '32' THEN YD_ZONE_GP ELSE '' END) AS SP32 
          , (CASE WHEN HD_INFO.SECT_GP = '33' THEN YD_ZONE_GP ELSE '' END) AS SP33 
          , (CASE WHEN HD_INFO.SECT_GP = '34' THEN YD_ZONE_GP ELSE '' END) AS SP34 
          , (CASE WHEN HD_INFO.SECT_GP = '35' THEN YD_ZONE_GP ELSE '' END) AS SP35 
          , (CASE WHEN HD_INFO.SECT_GP = '36' THEN YD_ZONE_GP ELSE '' END) AS SP36 
          , (CASE WHEN HD_INFO.SECT_GP = '37' THEN YD_ZONE_GP ELSE '' END) AS SP37 
          , (CASE WHEN HD_INFO.SECT_GP = '38' THEN YD_ZONE_GP ELSE '' END) AS SP38 
          , (CASE WHEN HD_INFO.SECT_GP = '39' THEN YD_ZONE_GP ELSE '' END) AS SP39 
          , (CASE WHEN HD_INFO.SECT_GP = '40' THEN YD_ZONE_GP ELSE '' END) AS SP40 
          , (CASE WHEN HD_INFO.SECT_GP = '41' THEN YD_ZONE_GP ELSE '' END) AS SP41 
          , (CASE WHEN HD_INFO.SECT_GP = '42' THEN YD_ZONE_GP ELSE '' END) AS SP42 
          , (CASE WHEN HD_INFO.SECT_GP = '43' THEN YD_ZONE_GP ELSE '' END) AS SP43
          , (CASE WHEN HD_INFO.SECT_GP = '44' THEN YD_ZONE_GP ELSE '' END) AS SP44 
          , (CASE WHEN HD_INFO.SECT_GP = '45' THEN YD_ZONE_GP ELSE '' END) AS SP45 
          , (CASE WHEN HD_INFO.SECT_GP = '46' THEN YD_ZONE_GP ELSE '' END) AS SP46 
          , (CASE WHEN HD_INFO.SECT_GP = '47' THEN YD_ZONE_GP ELSE '' END) AS SP47 
          , (CASE WHEN HD_INFO.SECT_GP = '48' THEN YD_ZONE_GP ELSE '' END) AS SP48 
          , (CASE WHEN HD_INFO.SECT_GP = '49' THEN YD_ZONE_GP ELSE '' END) AS SP49 
          , (CASE WHEN HD_INFO.SECT_GP = '50' THEN YD_ZONE_GP ELSE '' END) AS SP50  
  
      FROM (SELECT E.SECT_GP  AS SPAN 
                 , E.BAY_GP
                 , E.COL_GP   
                 , E.YD_STK_COL_GP
                 , (CASE WHEN E.YD_STK_COL_GP IS NULL THEN '0' ELSE F.YD_ZONE_GP END) AS CHK
                 , NVL(F.YD_ZONE_GP,'N') AS YD_ZONE_GP
              FROM TB_YF_STKCOL   E
                 , TB_YF_SCHLOCSRCH_ZONE F
                 , PARAM P
             WHERE E.YD_GP        = P.V_YD_GP 
               AND E.BAY_GP     LIKE P.V_YD_BAY_GP || '%'
               AND E.DEL_YN = 'N'
			   AND F.DEL_YN(+) = 'N'
               AND E.YD_STK_COL_ACTIVE_STAT IN ('L')
               AND REGEXP_INSTR(E.SECT_GP,'[^0-9]')   = 0
               AND E.SECT_GP < '17'
               AND ((REGEXP_LIKE(E.COL_GP, '[[:digit:]]') AND E.COL_GP BETWEEN '00' AND '10'))
               AND E.YD_STK_COL_GP = F.YD_STK_COL_GP(+)
               AND 'N' = F.DEL_YN(+)
           ) T
           ,HD_INFO
      WHERE T.SPAN = HD_INFO.SECT_GP
)

SELECT LPAD(TO_CHAR(ROWNUM),2,'0') AS RN
      , A.*
  FROM (SELECT BAY_GP
             , MAX(COL_GP) OVER(ORDER BY BAY_GP) AS MAXLOW
             , MAX(COL_GP) AS COL_GP
             , NVL(MAX(SP01),'*') AS SP01     
             , NVL(MAX(SP02),'*') AS SP02
             , NVL(MAX(SP03),'*') AS SP03     
             , NVL(MAX(SP04),'*') AS SP04
             , NVL(MAX(SP05),'*') AS SP05     
             , NVL(MAX(SP06),'*') AS SP06
             , NVL(MAX(SP07),'*') AS SP07     
             , NVL(MAX(SP08),'*') AS SP08
             , NVL(MAX(SP09),'*') AS SP09     
             , NVL(MAX(SP10),'*') AS SP10
             , NVL(MAX(SP11),'*') AS SP11     
             , NVL(MAX(SP12),'*') AS SP12
             , NVL(MAX(SP13),'*') AS SP13     
             , NVL(MAX(SP14),'*') AS SP14
             , NVL(MAX(SP15),'*') AS SP15     
             , NVL(MAX(SP16),'*') AS SP16
             , NVL(MAX(SP17),'*') AS SP17     
             , NVL(MAX(SP18),'*') AS SP18     
             , NVL(MAX(SP19),'*') AS SP19     
             , NVL(MAX(SP20),'*') AS SP20     
             , NVL(MAX(SP21),'*') AS SP21
             , NVL(MAX(SP22),'*') AS SP22     
             , NVL(MAX(SP23),'*') AS SP23
             , NVL(MAX(SP24),'*') AS SP24     
             , NVL(MAX(SP25),'*') AS SP25
             , NVL(MAX(SP26),'*') AS SP26     
             , NVL(MAX(SP27),'*') AS SP27
             , NVL(MAX(SP28),'*') AS SP28 
             , NVL(MAX(SP29),'*') AS SP29
             , NVL(MAX(SP30),'*') AS SP30
             , NVL(MAX(SP31),'*') AS SP31     
             , NVL(MAX(SP32),'*') AS SP32
             , NVL(MAX(SP33),'*') AS SP33     
             , NVL(MAX(SP34),'*') AS SP34
             , NVL(MAX(SP35),'*') AS SP35     
             , NVL(MAX(SP36),'*') AS SP36
             , NVL(MAX(SP37),'*') AS SP37     
             , NVL(MAX(SP38),'*') AS SP38
             , NVL(MAX(SP39),'*') AS SP39     
             , NVL(MAX(SP40),'*') AS SP40     
             , NVL(MAX(SP41),'*') AS SP41     
             , NVL(MAX(SP42),'*') AS SP42     
             , NVL(MAX(SP43),'*') AS SP43
             , NVL(MAX(SP44),'*') AS SP44
             , NVL(MAX(SP45),'*') AS SP45
             , NVL(MAX(SP46),'*') AS SP46
             , NVL(MAX(SP47),'*') AS SP47
             , NVL(MAX(SP48),'*') AS SP48
             , NVL(MAX(SP49),'*') AS SP49
             , NVL(MAX(SP50),'*') AS SP50 
          FROM LOW_CHK  
         GROUP BY BAY_GP,COL_GP
         ORDER BY BAY_GP) A
          
 </pre> */
public final static String getNumberSpanbyLowInfo = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getNumberSpanbyLowInfo";

 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchDnWoLocBt 
-- 베드 조회
SELECT * FROM
(
SELECT --+ORDERED USE_NL(A,B,CM)A.YD_STK_COL_GP  
     , A.YD_STK_BED_NO  
     , B.YD_STK_LYR_NO
     , MIN(A.YD_STK_BED_X_AXIS)              AS YD_DN_WO_LOC_XAXIS
     , MIN(A.YD_STK_BED_Y_AXIS)              AS YD_DN_WO_LOC_YAXIS
     , MIN(A.YD_STK_BED_Z_AXIS)              AS YD_DN_WO_LOC_ZAXIS
     , MIN(CM.YD_DN_WO_LOC)                 AS YD_DN_WO_LOC_OLD
     , MIN(CM.YD_DN_WO_LYR)               AS YD_DN_WO_LYR_OLD
     , (SELECT CASE WHEN SUM(DECODE(YD_STK_LYR_STAT,'U',1,0)) > 0  THEN 'UP' --권상대기 있음
                   ELSE '' END 
          FROM TB_YF_STKLYR 
         WHERE YD_STK_COL_GP = A.YD_STK_COL_GP 
           AND YD_STK_LYR_NO < B.YD_STK_LYR_NO 
       ) AS DL_LOC_CHK_RST 
     , COUNT(B.STL_NO)   AS STL_CNT  
  FROM TB_YF_STKBED A
     , TB_YF_STKLYR B
     , (SELECT --+ORDERED USE_NL(CM)CM.YD_DN_WO_LOC
              ,CM.YD_DN_WO_LYR 
              ,CM.YD_MTL_SH
              ,CM.YD_MTL_WT
              ,CM.YD_MTL_T
          FROM (SELECT --+ORDERED USE_NL(CS,CM,ST,CC) INDEX_DESC(CS PK_YF_CRNSCH)CS.YD_CRN_SCH_ID
                      ,MIN(CS.YD_WBOOK_ID   ) AS YD_WBOOK_ID
                      ,MIN(CS.YD_DN_WO_LOC  ) AS YD_DN_WO_LOC
                      ,MIN(CS.YD_DN_WO_LYR) AS YD_DN_WO_LYR
                      ,COUNT(*)               AS YD_MTL_SH
                      ,SUM(CC.COIL_WT)        AS YD_MTL_WT
                      ,SUM(CC.COIL_LEN)       AS YD_MTL_T
                  FROM TB_YF_CRNSCH    CS
                      ,TB_YF_CRNWRKMTL CM
                      ,TB_YF_STOCK     ST
                      ,VW_YF_COILCOMM  CC
                 WHERE CS.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
                   AND CM.YD_CRN_SCH_ID = CS.YD_CRN_SCH_ID
                   AND CM.STL_NO = ST.STL_NO
                   AND CM.STL_NO = CC.COIL_NO
                   AND CM.DEL_YN = 'N'
                 GROUP BY CS.YD_CRN_SCH_ID) CM) CM
 WHERE A.YD_STK_COL_GP  = SUBSTR(:V_YD_STK_COL_GP, 1, 6)
   AND A.YD_STK_COL_GP  = B.YD_STK_COL_GP
   AND A.YD_STK_BED_NO  = B.YD_STK_BED_NO
   AND B.YD_STK_LYR_NO  = NVL(
                            (SELECT YD_STK_LYR_NO +  DECODE(SUM_MTL_CNT,BED_CNT,1,0)
                               FROM
                                   (
                                    SELECT YD_STK_LYR_NO
                                         , SUM(CASE WHEN MTL_CNT > 0 THEN 1 ELSE 0 END ) AS SUM_MTL_CNT 
                                         , (SELECT TO_CHAR(COUNT(*)) 
                                              FROM TB_YF_STKBED 
                                             WHERE YD_STK_COL_GP = C.YD_STK_COL_GP 
                                               AND YD_STK_BED_ACTIVE_STAT = 'L'
                                           ) AS BED_CNT
                                    FROM (
                                             SELECT YD_STK_COL_GP
                                                  , YD_STK_BED_NO
                                                  , YD_STK_LYR_NO
                                                  , COUNT(STL_NO)  AS MTL_CNT
                                               FROM TB_YF_STKLYR C
                                              WHERE C.YD_STK_COL_GP = SUBSTR(:V_YD_STK_COL_GP, 1, 6)
                                                AND C.STL_NO IS NOT NULL
                                                AND C.YD_STK_LYR_ACTIVE_STAT = 'E'
                                              GROUP BY YD_STK_COL_GP, YD_STK_BED_NO, YD_STK_LYR_NO
                                         )  C         
                                     GROUP BY YD_STK_COL_GP, YD_STK_LYR_NO
                                     ORDER BY YD_STK_COL_GP, YD_STK_LYR_NO DESC
                                    ) 
                            WHERE ROWNUM =1 
                            ),'01')       
   AND A.YD_STK_COL_GP = SUBSTR(:V_YD_STK_COL_GP, 1, 6)
   AND A.DEL_YN = 'N'
   AND A.YD_STK_BED_ACTIVE_STAT = 'L'
   AND B.YD_STK_LYR_ACTIVE_STAT = 'E'
  GROUP BY  A.YD_STK_COL_GP, A.YD_STK_BED_NO, B.YD_STK_LYR_NO
  ORDER BY YD_STK_LYR_NO, YD_STK_BED_NO
) WHERE STL_CNT = 0
   AND  ROWNUM = 1  
 </pre> */
public final static String getCrnSchDnWoLocBt = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchDnWoLocBt";

 /** <pre> 2020-10-22
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getListYdCarPnt 
SELECT
      SUBSTR(YD_STK_COL_GP, 2,1) AS BAY_GP
    , T.*
    , DECODE(T.YD_CAR_PROG_STAT,'1','상차출발','2','상차도착','3','상차개시','4','상차개시','5','상차완료','A','하차출발','B','하차도착','C','하차개시','D','하차개시','E','하차완료',T.YD_CAR_PROG_STAT) AS YD_CAR_PROG_STAT_NM   
FROM
( 
        SELECT CP.YD_CARPNT_DESC AS GATE_NM
              ,CP.WLOC_CD
              ,CP.YD_PNT_CD
              ,CP.YD_STK_COL_GP
              ,CP.YD_CARPNT_CD
              ,CP.YD_CAR_USETYPE_GP
              ,CP.YD_STK_COL_ACT_STAT
              ,CP.YD_SPAN_FROM
              ,CP.YD_SPAN_TO
              ,CP.TRN_EQP_CD
              ,CP.CAR_NO
              ,CP.CARD_NO 
              ,CS.YD_CAR_PROG_STAT
              ,CS.ARR_WLOC_CD
              ,CS.YD_CAR_SCH_ID
          FROM TB_YD_CARPOINT  CP, (
                SELECT A.YD_CARPNT_CD
                    , B.YD_CAR_PROG_STAT
                    , B.ARR_WLOC_CD
                    , B.YD_CAR_SCH_ID
                FROM TB_YD_CARPOINT A, TB_YD_CARSCH B
                WHERE (A.CAR_NO = B.CAR_NO
                        OR A.TRN_EQP_CD = B.TRN_EQP_CD)
                AND B.DEL_YN = 'N'
                AND A.YD_GP = '1'
          ) CS
         WHERE CP.YD_GP = '1'
           AND CP.DEL_YN = 'N'
           AND CP.YD_CARPNT_CD = CS.YD_CARPNT_CD(+)
) T
ORDER BY T.YD_STK_COL_GP

 </pre> */
public final static String getListYdCarPnt = "com.inisteel.cim.yf.common.dao.YfCommDAO.getListYdCarPnt";

 /** <pre> 2020-06-16
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListACCraneStat 
SELECT  A.YD_GP
      , A.YD_BAY_GP
      , A.YD_BAY_GP||'동' AS BAY_GP_NM --동명
      , A.YD_EQP_ID
      , A.YD_EQP_NO
      , A.YD_EQP_PROG_STAT
      , A.YD_EQP_WRK_MODE
      , A.YD_EQP_WRK_MODE2  
      , D.YD_CRN_SCH_ID
      , D.YD_WBOOK_ID
      , D.YD_SCH_CD
      , D.YD_WRK_PROG_STAT
      , D.YD_UP_WO_LOC
      , D.YD_UP_WO_LYR
      , D.YD_DN_WO_LOC
      , D.YD_DN_WO_LYR
      , D.STL_NO
      , D.YD_AID_WRK_YN
      , D.YD_SCH_CD_NM
      , CASE WHEN D.YD_WORD_DT IS NULL THEN NULL
            ELSE TRUNC(TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')) ||'/ ' ||
                 LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')),1)*24), 2, '0') || ':' ||
                 LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24,1)*60), 2, '0') ||':'||
                 LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24*60,1)*60), 2, '0')
            END
        AS PASS_HR
      , A.YD_EQP_NAME
      
  FROM  TB_YF_EQP A
      , (

            SELECT  B.YD_CRN_SCH_ID
                  , B.YD_EQP_ID
                  , B.YD_WBOOK_ID
                  , B.YD_SCH_CD
                  , B.YD_WRK_PROG_STAT
                  , B.YD_UP_WO_LOC
                  , B.YD_UP_WO_LYR
                  , B.YD_DN_WO_LOC
                  , B.YD_DN_WO_LYR
                  , B.YD_WORD_DT
                  , C.STL_NO
                  , C.YD_AID_WRK_YN AS YD_AID_WRK_YN
                  , (SELECT CD_CONTENTS FROM TB_YF_SCHRULE WHERE YD_SCH_CD = B.YD_SCH_CD) AS YD_SCH_CD_NM
              FROM  TB_YF_CRNSCH B
                  , TB_YF_CRNWRKMTL C
             WHERE  B.DEL_YN = 'N'
               AND  B.YD_CRN_SCH_ID = C.YD_CRN_SCH_ID
               AND  B.YD_WRK_PROG_STAT||B.YD_CRN_SCH_ID IN (
               
                                SELECT MIN(CHK) AS CHK
                                FROM   (
                                            SELECT YD_CRN_SCH_ID
                                                  ,YD_WRK_PROG_STAT
                                                  ,YD_WBOOK_ID
                                                  ,YD_EQP_ID
                                                  ,MIN(YD_WRK_PROG_STAT||YD_CRN_SCH_ID) OVER (PARTITION BY  YD_WBOOK_ID ) AS CHK
                                            FROM   TB_YF_CRNSCH
                                            WHERE  DEL_YN = 'N'
                                       )
                                GROUP BY YD_EQP_ID
                            )

        ) D
 WHERE  A.YD_GP = '1'
   AND  A.YD_EQP_GP = 'CR'
   AND  A.DEL_YN = 'N'
   AND  A.YD_EQP_ID = D.YD_EQP_ID(+)
 ORDER BY A.YD_EQP_ID
 </pre> */
public final static String getListACCraneStat = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListACCraneStat";

 /** <pre> 2019-09-03
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdStockFRTOMOVE_WORD_DATE_RENTCOIL
SELECT
    C.STL_NO                    AS STL_NO,
    C.YD_AIM_RT_GP              AS YD_AIM_RT_GP,
    D.FRTOMOVE_WORD_DATE        AS FRTOMOVE_WORD_DATE,
    D.URGENT_FRTOMOVE_WORD_GP   AS URGENT_FRTOMOVE_WORD_GP,
    D.WO_CAR_PLNT_PROC_CD       AS PLNT_PROC_CD,
    D.FRTOMOVE_STAT_CD          AS FRTOMOVE_STAT_CD,
    D.FRTOMOVE_ORD_CANCEL_DATE  AS FRTOMOVE_ORD_CANCEL_DATE,
    D.RENTPROC_COMCD            AS RENTPROC_COMCD
FROM
    TB_YD_STOCK C,
    (
        SELECT
            A.STL_NO                    AS STL_NO,
            A.TRANSWORD_SEQNO           AS TRANSWORD_SEQNO,
            A.FRTOMOVE_WORD_DATE        AS FRTOMOVE_WORD_DATE,
            A.WO_CAR_PLNT_PROC_CD       AS WO_CAR_PLNT_PROC_CD,
            A.URGENT_FRTOMOVE_WORD_GP   AS URGENT_FRTOMOVE_WORD_GP,
            A.FRTOMOVE_STAT_CD          AS FRTOMOVE_STAT_CD,
            A.SLAB_WO_RT_CD             AS SLAB_WO_RT_CD,
            A.FRTOMOVE_ORD_CANCEL_DATE  AS FRTOMOVE_ORD_CANCEL_DATE,
            A.RENTPROC_COMCD
        FROM
            TB_PT_STLFRTOMOVE A,
            (
                SELECT
                    STL_NO,
                    MAX(TRANSWORD_SEQNO) AS TRANSWORD_SEQNO
                FROM
                    TB_PT_STLFRTOMOVE
                WHERE 1=1
                AND FRTOMOVE_WORD_DATE  = :V_FRTOMOVE_WORD_DATE
                AND FRTOMOVE_STAT_CD    IN ('1','C')
                GROUP BY STL_NO
            ) B
        WHERE 1=1
        AND B.STL_NO            = A.STL_NO
        AND A.TRANSWORD_SEQNO   = B.TRANSWORD_SEQNO
        AND A.STL_APPEAR_GP     = 'E'
        AND A.RENTPROC_COMCD    IS NOT NULL
    ) D
WHERE 1=1
AND C.STL_NO = D.STL_NO
 </pre> */
public final static String getYdStockFRTOMOVE_WORD_DATE_RENTCOIL = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdStockFRTOMOVE_WORD_DATE_RENTCOIL";

