 /** <pre> 2020-12-17
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getEqpOprnStat 
SELECT 
         A.YD_GP
       , A.YD_BAY_GP
       , A.YD_EQP_NAME
       , A.YD_EQP_ID
       , DECODE(A.YD_EQP_PROG_STAT, 'B', '고장', '정상') AS YD_EQP_STAT 
       , A.YD_EQP_PROG_STAT
       , D.YD_UP_WR_LYR
       , D.YD_DN_WR_LYR
       , D.YD_ALT_CRN_YN
       , D.YD_ALT_CRN
       , ( SELECT B.YD_EQP_NAME FROM TB_YF_EQP B WHERE B.YD_EQP_ID = D.YD_ALT_CRN ) AS YD_ALT_CRN_NM
       , A.YD_EQP_WRK_MODE2 AS YD_EQP_WRK_MODE 
       , D.YD_CRN_SCH_ID
FROM TB_YF_EQP A  
    ,(
        SELECT  B.YD_CRN_SCH_ID
              , B.YD_EQP_ID
              , B.YD_WBOOK_ID
              , B.YD_SCH_CD
              , B.YD_WRK_PROG_STAT
              , B.YD_UP_WO_LOC
              , B.YD_UP_WO_LYR
              , B.YD_DN_WO_LOC
              , B.YD_DN_WO_LYR
              , B.YD_UP_WR_LYR
              , B.YD_DN_WR_LYR
              , B.YD_WORD_DT
              , C.YD_ALT_CRN_YN
              , C.YD_ALT_CRN
              , (SELECT MAX(YD_AID_WRK_YN) FROM TB_YF_CRNWRKMTL WHERE YD_CRN_SCH_ID = B.YD_CRN_SCH_ID) AS YD_AID_WRK_YN
              , (SELECT CD_CONTENTS FROM TB_YF_SCHRULE WHERE YD_SCH_CD = B.YD_SCH_CD) AS YD_SCH_CD_NM
          FROM  TB_YF_CRNSCH B, TB_YF_SCHRULE C
         WHERE  B.YD_SCH_CD = C.YD_SCH_CD
           AND  B.YD_GP = C.YD_GP
           AND  B.DEL_YN = C.DEL_YN
           AND  B.DEL_YN = 'N'
           AND  B.YD_WRK_PROG_STAT||B.YD_CRN_SCH_ID IN (
           
                            SELECT MIN(CHK) AS CHK
                            FROM   (
                                        SELECT YD_CRN_SCH_ID
                                              ,YD_WRK_PROG_STAT
                                              ,YD_WBOOK_ID
                                              ,YD_EQP_ID
                                              ,MIN(YD_WRK_PROG_STAT||YD_CRN_SCH_ID) OVER (PARTITION BY  YD_WBOOK_ID ) AS CHK
                                        FROM   TB_YF_CRNSCH
                                        WHERE  DEL_YN = 'N'
                                   )
                            GROUP BY YD_EQP_ID
                        )
      ) D
WHERE A.YD_EQP_ID LIKE :V_YD_EQP_ID  -- 설비구분
  AND A.YD_EQP_ID = D.YD_EQP_ID(+) 
  ORDER BY A.YD_EQP_ID
 </pre> */
public final static String getEqpOprnStat = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getEqpOprnStat";

