 /** <pre> 2019-08-28
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getChkBayInYn
--대기장 도착시 입동 여부 체크
--저장품이 2단일 경우 해당 저장품만 체크
--저장품이 1단일 경우 앞번지 2단과 해당번지 2단 저장품 상태 체크
SELECT
    CASE
    WHEN MIN(CASE WHEN S2.YD_STK_LYR_STAT = 'D' THEN '1' END) > 0 THEN 'N'
    ELSE 'Y' END AS IPDONG_YN
FROM
    TB_YF_STKLYR SL,
    TB_YF_STKLYR S2
WHERE 1=1
AND SL.DEL_YN = 'N'
AND S2.YD_STK_COL_GP = SL.YD_STK_COL_GP
AND S2.YD_STK_BED_NO IN
(
    SL.YD_STK_BED_NO,
    CASE
    WHEN SL.YD_STK_LYR_NO = '02' THEN SL.YD_STK_BED_NO
    ELSE LPAD(TO_NUMBER(SL.YD_STK_BED_NO) - 1, 2, '0') END
)
AND S2.YD_STK_LYR_NO IN
(
    CASE
    WHEN SL.YD_STK_LYR_NO = '02' THEN '02'
    WHEN S2.YD_STK_BED_NO = TO_NUMBER(SL.YD_STK_BED_NO) THEN '01'
    ELSE '02' END,
    '02'
)
AND SL.STL_NO IN
(
    SELECT
        STL_NO
    FROM
        TB_YF_STOCK
    WHERE 1=1
    AND TRANS_ORD_DATE  = :V_TRANS_ORD_DATE
    AND TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
)
AND SUBSTR(SL.YD_STK_COL_GP, 2, 1) LIKE :V_YD_BAY_GP || '%'
 </pre> */
public final static String getChkBayInYn = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getChkBayInYn";

