 /** <pre> 2019-10-31
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getDCLineoffSchInfo
SELECT CS.*
     , CM.STL_NO
     , (SELECT YD_EQP_WRK_MODE2 FROM TB_YF_EQP WHERE YD_EQP_ID = CS.YD_EQP_ID AND ROWNUM = 1) AS YD_EQP_WRK_MODE2
     , CASE WHEN (SELECT YD_EQP_WRK_MODE2 FROM TB_YF_EQP WHERE YD_EQP_ID = CS.YD_EQP_ID AND ROWNUM = 1) != 'A' AND YD_WRK_PROG_STAT IN ('W','S','1') THEN 'Y'
            ELSE 'N' END CHK_DEL_YN
  FROM TB_YF_CRNSCH      CS 
     , TB_YF_CRNWRKMTL   CM
 WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
   AND CS.DEL_YN    = 'N'
   AND CM.DEL_YN    = 'N'
   AND CS.YD_SCH_CD like '1_DC01LM' --DC LineOff
   AND CM.STL_NO  = :V_STL_NO
 </pre> */
