 /** <pre> 2020-04-27
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.geCarTrackingMTList_PIDEV 
SELECT *
 FROM (
SELECT SUBSTR(A.YD_CARPNT_CD,2,1)||'0'||SUBSTR(A.YD_CARPNT_CD,4,1) AS YD_CARPNT_CD

     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN A.YD_CARPNT_CD ELSE '' END) AS A_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS A_STAT     
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS A_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN COLLOR_YN ELSE '' END) AS A_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN NVL(A.CAR_NO, A.TRN_EQP_CD) ELSE '' END) AS A_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN CAR_RLT ELSE '' END) AS A_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN NEXT_CARNO ELSE '' END) AS A_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN CAR_CNT ELSE '' END) AS A_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN CAR_GP ELSE '' END) AS A_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'A' THEN A.CAR_NO ELSE '' END) AS A_CARD_NO
     
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN A.YD_CARPNT_CD ELSE '' END) AS B_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS B_STAT
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS B_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN COLLOR_YN ELSE '' END) AS B_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN NVL(A.CAR_NO, A.TRN_EQP_CD) ELSE '' END) AS B_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN CAR_RLT ELSE '' END) AS B_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN NEXT_CARNO ELSE '' END) AS B_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN CAR_CNT ELSE '' END) AS B_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN CAR_GP ELSE '' END) AS B_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'B' THEN A.CAR_NO ELSE '' END) AS B_CARD_NO
     
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN A.YD_CARPNT_CD ELSE '' END) AS C_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS C_STAT
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS C_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN COLLOR_YN ELSE '' END) AS C_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN NVL(A.CAR_NO, A.TRN_EQP_CD) ELSE '' END) AS C_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN CAR_RLT ELSE '' END) AS C_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN NEXT_CARNO ELSE '' END) AS C_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN CAR_CNT ELSE '' END) AS C_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN CAR_GP ELSE '' END) AS C_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'C' THEN A.CAR_NO ELSE '' END) AS C_CARD_NO
     
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN A.YD_CARPNT_CD ELSE '' END) AS D_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS D_STAT
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS D_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN COLLOR_YN ELSE '' END) AS D_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN NVL(A.CAR_NO, A.TRN_EQP_CD) ELSE '' END) AS D_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN CAR_RLT ELSE '' END) AS D_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN NEXT_CARNO ELSE '' END) AS D_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN CAR_CNT ELSE '' END) AS D_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN CAR_GP ELSE '' END) AS D_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'D' THEN A.CAR_NO ELSE '' END) AS D_CARD_NO
     
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN A.YD_CARPNT_CD ELSE '' END) AS E_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS E_STAT
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS E_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN COLLOR_YN ELSE '' END) AS E_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN NVL(A.CAR_NO, A.TRN_EQP_CD) ELSE '' END) AS E_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN CAR_RLT ELSE '' END) AS E_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN NEXT_CARNO ELSE '' END) AS E_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN CAR_CNT ELSE '' END) AS E_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN CAR_GP ELSE '' END) AS E_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'E' THEN A.CAR_NO ELSE '' END) AS E_CARD_NO
     
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN A.YD_CARPNT_CD ELSE '' END) AS F_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS F_STAT
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS F_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN COLLOR_YN ELSE '' END) AS F_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN NVL(A.CAR_NO, A.TRN_EQP_CD) ELSE '' END) AS F_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN CAR_RLT ELSE '' END) AS F_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN NEXT_CARNO ELSE '' END) AS F_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN CAR_CNT ELSE '' END) AS F_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN CAR_GP ELSE '' END) AS F_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'F' THEN A.CAR_NO ELSE '' END) AS F_CARD_NO
     
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN A.YD_CARPNT_CD ELSE '' END) AS G_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS G_STAT
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS G_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN COLLOR_YN ELSE '' END) AS G_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN NVL(A.CAR_NO,A.TRN_EQP_CD) ELSE '' END) AS G_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN CAR_RLT ELSE '' END) AS G_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN NEXT_CARNO ELSE '' END) AS G_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN CAR_CNT ELSE '' END) AS G_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN CAR_GP ELSE '' END) AS G_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'G' THEN A.CAR_NO ELSE '' END) AS G_CARD_NO
     
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN A.YD_CARPNT_CD ELSE '' END) AS H_YD_CARPNT_CD
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN A.YD_STK_COL_ACT_STAT ELSE '' END) AS H_STAT
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN A.YD_CAR_USETYPE_GP ELSE '' END) AS H_USETYPE_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN COLLOR_YN ELSE '' END) AS H_COLLOR_YN
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN NVL(A.CAR_NO,A.TRN_EQP_CD) ELSE '' END) AS H_CAR_NO
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN CAR_RLT ELSE '' END) AS H_CAR_RLT
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN NEXT_CARNO ELSE '' END) AS H_NEXT_CARNO
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN CAR_CNT ELSE '' END) AS H_CAR_CNT
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN CAR_GP ELSE '' END) AS H_CAR_GP
     , MAX(CASE A.YD_BAY_GP WHEN 'H' THEN A.CAR_NO ELSE '' END) AS H_CARD_NO
 FROM (
       SELECT A.YD_CARPNT_CD , A.YD_BAY_GP ,A.YD_STK_COL_ACT_STAT , A.YD_CAR_USETYPE_GP 
          , (CASE WHEN A.YD_STK_COL_ACT_STAT='R' THEN '' ELSE CAR_NO END) AS CAR_NO
          , (CASE WHEN A.YD_STK_COL_ACT_STAT='R' THEN '' ELSE A.CAR_NO END) AS CARD_NO
          ,A.TRN_EQP_CD ,
          (CASE WHEN (SELECT YD_CAR_WRK_GP FROM TB_YD_CARSCH WHERE DEL_YN='N' AND CAR_NO=A.CAR_NO AND ROWNUM<=1)='9'   THEN 'N' 
                    WHEN SUBSTR(CAR_RLT,1,1)=SUBSTR(CAR_RLT,3,1) AND SUBSTR(CAR_RLT,1,1)<>'0'    THEN 'N'                    
             ELSE COLLOR_YN END)AS COLLOR_YN , CAR_RLT ,NEXT_CARNO , CAR_CNT , CAR_GP
         FROM (
               SELECT A.YD_CARPNT_CD , A.YD_BAY_GP ,A.YD_STK_COL_ACT_STAT , A.YD_CAR_USETYPE_GP 
                    ,NVL(A.CAR_NO,(SELECT CAR_NO FROM TB_YD_CARSCH WHERE DEL_YN='N' AND CAR_NO=A.CAR_NO AND ROWNUM<=1)) AS  CAR_NO
                    , A.CAR_NO AS CARD_NO ,A.TRN_EQP_CD
                    , NVL((SELECT 'N'
                         FROM TB_YD_CARSCH AA
                            , TB_YD_STKLYR BB 
                         WHERE (CASE WHEN AA.YD_CAR_PROG_STAT IN('1','2','3','4','5') THEN AA.YD_CARLD_STOP_LOC
                                 ELSE AA.YD_CARUD_STOP_LOC END)=BB.YD_STK_COL_GP
                           AND AA.DEL_YN='N'
                           AND BB.YD_STK_LYR_MTL_STAT IN ('U','D')
                           AND (AA.CAR_NO=A.CAR_NO OR  AA.TRN_EQP_CD=A.TRN_EQP_CD)
                           AND ROWNUM<=1
                           AND 'C' =(CASE WHEN A.YD_GP IN('A','D','K','H','J','T','S') THEN 'C' ELSE 'A' END)
                         UNION ALL
                         --
                         SELECT 'N'
                           FROM TB_YF_STKCOL CC
                             , TB_YF_STKLYR DD
                             , TB_YF_SCHRULE EE
                          WHERE CC.STACK_COL_GP=DD.STACK_COL_GP  
                           AND DD.STL_NO = EE.STL_NO
                           AND (CC.CAR_NO=A.CAR_NO OR  CC.TRN_EQP_CD=A.TRN_EQP_CD)
                           AND ROWNUM<=1
                           AND CC.YD_GP = A.YD_GP
                         UNION ALL     
                         
                         SELECT 'N'
                           FROM TB_YF_STKCOL CC
                             , TB_YF_STKLYR DD
                             , TB_YF_WRKBOOK EE
                             , TB_YF_WRKBOOKMTL FF
                          WHERE CC.YD_STK_COL_GP=DD.YD_STK_COL_GP
                           AND EE.YD_WBOOK_ID =FF.YD_WBOOK_ID                         
                           AND DD.STL_NO=FF.STL_NO
                           AND (CC.CAR_NO=A.CAR_NO OR  CC.TRN_EQP_CD=A.TRN_EQP_CD)
                           AND ROWNUM<=1
                           AND CC.YD_GP = A.YD_GP
                           ),'Y') AS COLLOR_YN 
                           
                , TO_CHAR(
                        (SELECT COUNT(*)
                           FROM TB_YD_CARSCH AA
                               ,TB_YF_STOCK CC
                          WHERE AA.DEL_YN='N'
                            AND AA.CAR_NO=A.CAR_NO
                            AND (CC.TRANS_ORD_DATE = AA.TRANS_ORD_DATE AND CC.TRANS_ORD_SEQNO = AA.TRANS_ORD_SEQNO))
                      +  
                        (SELECT  COUNT(*)
                           FROM  TB_YD_CARSCH AA
                                ,TB_YF_STOCK CC
                          WHERE AA.DEL_YN='N'
                            AND AA.TRN_EQP_CD=A.TRN_EQP_CD
                            AND (CC.FRTOMOVE_WORD_NO = AA.FRTOMOVE_WORD_NO))
                      +     
                        (SELECT COUNT(*)--복수 창고     
                           FROM TB_YD_CARSCH AA
                               ,TB_YD_STOCK CC
                          WHERE AA.DEL_YN='N'
                            AND AA.CAR_NO=A.CAR_NO
                            AND (CC.TRANS_ORD_DATE = AA.TRANS_ORD_DATE AND CC.TRANS_ORD_SEQNO = AA.TRANS_ORD_SEQNO)) 
                        )
               ||'/'||
              TO_CHAR(NVL((SELECT CASE 
                              WHEN AA.YD_CAR_PROG_STAT IN ('1','2','3','4','5')
                                THEN (SELECT COUNT(*) FROM TB_YD_CARFTMVMTL BB, TB_YF_STOCK CC WHERE BB.YD_CAR_SCH_ID = AA.YD_CAR_SCH_ID AND BB.DEL_YN = 'N' AND BB.STL_NO = CC.STL_NO)
                                ELSE (SELECT COUNT(*) FROM TB_YD_CARFTMVMTL BB, TB_YF_STOCK CC WHERE BB.YD_CAR_SCH_ID = AA.YD_CAR_SCH_ID AND BB.DEL_YN = 'Y' AND BB.STL_NO = CC.STL_NO)
                               END
                              FROM TB_YD_CARSCH AA
                             WHERE (AA.CAR_NO = A.CAR_NO OR AA.TRN_EQP_CD = A.TRN_EQP_CD)                                 
                               AND AA.DEL_YN = 'N'),0)) AS CAR_RLT  
                         
                         ,(SELECT REPLACE('['||AA.CAR_NO||']'||NVL(CAR_NO,TRN_EQP_CD),'[]','') AS NEXT_CARNO
                                    FROM TB_YD_CARSCH AA 
                                WHERE (CASE WHEN AA.YD_CAR_PROG_STAT IN('1','2','3','4','5') THEN AA.YD_CARLD_STOP_LOC
                                     ELSE AA.YD_CARUD_STOP_LOC END ) =SUBSTR(A.YD_STK_COL_GP,1,4)||(CASE WHEN YD_GP IN('1','3') THEN '1' ELSE'0' END)||SUBSTR(A.YD_STK_COL_GP,6,1)
                                   AND AA.DEL_YN='N'
                                   AND AA.YD_CAR_PROG_STAT='1'
                                   AND AA.YD_CAR_SCH_ID=(SELECT MIN(YD_CAR_SCH_ID)
                                                         FROM TB_YD_CARSCH BB 
                                                        WHERE (CASE WHEN BB.YD_CAR_PROG_STAT IN('1','2','3','4','5') THEN BB.YD_CARLD_STOP_LOC
                                                              ELSE BB.YD_CARUD_STOP_LOC END) =
                                                              (CASE WHEN AA.YD_CAR_PROG_STAT IN('1','2','3','4','5') THEN AA.YD_CARLD_STOP_LOC
                                                              ELSE AA.YD_CARUD_STOP_LOC END) 
                                                           AND BB.YD_CAR_PROG_STAT='1'
                                                           AND BB.DEL_YN='N')
                           ) AS NEXT_CARNO
                          , '대기차량:'|| TO_CHAR((SELECT COUNT(1)
                              FROM TB_YD_CARSCH AA
                             WHERE AA.DEL_YN = 'N'
                               AND YD_EQP_WRK_STAT = 'U' --U:공차 L:영차
                               AND YD_CAR_PROG_STAT = '1'
                               AND YD_CARLD_STOP_LOC = A.YD_STK_COL_GP)) AS CAR_CNT
                          --
                         ,'대기차량:'|| TO_CHAR(NVL((SELECT (CASE WHEN CAR_CNT>0 
                                                                    THEN CAR_CNT - (CASE 
                                                                                        WHEN TRN_EQP_CD IS NOT NULL OR CAR_NO IS NOT NULL 
                                                                                            THEN 1 
                                                                                            ELSE 0 
                                                                                         END ) 
                                                                     ELSE 0 
                                                                     END) 
                                                       FROM VW_YD_CARPOINT AA
                           WHERE AA.YD_CARPNT_CD=A.YD_CARPNT_CD),'0')) AS CAR_CNT
                          
                         , (
                         		 SELECT 
                         		 				MAX(
	                         								(
		                         								CASE WHEN BB.TRN_EQP_CD IS NULL 
					                                       THEN (
					                                        			 CASE WHEN CC.TRANS_FRTOMOVE_GP = '21' THEN '제품이송'
					                                                   WHEN CC.TRANS_FRTOMOVE_GP = '23' THEN '임가공'
					                                                	 ELSE DECODE(YD_CAR_WRK_GP ,'1','내수','2','수출','3','연안해송','9','냉연이송','내수') 
					                                               END
					                                             )
					                                       ELSE 
					                                       			'구내운송' 
					                                       END
	                                        ) 
                                       ) 
                             FROM 
                             			  TB_YD_CARSCH BB 
                             			, VW_LM_P_TRANSWORDCOMM CC
                             WHERE 
                             			 BB.TRANS_ORD_DATE = CC.TRANS_WORD_DATE
                             	 AND BB.TRANS_ORD_SEQNO = CC.TRANS_WORD_SEQNO
                             	 AND CC.DEL_YN='N' 
                             	 AND (
                             	 					 BB.CAR_NO=A.CAR_NO 
                             	 				OR BB.TRN_EQP_CD=A.TRN_EQP_CD 
                             	 			)
                            )  AS CAR_GP                          
--                          
                         , (SELECT MAX((CASE WHEN BB.TRN_EQP_CD IS NULL 
                                        THEN (CASE WHEN TRANS_ORD_SEQNO>=800000 THEN '제품이송'
                                                            WHEN TRANS_ORD_SEQNO>=700000 THEN '임가공'
                                                     ELSE DECODE(YD_CAR_WRK_GP ,'1','내수','2','수출','3','연안해송','9','냉연이송','내수') END)
                                        ELSE '구내운송' END) ) FROM TB_YD_CARSCH BB 
                                                WHERE DEL_YN='N' 
                                                AND (BB.CAR_NO=A.CAR_NO OR BB.TRN_EQP_CD=A.TRN_EQP_CD ))  AS CAR_GP

                FROM 
                		TB_YD_CARPOINT A
              WHERE 
              			YD_GP =:V_YD_GP
             		AND DEL_YN='N'
       ) A
       ) A
GROUP BY SUBSTR(A.YD_CARPNT_CD,2,1)||'0'||SUBSTR(A.YD_CARPNT_CD,4,1)
) A
 ORDER BY YD_CARPNT_CD
 </pre> */
public final static String geCarTrackingMTList = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.geCarTrackingMTList_PIDEV";

 /** <pre> 2020-09-22
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getWorkBookMtlbyWBookIdPage 

SELECT
    TT.*,
    SUBSTR(YD_STK_COL_GP,7,2) AS YD_STK_BED_NO,
    '01' AS YD_STK_LYR_NO
FROM 
    (SELECT AA.TOTALCOUNT
          ,AA.TOTAL_WGT
          ,AA.YD_CARPNT_CD
          ,AA.YD_STR_LOC_HIS1
          ,NVL(AA.YD_STK_COL_GP,  CASE WHEN  AA.YD_CARLD_STOP_LOC IS NULL THEN '' ELSE AA.YD_CARLD_STOP_LOC || AA.CARMTL_YD_CAR_UPP_LOC_CD END ) AS YD_STK_COL_GP
          ,NVL(AA.STOCK_YD_CAR_UPP_LOC_CD, AA.CARMTL_YD_CAR_UPP_LOC_CD) AS YD_CAR_UPP_LOC_CD
          ,AA.STL_NO
          ,AA.YD_MTL_T
          ,AA.YD_MTL_W
          ,AA.YD_MTL_WT
          ,AA.SPEC_ABBSYM
          ,AA.YD_STR_LOC_HIS1_
          ,AA.YD_AIM_RT_GP
          ,AA.HCR_GP
          ,AA.YD_CAR_SCH_ID
          ,AA.YD_WBOOK_ID
          ,AA.YD_CARLD_STOP_LOC
          ,AA.YD_PREP_SCH_ID_SUB
          ,AA.CMPL_YN 
    FROM  (
            SELECT COUNT(*) OVER() AS TOTALCOUNT
                 , SUM(NVL(CC.COIL_WT,0)) OVER() AS TOTAL_WGT
                 , CP.YD_CARPNT_CD
                 , NVL(
                    (SELECT 
                        YD_STK_COL_GP||YD_STK_BED_NO||YD_STK_LYR_NO 
                    FROM TB_YF_STKLYR 
                    WHERE STL_NO = ST.STL_NO 
                    AND YD_STK_LYR_STAT IN ('U','C')  
                    AND ROWNUM <= 1), (
                    SELECT  
                        YD_UP_WO_LOC
                    FROM TB_YF_WRKHIST 
                    WHERE YD_CAR_SCH_ID = CS.YD_CAR_SCH_ID
                    AND STL_NO = ST.STL_NO
                    AND DEL_YN = 'N'
                    )) AS YD_STR_LOC_HIS1
                 , (SELECT YD_STK_COL_GP||YD_STK_BED_NO  FROM TB_YF_STKLYR WHERE STL_NO = ST.STL_NO AND YD_STK_LYR_STAT = 'D') AS YD_STK_COL_GP 
                 , (SELECT YD_STK_LYR_NO FROM TB_YF_STKLYR WHERE STL_NO = ST.STL_NO AND YD_STK_LYR_STAT = 'D') AS YD_STK_LYR_NO
                 , ST.STL_NO
                 , NVL(CC.COIL_T,0) AS YD_MTL_T
                 , NVL(CC.COIL_W,0) AS YD_MTL_W
                 , NVL(CC.COIL_WT,0) AS YD_MTL_WT
                 , CC.SPEC_ABBSYM AS SPEC_ABBSYM
                 , CC.YD_STR_LOC_HIS1 AS YD_STR_LOC_HIS1_
                 -- 가장 최근 작업한 이력 OR 크레인작업 
                 , (
    --                SELECT 
    --                    FIRST_VALUE(YD_AIM_RT_GP) over ( order by  YD_WRK_HIST_ID desc )
    --                FROM TB_YF_WRKHIST 
    --                WHERE STL_NO = ST.STL_NO 
    --                UNION ALL
                    SELECT
                        FIRST_VALUE(YD_ROUTE_GP) over ( order by  YD_CRN_SCH_ID ASC )
                    FROM TB_YF_CRNWRKMTL 
                    WHERE STL_NO = ST.STL_NO
                    AND DEL_YN = 'N'
                 ) AS YD_AIM_RT_GP
                 , CC.HCR_GP
                 , '' AS CAR_PROG_STAT
                 , CS.YD_CAR_SCH_ID
                 , CS.YD_CARLD_WRK_BOOK_ID AS YD_WBOOK_ID
                 , CS.YD_CARLD_STOP_LOC
                 , (SELECT SUBSTR(YD_PREP_SCH_ID,16,3) FROM TB_YD_PREPSCH WHERE YD_WBOOK_ID = CS.YD_CARLD_WRK_BOOK_ID AND ROWNUM = 1) AS YD_PREP_SCH_ID_SUB
                 , DECODE((CASE WHEN CS.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN 
                                     (SELECT A.STL_NO FROM TB_YD_CARFTMVMTL A WHERE A.YD_CAR_SCH_ID = CS.YD_CAR_SCH_ID AND A.STL_NO = ST.STL_NO)
                                ELSE 
                                     (SELECT A.STL_NO FROM TB_YD_CARFTMVMTL A WHERE A.YD_CAR_SCH_ID = CS.YD_CAR_SCH_ID AND A.STL_NO = ST.STL_NO AND DEL_YN = 'Y')
                                END     
                                     ),NULL,'N','Y') AS CMPL_YN
                 , (SELECT A.YD_STK_BED_NO FROM TB_YD_CARFTMVMTL A WHERE A.YD_CAR_SCH_ID = CS.YD_CAR_SCH_ID AND A.STL_NO = ST.STL_NO) AS CARMTL_YD_CAR_UPP_LOC_CD -- 차상위치 박판열연은 YD_CAR_UPP_LOC_CD로 수정가능하면 수정 해야 함 
                 , ST.YD_CAR_UPP_LOC_CD AS STOCK_YD_CAR_UPP_LOC_CD
              FROM TB_YD_CARSCH CS
                 , TB_YF_STOCK  ST
                 , TB_YD_CARPOINT  CP
                 , VW_YF_COILCOMM  CC
             WHERE CS.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
               AND ( (CS.TRANS_ORD_DATE  = ST.TRANS_ORD_DATE AND CS.TRANS_ORD_SEQNO = ST.TRANS_ORD_SEQNO)
                 OR ( CS.FRTOMOVE_WORD_NO = ST.FRTOMOVE_WORD_NO)
               )
               AND CS.YD_CARLD_STOP_LOC = CP.YD_STK_COL_GP(+)
               AND ST.STL_NO = CC.COIL_NO
               AND CS.DEL_YN = 'N'
          ) AA
    ORDER BY YD_CAR_UPP_LOC_CD
) TT
 </pre> */
public final static String getWorkBookMtlbyWBookIdPage = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getWorkBookMtlbyWBookIdPage";

