 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointSelect_PIDEV
SELECT
    *
FROM
    (
        SELECT
            CC.YD_STK_COL_GP,
            CC.YD_CARPNT_CD,
            CC.YD_PNT_CD,
            DECODE(CC.YD_STK_COL_ACT_STAT,'C', 1, 2) AS STAT_RANK,
            (
                CASE
                --냉연출하 + 복수동인경우 통로 우선순위
                --2통로 E동 -> 2통로 F동 -> 2통로 G동 -> 1통로 G동 -> 1통로 F동 -> 1통로 E동
                WHEN (
                      SELECT 
                              COUNT(*) 
                        FROM 
                              TB_YF_STOCK A
                            , TB_YF_CR_COILCOMM B
                      WHERE 
                            A.TRANS_ORD_DATE  = :V_TRANS_ORD_DT
                        AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
                        AND A.STL_NO = B.COIL_NO
                     ) > 1 AND :V_CMBN_CARLD_YN IN ('S', 'E') THEN
                (
                    CASE
                    WHEN SUBSTR(CC.YD_CARPNT_CD, 3, 1) = 'E' AND SUBSTR(CC.YD_CARPNT_CD, 2, 1) = '2' THEN 1
                    WHEN SUBSTR(CC.YD_CARPNT_CD, 3, 1) = 'F' AND SUBSTR(CC.YD_CARPNT_CD, 2, 1) = '2' THEN 2
                    WHEN SUBSTR(CC.YD_CARPNT_CD, 3, 1) = 'G' AND SUBSTR(CC.YD_CARPNT_CD, 2, 1) = '2' THEN 3
                    WHEN SUBSTR(CC.YD_CARPNT_CD, 3, 1) = 'G' AND SUBSTR(CC.YD_CARPNT_CD, 2, 1) = '1' THEN 4
                    WHEN SUBSTR(CC.YD_CARPNT_CD, 3, 1) = 'F' AND SUBSTR(CC.YD_CARPNT_CD, 2, 1) = '1' THEN 5
                    WHEN SUBSTR(CC.YD_CARPNT_CD, 3, 1) = 'E' AND SUBSTR(CC.YD_CARPNT_CD, 2, 1) = '1' THEN 6
                    ELSE 7
                    END
                )
                --그외 출하 통로 우선순위
                --차량이 적은쪽 우선으로 들어감
                ELSE
                (
                    SELECT
                        COUNT(*)
                    FROM
                        TB_YD_CARSCH A
                    WHERE 1=1
                    AND A.DEL_YN='N'
                    AND A.YD_CARLD_STOP_LOC = CC.YD_STK_COL_GP
                )
                END 
            ) AS CARLD_RANK,
            CC.WLOC_CD,
            DECODE((
              SELECT 
                      COUNT(*) 
                FROM 
                      TB_YF_STOCK A
                    , TB_YF_CR_COILCOMM B
              WHERE 
                    A.TRANS_ORD_DATE  = :V_TRANS_ORD_DT
                AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
                AND A.STL_NO = B.COIL_NO
             ), 0, 'CR', 'HR') AS COIL_GP
        FROM
            (
                SELECT
                    TRANS_ORD_DATE,
                    TRANS_ORD_SEQNO,
                    A.STL_NO,
                    :V_YD_GP AS YD_GP
                FROM
                    TB_YF_STOCK A
                WHERE 1=1
                AND A.DEL_YN = 'N'
                AND A.TRANS_ORD_DATE  = :V_TRANS_ORD_DT
                AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
            ) AA,
            VW_YF_COILCOMM BB,
            USRYDA.TB_YD_CARPOINT CC
        WHERE 1=1
        AND AA.STL_NO = BB.COIL_NO
        AND CC.YD_CARPNT_CD LIKE AA.YD_GP || '%'
        AND BB.YD_GP = CC.YD_GP
        AND BB.YD_BAY_GP = CC.YD_BAY_GP
        AND BB.YD_EQP_GP BETWEEN CC.YD_SPAN_FROM AND CC.YD_SPAN_TO
        AND CC.YD_CAR_USETYPE_GP IN ('TR', 'RT', 'RA', 'TO') --트레일러
        AND CC.DEL_YN = 'N'
        ORDER BY CARLD_RANK, SUBSTR(YD_STK_COL_GP, 2, 1)
    )
WHERE 1=1
AND ROWNUM <= 1
 </pre> */
public final static String getYdCarPointSelect = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointSelect_PIDEV";

 /** <pre> 2020-03-24
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK
WITH TEMP_TABLE AS
(
    SELECT
        :V_YD_CARPNT_CD AS V_YD_CARPNT_CD,
        :V_CAR_KIND     AS V_CAR_KIND,
        (
            SELECT
                ITEM1
            FROM
                USRYFA.TB_YF_RULE
            WHERE 1=1
            AND REPR_CD_GP = 'J00002'
            AND CD_GP = '*'
            AND ITEM  = '*'
        ) AS PRE_SUP_YN
    FROM
        DUAL
)
--//TR--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C' --사용가능
AND B.V_CAR_KIND            = 'TR'
AND A.YD_CAR_USETYPE_GP     IN ('TR', 'RT', 'RA', 'TO')             --트레일러
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//TT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C' --사용가능
AND B.V_CAR_KIND            = 'TT'
AND A.YD_CAR_USETYPE_GP     IN ('TT', 'AT', 'RT', 'TO')         --TT_CAR
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//PT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C' --사용가능
AND B.V_CAR_KIND            = 'PT'
AND A.YD_CAR_USETYPE_GP     IN ('PT', 'GT', 'AT', 'RA', 'TO')   --PT
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))
 </pre> */
public final static String getYdCarPointCHK = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK";

 /** <pre> 2019-09-06
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getA7YML008SangChaEndChk
WITH DATA_TBL AS (
   SELECT TRANS_ORD_DATE
        , TRANS_ORD_SEQNO
     FROM TB_YF_STOCK 
    WHERE STL_NO = :V_STL_NO
)   
SELECT CASE WHEN STOCK_CNT > 0  AND STOCK_CNT <= LAYER_CNT THEN 'Y' 
            ELSE 'N' END AS SANG_CHA_END_YN
  FROM (
        SELECT (
                SELECT COUNT(*) 
                  FROM TB_YF_STOCK A
                     , DATA_TBL    B
                 WHERE A.TRANS_ORD_DATE  = B.TRANS_ORD_DATE
                   AND A.TRANS_ORD_SEQNO = B.TRANS_ORD_SEQNO
               )  AS STOCK_CNT    
             , (SELECT COUNT(DISTINCT(A.STL_NO)) + 1
                  FROM TB_YF_STKLYR A
                 WHERE ((SUBSTR(A.YD_STK_COL_GP,3,2) IN ('PT') AND YD_STK_LYR_STAT = 'C'))
                   AND STL_NO IN (SELECT B.STL_NO
                                      FROM TB_YF_STOCK B
                                         , DATA_TBL    C
                                     WHERE B.TRANS_ORD_DATE  = C.TRANS_ORD_DATE
                                       AND B.TRANS_ORD_SEQNO = C.TRANS_ORD_SEQNO )
               ) AS LAYER_CNT   
               
          FROM DUAL
      )
 </pre> */
public final static String getA7YML008SangChaEndChk = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getA7YML008SangChaEndChk";

 /** <pre> 2020-06-23
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCM
SELECT
    BB.YD_STK_COL_GP AS YD_STK_COL_GP,
    BB.YD_PNT_CD
FROM
    (
        SELECT
            MIN(A.YD_STK_COL_GP) AS YD_STK_COL_GP,
            A.YD_PNT_CD,
            SUM(A.COUNT) AS COUNT
        FROM
            (
                SELECT
                    YD_STK_COL_GP,
                    YD_PNT_CD,
                    1 AS COUNT
                FROM
                    TB_YF_STKCOL A
                WHERE 1=1
                AND SUBSTR(YD_STK_COL_GP, 3, 2) IN ('PT')
                AND WLOC_CD = :V_WLOC_CD
                AND BAY_GP  = :V_BAY_GP
                AND TRN_EQP_CD  IS NULL --현재차량정지위치
                AND CAR_CARD_NO IS NULL --예약차량정지위치
                AND CARD_NO     IS NULL
            )A
        GROUP BY YD_PNT_CD
    ) AA,
    TB_YD_CARPOINT BB
WHERE 1=1
AND AA.YD_STK_COL_GP = BB.YD_STK_COL_GP  
AND BB.YD_CAR_USETYPE_GP IN ('GT', 'TO')
AND BB.DEL_YN = 'N'
AND COUNT <= '2'
ORDER BY YD_PNT_CD DESC
 </pre> */
public final static String getListloadStoppointCM = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCM";

