 /** <pre> 2019-11-25
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L002ByLoc_SCRAP
-- 저장품제원정보_스크랩
SELECT JMS_TC_CD                                     --JMSTC코드
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTC생성일시
      ,JMS_TC_CD                                     --전문ID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')       --생성일시
     ||RPAD(NVL(MSG_GP                 ,'I'), 1,' ') --전문구분
     ||'0318'                                        --전문길이
     ||RPAD(' ',29,' ')                              --임시
     ||RPAD(NVL(YD_INFO_SYNC_CD        ,' '), 1,' ') --야드정보동기화코드
     ||RPAD(NVL(YD_STL_INFO_SND_SH     ,' '), 3,' ') --야드재료정보송신매수
     ||RPAD(NVL(YD_STL_INFO_SND_CNT    ,' '), 3,' ') --야드재료정보송신순번
     ||RPAD(NVL(STL_APPEAR_GP          ,' '), 1,' ') --재료외형구분
     ||RPAD(NVL(STL_NO               ,' '),11,' ') --재료번호
     ||RPAD(NVL(YD_STR_LOC             ,' '), 8,' ') --야드저장위치
     ||RPAD(NVL(YD_STK_LYR_NO         ,' '), 2,' ') --야드적치단번호
     ||LPAD(NVL(YD_STL_WT              ,'0'), 5,'0') --야드재료중량
     ||LPAD(NVL(YD_STL_T               ,'0'), 6,'0') --야드재료두께
     ||LPAD(NVL(YD_STL_W               ,'0'), 5,'0') --야드재료폭
     ||LPAD(NVL(YD_STL_L               ,'0'), 7,'0') --야드재료길이
     ||LPAD(NVL(MAT_ODIA               ,'0'), 5,'0') --재료외경
     ||LPAD(NVL(MAT_IDIA               ,'0'), 5,'0') --재료내경
     ||RPAD(NVL(STLKIND_CD             ,' '), 3,' ') --강종
     ||RPAD(NVL(SPEC_ABBSYM            ,' '),15,' ') --규격약호
     ||RPAD(NVL(YD_IPGO_DD             ,' '),14,' ') --야드입고일자
     ||RPAD(NVL(PLNT_PROC_CD           ,' '), 3,' ') --공장공정코드
     ||RPAD(NVL(CURR_PROG_CD           ,' '), 1,' ') --현재진도코드
     ||RPAD(NVL(ORD_YEOJAE_GP          ,' '), 1,' ') --주문여재구분
     ||RPAD(NVL(ORD_NO                 ,' '),10,' ') --주문번호
     ||RPAD(NVL(ORD_DTL                ,' '), 3,' ') --주문행번
     ||RPAD(NVL(BUY_SLAB_NO            ,' '),30,' ') --구입SLAB번호
     ||RPAD(NVL(SLAB_WO_RT_CD          ,' '), 2,' ') --SLAB지시행선코드
     ||RPAD(NVL(ORD_HCR_GP             ,' '), 1,' ') --설계HCR구분
     ||RPAD(NVL(HCR_GP                 ,' '), 1,' ') --HCR구분
     ||RPAD(NVL(CC_MC_CD               ,' '), 1,' ') --연주Machine코드          
     ||RPAD(NVL(SCARFING_YN            ,' '), 1,' ') --SCARFING여부             
     ||RPAD(NVL(SCARFING_DONE_YN       ,' '), 1,' ') --SCARFING완료유무         
     ||RPAD(NVL(RPR_MTD                ,' '), 1,' ') --주편손질방법             
     ||RPAD(NVL(SCARFING_DEPTH         ,' '), 2,' ') --SCARFING깊이             
     ||RPAD(NVL(REHEAT_SLAB_GP         ,' '), 1,' ') --재열재구분               
     ||RPAD(NVL(PTOP_PLNT_GP           ,' '), 2,' ') --조업공장구분             
     ||RPAD(NVL(REFUR_CHG_LOT_NO       ,' '),10,' ') --가열로장입Lot번호        
     ||LPAD(NVL(CT_LOT_SCH_SERNO       ,'0'),22,'0') --생산통제Lot스케줄일련번호
     ||RPAD(NVL(FRTOMOVE_ORD_DATE      ,' '), 8,' ') --이송지시일자             
     ||RPAD(NVL(FRTOMOVE_PLANT_GP      ,' '), 2,' ') --이송공장구분             
     ||RPAD(NVL(URGENT_FRTOMOVE_WORD_GP,' '), 1,' ') --긴급이송작업지시구분     
     ||RPAD(NVL(HYSCO_TRANS_CLS        ,' '), 1,' ') --HYSCO운송구분            
     ||RPAD(NVL(APPEAR_GRADE           ,' '), 1,' ') --외관종합판정등급         
     ||RPAD(NVL(COOL_METHOD            ,' '), 1,' ') --권취코일냉각방법         
     ||RPAD(NVL(COOL_DONE_GP           ,' '), 1,' ') --냉각완료구분             
     ||RPAD(NVL(CONV_BRANCH_CD         ,' '), 2,' ') --야드Conveyor분기코드     
     ||RPAD(NVL(CUST_KO_NAME           ,' '),40,' ') --고객사명                 
     ||RPAD(NVL(DEST_CD                ,' '), 5,' ') --목적지코드               
     ||RPAD(NVL(DLVRDD_RULE_DD         ,' '), 8,' ') --납기기준일               
     ||RPAD(NVL(ITEMNAME_CD            ,' '), 3,' ') --품명코드                 
     ||RPAD(NVL(OVERALL_STATAMP_GRADE  ,' '), 1,' ') --종합판정등급             
     ||RPAD(NVL(ORD_GP                 ,' '), 1,' ') --수주구분                 
     ||RPAD(NVL(YD_STK_LOT_TP          ,' '), 2,' ') --야드산적LotType          
     ||RPAD(NVL(YD_STK_LOT_CD          ,' '),18,' ') --야드산적Lot코드          
     ||RPAD(NVL(YD_PLAN_PROC           ,' '),10,' ') --계획공정                 
     ||RPAD(NVL(YD_PASS_PROC           ,' '),10,' ') --통과공정                 
     ||RPAD(NVL(YD_NEXT_PROC           ,' '), 2,' ') --다음공정                 
     ||RPAD(NVL(HRMILL_CMPL_DT         ,' '),14,' ') --열연압연완료일시         

       AS JMS_TC_MESSAGE --JMSTCMESSAGE
FROM (

        SELECT   'YFF1L002'                             AS JMS_TC_CD                --전문ID
               , :V_MSG_GP                              AS MSG_GP                   --전문구분
               , :V_YD_INFO_SYNC_CD                     AS YD_INFO_SYNC_CD          --야드정보동기화코드  
               , '001'                                  AS YD_STL_INFO_SND_SH       --야드재료정보송신매수
               , '001'                                  AS YD_STL_INFO_SND_CNT      --야드재료정보송신순번
               , NULL                                   AS STL_APPEAR_GP            --재료외형구분
               , ST.STL_NO                              AS STL_NO                 --재료번호
               , LY.YD_STK_COL_GP || LY.YD_STK_BED_NO   AS YD_STR_LOC               --야드저장위치
               , LY.YD_STK_LYR_NO                       AS YD_STK_LYR_NO           --야드적치단번호
               , '' AS YD_STL_WT
               , '' AS YD_STL_T
               , '' AS YD_STL_W
               , '' AS YD_STL_L
               , '' AS MAT_ODIA
               , '' AS MAT_IDIA
               , NULL                                   AS STLKIND_CD               --강종
               , NULL                                   AS SPEC_ABBSYM              --규격약호
               , NULL                                   AS YD_IPGO_DD               --야드입고일자
               , NULL                                   AS PLNT_PROC_CD             --공장공정코드
               , NULL                                   AS CURR_PROG_CD             --현재진도코드
               , NULL                                   AS ORD_YEOJAE_GP            --주문여재구분
               , NULL                                   AS ORD_NO                   --주문번호
               , NULL                                   AS ORD_DTL                  --주문행번
               , NULL                                   AS BUY_SLAB_NO              --구입SLAB번호
               , NULL                                   AS SLAB_WO_RT_CD            --SLAB지시행선코드
               , NULL                                   AS ORD_HCR_GP               --설계HCR구분
               , NULL                                   AS HCR_GP                   --HCR구분
               , NULL                                   AS CC_MC_CD                 --연주Machine코드
               , NULL                                   AS SCARFING_YN              --SCARFING여부
               , NULL                                   AS SCARFING_DONE_YN         --SCARFING완료유무
               , NULL                                   AS RPR_MTD                  --주편손질방법
               , NULL                                   AS SCARFING_DEPTH           --SCARFING깊이
               , NULL                                   AS REHEAT_SLAB_GP           --재열재구분
               , NULL                                   AS PTOP_PLNT_GP             --조업공장구분
               , NULL                                   AS REFUR_CHG_LOT_NO         --가열로장입Lot번호
               , NULL                                   AS CT_LOT_SCH_SERNO         --생산통제Lot스케줄일련번호
               , NULL                                   AS FRTOMOVE_ORD_DATE         --이송지시일자
               , NULL                                   AS FRTOMOVE_PLANT_GP         --이송공장구분
               , NULL                                   AS URGENT_FRTOMOVE_WORD_GP  --긴급이송작업지시구분
               , NULL                                   AS HYSCO_TRANS_CLS          --HYSCO운송구분
               , NULL                                   AS APPEAR_GRADE             --외관종합판정등급
               , NULL                                   AS COOL_METHOD              --권취코일냉각방법
               , NULL                                   AS COOL_DONE_GP             --냉각완료구분
               , NULL                                   AS CONV_BRANCH_CD           --야드Conveyor분기코드
               , NULL                                   AS CUST_KO_NAME             --고객사명
               , NULL                                   AS DEST_CD                  --목적지코드
               , NULL                                   AS DLVRDD_RULE_DD           --납기기준일
               , NULL                                   AS ITEMNAME_CD              --품명코드
               , NULL                                   AS OVERALL_STATAMP_GRADE    --종합판정등급
               , NULL                                   AS ORD_GP                   --수주구분
               , NULL                                   AS YD_STK_LOT_TP            --야드산적LotType
               , NULL                                   AS YD_STK_LOT_CD            --야드산적Lot코드
               , NULL                                   AS YD_PLAN_PROC  --계획공정
               , NULL                                   AS YD_PASS_PROC  --통과공정
               , NULL                                   AS YD_NEXT_PROC              --다음공정
               , NULL                                   AS HRMILL_CMPL_DT     --열연압연완료일시
          FROM   TB_YF_STOCK    ST
               , TB_YF_STKLYR   LY
         WHERE ST.STL_NO = LY.STL_NO
           AND LY.YD_STK_LYR_STAT IN ('C','U','L')
           AND LY.DEL_YN = 'N'
           AND LY.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'
           AND LY.YD_STK_BED_NO LIKE :V_YD_STK_BED_NO || '%'
     )
 </pre> */
public final static String getYFF1L002ByLoc_SCRAP = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L002ByLoc_SCRAP";

 /** <pre> 2019-09-06
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR011
SELECT 'YDDMR011'                          AS JMS_TC_CD          --JMSTC코드
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTC생성일시
     , 'YDDMR011'                          AS TC_CODE            --IF구분코드
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS TC_CREATE_DDTT     --TC생성일시
     , TS.CARD_NO                                                 --카드번호   
     , TS.CAR_NO                                                 --차량번호
     , SUBSTR(TS.YD_CARLD_STOP_LOC,1,1)    AS YD_GP              --야드구분
     , :V_GOODS_EA                         AS GOODS_EA           --제품개수완료시(*)
     , :V_STL_NO                         AS GOODS_NO           --제품번호
     , TS.TRANS_ORD_DATE                   AS TRANS_WORD_DATE                                        --운송지시일자
     , TS.TRANS_ORD_SEQNO                  AS TRANS_WORD_SEQNO                               --운송지시순번
  FROM USRYDA.TB_YD_CARSCH TS
 WHERE YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
 </pre> */
public final static String TcYDDMR011 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR011";

 /** <pre> 2019-10-31
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getWbookIdByLoc 
WITH PARAM AS(
SELECT :V_YD_STK_COL_GP AS P_YD_STK_COL_GP
     , :V_YD_STK_BED_NO AS P_YD_STK_BED_NO
  FROM DUAL
)
SELECT ST2.STL_NO
     , CS.TRANS_ORD_DATE
     , CS.TRANS_ORD_SEQNO
     , WB.YD_WBOOK_ID
     , SL.YD_STK_COL_GP
     , SL.YD_STK_BED_NO
     , SL.YD_STK_LYR_NO
  FROM TB_YF_STOCK       ST
     , TB_YD_CARSCH      CS
     , TB_YF_STOCK       ST2
     , TB_YF_WRKBOOK     WB
     , TB_YF_WRKBOOKMTL  WM
     , TB_YF_STKLYR  SL
 WHERE ST.STL_NO IN  (
                        SELECT STL_NO
                          FROM TB_YF_STKLYR, PARAM
                         WHERE YD_STK_COL_GP = P_YD_STK_COL_GP
                           AND YD_STK_BED_NO = P_YD_STK_BED_NO
                           AND YD_STK_LYR_NO = '01'
                           AND YD_STK_LYR_STAT = 'C'
                         UNION ALL
                        SELECT STL_NO
                          FROM TB_YF_STKLYR, PARAM
                         WHERE YD_STK_COL_GP = P_YD_STK_COL_GP
                           AND YD_STK_BED_NO = LPAD(TO_NUMBER(P_YD_STK_BED_NO) + 1, 2, '0')
                           AND YD_STK_LYR_NO = '01'
                           AND YD_STK_LYR_STAT = 'C' 
                       )
  AND ST.TRANS_ORD_DATE  = CS.TRANS_ORD_DATE
  AND ST.TRANS_ORD_SEQNO = CS.TRANS_ORD_SEQNO
  AND CS.DEL_YN = 'N'
  AND ST.TRANS_ORD_DATE  = ST2.TRANS_ORD_DATE
  AND ST.TRANS_ORD_SEQNO = ST2.TRANS_ORD_SEQNO
  AND WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
  AND SUBSTR(WB.YD_SCH_CD, 3,2) = 'PT'
  AND WB.DEL_YN = 'N'
  AND WM.DEL_YN = 'N'
  AND WB.YD_WBOOK_ID NOT IN (SELECT CS.YD_WBOOK_ID
                               FROM TB_YF_CRNSCH    CS
                                  , TB_YF_CRNWRKMTL CM
                              WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
                                AND CS.DEL_YN = 'N'
                                AND CM.DEL_YN = 'N'
                                AND CS.YD_GP  = '1')
  AND WM.STL_NO = ST2.STL_NO
  AND ST2.STL_NO = SL.STL_NO
 ORDER BY SL.YD_STK_LYR_NO DESC 
        , WB.YD_WBOOK_ID
 </pre> */
public final static String getWbookIdByLoc = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getWbookIdByLoc";

 /** <pre> 2020-11-24
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnWrkMgtjmNew_PIDEV 
  --크레인작업관리 스케줄조회
WITH TEMP_TABLE AS (
SELECT A.YD_CRN_SCH_ID
     , A.YD_WORD_DT
     , A.YD_WBOOK_ID
     , A.YD_SCH_CD
     , A.YD_EQP_ID
     , SUBSTR(A.YD_UP_WO_LOC, 2, 5) || TO_NUMBER(A.YD_UP_WO_LYR) ||  SUBSTR(A.YD_UP_WO_LOC, 7, 2) AS YD_UP_WO_LOC2
     , SUBSTR(A.YD_DN_WO_LOC, 2, 5) || TO_NUMBER(A.YD_DN_WO_LYR) ||  SUBSTR(A.YD_DN_WO_LOC, 7, 2) AS YD_DN_WO_LOC2
     , YD_DN_WO_LOC || YD_DN_WO_LYR AS YD_DN_LOC
     , NVL(YD_UP_WR_LOC , YD_UP_WO_LOC ) AS YD_UP_WO_LOC
     , NVL(YD_UP_WR_LYR, YD_UP_WO_LYR) AS YD_UP_WO_LYR
     , YD_DN_WO_LOC
     , YD_DN_WO_LYR
     , YD_EQP_WRK_SH
     , YD_EQP_WRK_WT
     , DECODE (A.YD_WRK_PROG_STAT, '1' , '선택'
                                 , '2' , '권상'
                                 , 'C' , '보류'
                                 , 'S' , '대기'
                                 ,' ') AS YD_WRK_PROG_STAT_NM
     , YD_SCH_PRIOR
     , B.STL_NO
     , A.YD_GP
     , A.YD_TO_LOC_DCSN_MTD
     , A.YD_WRK_PROG_STAT
     , TO_CHAR(A.YD_UP_CMPL_DT,'DD/ HH24:MI:SS') AS YD_UP_CMPL_DT
     , (SELECT COUNT(*) FROM TB_YF_CRNSCH WHERE YD_WBOOK_ID = A.YD_WBOOK_ID AND DEL_YN = 'N') AS STL_CNT
     , (CASE WHEN B.YD_AID_WRK_YN = 'Y' THEN '보조' ELSE '주' END ) AS YD_AID_WRK_YN
     , B.YD_AID_WRK_YN AS MAIN_CHK
     , SUBSTR(A.YD_UP_WO_LOC, 1, 1) AS DN_WO_LOC_YD
     , A.YD_L2_REQUEST_STAT
     , A.YD_WRK_PROG_REQ_MSG
     , A.YD_WRK_PARTY AS YD_SCH_ST_GP
     , MIN(A.YD_WRK_PROG_STAT||A.YD_CRN_SCH_ID||A.YD_SCH_CD||A.YD_EQP_ID) OVER (PARTITION BY A.YD_EQP_ID||A.YD_SCH_CD) AS CHK
     , A.YD_UP_WO_LOC_XAXIS
     , A.YD_UP_WO_LOC_YAXIS
     , A.YD_UP_WO_LOC_ZAXIS
     , A.YD_DN_WO_LOC_XAXIS
     , A.YD_DN_WO_LOC_YAXIS
     , A.YD_DN_WO_LOC_ZAXIS
     , CASE WHEN B.YD_AID_WRK_YN = 'Y' THEN '' 
        ELSE  (SELECT CASE WHEN CAR_NO IN ('9990','9991','9992','9993','9994') AND YD_SCH_CD LIKE '1_PT3__M' THEN CAR_NO
                    WHEN CAR_NO IS NOT NULL THEN CAR_NO
                    ELSE TRN_EQP_CD END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = A.YD_WBOOK_ID
       ) END AS CAR_CARD_NO
     , B.REG_DDTT AS SCH_CRE_DT
     , (SELECT CASE WHEN REGISTER = 'AUTO_MVSTK' THEN 'Y' ELSE 'N' END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = A.YD_WBOOK_ID) AS AUTO_YN
     , A.YD_SCH_REQ_GP --A냉각더미, B설비더미, C출하
     , ST.YD_RULE_PL_RS_GP  -- 조합
     ,(SELECT DTL_ITEM1
         FROM TB_YF_RULE Z
        WHERE Z.REPR_CD_GP = 'SCHRGB'
          AND Z.CD_GP = :V_MODIFIER
          AND Z.ITEM LIKE  SUBSTR(A.YD_SCH_CD,1,1) || '_' || SUBSTR(A.YD_SCH_CD,3)) AS SCH_COLOR
  FROM TB_YF_CRNSCH    A
     , TB_YF_CRNWRKMTL B
     , TB_YF_STOCK ST
 WHERE A.YD_CRN_SCH_ID=B.YD_CRN_SCH_ID
   AND B.STL_NO = ST.STL_NO
   AND A.DEL_YN = 'N'
   AND B.DEL_YN = 'N'
   AND A.YD_GP LIKE :V_YD_GP||'%'
   AND A.YD_BAY_GP LIKE :V_YD_BAY_GP||'%'
   AND A.YD_EQP_ID LIKE :V_YD_EQP_ID||'%'
   AND A.YD_SCH_CD LIKE :V_YD_SCH_CD||'%'
)
SELECT *
  FROM (
        SELECT ROWNUM RNUM
             , AA.*
             , CASE WHEN AA.PASS_CAR_TM >= 20 THEN 'Y' ELSE 'N' END AS  PASS_CAR_TM_YN
             , NVL((
                    SELECT
                       CA.CMBN_CARLD_YN
--                        CA.YD_CAR_SCH_ID
                        FROM TB_YF_WRKBOOK W
                        , TB_YF_WRKBOOKMTL WS
                        , TB_YD_CARSCH CA
                    WHERE  W.YD_WBOOK_ID = AA.YD_WBOOK_ID
                    AND W.YD_WBOOK_ID = WS.YD_WBOOK_ID
                    AND WS.STL_NO = AA.STL_NO
                    AND (W.TRN_EQP_CD = CA.TRN_EQP_CD OR W.CAR_NO = CA.CAR_NO)
                    AND CA.DEL_YN = 'N'
                    AND W.DEL_YN = 'N'
                    AND WS.DEL_YN = 'N'
               ), AA.YD_RULE_PL_RS_GP ) AS CMBN_CARLD_YN
          FROM (
                SELECT COUNT(*) OVER() AS TOTALCOUNT
                     , D.YD_SCH_PRIOR
                     , D.YD_SCH_PRIOR AS YD_SCH_PRIOR_ORG
                     , CASE WHEN F.YD_EQP_AUTO_CRN_MODE = '4' OR F.YD_EQP_AUTO_CRN_MODE = '5'
                            THEN F.YD_EQP_NAME||'[정지]'
                            ELSE F.YD_EQP_NAME
                            END AS YD_EQP_NAME
                     , E.CD_CONTENTS AS YD_SCH_CD_NM
                     , D.YD_AID_WRK_YN
                     , D.STL_NO
                     , D.YD_DN_LOC
                     , D.YD_UP_WO_LOC
                     , D.YD_UP_WO_LYR
                     , D.YD_UP_WO_LOC || D.YD_UP_WO_LYR AS YD_UP_WO_LOC_LYR
                     , D.YD_DN_WO_LOC
                     , D.YD_DN_WO_LYR
                     , D.YD_DN_WO_LOC||D.YD_DN_WO_LYR  AS YD_DN_WO_LOC_ORG
                     , D.YD_EQP_WRK_SH
                     , D.YD_EQP_WRK_WT
                     , TO_CHAR(D.YD_WORD_DT, 'DD/ HH24:MI:SS') AS YD_WORD_DT
                     , CASE WHEN D.YD_WRK_PROG_STAT NOT IN ('W', 'S') THEN
                       TRUNC(TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')) ||'/ ' ||
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')),1)*24), 2, '0') || ':' ||
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24,1)*60), 2, '0') ||':'||
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24*60,1)*60), 2, '0')
                       ELSE NULL END AS PASS_HR
                     , D.YD_TO_LOC_DCSN_MTD
                     , D.YD_WRK_PROG_STAT
                     , D.YD_WRK_PROG_STAT_NM
                     , D.YD_CRN_SCH_ID
                     , D.YD_WBOOK_ID
                     , D.YD_UP_CMPL_DT
                     , D.YD_EQP_ID
                     , CASE WHEN F.YD_EQP_AUTO_CRN_MODE = '4' OR F.YD_EQP_AUTO_CRN_MODE = '5'
                            THEN F.YD_EQP_NAME ||'[정지]'
                            WHEN F.YD_EQP_PROG_STAT = 'B'
                            THEN F.YD_EQP_NAME ||'[고장]'
                            WHEN F.YD_EQP_WRK_MODE = '2'
                            THEN F.YD_EQP_NAME ||'[off-line]'
                            ELSE F.YD_EQP_NAME
                            END YD_EQP_NM
                     , F.YD_EQP_WRK_MODE2 -- 야드설비운전모드 
                     , D.YD_SCH_CD
                     , D.STL_CNT
                     , D.MAIN_CHK
                     , D.DN_WO_LOC_YD
                     , D.YD_L2_REQUEST_STAT
                     , CASE WHEN D.STL_NO LIKE 'S%' AND (SELECT WRSLT_REAL_WT AS SCRAP_WT
                                                             FROM USRPOA.TB_PO_COILSHEARORD_SCRAP
                                                            WHERE SCRAP_COIL_NO = D.STL_NO
                                                              AND ROWNUM <= 1
                                                          ) IS NULL THEN '스크랩 정보가 없습니다. 조업L2에 문의하세요!!'
                            ELSE NVL(D.YD_WRK_PROG_REQ_MSG, (
                                                            SELECT MAX(SHEAR_INSPECT_MSG)
                                                              FROM TB_HR_C_SHEARWOWR
                                                             WHERE COIL_NO = D.STL_NO
                                                               AND STEP_NO = (SELECT MAX(STEP_NO)
                                                                                FROM TB_HR_C_SHEARWOWR
                                                                               WHERE COIL_NO = D.STL_NO)
                                                             ))
                        END AS YD_WRK_PROG_REQ_MSG
                     , YD_SCH_ST_GP
                     , D.YD_UP_WO_LOC_XAXIS
                     , D.YD_UP_WO_LOC_YAXIS
                     , D.YD_UP_WO_LOC_ZAXIS
                     , D.YD_DN_WO_LOC_XAXIS
                     , D.YD_DN_WO_LOC_YAXIS
                     , D.YD_DN_WO_LOC_ZAXIS
                     , D.CAR_CARD_NO
                     , CASE WHEN D.CAR_CARD_NO IS NOT NULL THEN TRUNC((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.SCH_CRE_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24*60) ELSE NULL
                       END AS PASS_CAR_TM
                     , E.ADV_CRN_PRIOR
                     , E.YD_SCH_AUTO_ST_YN
                     , D.YD_SCH_REQ_GP
                     , D.YD_RULE_PL_RS_GP
                     , D.SCH_COLOR
                  FROM TEMP_TABLE D
                     , TB_YF_SCHRULE E
                     , TB_YF_EQP F
                 WHERE D.YD_SCH_CD = E.YD_SCH_CD(+)
                   AND D.YD_EQP_ID = F.YD_EQP_ID(+)
                   AND D.YD_WRK_PROG_STAT||D.YD_CRN_SCH_ID||D.YD_SCH_CD||D.YD_EQP_ID = (SELECT MIN(CHK)
                                                                                          FROM TEMP_TABLE C
                                                                                         WHERE C.YD_WBOOK_ID=D.YD_WBOOK_ID
                                                                                           AND C.YD_EQP_ID  = D.YD_EQP_ID)
                 ORDER BY F.YD_EQP_NAME
                        , D.YD_WRK_PROG_STAT_NM DESC
                        , D.YD_SCH_PRIOR
                        , D.YD_CRN_SCH_ID
             ) AA
        WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE ) BB
 WHERE RNUM >= (( :V_PAGE_NO - 1 )* :V_PAGE_SIZE )+1
 </pre> */
public final static String getbtCrnWrkMgtjmNew = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnWrkMgtjmNew_PIDEV";

 /** <pre> 2020-12-03
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnWrkMgtjmMtlNew_PIDEV 
  --크레인작업관리 스케줄조회  
WITH TEMP_TABLE AS (  
            SELECT A.YD_CRN_SCH_ID  
                 , A.YD_WORD_DT  
                 , A.YD_WBOOK_ID  
                 , A.YD_SCH_CD  
                 , A.YD_EQP_ID  
                 , SUBSTR(A.YD_UP_WO_LOC, 2, 5) || TO_NUMBER(A.YD_UP_WO_LYR) ||  SUBSTR(A.YD_UP_WO_LOC, 7, 2) AS YD_UP_WO_LOC2  
                 , SUBSTR(A.YD_DN_WO_LOC, 2, 5) || TO_NUMBER(A.YD_DN_WO_LYR) ||  SUBSTR(A.YD_DN_WO_LOC, 7, 2) AS YD_DN_WO_LOC2  
                 , YD_DN_WO_LOC || YD_DN_WO_LYR AS YD_DN_LOC  
                 , NVL(YD_UP_WR_LOC , YD_UP_WO_LOC ) AS YD_UP_WO_LOC  
                 , NVL(YD_UP_WR_LYR, YD_UP_WO_LYR) AS YD_UP_WO_LYR  
                 , YD_DN_WO_LOC  
                 , YD_DN_WO_LYR  
                 , YD_EQP_WRK_SH  
                 , YD_EQP_WRK_WT  
                 , YD_EQP_WRK_STAT
                 , DECODE (A.YD_WRK_PROG_STAT, '1' , '선택'  
                                 , '2' , '권상'  
                                 , 'C' , '보류'  
                                 , 'S' , '대기'  
                                 ,' ') AS YD_WRK_PROG_STAT_NM   
                 , A.YD_WRK_PROG_STAT
                 , A.YD_SCH_PRIOR  
                 , B.STL_NO  
                 , A.YD_GP  
                 , A.YD_TO_LOC_DCSN_MTD   
                 , TO_CHAR(A.YD_UP_CMPL_DT,'DD/ HH24:MI:SS') AS YD_UP_CMPL_DT  
                 , (SELECT COUNT(*) FROM TB_YF_CRNSCH WHERE YD_WBOOK_ID = A.YD_WBOOK_ID AND DEL_YN = 'N') AS STL_CNT  
                 , (CASE WHEN B.YD_AID_WRK_YN = 'Y' THEN '보조' ELSE '주' END ) AS YD_AID_WRK_YN  
                 , B.YD_AID_WRK_YN AS MAIN_CHK  
                 , SUBSTR(A.YD_UP_WO_LOC, 1, 1) AS DN_WO_LOC_YD  
                 , A.YD_L2_REQUEST_STAT  
                 , A.YD_WRK_PROG_REQ_MSG  
                 , A.YD_WRK_PARTY AS YD_SCH_ST_GP  
                 , MIN(A.YD_WRK_PROG_STAT||A.YD_CRN_SCH_ID) OVER (PARTITION BY A.YD_WBOOK_ID ) AS CHK  
                 , A.YD_UP_WO_LOC_XAXIS  
                 , A.YD_UP_WO_LOC_YAXIS  
                 , A.YD_UP_WO_LOC_ZAXIS  
                 , A.YD_DN_WO_LOC_XAXIS  
                 , A.YD_DN_WO_LOC_YAXIS  
                 , A.YD_DN_WO_LOC_ZAXIS  
                 , CASE WHEN B.YD_AID_WRK_YN = 'Y'  THEN '' 
                    ELSE (SELECT CASE WHEN CAR_NO IN ('9990','9991','9992','9993','9994') THEN CAR_NO
                                WHEN CAR_NO IS NOT NULL THEN CAR_NO
                                ELSE TRN_EQP_CD END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = A.YD_WBOOK_ID
                   ) END AS CAR_CARD_NO  
                 , B.REG_DDTT AS SCH_CRE_DT              
                 , P.CURR_PROG_CD
                 , P.COIL_T   AS YD_MTL_T
                 , P.COIL_W   AS YD_MTL_W
                 , P.COIL_LEN AS YD_MTL_L
                 , CASE WHEN SUBSTR(B.STL_NO,1,1) = 'S' THEN A.YD_EQP_WRK_WT
                        ELSE P.COIL_WT END  AS YD_MTL_WT
                 , P.COIL_OUTDIA AS YD_MTL_OUTDIA
                 , P.ORD_NO || '-' || P.ORD_DTL AS ORD_NO_DTL       
                 , (SELECT CASE WHEN REGISTER = 'AUTO_MVSTK' THEN 'Y' ELSE 'N' END FROM TB_YF_WRKBOOK WHERE YD_WBOOK_ID = A.YD_WBOOK_ID) AS AUTO_YN
                 , CASE 
                        WHEN B.YD_ROUTE_GP IS NOT NULL THEN B.YD_ROUTE_GP
                    ELSE 
                        CASE 
                            WHEN W.YD_TO_LOC_DCSN_MTD = 'F' OR LENGTH(W.YD_TO_LOC_GUIDE) >= 4 THEN 'GD' -- 지정
                            WHEN W.YD_TO_LOC_DCSN_MTD = 'W' THEN 'MM' -- 동내 
                            ELSE 'GN'
                        END -- YD_TO_LOC_DCSN_MTD :: 
                        
                    END AS YD_ROUTE_GP
                 , CASE WHEN  W.YD_AIM_BAY_GP IS NOT NULL THEN W.YD_AIM_BAY_GP 
                    ELSE SUBSTR(A.YD_DN_WO_LOC,2,1) END AS YD_AIM_BAY_GP
              FROM TB_YF_CRNSCH    A  
                 , TB_YF_CRNWRKMTL B  
                 , VW_YF_COILCOMM  P
                 , TB_YF_STOCK S
                 , TB_YF_WRKBOOK W
             WHERE A.YD_CRN_SCH_ID=B.YD_CRN_SCH_ID  
               AND A.DEL_YN = 'N'  
               AND B.DEL_YN = 'N'  
               AND B.STL_NO      = P.COIL_NO(+)
               AND B.STL_NO      = S.STL_NO
               AND A.YD_WBOOK_ID = W.YD_WBOOK_ID
               AND A.YD_EQP_ID LIKE :V_YD_CRN_ID||'%'  
               AND A.YD_SCH_CD LIKE :V_YD_SCH_ID||'%'
           
)  
SELECT BB.*
       ,(SELECT REPR_CD_CONTENTS 
        FROM   USRYFA.TB_YF_RULE R,  VW_YF_GETCONDENSATIONLOC V 
        WHERE  R.REPR_CD_GP='YM6001' 
        AND    R.DEL_YN='N'
        AND    R.ITEM=V.YD_ZONE_GP
        AND    V.COIL_NO = BB.STL_NO) AS BZ_COIL
FROM ( 
        SELECT ROWNUM AS RNUM  --전체 SEQ
             , AA.*  
             , CASE WHEN AA.PASS_CAR_TM >= 20 THEN 'Y' ELSE 'N' END AS  PASS_CAR_TM_YN
          FROM (  
                SELECT COUNT(*) OVER() AS TOTALCOUNT  
                     , ROW_NUMBER() OVER(PARTITION BY YD_WBOOK_ID ORDER BY YD_CRN_SCH_ID) AS WRK_SEQ --작업예약별 작업순서
                     , D.YD_SCH_PRIOR  
                     , D.YD_SCH_PRIOR AS YD_SCH_PRIOR_ORG
                     , CASE WHEN F.YD_EQP_AUTO_CRN_MODE = '4' OR F.YD_EQP_AUTO_CRN_MODE = '5'  
                            THEN F.YD_EQP_NAME||'[정지]'  
                            ELSE F.YD_EQP_NAME  
                            END YD_EQP_NAME  
                     , E.CD_CONTENTS||DECODE(D.AUTO_YN, 'Y', '-A', '') AS YD_SCH_CD_NM  
                     , D.YD_CRN_SCH_ID  
                     , D.YD_WBOOK_ID  
                     , D.YD_AID_WRK_YN  
                     , D.STL_NO  
                     , D.YD_DN_LOC  
                     , D.YD_UP_WO_LOC  
                     , D.YD_UP_WO_LYR  
                     , D.YD_UP_WO_LOC || D.YD_UP_WO_LYR AS YD_UP_WO_LOC_LYR  
                     , D.YD_DN_WO_LOC  
                     , D.YD_DN_WO_LYR
                     , D.YD_DN_WO_LOC||D.YD_DN_WO_LYR  AS YD_DN_WO_LOC_ORG
                     , D.YD_EQP_WRK_SH  
                     , D.YD_EQP_WRK_WT  
                     , TO_CHAR(D.YD_WORD_DT, 'DD/ HH24:MI:SS') AS YD_WORD_DT  
                     , CASE WHEN D.YD_WRK_PROG_STAT NOT IN ('W', 'S') THEN 
                       TRUNC(TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')) ||'/ ' ||  
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')),1)*24), 2, '0') || ':' ||  
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24,1)*60), 2, '0') ||':'||  
                       LPAD(TRUNC(MOD((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.YD_WORD_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24*60,1)*60), 2, '0')  
                       ELSE NULL END AS PASS_HR  
                     , D.YD_TO_LOC_DCSN_MTD  
                     , D.YD_EQP_WRK_STAT  
                     , D.YD_WRK_PROG_STAT_NM  
                     , D.YD_WRK_PROG_STAT
                     , D.YD_UP_CMPL_DT  
                     , D.YD_EQP_ID  
                     , SUBSTR(D.YD_EQP_ID, 5, 6) AS YD_EQP_NM  
                     , F.YD_EQP_WRK_MODE2 -- 야드설비운전모드   
                     , D.YD_SCH_CD  
                     , D.STL_CNT  
                     , D.MAIN_CHK  
                     , D.DN_WO_LOC_YD  
                     , D.YD_L2_REQUEST_STAT  
                     , D.YD_WRK_PROG_REQ_MSG AS YD_WRK_PROG_REQ_MSG  
                     , D.YD_SCH_ST_GP  
                     , D.YD_UP_WO_LOC_XAXIS  
                     , D.YD_UP_WO_LOC_YAXIS  
                     , D.YD_UP_WO_LOC_ZAXIS  
                     , D.YD_DN_WO_LOC_XAXIS  
                     , D.YD_DN_WO_LOC_YAXIS  
                     , D.YD_DN_WO_LOC_ZAXIS  
                     , D.CAR_CARD_NO  
                     , CASE WHEN D.CAR_CARD_NO IS NOT NULL THEN TRUNC((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS') - TO_DATE(TO_CHAR(D.SCH_CRE_DT, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS'))*24*60) ELSE NULL
                       END AS PASS_CAR_TM                                         
                     , D.CURR_PROG_CD
                     , D.YD_MTL_T
                     , D.YD_MTL_W
                     , D.YD_MTL_L
                     , D.YD_MTL_WT
                     , D.YD_MTL_OUTDIA
                     , D.ORD_NO_DTL         
                     , E.ADV_CRN_PRIOR
                     , D.YD_ROUTE_GP
                     , D.YD_AIM_BAY_GP
                  FROM TEMP_TABLE D
                     , TB_YF_SCHRULE E  
                     , TB_YF_EQP F  
                 WHERE D.YD_SCH_CD = E.YD_SCH_CD(+)  
                   AND D.YD_EQP_ID = F.YD_EQP_ID(+)  
                 ORDER BY F.YD_EQP_NAME
                        , D.YD_WRK_PROG_STAT_NM DESC
                        , D.YD_SCH_PRIOR
                        , CASE WHEN D.YD_SCH_CD LIKE '1_DC01LM' THEN  TO_NUMBER(D.YD_CRN_SCH_ID) * -1
                               ---WHEN D.YD_SCH_CD LIKE '1EKD02LM' THEN  TO_NUMBER(D.YD_CRN_SCH_ID) * -1
                               ELSE TO_NUMBER(D.YD_CRN_SCH_ID) END
             ) AA
WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE 
) BB  
WHERE RNUM >= (( :V_PAGE_NO - 1 )* :V_PAGE_SIZE )+1
 </pre> */
public final static String getbtCrnWrkMgtjmMtlNew = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnWrkMgtjmMtlNew_PIDEV";

 /** <pre> 2020-03-26
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnStsSetPp 
--크레인상태변경 조회 - 
SELECT EQ.YD_EQP_GP AS YD_EQP_ID
      ,DECODE(EQ.YD_EQP_PROG_STAT,'B','B'   ,'N'   ) AS YD_EQP_STAT
      ,DECODE(EQ.YD_EQP_PROG_STAT,'B','고장','정상') AS YD_EQP_STAT_NM
      ,DECODE(EQ.YD_EQP_WRK_MODE,'1','1'      ,'2'       ) AS YD_EQP_WRK_MODE
      ,DECODE(EQ.YD_EQP_WRK_MODE,'1','On-Line','Off-Line') AS YD_EQP_WRK_MODE_NM
      ,EQ.YD_EQP_AUTO_CRN_MODE
      ,EQ.YD_EQP_WRK_MODE2
      ,CASE EQ.YD_EQP_WRK_MODE2 WHEN 'A' THEN '무인'
            WHEN 'R' THEN '리모컨'
            WHEN 'E' THEN '정비'
            WHEN 'M' THEN '유인'
            ELSE '' END AS YD_EQP_WRK_MODE2_NM
      ,CS.YD_CRN_SCH_ID
      ,CS.YD_WBOOK_ID
      ,CS.YD_SCH_CD
      ,(SELECT SR.CD_CONTENTS
          FROM TB_YF_SCHRULE SR
         WHERE SR.YD_SCH_CD = CS.YD_SCH_CD AND ROWNUM<=1) AS YD_SCH_CD_NM
      ,CS.YD_SCH_PRIOR
      ,CS.YD_WRK_PROG_STAT
      ,(SELECT BR.CD_MNNG
          FROM BRE.VW_CM_CODES BR
         WHERE BR.CD_EN_ID  = 'YD_WRK_PROG_STAT'
           AND BR.CD_CAT_ID = 'HS0000'
           AND BR.CD_VAL    = CS.YD_WRK_PROG_STAT) AS YD_WRK_PROG_STAT_NM
      ,CASE WHEN CS.YD_TO_LOC_DCSN_MTD IN ('W','Y') THEN '보조작업'
            WHEN CS.YD_TO_LOC_DCSN_MTD IS NOT NULL  THEN '주작업'
       END AS YD_WRK_GP
      ,CS.YD_UP_WO_LOC
      ,CS.YD_UP_WO_LYR
      ,CS.YD_UP_WO_LOC_XAXIS
      ,CS.YD_UP_WO_LOC_YAXIS
      ,CS.YD_UP_WO_LOC_ZAXIS
      ,CS.YD_DN_WO_LOC
      ,CS.YD_DN_WO_LYR
      ,CS.YD_DN_WO_LOC_XAXIS
      ,CS.YD_DN_WO_LOC_YAXIS
      ,CS.YD_DN_WO_LOC_ZAXIS
      ,TO_CHAR(CS.YD_WORD_DT   ,'YYYY-MM-DD HH24:MI:SS') AS YD_WORD_DT
      ,TO_CHAR(CS.YD_UP_CMPL_DT,'YYYY-MM-DD HH24:MI:SS') AS YD_UP_CMPL_DT
      ,CS.YD_EQP_WRK_SH
      ,TO_CHAR(CS.YD_EQP_WRK_WT,'FM999,999') AS YD_EQP_WRK_WT
      ,TO_CHAR(CS.YD_EQP_WRK_T ,'FM999,999') AS YD_EQP_WRK_T
      ,CS.YD_CRN_GRAB_USE_RULE_ID AS YD_AIM_RT_GP
  FROM TB_YF_EQP EQ
      ,(SELECT CS.YD_EQP_ID
              ,CS.YD_CRN_SCH_ID
              ,CS.YD_WBOOK_ID
              ,CS.YD_SCH_CD
              ,CS.YD_SCH_PRIOR
              ,CS.YD_WRK_PROG_STAT
              ,CS.YD_UP_WO_LOC
              ,CS.YD_UP_WO_LYR
              ,CS.YD_UP_WO_LOC_XAXIS
              ,CS.YD_UP_WO_LOC_YAXIS
              ,CS.YD_UP_WO_LOC_ZAXIS
              ,CS.YD_DN_WO_LOC
              ,CS.YD_DN_WO_LYR
              ,CS.YD_DN_WO_LOC_XAXIS
              ,CS.YD_DN_WO_LOC_YAXIS
              ,CS.YD_DN_WO_LOC_ZAXIS
              ,CS.YD_WORD_DT
              ,CS.YD_UP_CMPL_DT
              ,CS.YD_TO_LOC_DCSN_MTD
              ,CS.YD_EQP_WRK_SH
              ,CS.YD_EQP_WRK_WT
              ,CS.YD_EQP_WRK_T
              ,CS.YD_CRN_GRAB_USE_RULE_ID
              ,ROW_NUMBER() OVER (ORDER BY CASE 
                                            WHEN CS.YD_WRK_PROG_STAT IN ('W') THEN 1
                                            WHEN CS.YD_WRK_PROG_STAT IN ('S') THEN 2
                                            WHEN CS.YD_WRK_PROG_STAT IN ('1') THEN 3 
                                            WHEN CS.YD_WRK_PROG_STAT IN ('2') THEN 4
                                            WHEN CS.YD_WRK_PROG_STAT IN ('3') THEN 3
                                           END DESC,
                                            CS.YD_SCH_PRIOR, CS.YD_CRN_SCH_ID) AS CS_SEQ
          FROM TB_YF_CRNSCH CS
         WHERE CS.YD_EQP_ID = :V_YD_EQP_ID
           AND CS.YD_WRK_PROG_STAT IN ('S','W','1','2','3')
           AND CS.DEL_YN = 'N') CS
 WHERE EQ.YD_EQP_ID = CS.YD_EQP_ID(+)
   AND 1           = CS.CS_SEQ(+)
   AND EQ.YD_EQP_ID = :V_YD_EQP_ID
 </pre> */
public final static String getbtCrnStsSetPp = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getbtCrnStsSetPp";

 /** <pre> 2020-11-17
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L002ByLoc_PIDEV
-- 저장품제원정보
SELECT JMS_TC_CD                                     --JMSTC코드
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTC생성일시
      ,JMS_TC_CD                                     --전문ID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')       --생성일시
     ||RPAD(NVL(MSG_GP                 ,'I'), 1,' ') --전문구분
     ||'0318'                                        --전문길이
     ||RPAD(' ',29,' ')                              --임시
     ||RPAD(NVL(YD_INFO_SYNC_CD        ,' '), 1,' ') --야드정보동기화코드
     ||TO_CHAR(LEAST(COUNT(*) OVER (),999),'FM000')  --야드재료정보송신매수
     ||TO_CHAR(LEAST(ROWNUM          ,999),'FM000')  --야드재료정보송신순번
     ||RPAD(NVL(STL_APPEAR_GP          ,' '), 1,' ') --재료외형구분
     ||RPAD(NVL(STL_NO               ,' '),11,' ') --재료번호
     ||RPAD(NVL(YD_STR_LOC             ,' '), 8,' ') --야드저장위치
     ||RPAD(NVL(YD_STK_LYR_NO         ,' '), 2,' ') --야드적치단번호
     ||LPAD(NVL(YD_STL_WT              ,'0'), 5,'0') --야드재료중량
     ||LPAD(NVL(YD_STL_T               ,'0'), 6,'0') --야드재료두께
     ||LPAD(NVL(YD_STL_W               ,'0'), 5,'0') --야드재료폭
     ||LPAD(NVL(YD_STL_L               ,'0'), 7,'0') --야드재료길이
     ||LPAD(NVL(MAT_ODIA               ,'0'), 5,'0') --재료외경
     ||LPAD(NVL(MAT_IDIA               ,'0'), 5,'0') --재료내경
     ||RPAD(NVL(STLKIND_CD             ,' '), 3,' ') --강종
     ||RPAD(NVL(SPEC_ABBSYM            ,' '),15,' ') --규격약호
     ||RPAD(NVL(YD_IPGO_DD             ,' '),14,' ') --야드입고일자
     ||RPAD(NVL(PLNT_PROC_CD           ,' '), 3,' ') --공장공정코드
     ||RPAD(NVL(CURR_PROG_CD           ,' '), 1,' ') --현재진도코드
     ||RPAD(NVL(ORD_YEOJAE_GP          ,' '), 1,' ') --주문여재구분
     ||RPAD(NVL(ORD_NO                 ,' '),10,' ') --주문번호
     ||RPAD(NVL(ORD_DTL                ,' '), 3,' ') --주문행번
     ||RPAD(NVL(BUY_SLAB_NO            ,' '),30,' ') --구입SLAB번호
     ||RPAD(NVL(SLAB_WO_RT_CD          ,' '), 2,' ') --SLAB지시행선코드
     ||RPAD(NVL(ORD_HCR_GP             ,' '), 1,' ') --설계HCR구분
     ||RPAD(NVL(HCR_GP                 ,' '), 1,' ') --HCR구분
     ||RPAD(NVL(CC_MC_CD               ,' '), 1,' ') --연주Machine코드          
     ||RPAD(NVL(SCARFING_YN            ,' '), 1,' ') --SCARFING여부             
     ||RPAD(NVL(SCARFING_DONE_YN       ,' '), 1,' ') --SCARFING완료유무         
     ||RPAD(NVL(RPR_MTD                ,' '), 1,' ') --주편손질방법             
     ||RPAD(NVL(SCARFING_DEPTH         ,' '), 2,' ') --SCARFING깊이             
     ||RPAD(NVL(REHEAT_SLAB_GP         ,' '), 1,' ') --재열재구분               
     ||RPAD(NVL(PTOP_PLNT_GP           ,' '), 2,' ') --조업공장구분             
     ||RPAD(NVL(REFUR_CHG_LOT_NO       ,' '),10,' ') --가열로장입Lot번호        
     ||LPAD(NVL(CT_LOT_SCH_SERNO       ,'0'),22,'0') --생산통제Lot스케줄일련번호
     ||RPAD(NVL(FRTOMOVE_ORD_DATE      ,' '), 8,' ') --이송지시일자             
     ||RPAD(NVL(FRTOMOVE_PLANT_GP      ,' '), 2,' ') --이송공장구분             
     ||RPAD(NVL(URGENT_FRTOMOVE_WORD_GP,' '), 1,' ') --긴급이송작업지시구분     
     ||RPAD(NVL(HYSCO_TRANS_CLS        ,' '), 1,' ') --HYSCO운송구분            
     ||RPAD(NVL(APPEAR_GRADE           ,' '), 1,' ') --외관종합판정등급         
     ||RPAD(NVL(COOL_METHOD            ,' '), 1,' ') --권취코일냉각방법         
     ||RPAD(NVL(COOL_DONE_GP           ,' '), 1,' ') --냉각완료구분             
     ||RPAD(NVL(CONV_BRANCH_CD         ,' '), 2,' ') --야드Conveyor분기코드     
     ||RPAD(NVL(CUST_KO_NAME           ,' '),40,' ') --고객사명                 
     ||RPAD(NVL(DEST_CD                ,' '), 5,' ') --목적지코드               
     ||RPAD(NVL(DLVRDD_RULE_DD         ,' '), 8,' ') --납기기준일               
     ||RPAD(NVL(ITEMNAME_CD            ,' '), 3,' ') --품명코드                 
     ||RPAD(NVL(OVERALL_STATAMP_GRADE  ,' '), 1,' ') --종합판정등급             
     ||RPAD(NVL(ORD_GP                 ,' '), 1,' ') --수주구분                 
     ||RPAD(NVL(YD_STK_LOT_TP          ,' '), 2,' ') --야드산적LotType          
     ||RPAD(NVL(YD_STK_LOT_CD          ,' '),18,' ') --야드산적Lot코드          
     ||RPAD(NVL(YD_PLAN_PROC           ,' '),10,' ') --계획공정                 
     ||RPAD(NVL(YD_PASS_PROC           ,' '),10,' ') --통과공정                 
     ||RPAD(NVL(YD_NEXT_PROC           ,' '), 2,' ') --다음공정                 
     ||RPAD(NVL(HRMILL_CMPL_DT         ,' '),14,' ') --열연압연완료일시         

       AS JMS_TC_MESSAGE --JMSTCMESSAGE
FROM (

        SELECT   'YFF1L002'                             AS JMS_TC_CD                --전문ID
               , :V_MSG_GP                              AS MSG_GP                   --전문구분
               , :V_YD_INFO_SYNC_CD                     AS YD_INFO_SYNC_CD          --야드정보동기화코드  
               , '001'                                  AS YD_STL_INFO_SND_SH       --야드재료정보송신매수
               , '001'                                  AS YD_STL_INFO_SND_CNT      --야드재료정보송신순번
               , CC.STL_APPEAR_GP                       AS STL_APPEAR_GP            --재료외형구분
               , ST.STL_NO                              AS STL_NO                 --재료번호
               , LY.YD_STK_COL_GP || LY.YD_STK_BED_NO   AS YD_STR_LOC               --야드저장위치
               , LY.YD_STK_LYR_NO                       AS YD_STK_LYR_NO           --야드적치단번호
               , TO_CHAR(CC.COIL_WT    , 'FM00000'  )   AS YD_STL_WT                --야드재료중량
               , TO_CHAR(CC.COIL_T     , 'FM000V000')   AS YD_STL_T                 --야드재료두께
               , TO_CHAR(CC.COIL_W     , 'FM0000V0' )   AS YD_STL_W                 --야드재료폭
               , TO_CHAR(CC.COIL_LEN   , 'FM0000000')   AS YD_STL_L                 --야드재료길이
               , TO_CHAR(CC.COIL_OUTDIA, 'FM00000'  )   AS MAT_ODIA                 --재료외경
               , TO_CHAR(CC.COIL_INDIA , 'FM0000V0' )* 25.4   AS MAT_IDIA                 --재료내경
               , NULL                                   AS STLKIND_CD               --강종
               , CC.SPEC_ABBSYM                         AS SPEC_ABBSYM              --규격약호
               , CC.RECEIPT_DATE                        AS YD_IPGO_DD               --야드입고일자
               , CC.PLNT_PROC_CD                        AS PLNT_PROC_CD             --공장공정코드
               , CC.CURR_PROG_CD                        AS CURR_PROG_CD             --현재진도코드
               , CC.ORD_YEOJAE_GP                       AS ORD_YEOJAE_GP            --주문여재구분
               , CC.ORD_NO                              AS ORD_NO                   --주문번호
               , CC.ORD_DTL                             AS ORD_DTL                  --주문행번
               , NULL                                   AS BUY_SLAB_NO              --구입SLAB번호
               , NULL                                   AS SLAB_WO_RT_CD            --SLAB지시행선코드
               , OC.ORD_HCR_GP                          AS ORD_HCR_GP               --설계HCR구분
               , CC.HCR_GP                              AS HCR_GP                   --HCR구분
               , NULL                                   AS CC_MC_CD                 --연주Machine코드
               , NULL                                   AS SCARFING_YN              --SCARFING여부
               , NULL                                   AS SCARFING_DONE_YN         --SCARFING완료유무
               , NULL                                   AS RPR_MTD                  --주편손질방법
               , NULL                                   AS SCARFING_DEPTH           --SCARFING깊이
               , NULL                                   AS REHEAT_SLAB_GP           --재열재구분
               , CC.PTOP_PLNT_GP                        AS PTOP_PLNT_GP             --조업공장구분
               , NULL                                   AS REFUR_CHG_LOT_NO         --가열로장입Lot번호
               , NULL                                   AS CT_LOT_SCH_SERNO         --생산통제Lot스케줄일련번호
               , CC.FRTOMOVE_ORD_DATE                   AS FRTOMOVE_ORD_DATE         --이송지시일자
               , CC.FRTOMOVE_PLANT_GP                   AS FRTOMOVE_PLANT_GP         --이송공장구분
               , ''                                     AS URGENT_FRTOMOVE_WORD_GP  --긴급이송작업지시구분
               , SUBSTR(CC.COIL_GP,1,2)                 AS HYSCO_TRANS_CLS          --HYSCO운송구분
               , CC.APPEAR_GRADE                        AS APPEAR_GRADE             --외관종합판정등급
               , OC.COOL_METHOD                         AS COOL_METHOD              --권취코일냉각방법
               , CC.COOL_DONE_GP                                   AS COOL_DONE_GP             --냉각완료구분
               , NULL                                   AS CONV_BRANCH_CD           --야드Conveyor분기코드
               , (SELECT REPLACE(NAME_ORG1,'㈜','(주)') 
                    FROM USRCOM.TB_COM_BP_MASTER 
                   WHERE PARTNER = OC.CUST_CD)          AS CUST_KO_NAME             --고객사명
               , OC.DEST_CD                             AS DEST_CD                  --목적지코드
               , TO_CHAR(OC.ORD_CONS_DATE,'YYYYMMDD')   AS DLVRDD_RULE_DD           --납기기준일
               , CC.ITEMNAME_CD                         AS ITEMNAME_CD              --품명코드
               , CC.OVERALL_STAMP_GRADE                 AS OVERALL_STATAMP_GRADE    --종합판정등급
               , OC.ORD_GP                              AS ORD_GP                   --수주구분
               , NULL                                   AS YD_STK_LOT_TP             --야드산적LotType
               , NULL                                   AS YD_STK_LOT_CD             --야드산적Lot코드
               , CC.PLAN_PROC1||CC.PLAN_PROC2||CC.PLAN_PROC3||CC.PLAN_PROC4||CC.PLAN_PROC5  AS YD_PLAN_PROC  --계획공정
               , CC.PASS_PROC1||CC.PASS_PROC2||CC.PASS_PROC3||CC.PASS_PROC4||CC.PASS_PROC5  AS YD_PASS_PROC  --통과공정
               , CC.NEXT_PROC                           AS YD_NEXT_PROC              --다음공정
               , TO_CHAR(CC.HRMILL_CMPL_DT,'YYYYMMDDHH24MISS') AS HRMILL_CMPL_DT     --열연압연완료일시
               
          FROM 
                 TB_YF_STOCK ST
               , TB_YF_STKLYR LY
               , VW_YF_COILCOMM CC
               , TB_PT_OSCOMM OC
              
         WHERE LY.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'
           AND LY.YD_STK_BED_NO LIKE :V_YD_STK_BED_NO || '%'
           AND LY.YD_STK_LYR_STAT IN ('C','U','L')
           AND LY.DEL_YN = 'N'
           AND LY.STL_NO = ST.STL_NO 
           AND LY.STL_NO = CC.COIL_NO
           AND CC.ORD_NO  = OC.ORD_NO(+)        
           AND CC.ORD_DTL = OC.ORD_DTL(+) 
     )
 </pre> */
public final static String getYFF1L002ByLoc = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L002ByLoc_PIDEV";

 /** <pre> 2020-10-23
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarschCarGetInWorkByCarNoBackUp_PIDEV
-- 원본 ID : com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilYardCarExplainInfo.getYdCarschCarGetInWorkByCarNoBackUp
WITH TEMP_PARRAM AS (
SELECT MAX(YD_CAR_SCH_ID) AS YD_CAR_SCH_ID
  FROM USRYDA.TB_YD_CARSCH   CS
     , USRYDA.TB_YD_CARPOINT CP
 WHERE (CASE WHEN YD_CAR_PROG_STAT IN('2','3','4','5') THEN YD_CARLD_STOP_LOC
             ELSE YD_CARUD_STOP_LOC END) = CP.YD_STK_COL_GP
   AND CP.DEL_YN = 'N'
   AND CS.DEL_YN = 'N'
   AND CP.YD_GP = :V_YD_GP
   AND CP.CAR_NO = :V_CAR_NO
)
, TEMP_TABLE AS (
--//상차대상
SELECT   A.STL_NO AS STL_NO
       , B.CAR_NO
       , B.CARD_NO
       , B.CAR_KIND
       , B.TRN_EQP_CD
       , YD_CARLD_STOP_LOC AS STOP_LOC                                -- 상차
       , (CASE WHEN (B.CAR_KIND='TT') THEN (SELECT ITEM 
                                                                        FROM TB_YF_RULE CC
                                                                       WHERE CC.REPR_CD_GP='YM1001' --TTCar위치변환
                                                                         AND CC.CD_GP=A.YD_CAR_UPP_LOC_CD
                                                                     )
-- WHEN A.TRANS_ORD_SEQNO <= 700000 THEN NULL
               WHEN LM_TRN_COMM.TRANS_FRTOMOVE_GP NOT IN ('21','23') THEN NULL
               ELSE A.YD_CAR_UPP_LOC_CD END       
         ) AS YD_CAR_UPP_LOC_CD 
       , B.YD_CAR_WRK_GP
       , YD_CAR_PROG_STAT
       , YD_CAR_USE_GP
       , B.YD_CAR_SCH_ID
       , C.CMBN_CARLD_NO
       , C.TRANS_WORD_DATE
       , C.TRANS_WORD_SEQNO 
       , A.TRANS_ORD_DATE AS TRANS_ORD_DATE
       , A.TRANS_ORD_SEQNO AS TRANS_ORD_SEQNO
  FROM   TB_YF_STOCK A
       , USRYDA.TB_YD_CARSCH B
       , VW_LM_P_TRANSWORDCOMM  C
       , VW_YF_COILCOMM E
       , TEMP_PARRAM D
       , VW_LM_P_TRANSWORDCOMM LM_TRN_COMM
 WHERE A.TRANS_ORD_DATE=B.TRANS_ORD_DATE
   AND A.TRANS_ORD_SEQNO=B.TRANS_ORD_SEQNO
   AND A.TRANS_ORD_DATE=LM_TRN_COMM.TRANS_WORD_DATE
   AND A.TRANS_ORD_SEQNO=LM_TRN_COMM.TRANS_WORD_SEQNO
   AND B.YD_CAR_SCH_ID =D.YD_CAR_SCH_ID
   AND A.STL_NO=E.COIL_NO
   AND A.TRANS_ORD_DATE=C.TRANS_WORD_DATE(+)
   AND A.TRANS_ORD_SEQNO=C.TRANS_WORD_SEQNO(+) 
   AND E.YD_BAY_GP=SUBSTR(YD_CARLD_STOP_LOC,2,1)
   AND B.CAR_NO NOT IN ('9990','9991','9992','9993','9994')
   AND B.YD_CAR_USE_GP='G'
   AND B.SPOS_WLOC_CD IN ('D2Y44','D2Y45')
   AND YD_CAR_PROG_STAT IN ('1','2','3','4','5') 
UNION ALL
   --//하차대상
SELECT   F.STL_NO AS STL_NO
       , B.CAR_NO
       , B.CARD_NO
       , B.CAR_KIND
       , B.TRN_EQP_CD
       , YD_CARUD_STOP_LOC AS STOP_LOC                                -- 하차
       , F.YD_STK_BED_NO AS    YD_CAR_UPP_LOC_CD    
       , B.YD_CAR_WRK_GP
       , B.YD_CAR_PROG_STAT
       , B.YD_CAR_USE_GP
       , B.YD_CAR_SCH_ID
       , '' AS CMBN_CARLD_NO
       , B.TRANS_ORD_DATE AS TRANS_WORD_DATE
       , B.TRANS_ORD_SEQNO AS TRANS_WORD_SEQNO 
       , B.TRANS_ORD_DATE
       , B.TRANS_ORD_SEQNO
  FROM   USRYDA.TB_YD_CARSCH B
       , TEMP_PARRAM D
       , USRYDA.TB_YD_CARFTMVMTL F
 WHERE B.YD_CAR_SCH_ID =D.YD_CAR_SCH_ID
   AND B.YD_CAR_SCH_ID =F.YD_CAR_SCH_ID  
   AND B.CAR_NO NOT IN ('9990','9991','9992','9993','9994')
   AND B.YD_CAR_USE_GP='G'
   AND B.SPOS_WLOC_CD IN ('D2Y44','D2Y45')
   AND B.YD_CAR_PROG_STAT IN('A','B','C','D','E') 
   AND F.DEL_YN = 'N'
)
, TEMP_TRANSWORDCOMM AS (
 SELECT NVL(MAX(C.TRANS_WORD_DATE),'99999999') AS TRANS_WORD_DATE,  NVL(MAX(C.TRANS_WORD_SEQNO),0) AS TRANS_WORD_SEQNO
   FROM VW_LM_P_TRANSWORDCOMM  C
       ,TEMP_TABLE D
  WHERE C.CMBN_CARLD_NO=D.CMBN_CARLD_NO
)  

SELECT *
  FROM (
SELECT ROWNUM AS RNUM
     , INFO.*
  FROM (     

SELECT COUNT(1) OVER(PARTITION BY YD_CAR_NO ) AS YD_WORK_COIL_MAX_CNT
     , A.* 
FROM (
----------------------------------------------------------------------
SELECT  A.YD_CAR_SCH_ID
       ,A.STL_NO  AS YD_STL_NO
       ,(CASE WHEN CHK=1 THEN (SELECT STOP_LOC FROM TEMP_TABLE WHERE ROWNUM<=1) ELSE STOP_LOC END)     AS YD_PT_LOAD_LOC
       ,A.CAR_NO    AS YD_CAR_NO
       ,A.CARD_NO   AS YD_CARD_NO
       ,A.PT_CLS    AS YD_PT_CLS
       , (CASE 
              WHEN A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN 
                  CASE  WHEN A.CAR_NO in ('9990','9991','9992','9993','9994') THEN '4'
                        WHEN A.YD_CAR_USE_GP= 'G' AND ( A.CAR_KIND ='TT' OR A.CAR_KIND ='PT') THEN '4'
                        WHEN A.YD_CAR_USE_GP= 'G' THEN '2' -- 출하출고
                  ELSE '4'  -- 구내출고 
                  END
              WHEN A.YD_CAR_PROG_STAT IN ('A','B','C','D','E') THEN
                  CASE WHEN A.CAR_NO in ('9990','9991','9992','9993','9994') THEN '3'
                       WHEN A.YD_CAR_USE_GP= 'G' AND ( A.CAR_KIND ='TT' OR A.CAR_KIND ='PT') THEN '3'
                       WHEN A.YD_CAR_USE_GP= 'G' THEN '1' -- 출하입고
                       ELSE '3'  -- 구내입고
                  END
              END) YD_WORK_CLS
       ,'    '             AS YD_PT_WTH
       ,'    '             AS YD_PT_LEN
       ,'    '             AS YD_PT_HEIGHT
       ,'    '             AS YD_RAIN_CLS
       
       ,A.STOP_LOC         AS YD_CURR_BAY_GP -- 동정보(차량적재위치)
       ,DECODE(NVL(A.YD_CAR_UPP_LOC_CD,'00'),'00',LPAD(ROWNUM,2,'0'),A.YD_CAR_UPP_LOC_CD) AS YD_CAR_UPP_LOC_CD--YD_LOAD_LOC_CD -- 상차위치코드
       ,C.COIL_WT          AS YD_COIL_WT -- 중량
       ,C.COIL_T           AS YD_COIL_T  -- 두께
       ,C.COIL_W           AS YD_COIL_W  -- 폭
       ,C.COIL_LEN         AS YD_COIL_LEN -- 길이
       ,C.COIL_OUTDIA      AS YD_COIL_OUTDIA -- 외경
       ,C.COIL_INDIA       AS YD_COIL_INDIA -- 내경
       ,(CASE WHEN CHK2 =2 THEN '*' 
             WHEN YD_CAR_PROG_STAT IN('5','E') THEN '*'
             WHEN YD_CAR_PROG_STAT IN('1','2','3','4') AND YD_EQP_GP='PT' THEN '*'
             WHEN YD_CAR_PROG_STAT IN('A','B','C','D') AND C.YD_GP IN ('0','1') AND YD_EQP_GP BETWEEN '00' AND '99' THEN '*'
             ELSE '0'
         END) YD_WORK_STATE
       ,CHK2 
       ,CHK
       ,YD_CAR_PROG_STAT
       ,YD_GP
 FROM (
        --출하
        SELECT  1 AS CHK 
              , A.STL_NO
              , CAR_NO
              , CARD_NO
              , STOP_LOC
              , YD_CAR_UPP_LOC_CD
              , LPAD((CASE WHEN CAR_KIND IS NULL THEN SUBSTR(TRN_EQP_CD,2,2) ELSE CAR_KIND END),2,' ') AS PT_CLS
              , YD_CAR_WRK_GP
              , YD_CAR_PROG_STAT
              , YD_CAR_USE_GP
              , CAR_KIND
              , YD_CAR_SCH_ID
              , CHK2
         FROM ( --//일반차량
                SELECT DISTINCT 
                        1 AS CHK2
                       , STL_NO 
                       , CAR_NO
                       , CARD_NO
                       , CAR_KIND
                       , TRN_EQP_CD
                       , STOP_LOC                                -- 하차
                       , YD_CAR_UPP_LOC_CD    
                       , YD_CAR_WRK_GP
                       , YD_CAR_PROG_STAT
                       , YD_CAR_USE_GP
                       , YD_CAR_SCH_ID 
                  FROM TEMP_TABLE
                UNION ALL
                --//복수상차완료 차량(조합상차번호)
                SELECT  DISTINCT
                         2 AS CHK2
                       , A.STL_NO AS STL_NO 
                       , B.CAR_NO
                       , B.CARD_NO
                       , B.CAR_KIND
                       , B.TRN_EQP_CD
                       , (CASE WHEN YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN YD_CARLD_STOP_LOC  -- 상차
                               ELSE YD_CARUD_STOP_LOC END) AS STOP_LOC                                -- 하차
                       , (CASE WHEN (B.CAR_KIND='TT') THEN (SELECT ITEM 
                                                                                        FROM TB_YF_RULE CC
                                                                                       WHERE CC.REPR_CD_GP='YM1001' --TTCar위치변환
                                                                                         AND CC.CD_GP=A.YD_CAR_UPP_LOC_CD
                                                                                     )
                               ELSE A.YD_CAR_UPP_LOC_CD END
                         ) AS YD_CAR_UPP_LOC_CD    
                       , B.YD_CAR_WRK_GP
                       , YD_CAR_PROG_STAT
                       , YD_CAR_USE_GP
                       , B.YD_CAR_SCH_ID                    
                  FROM   TB_YF_STOCK A
                       , TB_YD_CARSCH B  
                       , VW_YF_COILCOMM E
                       , TEMP_TRANSWORDCOMM F
                 WHERE A.TRANS_ORD_DATE=B.TRANS_ORD_DATE
                   AND A.TRANS_ORD_SEQNO=B.TRANS_ORD_SEQNO
                   AND A.TRANS_ORD_DATE=F.TRANS_WORD_DATE
                   AND A.TRANS_ORD_SEQNO=F.TRANS_WORD_SEQNO
                   AND A.STL_NO=E.COIL_NO
                   AND B.YD_CAR_SCH_ID||'' >=TO_CHAR(SYSDATE-3,'YYYYMMDD')||'%' 
                   AND E.YD_BAY_GP=SUBSTR((CASE WHEN B.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN B.YD_CARLD_STOP_LOC ELSE B.YD_CARUD_STOP_LOC END),2,1)
                   AND B.DEL_YN='Y' 
                   AND B.YD_CAR_PROG_STAT ='5'
                   AND B.YD_CAR_USE_GP='G' 
                   AND A.CAR_NO NOT IN ('9990','9991','9992','9993','9994')
                   AND A.STL_NO NOT IN (SELECT STL_NO FROM TEMP_TABLE)
                   AND B.YD_CAR_SCH_ID||''  NOT IN (SELECT YD_CAR_SCH_ID FROM TEMP_TABLE)
                 
                 UNION ALL
--                 //복수상차완료 차량(복수창고,복수동 운송지시번호 동일한경우)
                 SELECT DISTINCT
                         3 AS CHK2
                       , A.STL_NO AS STL_NO 
                       , B.CAR_NO
                       , B.CARD_NO
                       , B.CAR_KIND
                       , B.TRN_EQP_CD
                       , (CASE WHEN YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN YD_CARLD_STOP_LOC  -- 상차
                               ELSE YD_CARUD_STOP_LOC END) AS STOP_LOC                                -- 하차
                       , (CASE WHEN (B.CAR_KIND='TT') THEN (SELECT ITEM 
                                                                                        FROM TB_YF_RULE CC
                                                                                       WHERE CC.REPR_CD_GP='YM1001' --TTCar위치변환
                                                                                         AND CC.CD_GP=A.YD_CAR_UPP_LOC_CD

                                                                                     )
                               ELSE A.YD_CAR_UPP_LOC_CD END
                         ) AS YD_CAR_UPP_LOC_CD    
                       , B.YD_CAR_WRK_GP
                       , YD_CAR_PROG_STAT
                       , YD_CAR_USE_GP
                       , B.YD_CAR_SCH_ID                    
                  FROM   TB_YF_STOCK A
                       , TB_YD_CARSCH B 
                       , VW_YF_COILCOMM E
                 WHERE A.TRANS_ORD_DATE IS NOT NULL
                   AND A.TRANS_ORD_SEQNO  IS NOT NULL
                   AND A.TRANS_ORD_DATE=B.TRANS_ORD_DATE
                   AND A.TRANS_ORD_SEQNO=B.TRANS_ORD_SEQNO
                   AND A.STL_NO=E.COIL_NO
                   AND B.YD_CAR_SCH_ID NOT IN (SELECT YD_CAR_SCH_ID FROM TEMP_TABLE)
                   AND E.YD_BAY_GP=SUBSTR((CASE WHEN B.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN B.YD_CARLD_STOP_LOC ELSE B.YD_CARUD_STOP_LOC END),2,1)
                   AND B.DEL_YN='Y'
                   AND A.DEL_YN='Y'
                   AND B.YD_CAR_PROG_STAT ='5'
                   AND B.CAR_NO NOT IN ('9990','9991','9992','9993','9994')
                   AND B.YD_CAR_USE_GP='G' 
                   AND A.STL_NO NOT IN (SELECT STL_NO FROM TEMP_TABLE)
                   AND (A.TRANS_ORD_DATE, A.TRANS_ORD_SEQNO) IN ( SELECT TRANS_ORD_DATE ,TRANS_ORD_SEQNO
                                                                   FROM TEMP_TABLE
                                                                 )
                    
                 UNION ALL
                 --//복수상차완료 차량(복수창고(일관제철)운송지시번호 동일한경우)
                 SELECT DISTINCT
                         4 AS CHK2
                       , A.STL_NO 
                       , B.CAR_NO
                       , B.CARD_NO
                       , B.CAR_KIND
                       , B.TRN_EQP_CD
                       , (CASE WHEN YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN YD_CARLD_STOP_LOC  -- 상차
                               ELSE YD_CARUD_STOP_LOC END) AS STOP_LOC                                -- 하차
                       , (CASE WHEN (B.CAR_KIND='TT' OR A.CR_FRTOMOVE_GP='81') THEN (SELECT ITEM 
                                                                                        FROM TB_YF_RULE CC
                                                                                       WHERE CC.REPR_CD_GP='YM1001' --TTCar위치변환
                                                                                         AND CC.CD_GP=A.YD_CAR_UPP_LOC_CD
                                                                                    )
                          ELSE A.YD_CAR_UPP_LOC_CD END
                         )AS    YD_CAR_UPP_LOC_CD    
                       , B.YD_CAR_WRK_GP
                       , YD_CAR_PROG_STAT
                       , YD_CAR_USE_GP
                       , B.YD_CAR_SCH_ID                    
                  FROM   TB_YD_STOCK A
                       , USRYDA.TB_YD_CARSCH B 
                       , VW_YF_COILCOMM E
                 WHERE A.TRANS_ORD_DATE=B.TRANS_ORD_DATE
                   AND A.TRANS_ORD_SEQNO=B.TRANS_ORD_SEQNO
                   AND A.STL_NO=E.COIL_NO
                   AND B.YD_CAR_SCH_ID NOT IN (SELECT YD_CAR_SCH_ID FROM TEMP_TABLE)
                   AND E.YD_BAY_GP=SUBSTR((CASE WHEN B.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN B.YD_CARLD_STOP_LOC ELSE B.YD_CARUD_STOP_LOC END),2,1)
                   AND B.DEL_YN='Y'
                   AND A.DEL_YN='Y'
                   AND B.YD_CAR_PROG_STAT ='5'
                   AND B.CAR_NO NOT IN ('7777','8888','9990','9991','9992','9993','9994','9999','9998','9997','9996','9995')
                   AND B.YD_CAR_USE_GP='G' 
                   AND A.STL_NO NOT IN (SELECT STL_NO FROM TEMP_TABLE)
                   AND (A.TRANS_ORD_DATE, A.TRANS_ORD_SEQNO) IN ( SELECT TRANS_ORD_DATE ,TRANS_ORD_SEQNO
                                                                   FROM TEMP_TABLE
                                                                 )
                   
                ) A
                
        UNION ALL
--        --구내운송 
         SELECT DISTINCT
                2 AS CHK 
              , D.STL_NO AS STL_NO 
              , A.TRN_EQP_CD
              , A.CARD_NO
              , (CASE WHEN YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN YD_CARLD_STOP_LOC ELSE YD_CARUD_STOP_LOC END) AS STOP_LOC 
              , LPAD(ROWNUM,2,'0') AS YD_CAR_UPP_LOC_CD
              , LPAD((SUBSTR(A.TRN_EQP_CD,2,2)),2,' ') AS PT_CLS
              , A.YD_CAR_WRK_GP
              , A.YD_CAR_PROG_STAT
              , A.YD_CAR_USE_GP
              , A.CAR_KIND
              , A.YD_CAR_SCH_ID
              , 3 AS CHK2
            FROM USRYDA.TB_YD_CARSCH A
            , TB_YF_STOCK D
            , TEMP_PARRAM E
            WHERE A.FRTOMOVE_WORD_NO  = D.FRTOMOVE_WORD_NO
              AND A.YD_CAR_SCH_ID =E.YD_CAR_SCH_ID
              AND A.YD_CAR_USE_GP='L'
              AND NVL(A.CAR_NO,A.TRN_EQP_CD) NOT IN ('9990','9991','9992','9993','9994')
              AND A.DEL_YN='N'
              AND (A.SPOS_WLOC_CD IN ('D2Y44','D2Y45') OR A.ARR_WLOC_CD IN ('D2Y44','D2Y45') )
              AND A.YD_CAR_SCH_ID||'' NOT IN (SELECT YD_CAR_SCH_ID FROM TEMP_TABLE)
        UNION
        --차량동간이적
        SELECT  DISTINCT
                2 AS CHK 
              , CM.STL_NO 
              , A.CAR_NO AS TRN_EQP_CD 
              , A.CARD_NO
              , (CASE WHEN YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN YD_CARLD_STOP_LOC ELSE YD_CARUD_STOP_LOC END) AS STOP_LOC 
              , '00' AS YD_CAR_UPP_LOC_CD
              , LPAD((CASE WHEN A.CAR_KIND IS NULL THEN SUBSTR(A.TRN_EQP_CD,2,2) ELSE A.CAR_KIND END),2,' ') AS PT_CLS
              , A.YD_CAR_WRK_GP
              , YD_CAR_PROG_STAT
              , A.YD_CAR_USE_GP
              , A.CAR_KIND
              , A.YD_CAR_SCH_ID
              , 3 AS CHK2
         FROM USRYDA.TB_YD_CARSCH A
            , USRYDA.TB_YD_CARFTMVMTL CM
            , TB_YF_STOCK D
            , TEMP_PARRAM E
        WHERE CM.STL_NO=D.STL_NO
          AND A.YD_CAR_SCH_ID =E.YD_CAR_SCH_ID
          AND A.YD_CAR_SCH_ID = CM.YD_CAR_SCH_ID 
          AND A.YD_CAR_USE_GP='G'
          AND A.DEL_YN='N'
          AND CM.DEL_YN='N'
          AND A.CAR_NO IN ('9990','9991','9992','9993','9994')
          AND (A.SPOS_WLOC_CD IN ('D2Y44','D2Y45') OR A.ARR_WLOC_CD IN ('D2Y44','D2Y45') )
          AND A.YD_CAR_SCH_ID||'' NOT IN (SELECT YD_CAR_SCH_ID FROM TEMP_TABLE)
    ) A
    , VW_YF_COILCOMM C
    WHERE A.STL_NO = C.COIL_NO  
----------------------------------------------------------------------
) A  
ORDER BY YD_WORK_STATE,YD_CAR_UPP_LOC_CD
      ) INFO
      ) INFO
     , (SELECT ROWNUM AS RNUM
          FROM DUAL
       CONNECT BY LEVEL <= 15
       ) R
 WHERE R.RNUM = INFO.RNUM(+)
 </pre> */
public final static String getYdCarschCarGetInWorkByCarNoBackUp = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarschCarGetInWorkByCarNoBackUp_PIDEV";

