 /** <pre> 2020-12-15
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getCurrProgCd 
SELECT T.CD_VAL, T.CD_NM
FROM (
    SELECT CD_VAL
         , CD_MNNG AS CD_NM
         , SORT_SEQ
      FROM BRE.VW_CM_CODES 
     WHERE CD_EN_ID  = 'CURR_PROG_CD'
       AND CD_CAT_ID = 'PT0110'
       AND '0' = :V_YD_GP
UNION ALL
    SELECT
           CD_VAL
         , CD_MNNG AS CD_NM
         , SORT_SEQ
    FROM 
    (
        SELECT B.CURR_PROG_CD
        FROM TB_YF_STOCK A, VW_YF_COILCOMM B
        WHERE A.STL_NO = B.COIL_NO
        AND A.DEL_YN = 'N'
        GROUP BY B.CURR_PROG_CD
    ) A, BRE.VW_CM_CODES B
    WHERE A.CURR_PROG_CD = B.CD_VAL
    AND B.CD_EN_ID = 'CURR_PROG_CD'
    AND B.CD_CAT_ID = 'YD0002' 
    AND '1' = :V_YD_GP
) T
ORDER BY DECODE(T.CD_VAL, 'B', 1, 'C', 2, 'D', 3, 'E', 4, 'K', 5, 99), SORT_SEQ
 </pre> */
public final static String getCurrProgCd = "com.inisteel.cim.yf.common.dao.YfCommDAO.getCurrProgCd";

