 /** <pre> 2019-09-30
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCustCdPp_PIDEV  
SELECT WB.*
  FROM (SELECT ROWNUM AS RNUM
             , WB.*
          FROM ( SELECT  COUNT(*) OVER() AS TOTALCOUNT
                             , PARTNER AS CUST_CD
                             , NAME_ORG1 AS CUST_KO_NAME
                             , STREET || ' ' || STR_SUPPL1 AS ADDRESS
                             , STCD2 AS COMREGNO
                       FROM USRCOM.TB_COM_BP_MASTER
                       WHERE PARTNER LIKE :V_CUST_CD || '%'
                       AND   NAME_ORG1 LIKE '%' || :V_CUST_KO_NAME || '%'
                       AND   STCD2 LIKE :V_COMREGNO || '%') WB
         WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE) WB
 WHERE RNUM >= (( :V_PAGE_NO -1)* :V_PAGE_SIZE ) + 1
 </pre> */
public final static String getCustCdPp = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCustCdPp_PIDEV";

 /** <pre> 2019-11-14
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.aslabCommDtlInqjl.getSlabcommRecordProgStat 
SELECT NVL((SELECT A.RECORD_PROG_STAT 
              FROM TB_PT_SLABCOMM A 
             WHERE A.SLAB_NO=M.SLAB_NO),'') AS RECORD_PROG_STAT
      , M.SLAB_NO 
      , M.MSLAB_NO
      , M.SLAB_GP
      , NVL((
            SELECT A.STL_NO
              FROM USRPTA.TB_PT_STLFRTOMOVE A
            WHERE A.TRANSWORD_SEQNO =(SELECT MAX(TRANSWORD_SEQNO)
                                        FROM TB_PT_STLFRTOMOVE B
                                      WHERE A.STL_NO=B.STL_NO
                                      )
              AND A.STL_NO=M.SLAB_NO
              AND A.FRTOMOVE_STAT_CD in ('3','*')
              AND A.ARR_WLOC_CD='D2Y43'
      ),'N') AS TRANSWORD_YN
      ,M.CURR_PROG_CD
FROM VW_YD_SLABCOMM M
WHERE M.SLAB_NO = :V_STL_NO
 </pre> */
