 /** <pre> 2019-09-24
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getWrkScrpSchList
SELECT CM.STL_NO
     , CS.YD_EQP_ID
     , CS.YD_SCH_CD
     , CS.YD_CRN_SCH_ID
     , CS.YD_WBOOK_ID
     , CS.YD_WRK_PROG_STAT
     , CS.YD_DN_WO_LOC||CS.YD_DN_WO_LYR  AS YD_DN_WO_LOC_ORG
  FROM TB_YF_CRNSCH    CS
     , TB_YF_CRNWRKMTL CM
 WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
   AND CS.DEL_YN = 'N'
   AND CM.DEL_YN = 'N'
   AND CS.YD_WRK_PROG_STAT NOT IN ('W')
   AND CS.YD_SCH_CD IN ('1EKD02LM', '1EYD01MM')
   AND SUBSTR(CS.YD_DN_WO_LOC, 1, 6) IN ('1ESC02','1ESC03')
   AND CM.STL_NO LIKE 'S%'
   AND '1' = (SELECT YD_L2_HMI_STAT FROM TB_YF_EQP WHERE YD_EQP_ID = '1EGT01')
 UNION ALL
SELECT CM.STL_NO
     , CS.YD_EQP_ID
     , CS.YD_SCH_CD
     , CS.YD_CRN_SCH_ID
     , CS.YD_WBOOK_ID
     , CS.YD_WRK_PROG_STAT
     , CS.YD_DN_WO_LOC||CS.YD_DN_WO_LYR  AS YD_DN_WO_LOC_ORG
  FROM TB_YF_CRNSCH    CS
     , TB_YF_CRNWRKMTL CM
 WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
   AND CS.DEL_YN = 'N'
   AND CM.DEL_YN = 'N'
   AND CS.YD_WRK_PROG_STAT NOT IN ('W')
   AND CS.YD_SCH_CD IN ('1EKD02LM', '1EYD01MM')
   AND SUBSTR(CS.YD_DN_WO_LOC, 1, 6) IN ('1ESC01')
   AND SUBSTR(CS.YD_DN_WO_LOC, 7, 2) BETWEEN '01' AND '08' --임시적치구역
   AND CM.STL_NO LIKE 'S%'
   AND '0' = (SELECT YD_L2_HMI_STAT FROM TB_YF_EQP WHERE YD_EQP_ID = '1EGT01')
 </pre> */
public final static String getWrkScrpSchList = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getWrkScrpSchList";

