 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getStlCommInfo_PIDEV 
SELECT  T0.ORD_NO
       ,T0.ORD_DTL
       ,T0.RECORD_PROG_STAT
       ,T0.COMBO_RECORD_PROG_STAT
       ,T0.CURR_PROG_CD
       ,T0.COMBO_CURR_PROG_CD
       ,T0.STL_SPEC_ABBSYM
       ,T0.ORD_YEOJAE_GP
       ,T0.COMBO_ORD_YEOJAE_GP
       ,T0.YEOJAE_CAUSE_CD
       ,T0.STL_T
       ,T0.STL_W
       ,DECODE(TRIM(T0.STL_LEN), '.0', '', T0.STL_LEN) AS STL_LEN
       ,T0.STL_WT_DECISION_CD
       ,T0.STL_NET_CAL_WT
       ,T0.STL_NET_WEIGH_WT
       ,T0.STL_STORE_LOC_CD
       ,T0.OVERALL_STAMP_GRADE
       ,T0.KEEPSTOCK_RESERVED_YN
       ,DECODE(T0.STL_ORD_NO_DTL, '-', '', T0.STL_ORD_NO_DTL) AS STL_ORD_NO_DTL
FROM    (
        SELECT  B.ORD_NO
               ,B.ORD_DTL
               ,B.ORD_NO || '-' || B.ORD_DTL  AS STL_ORD_NO_DTL
               ,B.RECORD_PROG_STAT
               ,B.RECORD_PROG_STAT  AS COMBO_RECORD_PROG_STAT
               ,B.CURR_PROG_CD
               ,B.CURR_PROG_CD      AS COMBO_CURR_PROG_CD
               ,B.HR_SPEC_ABBSYM    AS STL_SPEC_ABBSYM
               ,B.ORD_YEOJAE_GP
               ,B.ORD_YEOJAE_GP     AS COMBO_ORD_YEOJAE_GP
               ,B.YEOJAE_CAUSE_CD
               ,TO_CHAR(B.COIL_T,   '9,999,999.999') AS STL_T
               ,TO_CHAR(B.COIL_W,   '9,999,999.9')   AS STL_W
               ,TO_CHAR(B.COIL_LEN, '9,999,999.9')   AS STL_LEN
               ,B.WT_DECISION_CD    AS STL_WT_DECISION_CD
               ,TO_CHAR(B.NET_CAL_WT, '9,999,999')        AS STL_NET_CAL_WT   --NC
               ,TO_CHAR(B.NET_WEIGH_WT, '9,999,999')      AS STL_NET_WEIGH_WT --NA
               ,B.YD_STR_LOC        AS STL_STORE_LOC_CD
               ,B.OVERALL_STAMP_GRADE
               ,B.KEEPSTOCK_RESERVED_YN
        FROM    VW_YF_COILCOMM      B
        WHERE   'H'                 = :V_DIST_GOODS_GP      -- COIL 
        AND     B.COIL_NO           = :V_GOODS_NO

        UNION ALL

        SELECT  B.ORD_NO
               ,B.ORD_DTL
               ,B.ORD_NO || '-' || B.ORD_DTL  AS STL_ORD_NO_DTL
               ,B.RECORD_PROG_STAT
               ,B.RECORD_PROG_STAT  AS COMBO_RECORD_PROG_STAT
               ,B.CURR_PROG_CD
               ,B.CURR_PROG_CD      AS COMBO_CURR_PROG_CD
               ,B.SPEC_ABBSYM       AS STL_SPEC_ABBSYM
               ,B.ORD_YEOJAE_GP
               ,B.ORD_YEOJAE_GP     AS COMBO_ORD_YEOJAE_GP
               ,B.YEOJAE_CAUSE_CD
               ,TO_CHAR(B.PL_MEA_GDS_T, '9,999,999.999')    AS STL_T           --?
               ,TO_CHAR(B.PL_MEA_GDS_W, '9,999,999.9')      AS STL_W           --?
               ,TO_CHAR(B.PL_MEA_GDS_L, '9,999,999.9')      AS STL_LEN         --?
               ,''                  AS STL_WT_DECISION_CD
               ,TO_CHAR(B.PL_MEA_GDS_WT, '9,999,999')       AS STL_NET_CAL_WT        --NC
               ,'0'                                         AS STL_NET_WEIGH_WT      --NA
               ,B.YD_STR_LOC                                AS STL_STORE_LOC_CD
               ,B.OVERALL_STAMP_GRADE
               ,''                  AS KEEPSTOCK_RESERVED_YN
        FROM    TB_PT_PLATECOMM     B
        WHERE   'P'                 = :V_DIST_GOODS_GP   -- PLATE 
        AND     B.PLATE_NO          = :V_GOODS_NO

        UNION ALL

        SELECT  B.ORD_NO
               ,B.ORD_DTL
               ,B.ORD_NO || '-' || B.ORD_DTL  AS STL_ORD_NO_DTL
               ,B.RECORD_PROG_STAT
               ,B.RECORD_PROG_STAT  AS COMBO_RECORD_PROG_STAT
               ,B.CURR_PROG_CD
               ,B.CURR_PROG_CD      AS COMBO_CURR_PROG_CD
               ,B.SPEC_ABBSYM       AS STL_SPEC_ABBSYM
               ,B.ORD_YEOJAE_GP
               ,B.ORD_YEOJAE_GP     AS COMBO_ORD_YEOJAE_GP
               ,B.YEOJAE_CAUSE_CD
               ,TO_CHAR(B.MS_SLAB_T,    '9,999,999.999') AS STL_T
               ,TO_CHAR(B.MS_SLAB_W,    '9,999,999.9')   AS STL_W
               ,TO_CHAR(B.MS_SLAB_LEN,  '9,999,999.9')   AS STL_LEN
               ,''                  AS WT_DECISION_CD
               ,'0'                 AS STL_NET_CAL_WT        --NC
               ,'0'                 AS STL_NET_WEIGH_WT      --NA
               ,B.YD_STR_LOC        AS STORE_LOC_CD
               ,B.OVERALL_STAMP_GRADE
               ,''                  AS KEEPSTOCK_RESERVED_YN
        FROM    TB_PT_SLABCOMM      B
        WHERE   'C'                 = :V_DIST_GOODS_GP      -- SLAB 
        AND     B.SLAB_NO           = :V_GOODS_NO

        UNION ALL

        SELECT  B.ORD_NO
               ,B.ORD_DTL
               ,B.ORD_NO || '-' || B.ORD_DTL  AS STL_ORD_NO_DTL
               ,B.RECORD_PROG_STAT
               ,B.RECORD_PROG_STAT  AS COMBO_RECORD_PROG_STAT
               ,B.CURR_PROG_CD
               ,B.CURR_PROG_CD      AS COMBO_CURR_PROG_CD
               ,B.SPEC_ABBSYM
               ,B.ORD_YEOJAE_GP
               ,B.ORD_YEOJAE_GP     AS COMBO_ORD_YEOJAE_GP
               ,B.YEOJAE_CAUSE_CD
               ,TO_CHAR(B.PLATE_T,    '9,999,999.999') AS STL_T
               ,TO_CHAR(B.PLATE_W,    '9,999,999.9')   AS STL_W
               ,TO_CHAR(B.PLATE_LEN,  '9,999,999.9')   AS STL_LEN
               ,B.WT_DECISION_CD
               ,TO_CHAR(B.NET_CAL_WT,  '9,999,999')    AS STL_NET_CAL_WT       --NC
               ,TO_CHAR(B.NET_WEIGH_WT,  '9,999,999')  AS STL_NET_WEIGH_WT     --NA
               ,B.YD_STR_LOC        AS STORE_LOC_CD
               ,B.OVERALL_STAMP_GRADE
               ,''                  AS KEEPSTOCK_RESERVED_YN
        FROM    TB_PT_HRPLATECOMM   B
        WHERE   'T'                 = :V_DIST_GOODS_GP  -- HRPLATE 
        AND     B.COIL_NO           = :V_GOODS_NO

                UNION ALL

        SELECT  B.ORD_NO
               ,B.ORD_DTL
               ,B.ORD_NO || '-' || B.ORD_DTL  AS STL_ORD_NO_DTL
               ,B.RECORD_PROG_STAT
               ,B.RECORD_PROG_STAT  AS COMBO_RECORD_PROG_STAT
               ,B.CURR_PROG_CD
               ,B.CURR_PROG_CD      AS COMBO_CURR_PROG_CD
               ,B.SPEC_ABBSYM
               ,B.ORD_YEOJAE_GP
               ,B.ORD_YEOJAE_GP     AS COMBO_ORD_YEOJAE_GP
               ,B.YEOJAE_CAUSE_CD
               ,TO_CHAR(B.PLATE_T,    '9,999,999.999') AS STL_T
               ,TO_CHAR(B.PLATE_W,    '9,999,999.9')   AS STL_W
               ,TO_CHAR(B.PLATE_LEN,  '9,999,999.9')   AS STL_LEN
               ,B.WT_DECISION_CD
               ,TO_CHAR(B.NET_CAL_WT,  '9,999,999')    AS STL_NET_CAL_WT       --NC
               ,TO_CHAR(B.NET_WEIGH_WT,  '9,999,999')  AS STL_NET_WEIGH_WT     --NA
               ,B.YD_STR_LOC        AS STORE_LOC_CD
               ,B.OVERALL_STAMP_GRADE
               ,''                  AS KEEPSTOCK_RESERVED_YN
        FROM    TB_PT_HRPLATECOMM   B
        WHERE   'S'                 = :V_DIST_GOODS_GP  -- HRSHEET 
        AND     B.COIL_NO           = :V_GOODS_NO

        UNION ALL

        -- 냉연반제품/제품
        SELECT  B.ORD_NO
               ,LPAD(B.ORD_LN,3,'0')                    AS ORD_LN
               ,B.ORD_NO || '-' || LPAD(B.ORD_LN,3,'0') AS STL_ORD_NO_DTL
               ,B.RCD_STS_TP
               ,B.RCD_STS_TP    AS COMBO_RECORD_PROG_STAT
               ,B.PRG_CD
               ,B.PRG_CD        AS COMBO_CURR_PROG_CD
               ,B.SPC_AVR
               ,B.ORD_SPL_TP
               ,B.ORD_SPL_TP    AS COMBO_ORD_YEOJAE_GP
               ,B.SPL_CAU_CD
               ,TO_CHAR(B.COIL_ACT_THK,  '9,999,999.999') AS STL_T
               ,TO_CHAR(B.COIL_ACT_WTH,  '9,999,999.9')   AS STL_W
               ,TO_CHAR(B.COIL_ACT_LTH,  '9,999,999.9')   AS STL_LEN
               ,B.WGT_DCS_MTH_TP
               ,TO_CHAR(B.COIL_THY_WGT,  '9,999,999')  AS STL_NET_CAL_WT       --NC
               ,TO_CHAR(B.COIL_RMW_WGT,  '9,999,999')  AS STL_NET_WEIGH_WT     --NA
               ,B.LOD_LOC        AS STORE_LOC_CD
               ,B.PRD_SYN_GRD
               ,''                  AS KEEPSTOCK_RESERVED_YN
        FROM    TB_M30_COIL_CMN@DL_CRDB   B
        WHERE   'L'                 = :V_DIST_GOODS_GP  -- CR 
        AND     B.COIL_NO           = :V_GOODS_NO
        
        UNION ALL
        
        -- 냉연소재
        SELECT  B.ORD_NO
               ,LPAD(B.ORD_LN,3,'0')                    AS ORD_LN
               ,B.ORD_NO || '-' || LPAD(B.ORD_LN,3,'0') AS STL_ORD_NO_DTL
               ,B.RMTL_PRG_STS_TP
               ,B.RMTL_PRG_STS_TP                       AS COMBO_RECORD_PROG_STAT
               ,B.RMTL_PRG_CD
               ,B.RMTL_PRG_CD                           AS COMBO_CURR_PROG_CD
               ,B.RMTL_SPC                              AS SPC_AVR
               ,B.ORD_SPL_TP                            AS ORD_SPL_TP
               ,B.ORD_SPL_TP                            AS COMBO_ORD_YEOJAE_GP
               ,B.SPL_CAU_CD
               ,TO_CHAR(B.RMTL_THK,  '9,999,999.999')   AS STL_T
               ,TO_CHAR(B.RMTL_WTH,  '9,999,999.9')     AS STL_W
               ,TO_CHAR(B.RMTL_LTH,  '9,999,999.9')     AS STL_LEN
               ,NULL                                    AS WGT_DCS_MTH_TP
               ,TO_CHAR(B.RMTL_WGT,  '9,999,999')       AS STL_NET_CAL_WT       --NC
               ,TO_CHAR(B.RMTL_WGT,  '9,999,999')       AS STL_NET_WEIGH_WT     --NA
               ,B.LOD_LOC                               AS STORE_LOC_CD
               ,NULL                                    AS PRD_SYN_GRD
               ,''                                      AS KEEPSTOCK_RESERVED_YN
        FROM    TB_M21_MASTER@DL_CRDB   B
        WHERE   'M'                 = :V_DIST_GOODS_GP  -- CR 
        AND     B.RMTL_NO           = :V_GOODS_NO        
        ) T0
 </pre> */
public final static String getStlCommInfo = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getStlCommInfo_PIDEV";

 /** <pre> 2021-04-01
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getGoodsDetailInfo_PIDEV 
SELECT T0.GOODS_NO
     , T0.DIST_GOODS_GP
     , T0.ORD_NO
     , T0.ORD_DTL
     , T0.CUST_CD
     , T0.COMBO_CUST_CD
     , T0.BEF_ORD_NO
     , T0.BEF_ORD_DTL
     , T0.SPEC_ABBSYM
     , T0.SPEC_YY
     , T0.USAGE_CD
     , T0.COMBO_USAGE_CD
     , T0.GOODS_T
     , T0.GOODS_W
     , DECODE(TRIM(T0.GOODS_LEN), '.0', '', T0.GOODS_LEN) AS GOODS_LEN
     , T0.ORD_CONV_T
     , T0.ORD_CONV_W
     , DECODE(TRIM(T0.ORD_CONV_LEN), '.0', '', T0.ORD_CONV_LEN) AS ORD_CONV_LEN
     , T0.WT_DECISION_CD
     , T0.GOODS_NET_WEIGH_WT
     , T0.GOODS_NET_CAL_WT
     , T0.STORE_LOC_CD
     , T0.CAR_STAT_GP
     , T0.COMBO_CAR_STAT_GP
     , ''                           AS MS_ISSUE_REQUEST_GP
     , T0.URGENT_DIST_YN
     , ''                           AS LONGTERM_INV_GP       -- 장기재고 관리 안함
     , ''                           AS LONGTERM_INV_CAUSE_CD -- 장기재고사유 관리 안함
     , T0.RECEIPT_INI_DATE
     , T0.GOODS_RECEIPT_STEP_NO
     , T0.RECEIPT_TIME
     , ''                           AS MOVENSTACK_DATE           -- 이적일자
     , ''                           AS GOODS_MOVENSTACK_STEP_NO  -- 이적차수
     , ''                           AS MOVENSTACK_TIME           -- 이적시간 
     , T0.RETURN_REQUEST_DATE
     , T0.GOODS_RETURN_STEP_NO
     , T0.RETURN_INI_DATE
     , T0.RECEIPT_ITEM_CD
     , T0.RETURN_ITEM_CD
     , ''                           AS MOVENSTACK_CD  --이적ITEMCODE
     , T0.GOODSRETURN_CAUSE_CD
     , T0.GOODSRETURN_DATE
     , T0.SHIP_CD
     , T0.CUST_DELIVER_DATE
     , T0.TRANS_WRSLT_DATE
     , T0.TRANS_WRSLT_SEQNO
     , T0.GOODS_OUTDIA
     , T0.CR_YD_GP
     , DECODE(T0.ORD_NO_DTL, '-', '', T0.ORD_NO_DTL) AS ORD_NO_DTL
     , DECODE(T0.BEF_ORD_NO_DTL, '-', '', T0.BEF_ORD_NO_DTL) AS BEF_ORD_NO_DTL
     , T0.CUST_CD || '[' || T1.NAME_ORG1 ||']' AS CUST
     , DECODE(T0.SHIP_CD || '[' 
                 || T0.SHIP_NAME ||']', '[]', '',
              T0.SHIP_CD || '[' 
                 || T0.SHIP_NAME ||']') AS SHIP
     , 00  AS MAX_LOC_CNT
     , DECODE(T0.CHECKERED_INOUT_CD,'B','내권부','T','외권부','') AS CHECKERED_INOUT_CD
     , T0.LOT_NO
     , T0.DETAIL_ARR_CD
     , MOD_DDTT_EXE
     , LABEL_YN
     , YD_AB_CD
     , YD_CAR_UPP_LOC_CD
  FROM (
        SELECT -- 제품공통정보 
               A.GOODS_NO
             , A.DIST_GOODS_GP
             , A.ORD_NO
             , A.ORD_DTL
             , A.ORD_NO || '-' || A.ORD_DTL            AS ORD_NO_DTL
             , C.CUST_CD
             , C.CUST_CD                               AS COMBO_CUST_CD
             , A.BEF_ORD_NO
             , A.BEF_ORD_DTL
             , A.BEF_ORD_NO || '-' || A.BEF_ORD_DTL    AS BEF_ORD_NO_DTL
             , CASE WHEN A.DIST_GOODS_GP = 'H' THEN A.SPEC_ABBSYM||'('||J.HR_SPEC_ABBSYM||')'
                    ELSE A.SPEC_ABBSYM
               END AS SPEC_ABBSYM
             , C.SPEC_YY
             , C.USAGE_CD
             , C.USAGE_CD                  AS COMBO_USAGE_CD
             , TO_CHAR(A.GOODS_T,   '9,999,999.999')   AS GOODS_T
             , TO_CHAR(A.GOODS_W,   '9,999,999.9')     AS GOODS_W
             , TO_CHAR(A.GOODS_LEN, '9,999,999.9')     AS GOODS_LEN
             , TO_CHAR(C.ORD_CONV_T,   '9,999,999.999') AS ORD_CONV_T
             , TO_CHAR(C.ORD_CONV_W,   '9,999,999.9')   AS ORD_CONV_W
             , TO_CHAR(C.ORD_CONV_LEN, '9,999,999.9')   AS ORD_CONV_LEN
             , A.WT_DECISION_CD
             , TO_CHAR(A.GOODS_NET_WEIGH_WT, '9,999,999') AS GOODS_NET_WEIGH_WT        
             , TO_CHAR(A.GOODS_NET_CAL_WT,   '9,999,999') AS GOODS_NET_CAL_WT
             , CASE
               WHEN J.COIL_GP = 'CR' THEN J.YD_STR_LOC
               ELSE DECODE(A.DIST_GOODS_GP, 'L', NVL(I.LOD_LOC, A.STORE_LOC_CD), A.STORE_LOC_CD) 
                END AS STORE_LOC_CD
             , A.CAR_STAT_GP
             , A.CAR_STAT_GP               AS COMBO_CAR_STAT_GP
             , A.URGENT_DIST_YN
             , A.TRANS_WRSLT_DATE
             , A.TRANS_WRSLT_SEQNO
             , C.CHECKERED_INOUT_CD        --내외권부
             , A.GOODS_OUTDIA
               
               -- 입고정보 
             , TO_CHAR(TO_DATE(D.RECEIPT_INI_DATE, 'YYYYMMDD'), 'YYYY-MM-DD')    AS RECEIPT_INI_DATE
             , D.GOODS_RECEIPT_STEP_NO
             , TO_CHAR(TO_DATE(D.RECEIPT_TIME,     'HH24MISS'), 'HH24:MI:SS')    AS RECEIPT_TIME
--           , TO_CHAR(TO_DATE(E.MOVENSTACK_DATE,  'YYYYMMDD'), 'YYYY-MM-DD')    AS MOVENSTACK_DATE
--           , E.GOODS_MOVENSTACK_STEP_NO
--           , TO_CHAR(TO_DATE(E.MOVENSTACK_TIME,  'HH24MISS'), 'HH24:MI:SS')    AS MOVENSTACK_TIME
             , TO_CHAR(TO_DATE(F.RETURN_REQUEST_DATE,  'YYYYMMDD'), 'YYYY-MM-DD')AS RETURN_REQUEST_DATE
             , F.GOODS_RETURN_STEP_NO
             , TO_CHAR(TO_DATE(F.RETURN_INI_DATE,  'YYYYMMDD'), 'YYYY-MM-DD')    AS RETURN_INI_DATE
             , D.RECEIPT_ITEM_CD
             , F.RETURN_ITEM_CD
--           , E.MOVENSTACK_CD             --이적아이템코드
               
             , F.RETURN_REQUEST_CAUSE_CD                                         AS GOODSRETURN_CAUSE_CD      --반품원인
             , TO_CHAR(TO_DATE(TRIM(F.RETURN_TREAT_DATE),  'YYYYMMDD'), 'YYYY-MM-DD')    AS GOODSRETURN_DATE
             , A.SHIP_CD                   --선박코드
             , H.SHIP_NAME             
             , TO_CHAR(TO_DATE(A.CUST_DELIVER_DATE,  'YYYYMMDD'), 'YYYY-MM-DD')   AS CUST_DELIVER_DATE
             
             -- 이적정보 
--           , E.GOODS_MOVENSTACK_STEP_NO  AS MOVENSTACK_STEP_NO
             , A.STORE_LOC_CD              AS MOVENSTACK_LOC
             
             , A.LOT_NO
             , C.DETAIL_ARR_CD
             , TO_CHAR(G.MOD_DDTT,'YYYY/MM/DD HH24:MI') AS MOD_DDTT_EXE
             , G.LABEL_YN
             , G.YD_AB_CD
             , G.YD_CAR_UPP_LOC_CD
             , A.CR_YD_GP
             , C.REGISTER
          FROM    
               VW_LM_P_GOODSPROG           A           --TB_DM_GOODSPROG             A 
--           , TB_PT_OSCOMM                B           --TB_SM_ORDCOMM               B
             , TB_PT_OSCOMM                C           --TB_SM_ORDDTL                C
             , VW_LM_P_GOODSRECEIPT        D           --TB_DM_GOODSRECEIPT          D
--           , TB_DM_GOODSMOVENSTACK@DL_SMDB         --TB_DM_GOODSMOVENSTACK@DL_SMDB       E
             , (SELECT * 
                  FROM VW_LM_P_GOODSRETURN S1
                 WHERE S1.GOODS_NO    = :V_GOODS_NO
                   AND GOODS_RETURN_STEP_NO =   
                                        (SELECT MAX(GOODS_RETURN_STEP_NO) 
                                           FROM VW_LM_P_GOODSRETURN
                                          WHERE GOODS_NO    = :V_GOODS_NO )  ) F     --TB_DM_GOODSRETURN           F
             , TB_YD_EXAMINATIONCHKLIST    G           --TB_YD_EXAMINATIONCHKLIST  G
             , VW_LM_P_SHIPASSIGNORD       H           --TB_DM_DISTPROG@DL_SMDB H
             , TB_M30_COIL_CMN@DL_CRDB     I           --TB_M30_COIL_CMN@DL_SMDB I
             , (SELECT * FROM VW_YF_COILCOMM WHERE COIL_NO = :V_GOODS_NO) J        -- VW_YF_COILCOMM J                         
         WHERE 1=1
--           AND A.ORD_NO                    = B.ORD_NO(+)
           AND A.ORD_NO                    = C.ORD_NO(+)
           AND A.ORD_DTL                   = C.ORD_DTL(+)
           AND A.GOODS_NO                  = D.GOODS_NO(+)
           AND A.GOODS_RECEIPT_STEP_NO     = D.GOODS_RECEIPT_STEP_NO(+)
           AND A.GOODS_NO                  = F.GOODS_NO(+)
--         AND A.GOODS_RETURN_STEP_NO      = F.GOODS_RETURN_STEP_NO(+)
           AND A.TRANS_WRSLT_DATE          = G.TRANS_ORD_DATE(+)
           AND A.TRANS_WRSLT_SEQNO         = G.TRANS_ORD_SEQNO(+)
           AND A.GOODS_NO                  = G.STL_NO(+)
           AND A.DIST_SHIPASSIGN_GP        = H.DIST_SHIPASSIGN_GP(+)
           AND A.ERP_DOC_NO                = H.ERP_DOC_NO(+)
           AND A.ERP_DOC_DTL               = H.ERP_DOC_DTL(+)
           AND A.GOODS_NO                  = I.COIL_NO(+)
           AND A.GOODS_NO                  = J.COIL_NO(+)
           AND A.GOODS_NO                  = :V_GOODS_NO
        
--         AND B.DEL_YN(+)                 = 'N'
--         AND C.DEL_YN(+)                 = 'N'
           AND D.DEL_YN(+)                 = 'N'
--         AND E.DEL_YN(+)                 = 'N'
           AND F.DEL_YN(+)                 = 'N'      
          ) T0
         , USRCOM.TB_COM_BP_MASTER    T1  --TB_SM_CUSTINFO    T1
WHERE     T0.CUST_CD        = T1.PARTNER(+)

 </pre> */
public final static String getGoodsDetailInfo = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getGoodsDetailInfo_PIDEV";

 /** <pre> 2019-10-10
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getTransInfo_PIDEV
SELECT T0.*
       ,T0.TRANS_WORD_DATE || '-' || T0.TRANS_WORD_SEQNO AS TRANS_WORD_NO
       ,T0.TRANS_WRSLT_DATE || '-' || T0.TRANS_WRSLT_SEQNO  AS TRANS_WRSLT_NO
       ,T0.TRANS_COM_CD || '[' || T2.TRANS_COM_NAME ||']'   AS TRANS_COM
       ,T0.DEST_CD || '[' || T1.DEST_NAME ||']'   AS DEST
FROM (
       SELECT A.TRANS_WORD_DATE
             ,A.TRANS_WORD_SEQNO
             ,''                 AS TRANS_WRSLT_DATE
             ,NULL               AS TRANS_WRSLT_SEQNO
             ,B.TRANS_COM_CD
             ,B.H_DEST_CD        AS DEST_CD
             ,B.CAR_NO
             ,''                 AS DIST_DATE
             ,''                 AS AR_TREAT_DATE
             ,''                 AS BL_DATE
        FROM VW_LM_P_TRANSWORDGOODS A
            ,VW_LM_P_TRANSWORDCOMM  B
        WHERE '1' = :V_SELECT_GP
         AND A.TRANS_WORD_DATE  = B.TRANS_WORD_DATE
         AND A.TRANS_WORD_SEQNO = B.TRANS_WORD_SEQNO
         AND A.GOODS_NO = :V_GOODS_NO
         AND A.DEL_YN = 'N'
         AND B.DEL_YN ='N'

       UNION ALL

       SELECT B.TRANS_WORD_DATE
             ,B.TRANS_WORD_SEQNO
             ,A.TRANS_WORD_DATE
             ,A.TRANS_WORD_SEQNO
             ,B.TRANS_COM_CD
             ,B.H_DEST_CD            DEST_CD
             ,B.CAR_NO
             ,TO_CHAR(TO_DATE(B.DIST_DATE,'YYYYMMDD') , 'YYY.MM.DD') AS DIST_DATE
             ,''    AS AR_TREAT_DATE
             ,''    AS BL_DATE
         FROM VW_LM_P_TRANSWORDGOODS A
             ,VW_LM_P_TRANSWORDCOMM B
        WHERE '2' = :V_SELECT_GP
          AND A.TRANS_WORD_DATE  = B.TRANS_WORD_DATE
          AND A.TRANS_WORD_SEQNO = B.TRANS_WORD_SEQNO
          AND A.TRANS_WORD_DATE = :V_TRANS_WRSLT_DATE
          AND A.TRANS_WORD_SEQNO = :V_TRANS_WRSLT_SEQNO
          AND A.DEL_YN = 'N'
          AND B.DEL_YN ='N'
          ) T0
          ,USRLMA.VW_LM_Z_DESTCD   T1
          ,VW_LM_Z_TRANSCOMCD T2
WHERE    T0.DEST_CD = T1.DEST_CD(+)
  AND    T0.TRANS_COM_CD = T2.TRANS_COM_CD(+)
 </pre> */
public final static String getTransInfo = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getTransInfo_PIDEV";

 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdPrimaryWorkSearchScrapNewRe 
WITH SCRAP_INFO AS (
SELECT MIN(WRSLT_REAL_WT) AS SCRAP_WT
     , MIN((SELECT COIL_W FROM VW_YF_COILCOMM CC WHERE CC.COIL_NO = PC.COIL_NO)) AS SCRAP_W
  FROM USRPOA.TB_PO_COILSHEARORD_SCRAP PC
 WHERE SCRAP_COIL_NO = :V_STL_NO
   AND STEP_NO = (SELECT MAX(STEP_NO) 
                    FROM USRPOA.TB_PO_COILSHEARORD_SCRAP
                   WHERE SCRAP_COIL_NO = :V_STL_NO)
),
TO_LOC_TABLE AS
(
SELECT * 
  FROM (
        SELECT
               CASE WHEN SI.SCRAP_WT > 3000 THEN 1 ELSE 2 END AS PRIOR1 
             , K2.YD_L2_HMI_STAT
             , CASE WHEN K2.YD_L2_HMI_STAT = '1' AND K1.TAG_YD_STK_COL_GP IN ('1ESC02','1ESC03')      THEN 'N' --집게차 진입시 2, 3열 적치 불가
                    WHEN K2.YD_L2_HMI_STAT = '1' AND SI.SCRAP_WT < 3000 AND TO_NUMBER(K1.TAG_YD_STK_BED_NO) > '7' THEN 'N' --집게차 진입시 1열 5번지이내 적치
                    WHEN SUBSTR(K1.YD_SCH_CD,3,2) = 'YD' AND K1.TAG_YD_STK_COL_GP IN ('1ESC01') THEN 'N' --동내이적은 1열에서 2, 3열만 가능
                    WHEN SI.SCRAP_WT > 3000 AND K1.TAG_YD_STK_COL_GP IN ('1ESC02','1ESC03')     THEN 'N' --3톤이상은 1열에만 적치
                    WHEN SI.SCRAP_WT > 3000 AND TO_NUMBER(K1.TAG_YD_STK_BED_NO) <= '5'          THEN 'N' --3톤이상은 6~15번지 적치만 적치
                    WHEN SI.SCRAP_W  > 1300 AND K1.TAG_YD_STK_COL_GP IN ('1ESC02')              THEN 'N' --1300이상 광폭스크랩은 2열 적치 금지
                    ELSE 'Y' END  AS LOC_ABLE_YN
             , K1.*       
             , TO_NUMBER(SUBSTR(TAG_YD_STK_COL_GP, 6, 1)) AS SCR_COL
             , SI.SCRAP_WT
             , CASE WHEN (SELECT COUNT(*)  
                            FROM TB_YF_STKLYR
                           WHERE YD_STK_COL_GP = '1ESC01'
                             AND YD_STK_LYR_STAT IN('E')
                             AND YD_STK_LYR_NO = '01'
                             AND YD_STK_BED_NO BETWEEN '01' AND '08') > 0 THEN '01'
                    WHEN SI.SCRAP_WT < 3000 AND K1.TAG_YD_STK_COL_GP = '1ESC01'  THEN '01' 
                    ELSE '02' END RULL_DAN_PRIOR
--             , '02' AS RULL_DAN_PRIOR              
          FROM 
               (
                SELECT 1                      AS PRIOR2 
                     , A.YD_STK_COL_GP         AS TAG_YD_STK_COL_GP
                     , A.YD_STK_BED_NO         AS TAG_YD_STK_BED_NO
                     , A.YD_STK_LYR_NO       AS TAG_YD_STK_LYR_NO
                     , DECODE(A.YD_STK_LYR_NO, '01', LPAD(TO_NUMBER(A.YD_STK_BED_NO)   - 1, 2, '0'),
                                                '02', A.YD_STK_BED_NO)                                AS TAG_LEFT_BED
                     , DECODE(A.YD_STK_LYR_NO, '01', A.YD_STK_LYR_NO,
                                                '02', LPAD(TO_NUMBER(A.YD_STK_LYR_NO) - 1, 2, '0')) AS TAG_LEFT_LAYER
                     , DECODE(A.YD_STK_LYR_NO, '01', LPAD(TO_NUMBER(A.YD_STK_BED_NO)   + 1, 2, '0'),
                                                '02', LPAD(TO_NUMBER(A.YD_STK_BED_NO)   + 1, 2, '0')) AS TAG_RIGHT_BED
                     , DECODE(A.YD_STK_LYR_NO, '01', A.YD_STK_LYR_NO,
                                                '02', LPAD(TO_NUMBER(A.YD_STK_LYR_NO) - 1, 2, '0')) AS TAG_RIGHT_LAYER
                     , :V_YD_SCH_CD           AS YD_SCH_CD         
                     , :V_STL_NO            AS STL_NO
                  FROM TB_YF_STKLYR A
                     , TB_YF_STKCOL   B
                 WHERE A.YD_STK_LYR_NO         IN ('01','02')
                   AND A.YD_STK_LYR_ACTIVE_STAT= 'E'
                   AND A.YD_STK_LYR_STAT       = 'E'
                   AND A.YD_STK_COL_GP           = B.YD_STK_COL_GP
                   AND A.YD_STK_COL_GP           IN ('1ESC01','1ESC02','1ESC03')
                   AND SUBSTR(A.YD_STK_COL_GP,1,2)  = '1E'
                   AND A.YD_STK_COL_GP||A.YD_STK_BED_NO||A.YD_STK_LYR_NO NOT IN ( SELECT NVL(YD_DN_WO_LOC||YD_DN_WO_LYR,'1') FROM TB_YF_CRNSCH WHERE DEL_YN = 'N')
                ) K1 
         -- YD_L2_HMI_STAT :0 차량없음 ,1 : 차량있음
              , (SELECT YD_L2_HMI_STAT FROM TB_YF_EQP WHERE YD_EQP_ID = '1EGT01') K2      
              , SCRAP_INFO  SI
        )      
  WHERE LOC_ABLE_YN = 'Y'      
--  ORDER BY PRIOR1, PRIOR2 
)  
, TO_LOC_DATA_TABLE AS (
-- TO 위치코일정보 SELECT
SELECT A.PRIOR1 
     , A.PRIOR2 
     , A.TAG_YD_STK_LYR_NO AS PRIOR3    -- 단우선순위
     , A.RULL_DAN_PRIOR     AS RULL_DAN_PRIOR
     , A.STL_NO           AS STL_NO
     , A.TAG_YD_STK_COL_GP   
     , A.TAG_YD_STK_BED_NO
     , A.TAG_YD_STK_LYR_NO
     , A.TAG_LEFT_BED
     , A.TAG_LEFT_LAYER
     , (SELECT YD_STK_LYR_ACTIVE_STAT 
          FROM TB_YF_STKLYR B 
         WHERE B.YD_STK_COL_GP   = A.TAG_YD_STK_COL_GP
           AND B.YD_STK_BED_NO   = A.TAG_LEFT_BED
           AND B.YD_STK_LYR_NO = A.TAG_LEFT_LAYER)  AS  TAG_LEFT_ACTIVE_STAT 
     , (SELECT YD_STK_LYR_STAT 
          FROM TB_YF_STKLYR B 
         WHERE B.YD_STK_COL_GP   = A.TAG_YD_STK_COL_GP
           AND B.YD_STK_BED_NO   = A.TAG_LEFT_BED
           AND B.YD_STK_LYR_NO = A.TAG_LEFT_LAYER)  AS  TAG_LEFT_LAYER_STAT
     , (SELECT STL_NO 
          FROM TB_YF_STKLYR B 
         WHERE B.YD_STK_COL_GP   = A.TAG_YD_STK_COL_GP
           AND B.YD_STK_BED_NO   = A.TAG_LEFT_BED
           AND B.YD_STK_LYR_NO = A.TAG_LEFT_LAYER)  AS  TAG_LEFT_STL_NO
     , A.TAG_RIGHT_BED
     , A.TAG_RIGHT_LAYER
     , (SELECT YD_STK_LYR_ACTIVE_STAT 
          FROM TB_YF_STKLYR B 
         WHERE B.YD_STK_COL_GP   = A.TAG_YD_STK_COL_GP
           AND B.YD_STK_BED_NO   = A.TAG_RIGHT_BED
           AND B.YD_STK_LYR_NO = A.TAG_RIGHT_LAYER) AS  TAG_RIGHT_ACTIVE_STAT 
     , (SELECT YD_STK_LYR_STAT 
          FROM TB_YF_STKLYR B 
         WHERE B.YD_STK_COL_GP   = A.TAG_YD_STK_COL_GP
           AND B.YD_STK_BED_NO   = A.TAG_RIGHT_BED
           AND B.YD_STK_LYR_NO = A.TAG_RIGHT_LAYER) AS  TAG_RIGHT_LAYER_STAT
     , (SELECT STL_NO 
          FROM TB_YF_STKLYR B 
         WHERE B.YD_STK_COL_GP   = A.TAG_YD_STK_COL_GP
           AND B.YD_STK_BED_NO   = A.TAG_RIGHT_BED
           AND B.YD_STK_LYR_NO = A.TAG_RIGHT_LAYER) AS  TAG_RIGHT_STL_NO
     , A.SCR_COL
     , A.SCRAP_WT
  FROM TO_LOC_TABLE A
)
SELECT * 
  FROM
(
SELECT KK.*
     , ROW_NUMBER() OVER(PARTITION BY PRIOR5 ORDER BY CASE WHEN PRIOR1 = 1 THEN SCR_COL ELSE -SCR_COL END--PRIOR1
                                                    , PRIOR5
                                                    , PRIOR2 
                                                    , TAG_YD_STK_BED_NO
                                                    ) AS GROUP_ROW       
  FROM
        (
        SELECT K.* 
             , '1' AS PRIOR5
          FROM TO_LOC_DATA_TABLE K
         WHERE 1  = CASE WHEN TAG_YD_STK_LYR_NO = '01'    THEN 1
                         WHEN TAG_YD_STK_LYR_NO = '02'                             -- 2단일 경우 좌우 적치 상태 CHECK
                              AND TAG_LEFT_ACTIVE_STAT = 'E' AND TAG_RIGHT_ACTIVE_STAT = 'E' 
                              AND TAG_LEFT_LAYER_STAT  = 'C' AND TAG_RIGHT_LAYER_STAT  = 'C' THEN 1
                    ELSE 0 END  
           -- 권하위치변경 중인 위치는 제외
           AND (TAG_YD_STK_COL_GP||TAG_YD_STK_BED_NO, TAG_YD_STK_LYR_NO) NOT IN (SELECT YD_DN_WO_LOC_TO
                                                                                     , STK_LYR_NO_TEMP
                                                                                  FROM TB_YF_CRNSCH
                                                                                 WHERE 1 = 1
                                                                                   AND DEL_YN = 'N'
                                                                                   AND YD_DN_WO_LOC_TO LIKE '1ESC%'
                                                                               )
        ) KK       
)
 WHERE ((PRIOR5 < 3) OR (PRIOR5 = 3 AND GROUP_ROW < 10))   -- PRIOR5=3은 공BED: 1개만 검색
 ORDER BY PRIOR1                                        --위치검색그룹
        , CASE WHEN SCRAP_WT <  3000 AND SUBSTR(TAG_YD_STK_COL_GP, 5,2) IN('02','03') THEN 1 
               WHEN SCRAP_WT >= 3000 AND SUBSTR(TAG_YD_STK_COL_GP, 5,2) IN('01')      THEN 1 
               ELSE 2 END --중량은 1열 일반은 2, 3열 우선
        , PRIOR2                                        --야드위치 검색범위순서   
        , CASE WHEN SCRAP_WT > 3000 THEN '2'
               WHEN SUBSTR(TAG_YD_STK_COL_GP, 5,2) IN('01') AND TAG_YD_STK_LYR_NO = '01' THEN '1'
               ELSE '2' END --단 우선순위  
        , PRIOR5                                        --평점계산시 우선순위
        , CASE WHEN SCRAP_WT > 3000 THEN TO_NUMBER(TAG_YD_STK_BED_NO) * -1 
               ELSE TO_NUMBER(TAG_YD_STK_BED_NO) END --중량코일은 뒷번지부터 적치
        
 </pre> */
public final static String getYdPrimaryWorkSearchScrapNewRe = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdPrimaryWorkSearchScrapNewRe";

 /** <pre> 2019-10-01
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.aslabYdNEqpXyaxisSet.getSlabYfStackBed 
SELECT DISTINCT A.YD_STK_COL_GP AS YD_STK_COL_GP
      ,A.YD_STK_BED_NO AS YD_STK_BED_NO
      --,B.STACK_LAYER_GP  AS STACK_LAYER_GP
      ,A.REGISTER AS REGISTER
      ,TO_CHAR(A.REG_DDTT, 'YYYYMMDDHH24MISS')  AS REG_DDTT
      ,A.MODIFIER AS MODIFIER
      ,TO_CHAR(A.MOD_DDTT, 'YYYYMMDDHH24MISS')  AS MOD_DDTT
      ,A.DEL_YN AS DEL_YN
      --,B.STACK_LAYER_ACTIVE_STAT  AS STACK_LAYER_ACTIVE_STAT
      ,B.YD_STK_LYR_X_AXIS  AS YD_STK_LYR_X_AXIS
      ,B.YD_STK_LYR_Y_AXIS
      ,B.YD_STK_LYR_Z_AXIS  AS YD_STK_LYR_Z_AXIS
      ,B.YD_STK_LYR_X_AXIS  AS YD_STK_LYR_X_AXIS_HIDDEN
      ,B.YD_STK_LYR_Y_AXIS  AS YD_STK_LYR_Y_AXIS_HIDDEN
      ,B.YD_STK_LYR_Z_AXIS  AS YD_STK_LYR_Z_AXIS_HIDDEN
      ,(SUBSTR(A.YD_STK_COL_GP,2,5) || A.YD_STK_BED_NO) AS YD_STK_POS1
      ,A.YD_STK_BED_XAXIS_TOL 
      ,A.YD_STK_BED_YAXIS_TOL 
      ,A.YD_STK_BED_ZAXIS_TOL 
      ,A.YD_STK_BED_XAXIS_TOL AS YD_STK_BED_XAXIS_TOL_HIDDEN
      ,A.YD_STK_BED_YAXIS_TOL AS YD_STK_BED_YAXIS_TOL_HIDDEN
      ,A.YD_STK_BED_ZAXIS_TOL AS YD_STK_BED_ZAXIS_TOL_HIDDEN 
  FROM TB_YF_STKBED A
     , TB_YF_STKLYR B
 WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP 
   AND A.YD_STK_BED_NO = B.YD_STK_BED_NO 
   AND A.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'
   AND A.DEL_YN = 'N'
   AND B.DEL_YN = 'N'
   AND SUBSTR(A.YD_STK_COL_GP,3,2) IN ('01','02','BK','TC','PT','HB','CT','MT','WB','SD','SE')
 ORDER BY YD_STK_BED_NO
 </pre> */
public final static String getSlabYfStackBed = "com.inisteel.cim.yf.aslab.dao.ASlabDAO.aslabYdNEqpXyaxisSet.getSlabYfStackBed";

