 /** <pre> 2020-01-09
--com.inisteel.cim.yf.common.dao.YfCommDAO.getTcByBayLr
WITH PARAM AS (
SELECT :V_YD_GP  AS P_YD_GP
     , :V_FR_BAY_GP AS P_BAY_GP
     , :V_TO_BAY_GP AS P_TO_BAY_GP
  FROM DUAL
)
SELECT EQ.YD_EQP_ID   AS CD_VAL
     , CASE EQ.YD_EQP_ID WHEN '1XTC01' THEN 'CTS' ELSE EQ.YD_EQP_NAME END AS CD_NM
  FROM TB_YF_EQP EQ
     , PARAM P
 WHERE EQ.YD_GP   = P.P_YD_GP
   AND EQ.YD_EQP_GP = 'TC'
   AND EQ.DEL_YN     = 'N'
   AND ( 
        -- 확장대차
        ( P.P_BAY_GP IN ('A','B') AND P.P_TO_BAY_GP IN ('A','B') AND EQ.YD_EQP_ID = '1XTC03')
        OR 
        -- CTS ( 1호차만 )
        ( P.P_BAY_GP IN ('A','B','C','D','E','F','G','H') 
            AND P.P_TO_BAY_GP IN ('A','B','C','D','E','F','G','H') 
            AND EQ.YD_EQP_ID = '1XTC01'
        )
        OR
        -- 동간이적시 대차구분코드를 MV_BAY_GP로 사용한다. 
        (
            P.P_TO_BAY_GP = 'MV_BAY_GP'
            AND EQ.YD_EQP_ID = '1XTC01'
        )
    )
 </pre> */
public final static String getTcByBayLr = "com.inisteel.cim.yf.common.dao.YfCommDAO.getTcByBayLr";

