 /** <pre> 2019-09-26
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookBySchCd
SELECT KK.*
     , (SELECT YD_STK_BED_NO 
          FROM TB_YD_CARFTMVMTL 
         WHERE YD_CAR_SCH_ID = KK.YD_CAR_SCH_ID 
           AND STL_NO = KK.STL_NO) AS YD_STK_BED_NO
  FROM (
        SELECT A.* 
             , B.CTS_RELAY_BAY
             , B.STL_NO 
             , ( SELECT YD_CAR_SCH_ID 
                   FROM TB_YD_CARSCH 
                  WHERE DEL_YN = 'N' 
                    AND TRANS_ORD_DATE  = B.TRANS_ORD_DATE 
                    AND TRANS_ORD_SEQNO = B.TRANS_ORD_SEQNO
                    AND CAR_CARD_NO     = B.CAR_CARD_NO ) AS YD_CAR_SCH_ID
          FROM TB_YF_WRKBOOK A
             , TB_YF_STOCK B
             , TB_YF_WRKBOOKMTL C
         WHERE 1=1
           AND A.YD_WBOOK_ID = C.YD_WBOOK_ID 
           AND B.STL_NO    = C.STL_NO
           AND A.YD_SCH_CD   = :V_YD_SCH_CD
           AND B.CAR_CARD_NO = :V_CAR_NO
        AND A.DEL_YN='N'
        AND B.DEL_YN='N'
        AND C.DEL_YN='N'
        AND A.YD_WBOOK_ID NOT IN (
                                    SELECT YD_WBOOK_ID
                                     FROM TB_YF_CRNSCH B
                                    WHERE B.YD_GP= '1'
                                      AND B.YD_SCH_CD LIKE '1_PT__LM'
                                      AND B.DEL_YN='N'
                                 )
        ORDER BY A.YD_WBOOK_ID
) KK
 </pre> */
public final static String getYdWrkbookBySchCd = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookBySchCd";

 /** <pre> 2019-09-19
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getIfTestLayout_PIDEV
--IFTest Layout 조회
SELECT
    ITM_SEQ,
    ITM_ID,
    ITM_NM,
    ITM_DATA_TP || '(' || NVL(ITM_DATA_L, 0) || DECODE(NULLIF(ITM_DATA_DOT, 0), NULL, '', ',') || TO_CHAR(NULLIF(ITM_DATA_DOT, 0)) || ')' AS DATA_TP,
    CASE
    WHEN ITM_ID IN ('MSG_ID','JMS_TC_CD','TC_CODE') THEN NVL(:V_ORG_IF_ID,IF_ID)
    WHEN ITM_ID IN ('JMS_TC_CREATE_DDTT','TC_CREATE_DDTT') THEN TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
    WHEN ITM_ID = 'DATE'    THEN TO_CHAR(SYSDATE, 'YYYY-MM-DD')
    WHEN ITM_ID = 'TIME'    THEN TO_CHAR(SYSDATE, 'HH24:MI:SS')
    WHEN ITM_ID = 'MSG_GP'  THEN NVL(ITM_VAL9,'I')
    WHEN ITM_ID = 'MSG_LEN' THEN TO_CHAR(SUM(ITM_DATA_L) OVER () - 60,'FM0000')
    ELSE DECODE(SUBSTR(IF_ID, 5, 1), 'L', DECODE(ITM_VAL9, NULL, RPAD(' ', ITM_DATA_L, ' '), DECODE(ITM_DATA_TP, 'N', LPAD(ITM_VAL9, ITM_DATA_L, '0'), RPAD(ITM_VAL9, ITM_DATA_L, ' '))), TRIM(ITM_VAL9))
    END AS ITM_VAL,
    ESS_YN,
    REMARKS,
    IF_ID,
    ITM_DATA_TP,
    ITM_DATA_L,
    COUNT(*) OVER() TOTALCOUNT
FROM
    TB_YF_Z_IFLAYOUT
WHERE 1=1
AND IF_ID = SUBSTR(:V_IF_ID,1, CASE WHEN SUBSTR(:V_IF_ID,1,3) = 'M10' THEN 12 ELSE 8 END) 
ORDER BY ITM_SEQ
 </pre> */
public final static String getIfTestLayout = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getIfTestLayout_PIDEV";

 /** <pre> 2020-03-26
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarschCarNoCardNoTransNoCHK
WITH TEMP_TABLE AS
(
    SELECT
        :V_YD_GP AS YD_GP,
        :V_TRANS_ORD_DATE AS TRANS_ORD_DATE,
        :V_TRANS_ORD_SEQNO AS TRANS_ORD_SEQNO
    FROM
        DUAL
)
SELECT
    COUNT(*) AS CHK
FROM
    (
        SELECT
            SUBSTR(YD_CARPNT_CD, 2, 2)
        FROM
            (
                SELECT
                    A.STL_NO,
                    B.YD_STK_COL_GP,
                    SUBSTR(B.YD_STK_COL_GP, 1, 1) AS YD_GP,
                    SUBSTR(B.YD_STK_COL_GP, 3, 2) AS SPAN_GP,
                    SUBSTR(B.YD_STK_COL_GP, 2, 1) AS BAY_GP
                FROM
                    USRYDA.TB_YD_STOCK A,
                    USRYDA.TB_YD_STKLYR B,
                    TEMP_TABLE C
                WHERE 1=1
                AND A.STL_NO = B.STL_NO
                AND A.TRANS_ORD_DATE = C.TRANS_ORD_DATE
                AND A.TRANS_ORD_SEQNO = C.TRANS_ORD_SEQNO
                AND C.YD_GP = 'J'

                UNION ALL

                SELECT
                    A.STOCK_ID,
                    B.STACK_COL_GP,
                    SUBSTR(B.STACK_COL_GP, 1, 1) AS YD_GP,
                    SUBSTR(B.STACK_COL_GP, 3, 2) AS SPAN_GP,
                    SUBSTR(B.STACK_COL_GP, 2, 1) AS BAY_GP
                FROM
                    USRYMA.TB_YM_STOCK A,
                    USRYMA.TB_YM_STACKLAYER B,
                    TEMP_TABLE C
                WHERE 1=1
                AND A.STOCK_ID = B.STOCK_ID
                AND A.TRANS_ORD_DATE2 = C.TRANS_ORD_DATE
                AND A.TRANS_ORD_SEQNO2 = C.TRANS_ORD_SEQNO
                AND C.YD_GP = '3'

                UNION ALL

                SELECT
                    A.STL_NO,
                    B.YD_STK_COL_GP,
                    SUBSTR(B.YD_STK_COL_GP, 1, 1) AS YD_GP,
                    SUBSTR(B.YD_STK_COL_GP, 3, 2) AS SPAN_GP,
                    SUBSTR(B.YD_STK_COL_GP, 2, 1) AS BAY_GP
                FROM
                    USRYFA.TB_YF_STOCK A,
                    USRYFA.TB_YF_STKLYR B,
                    TEMP_TABLE C
                WHERE 1=1
                AND A.STL_NO = B.STL_NO
                AND A.TRANS_ORD_DATE = C.TRANS_ORD_DATE
                AND A.TRANS_ORD_SEQNO = C.TRANS_ORD_SEQNO
                AND C.YD_GP = '1'
            ) A,
            USRYDA.TB_YD_CARPOINT B
        WHERE 1=1
        AND A.YD_GP = B.YD_GP
        AND B.DEL_YN = 'N'
        AND A.SPAN_GP BETWEEN B.YD_SPAN_FROM AND B.YD_SPAN_TO
        AND A.BAY_GP = B.YD_BAY_GP
        AND A.STL_NO <> :V_STL_NO
        GROUP BY SUBSTR(YD_CARPNT_CD, 2, 2)
    ) A
 </pre> */
public final static String getYdCarschCarNoCardNoTransNoCHK = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarschCarNoCardNoTransNoCHK";

