public final static String getYmEqpSchCnt = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYmEqpSchCnt";

 /** <pre> 2019-10-28
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.getaslabYdNEqpXyaxisSet 
SELECT X.YD_STK_COL_GP           -- 적치열구분
      ,X.COL_GP          -- 적치열번호
      ,X.YD_STK_COL_ACTIVE_STAT    -- 적치열활성상태
      ,decode(X.YD_STK_COL_ACTIVE_STAT,'C','비활성화'
                                   ,'L','적치 가능'
                                   ,'N','사용 불가')
                                   AS YD_STK_COL_ACTIVE_STATHIDDEN        -- 적치열활성상태
      ,X.YD_STK_COL_USAGE_CD
      ,A.DTL_ITEM2 AS CLASS2_NAME1
      ,A.ITEM AS CLASS2_CD
      ,Y.SUM_LYR_CNT AS SUM_LYR_CNT_TOT        -- 최대적치가능본수
      ,Y.SUM_STL_CNT_TOT        -- 현적치본수
      ,X.YD_STK_COL_RULE_X_AXIS 
      ,X.YD_STK_COL_RULE_Y_AXIS 
      ,X.YD_STK_COL_RULE_Z_AXIS
      ,X.YD_STK_COL_RULE_X_AXIS AS YD_STK_COL_RULE_X_AXIS_HIDDEN
      ,X.YD_STK_COL_RULE_Y_AXIS AS YD_STK_COL_RULE_Y_AXIS_HIDDEN
      ,X.YD_STK_COL_RULE_Z_AXIS AS YD_STK_COL_RULE_Z_AXIS_HIDDEN
      ,(CASE WHEN X.MOD_DDTT > Z.MOD_DDTT THEN X.MODIFIER
        ELSE Z.MODIFIER END) AS MODIFIER
      ,TO_CHAR((CASE WHEN X.MOD_DDTT > Z.MOD_DDTT THEN X.MOD_DDTT
        ELSE Z.MOD_DDTT END), 'YYYY-MM-DD HH24:MI') AS MOD_DDTT
      ,RULE.DTL_ITEM1 AS RULE_L
      ,RULE.DTL_ITEM2 AS RULE_W
  FROM (SELECT YD_STK_COL_GP
              ,COL_GP
              ,YD_STK_COL_ACTIVE_STAT
              ,YD_STK_COL_USAGE_CD
              ,YD_STK_COL_RULE_X_AXIS 
              ,YD_STK_COL_RULE_Y_AXIS
              ,YD_STK_COL_RULE_Z_AXIS
              ,MODIFIER
              ,MOD_DDTT
          FROM TB_YF_STKCOL
         WHERE YD_GP = :V_YD_GP
           AND BAY_GP  LIKE :V_BAY_GP  || '%'
           AND SECT_GP LIKE :V_SECT_GP || '%'
           AND COL_GP  LIKE :V_COL_GP  ||'%'
           AND DEL_YN = 'N'
           AND SECT_GP NOT IN ('CR','TR','TT','XX')
         ORDER BY COL_GP ) X
      ,(SELECT YD_STK_COL_GP
              ,SUM(CASE WHEN YD_STK_LYR_STAT = 'E' THEN 1 ELSE 0 END) AS SUM_LYR_CNT -- 1단적치가능본수
              --,SUM(CASE WHEN YD_STK_LYR_NO = '02' AND YD_STK_LYR_STAT = 'E' THEN 1 ELSE 0 END) AS SUM_LYR_CNT_L2 -- 2단적치가능본수
              ,SUM(DECODE(STL_NO, NULL, 0, 1)) AS SUM_STL_CNT_TOT -- 현적치본수 
          FROM TB_YF_STKLYR
         WHERE YD_STK_COL_GP LIKE :V_YD_GP || NVL(:V_BAY_GP,'_') || NVL(:V_SECT_GP,'__') || NVL(:V_COL_GP,'') || '%'
           AND DEL_YN = 'N'
         GROUP BY YD_STK_COL_GP ) Y
      ,(SELECT * 
          FROM TB_YF_STKBED
         WHERE YD_STK_BED_NO = '01') Z
       ,(SELECT * 
           FROM TB_YF_RULE
          WHERE REPR_CD_GP = 'YM103'
            AND CD_GP ='0') A 
      ,(SELECT *
          FROM TB_YF_RULE
         WHERE REPR_CD_GP = 'X_AXIS'
           AND CD_GP = '0'
           AND ITEM = '1') RULE
       
 WHERE X.YD_STK_COL_GP = Y.YD_STK_COL_GP
   AND X.YD_STK_COL_GP = Z.YD_STK_COL_GP(+)
   AND X.YD_STK_COL_USAGE_CD = A.ITEM 
 ORDER BY X.YD_STK_COL_GP
 </pre> */
public final static String getaslabYdNEqpXyaxisSet = "com.inisteel.cim.yf.aslab.dao.ASlabDAO.getaslabYdNEqpXyaxisSet";

