 /** <pre> 2020-12-15
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookBySchCd2
WITH DATA_TBL AS 
(
    SELECT
        *
    FROM
        (
            SELECT
                A.YD_WBOOK_ID,
                B.CTS_RELAY_BAY,
                A.YD_AIM_BAY_GP,
                B.CTS_RELAY_SADDLE,
                B.CAR_CARD_NO,
                SUBSTR(A.YD_SCH_CD, 6, 3),
                A.YD_SCH_CD
            FROM
                TB_YF_WRKBOOK      A,
                TB_YF_STOCK        B,
                TB_YF_WRKBOOKMTL   C
            WHERE 1 = 1
                AND A.YD_WBOOK_ID = C.YD_WBOOK_ID
                AND B.STL_NO = C.STL_NO
                AND A.YD_SCH_CD LIKE '1_PT__UM'
                AND B.CAR_CARD_NO = :V_CAR_NO
                AND A.DEL_YN = 'N'
                AND B.DEL_YN = 'N'
                AND C.DEL_YN = 'N'
                AND A.YD_WBOOK_ID NOT IN (
                    SELECT
                        YD_WBOOK_ID
                    FROM
                        TB_YF_CRNSCH B
                    WHERE
                        B.YD_GP = '1'
                        AND B.YD_SCH_CD LIKE '1_PT__UM'
                        AND B.DEL_YN = 'N'
                )
            ORDER BY
                A.YD_SCH_CD, A.YD_WBOOK_ID
        )
    WHERE
        ROWNUM = 1
)
SELECT
    *
FROM
    (
        SELECT
            ROWNUM AS CNT,
            AA.*
        FROM
            (
                SELECT
                    A.YD_WBOOK_ID,
                    D.CTS_RELAY_BAY,
                    A.YD_AIM_BAY_GP,
                    D.CTS_RELAY_SADDLE,
                    B.CAR_CARD_NO,
                    B.STL_NO,
                    B.YD_CAR_UPP_LOC_CD
                FROM
                    TB_YF_WRKBOOK      A,
                    TB_YF_STOCK        B,
                    TB_YF_WRKBOOKMTL   C,
                    DATA_TBL           D
                WHERE
                    1 = 1
                    AND A.YD_WBOOK_ID = C.YD_WBOOK_ID
                    AND B.STL_NO = C.STL_NO
                    AND A.YD_SCH_CD LIKE '1_PT__UM'
                    AND B.CAR_CARD_NO = :V_CAR_NO
                    AND A.DEL_YN = 'N'
                    AND B.DEL_YN = 'N'
                    AND C.DEL_YN = 'N'
                    AND A.YD_WBOOK_ID NOT IN (
                        SELECT
                            YD_WBOOK_ID
                        FROM
                            TB_YF_CRNSCH B
                        WHERE
                            B.YD_GP = '1'
                            AND B.YD_SCH_CD LIKE '1_PT__UM'
                            AND B.DEL_YN = 'N'
                    )
                    AND D.YD_AIM_BAY_GP = A.YD_AIM_BAY_GP    --동일 동
                    AND D.CTS_RELAY_SADDLE = B.CTS_RELAY_SADDLE --동일 방향
                ORDER BY
                    A.YD_SCH_CD, A.YD_WBOOK_ID
            ) AA
    )
WHERE
    CNT <= CTS_RELAY_BAY   -- 편성가능 갯수 
 </pre> */
public final static String getYdWrkbookBySchCd2 = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookBySchCd2";

