 /** <pre> 2019-10-15
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR020 
SELECT 'YDDMR020'                          AS JMS_TC_CD            --JMSTC코드
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT   --JMSTC생성일시
     , 'YDDMR020'                          AS TC_CODE              --IF구분코드
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS TC_CREATE_DDTT       --TC생성일시
     , CASE WHEN YD_CAR_PROG_STAT IN ('2','3','4','5')       THEN 'U'   
            ELSE 'D' END                   AS UPCARUNLOAD_GP
     , CARD_NO                             AS CARD_NO         
     , CAR_NO                              AS CAR_NO
     , SUBSTR(YD_CARLD_STOP_LOC,1,1)       AS YD_GP
     , CASE WHEN  YD_CAR_PROG_STAT IN ('2','3','4','5') 
            THEN SUBSTR(TO_CHAR(YD_CARLD_ST_DT,'YYYYMMDDHH24MISS'),1,8) 
            ELSE SUBSTR(TO_CHAR(YD_CARUD_ST_DT,'YYYYMMDDHH24MISS'),1,8) END  AS CARLOAD_START_DATE
     , CASE WHEN  YD_CAR_PROG_STAT IN ('2','3','4','5')
            THEN SUBSTR(TO_CHAR(YD_CARLD_ST_DT,'YYYYMMDDHH24MISS'),9,6) 
            ELSE SUBSTR(TO_CHAR(YD_CARUD_ST_DT,'YYYYMMDDHH24MISS'),9,6) END  AS CARLOAD_START_TIME 
     , TRANS_ORD_DATE                      AS TRANS_WORD_DATE
     , TRANS_ORD_SEQNO                     AS TRANS_WORD_SEQNO
  FROM TB_YD_CARSCH C
 WHERE YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
 </pre> */
public final static String TcYDDMR020 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR020";

 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getListACCountToExcel
SELECT A.YD_GP AS 야드구분, 
       A.BAY_GP AS 동구분, 
       DECODE(A.BAY_GP, 'T', '합계', A.BAY_GP||'동') AS 동이름, 
       TO_CHAR(A.QT_01, '99,999,999')        AS A재공수량,
       NVL(TO_CHAR(A.QT_02, '99,999,999'),0) AS B재공수량,
       NVL(TO_CHAR(A.QT_0C, '99,999,999'),0) AS C재공수량,
       
       TO_CHAR(A.WT_01, '99,999,999')        AS A재공중량,
       NVL(TO_CHAR(A.WT_02, '99,999,999'),0) AS B재공중량,
       NVL(TO_CHAR(A.WT_0C, '99,999,999'),0) AS C재공중량,
       
       TO_CHAR(A.QT_01+A.QT_03 , '99,999,999')       AS A수량,
       NVL(TO_CHAR(A.WT_01+A.WT_03, '99,999,999'),0) AS A중량,
       TO_CHAR((A.QT_01+NVL(A.QT_02,0)+NVL(A.QT_0C,0)) / A.TOT_QT * 100, '990.00') AS 재공비율,
       TO_CHAR(A.QT_03, '99,999,999')        AS A입고수량,
       NVL(TO_CHAR(A.QT_04, '99,999,999'),0) AS B입고수량,
       NVL(TO_CHAR(A.QT_05, '99,999,999'),0) AS C입고수량,
       
       TO_CHAR(A.WT_03, '99,999,999')        AS A입고중량,
       NVL(TO_CHAR(A.WT_04, '99,999,999'),0) AS B입고중량,
       NVL(TO_CHAR(A.WT_05, '99,999,999'),0) AS C입고중량,
       
       TO_CHAR(NVL(A.QT_02,0)+NVL(A.QT_04,0) , '99,999,999') AS B수량,
       NVL(TO_CHAR(A.WT_02+A.WT_04, '99,999,999'),0)         AS B중량,
       TO_CHAR((A.QT_03+NVL(A.QT_04,0)+NVL(A.QT_05,0)) / A.TOT_QT * 100, '990.00') AS 입고비율,
       
       TO_CHAR(NVL(A.QT_0C,0)+NVL(A.QT_05,0) , '99,999,999') AS C수량,
       NVL(TO_CHAR(A.WT_0C+A.WT_05, '99,999,999'),0)         AS C중량,       
       
       TO_CHAR(A.TOT_QT, '99,999,999') AS 총수량, 
       TO_CHAR(A.TOT_WT, '999,999,999') AS 총중량 
FROM (
       SELECT C.NO, A.YD_GP, 
              DECODE(C.NO, '01', A.BAY_GP, 'T') AS BAY_GP,
              SUM(DECODE(B.CURR_PROG_CD, 'M', 1, -- 종료상태
                                         'A', 1, -- 재질판정대기
                                         'B', 1, -- 정정지시대기
                                         'C', 1, -- 정정작업대기
                                         'D', 1, -- 이송지시대기
                                         'E', 1, -- 이송작업대기
                                         'F', 1, -- 판정보류
                                         'G', 1, -- 판정대기
                                         'H', 1, -- 입고대기
                                         'J', 1, -- 반납대기
                                         'K', 1, -- 출하지시대기
                                         'N', 1, -- 출하지시대기
                                         'L', 1, -- 출하작업대기
                                         'X', 1, -- 경매대상선정
                                         'Y', 1, -- 재공충당대기
                                         'Z', 1, -- 제품충당대기
                                         'R', 1, -- 재질판정대기
                                         0)) AS TOT_QT,
              SUM(DECODE(B.CURR_PROG_CD, 'M', B.COIL_WT, -- 종료상태
                                         'A', B.COIL_WT, -- 재질판정대기
                                         'B', B.COIL_WT, -- 정정지시대기
                                         'C', B.COIL_WT, -- 정정작업대기
                                         'D', B.COIL_WT, -- 이송지시대기
                                         'E', B.COIL_WT, -- 이송작업대기
                                         'F', B.COIL_WT, -- 판정보류
                                         'G', B.COIL_WT, -- 판정대기
                                         'H', B.COIL_WT, -- 입고대기
                                         'J', B.COIL_WT, -- 반납대기
                                         'K', B.COIL_WT, -- 출하지시대기
                                         'N', B.COIL_WT, -- 출하지시대기
                                         'L', B.COIL_WT, -- 출하작업대기
                                         'X', B.COIL_WT, -- 경매대상선정
                                         'Y', B.COIL_WT, -- 재공충당대기
                                         'Z', B.COIL_WT, -- 제품충당대기
                                         'R', B.COIL_WT, -- 재질판정대기
                                         0)) AS TOT_WT,
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, '1', 1, -- 종료상태
                                         'A', 1, -- 재질판정대기
                                         'B', 1, -- 정정지시대기
                                         'C', 1, -- 정정작업대기
                                         'D', 1, -- 이송지시대기
                                         'E', 1, -- 이송작업대기
                                         'F', 1, -- 판정보류
                                         'G', 1, -- 판정대기
                                         'H', 1, -- 입고대기
                                         'Y', 1, -- 재공충당대기
                                         'R', 1, -- 재질판정대기
                                         0)))) AS QT_01, -- A재공수량
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, '1', 1, -- 종료상태
                                         'A', 1, -- 재질판정대기
                                         'B', 1, -- 정정지시대기
                                         'C', 1, -- 정정작업대기
                                         'D', 1, -- 이송지시대기
                                         'E', 1, -- 이송작업대기
                                         'F', 1, -- 판정보류
                                         'G', 1, -- 판정대기
                                         'H', 1, -- 입고대기
                                         'Y', 1, -- 재공충당대기
                                         'R', 1, -- 재질판정대기
                                         0)))) AS QT_02, -- B재공수량
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, '1', 1, -- 종료상태
                                         'A', 1, -- 재질판정대기
                                         'B', 1, -- 정정지시대기
                                         'C', 1, -- 정정작업대기
                                         'D', 1, -- 이송지시대기
                                         'E', 1, -- 이송작업대기
                                         'F', 1, -- 판정보류
                                         'G', 1, -- 판정대기
                                         'H', 1, -- 입고대기
                                         'Y', 1, -- 재공충당대기
                                         'R', 1, -- 재질판정대기
                                         0)))) AS QT_0C, -- C재공수량
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, '1', B.COIL_WT, -- 종료상태
                                         'A', B.COIL_WT, -- 재질판정대기
                                         'B', B.COIL_WT, -- 정정지시대기
                                         'C', B.COIL_WT, -- 정정작업대기
                                         'D', B.COIL_WT, -- 이송지시대기
                                         'E', B.COIL_WT, -- 이송작업대기
                                         'F', B.COIL_WT, -- 판정보류
                                         'G', B.COIL_WT, -- 판정대기
                                         'H', B.COIL_WT, -- 입고대기
                                         'Y', B.COIL_WT, -- 재공충당대기
                                         'R', B.COIL_WT, -- 재질판정대기
                                         0)))) AS WT_01, --A 재고중량
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, '1', B.COIL_WT, -- 종료상태
                                         'A', B.COIL_WT, -- 재질판정대기
                                         'B', B.COIL_WT, -- 정정지시대기
                                         'C', B.COIL_WT, -- 정정작업대기
                                         'D', B.COIL_WT, -- 이송지시대기
                                         'E', B.COIL_WT, -- 이송작업대기
                                         'F', B.COIL_WT, -- 판정보류
                                         'G', B.COIL_WT, -- 판정대기
                                         'H', B.COIL_WT, -- 입고대기
                                         'Y', B.COIL_WT, -- 재공충당대기
                                         'R', B.COIL_WT, -- 재질판정대기
                                         0)))) AS WT_02,  --B 재고중량    
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, '1', B.COIL_WT, -- 종료상태
                                         'A', B.COIL_WT, -- 재질판정대기
                                         'B', B.COIL_WT, -- 정정지시대기
                                         'C', B.COIL_WT, -- 정정작업대기
                                         'D', B.COIL_WT, -- 이송지시대기
                                         'E', B.COIL_WT, -- 이송작업대기
                                         'F', B.COIL_WT, -- 판정보류
                                         'G', B.COIL_WT, -- 판정대기
                                         'H', B.COIL_WT, -- 입고대기
                                         'Y', B.COIL_WT, -- 재공충당대기
                                         'R', B.COIL_WT, -- 재질판정대기
                                         0)))) AS WT_0C,  --C 재고중량    
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, 'J', 1, -- 반납대기
                                         'K', 1, -- 출하지시대기
                                         'L', 1, -- 출하작업대기
                                         'N', 1, -- 출하작업대기
                                         'X', 1, -- 경매대상선정
                                         'Z', 1, -- 제품충당대기
                                         'M', 1, -- 종료
                                         0)))) AS QT_03,   -- A입고수량
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, 'J', 1, -- 반납대기
                                         'K', 1, -- 출하지시대기
                                         'L', 1, -- 출하작업대기
                                         'N', 1, -- 출하작업대기
                                         'X', 1, -- 경매대상선정
                                         'Z', 1, -- 제품충당대기
                                         'M', 1, -- 종료
                                         0)))) AS QT_04,   -- B입고수량
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, 'J', 1, -- 반납대기
                                         'K', 1, -- 출하지시대기
                                         'L', 1, -- 출하작업대기
                                         'N', 1, -- 출하작업대기
                                         'X', 1, -- 경매대상선정
                                         'Z', 1, -- 제품충당대기
                                         'M', 1, -- 종료
                                         0)))) AS QT_05,   -- C입고수량
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, 'J', B.COIL_WT, -- 반납대기
                                         'K', B.COIL_WT, -- 출하지시대기
                                         'L', B.COIL_WT, -- 출하작업대기
                                         'N', B.COIL_WT, -- 출하작업대기
                                         'X', B.COIL_WT, -- 경매대상선정
                                         'Z', B.COIL_WT, -- 제품충당대기
                                         'M', B.COIL_WT, -- 종료
                                         0)))) AS WT_03, --A 입고 중량                                                              
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, 'J', B.COIL_WT, -- 반납대기
                                         'K', B.COIL_WT, -- 출하지시대기
                                         'L', B.COIL_WT, -- 출하작업대기
                                         'N', B.COIL_WT, -- 출하작업대기
                                         'X', B.COIL_WT, -- 경매대상선정
                                         'Z', B.COIL_WT, -- 제품충당대기
                                         'M', B.COIL_WT, -- 종료
                                         0)))) AS WT_04, --B 입고 중량 
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, 'J', B.COIL_WT, -- 반납대기
                                         'K', B.COIL_WT, -- 출하지시대기
                                         'L', B.COIL_WT, -- 출하작업대기
                                         'N', B.COIL_WT, -- 출하작업대기
                                         'X', B.COIL_WT, -- 경매대상선정
                                         'Z', B.COIL_WT, -- 제품충당대기
                                         'M', B.COIL_WT, -- 종료
                                         0)))) AS WT_05 --C 입고 중량  
       FROM (
                  SELECT SUBSTR(A.YD_STK_COL_GP,1,1) AS YD_GP, 
                         SUBSTR(A.YD_STK_COL_GP,2,1) AS BAY_GP,
                         SUBSTR(A.YD_STK_COL_GP,3,2) AS SECT_GP,
                         DECODE(B.YD_STK_LYR_STAT, 'L', 1, 'S', 1, 'U', 1, 0) AS LOAD_YN, 
                         B.STL_NO,
                         NVL(C.KEEP_STL_YN, 'N') AS KEEP_YN,
                         SUBSTR(B.STL_NO,1,1) AS GUBUN
                      FROM TB_YF_STKCOL A, TB_YF_STKLYR B , TB_YF_STOCK C
                  WHERE A.YD_STK_COL_GP LIKE :V_YD_GP ||'%' -- ? 야드구분
                    AND A.SECT_GP BETWEEN '01' AND '99'
                    AND B.YD_STK_LYR_STAT IN ('L','S','U')
                    AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
                    AND B.STL_NO =C.STL_NO
                    AND B.YD_STK_LYR_ACTIVE_STAT IN ( 'E', 'O' )
                ) A, VW_YF_COILCOMM B ,(SELECT LPAD(LEVEL,2,'0') AS NO FROM DUAL CONNECT BY LEVEL <= 99 ) C
           WHERE A.SECT_GP BETWEEN '01' AND '99'
             AND A.KEEP_YN LIKE :V_KEEP_YN --  보관매출여부
             AND A.STL_NO = B.COIL_NO(+)
             AND C.NO < '03'
           GROUP BY C.NO, A.YD_GP, DECODE(C.NO, '01', A.BAY_GP, 'T')     
     ) A
ORDER BY A.NO, A.YD_GP, A.BAY_GP
 </pre> */
public final static String getListACCountToExcel = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getListACCountToExcel";

