 /** <pre> 2021-01-11
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilSpanUnitCarMvstkRegNew.getBecauseMv_PIDEV 
SELECT CC.*,
     (
        SELECT REPR_CD_CONTENTS
        FROM   USRYFA.TB_YF_RULE R 
        WHERE  R.REPR_CD_GP='YM6001' 
        AND    R.DEL_YN='N'
        AND    R.ITEM=CC.YD_ZONE_GP_S
     ) AS YD_ZONE_GP
  FROM (
  
        SELECT ROWNUM AS RNUM
              ,AA.*
              ,BB.YD_WBOOK_ID
              ,BB.YD_SCH_CD
              ,BB.CD_CONTENTS
           
          FROM (
          
                SELECT DECODE(STK.STOCK_ITEM, 'SM', D.ORD_NO, 'CM', COM.ORD_NO, 'CG', COM.ORD_NO, '-') AS ORD_NO, -- 주문번호,
                       DECODE(STK.STOCK_ITEM, 'SM', D.ORD_DTL, 'CM', COM.ORD_DTL, 'CG', COM.ORD_DTL, '-') AS ORD_DTL -- 주문행번,
                      ,STK.STL_NO
                      ,STK.STOCK_ITEM
                      ,LYR.YD_STK_COL_GP||LYR.YD_STK_BED_NO||LYR.YD_STK_LYR_NO AS FROMLOC
                      ,LYR.YD_STK_LYR_NO
                      ,LYR.YD_STK_LYR_STAT
                      ,COM.CURR_PROG_CD AS STL_PROG_CD -- 진도
                      ,COM.NEXT_PROC -- 다음공정
                      ,COM.COIL_T AS YD_MTL_T -- 두께 
                      ,COM.COIL_W AS YD_MTL_W -- 폭 
                      ,COM.COIL_WT AS YD_MTL_WT -- 중량 
                      ,COM.COIL_OUTDIA -- 외경 
                      ,COUNT(*) OVER() AS TOTALCOUNT
                      ,NVL(E.NAME_ORG1 , ' ') AS CUST_KO_NAME -- 수요가명
                      ,NVL((SELECT YD_ZONE_GP FROM VW_YF_GETCONDENSATIONLOC  WHERE COIL_NO=LYR.STL_NO ),' ') AS YD_ZONE_GP_S
      
                      
                  FROM TB_YF_STKLYR LYR
                      ,TB_YF_STKCOL COL
                      ,TB_YF_STOCK STK
                      ,VW_YF_COILCOMM COM
                      ,USRCOM.TB_COM_BP_MASTER E
                      ,(SELECT WM.*  -------------------------------------------------------------------------------------
                                   FROM TB_YF_WRKBOOK      WB
                                      , TB_YF_WRKBOOKMTL   WM
                                  WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
                                    AND WB.DEL_YN = 'N'
                                    AND WM.DEL_YN = 'N'
                       ) C
                      ,VW_YD_SLABCOMM D
                      
                 WHERE LYR.YD_STK_COL_GP LIKE :V_YD_GP || :V_BAY_GP || :V_SECT_GP || :V_COL_GP || '%'
                   AND LYR.DEL_YN = 'N'
                   AND LYR.STL_NO IS NOT NULL
                   AND LYR.YD_STK_LYR_STAT IN ('C', 'U')  --적치중,권상대기 
                   AND LYR.YD_STK_COL_GP = COL.YD_STK_COL_GP
                   AND COL.SECT_GP BETWEEN '00' AND '99'
                   AND LYR.STL_NO = STK.STL_NO
                   AND STK.STL_NO = COM.COIL_NO(+)
                   AND LYR.STL_NO = C.STL_NO(+)
                   AND C.DEL_YN(+) = 'N'
                   AND LYR.STL_NO = D.SLAB_NO(+)
                
                   AND NVL(COM.CURR_PROG_CD,' ') LIKE :V_CURR_PROG_CD || '%'
                   AND NVL(COM.NEXT_PROC,'-') LIKE :V_NEXT_PROC || '%'
                   AND (
                          --------------------------------------------------------- 
                          (:V_STL_NO IS NULL AND STK.STL_NO = COM.COIL_NO) OR (
                             :V_STL_NO IS NOT NULL AND STK.STL_NO IN (
                                SELECT SUBSTR (AA, INSTR (AA, ',', 1, LEVEL) + 1, INSTR (AA, ',', 1, LEVEL + 1) - INSTR (AA, ',', 1, LEVEL) - 1 ) AS COIL_NO
                                  FROM (SELECT ',' || :V_STL_NO || ',' AA FROM DUAL)
                                CONNECT BY LEVEL <= LENGTH (AA) - LENGTH (REPLACE (AA, ',')) - 1             
                             )
                          )
                          --------------------------------------------------------- 
                       )
                   AND STK.STL_NO NOT IN (
                          SELECT B.STL_NO 
                            FROM TB_YF_WRKBOOK A
                               , TB_YF_WRKBOOKMTL B
                           WHERE A.YD_WBOOK_ID=B.YD_WBOOK_ID
                             AND A.DEL_YN='N'
                             AND B.DEL_YN='N'
                             AND (A.YD_SCH_CD LIKE '1_PT31%' OR A.YD_SCH_CD LIKE '1_PT32%') --박판열연코일 차량동간이적 LEFT RIGHT 제외
                       )
                   AND COM.DEMANDER_CD = E.PARTNER(+)    
                   AND NVL(E.PARTNER,' ') = DECODE(:V_CUST_CD,'',NVL(E.PARTNER,' '),:V_CUST_CD)     
                 ORDER BY LYR.YD_STK_COL_GP 
                         ,LYR.YD_STK_BED_NO 
                         ,LYR.YD_STK_LYR_NO   DESC
          
               ) AA
              
              ,(
              
                 SELECT A.STL_NO
                       ,A.YD_WBOOK_ID
                       ,B.YD_SCH_CD
                       ,C.CD_CONTENTS
                   FROM TB_YF_WRKBOOKMTL A
                       ,TB_YF_WRKBOOK B
                       ,TB_YF_SCHRULE C
                  WHERE A.DEL_YN = 'N'
                    AND A.YD_WBOOK_ID = B.YD_WBOOK_ID
                    AND B.DEL_YN = 'N' 
                    AND B.YD_SCH_CD = C.YD_SCH_CD(+)
                    
               ) BB
         WHERE NVL(AA.ORD_NO,' ') LIKE :V_ORD_NO||'%'
           AND NVL(AA.ORD_DTL,' ') LIKE :V_ORD_DTL||'%'
           AND AA.YD_ZONE_GP_S LIKE :V_YD_ZONE_GP||'%'
           AND ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE
           AND AA.STL_NO = BB.STL_NO(+)
     

       ) CC
 WHERE RNUM >= (( :V_PAGE_NO - 1 )* :V_PAGE_SIZE) + 1
 </pre> */
public final static String getBecauseMv = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilSpanUnitCarMvstkRegNew.getBecauseMv_PIDEV";

 /** <pre> 2019-11-26
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYFF1L007
WITH PARAM AS (
    SELECT :V_YD_EQP_ID AS V_YD_EQP_ID
      FROM DUAL
)


SELECT 'YFF1L007'                          AS JMS_TC_CD --JMSTC코드
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTC생성일시
      ,'YFF1L007'                                 --전문ID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')    --생성일시
     ||'I'                                        --전문구분
     ||'0046' --전문길이
     ||RPAD(' ',29,' ')                           --임시
     ||RPAD(NVL(P.V_YD_EQP_ID       ,' '), 6,' ')  --야드설비ID
     ||RPAD(NVL(YD_SCH_FLAG1       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT1        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG2       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT2        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG3       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT3        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG4       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT4        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG5       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT5        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG6       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT6        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG7       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT7        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG8       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT8        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG9       ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT9        ,' '), 3,' ')  --요구스케쥴건수1
     ||RPAD(NVL(YD_SCH_FLAG10      ,' '), 1,' ')  --요구스케쥴구분1
     ||RPAD(NVL(YD_SCH_CNT10       ,' '), 3,' ')  --요구스케쥴건수1
     
       AS JMS_TC_MESSAGE    --JMSTCMessage
  FROM (

        SELECT MAX(DECODE(CNT, 1,YD_SCH_FLAG,''))  AS YD_SCH_FLAG1
             , MAX(DECODE(CNT, 1,YD_SCH_CNT,''))   AS YD_SCH_CNT1
             , MAX(DECODE(CNT, 2,YD_SCH_FLAG,''))  AS YD_SCH_FLAG2
             , MAX(DECODE(CNT, 2,YD_SCH_CNT,''))   AS YD_SCH_CNT2
             , MAX(DECODE(CNT, 3,YD_SCH_FLAG,''))  AS YD_SCH_FLAG3
             , MAX(DECODE(CNT, 3,YD_SCH_CNT,''))   AS YD_SCH_CNT3
             , MAX(DECODE(CNT, 4,YD_SCH_FLAG,''))  AS YD_SCH_FLAG4
             , MAX(DECODE(CNT, 4,YD_SCH_CNT,''))   AS YD_SCH_CNT4
             , MAX(DECODE(CNT, 5,YD_SCH_FLAG,''))  AS YD_SCH_FLAG5
             , MAX(DECODE(CNT, 5,YD_SCH_CNT,''))   AS YD_SCH_CNT5
             , MAX(DECODE(CNT, 6,YD_SCH_FLAG,''))  AS YD_SCH_FLAG6
             , MAX(DECODE(CNT, 6,YD_SCH_CNT,''))   AS YD_SCH_CNT6
             , MAX(DECODE(CNT, 7,YD_SCH_FLAG,''))  AS YD_SCH_FLAG7
             , MAX(DECODE(CNT, 7,YD_SCH_CNT,''))   AS YD_SCH_CNT7
             , MAX(DECODE(CNT, 8,YD_SCH_FLAG,''))  AS YD_SCH_FLAG8
             , MAX(DECODE(CNT, 8,YD_SCH_CNT,''))   AS YD_SCH_CNT8
             , MAX(DECODE(CNT, 9,YD_SCH_FLAG,''))  AS YD_SCH_FLAG9
             , MAX(DECODE(CNT, 9,YD_SCH_CNT,''))   AS YD_SCH_CNT9
             , MAX(DECODE(CNT,10,YD_SCH_FLAG,''))  AS YD_SCH_FLAG10
             , MAX(DECODE(CNT,10,YD_SCH_CNT,''))   AS YD_SCH_CNT10
          FROM     
        (     
        SELECT YD_SCH_FLAG 
             , LPAD(TO_CHAR(COUNT(*)),'3',0) AS YD_SCH_CNT
             , ROW_NUMBER() OVER(ORDER BY YD_SCH_FLAG) AS CNT
          FROM (
                SELECT USRYFA.SF_YF_GET_SCH_FLAG(A.YD_SCH_CD) AS YD_SCH_FLAG
                    ,B.YD_WRK_CRN ,B.YD_ALT_CRN,A.YD_SCH_CD
                FROM TB_YF_CRNSCH A
                   , TB_YF_SCHRULE B
                   , TB_YF_EQP C
                   , PARAM P
                WHERE A.YD_SCH_CD = B.YD_SCH_CD
                 AND B.YD_WRK_CRN = C.YD_EQP_ID
                 AND A.DEL_YN='N'
                 AND (CASE C.YD_EQP_PROG_STAT WHEN 'B' THEN B.YD_ALT_CRN ELSE A.YD_EQP_ID END)=P.V_YD_EQP_ID
                ) A
                ,PARAM P
         GROUP BY YD_SCH_FLAG
        ) 
),PARAM P
 </pre> */
public final static String TcYFF1L007 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYFF1L007";

