 /** <pre> 2019-10-15
--com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabProducList.getExcel01

    SELECT --+ ALL_ROWS A.*, ROWNUM AS RNUM
    FROM
    (
        SELECT
               --+ORDERED USE_NL(A B) USE_MERGE(A C)
              COUNT(*) OVER() AS TOTALCOUNT,
              A.YD_STK_COL_GP AS ORDER1,
              A.YD_STK_BED_NO AS ORDER2,
              A.YD_STK_LYR_NO AS ORDER3,
              DECODE(SUBSTR(A.YD_STK_COL_GP, 1, 1),0,'박판열연 SLAB야드',2,'1열연 SLAB야드') AS YD_GP,
              SUBSTR(A.YD_STK_COL_GP, 2, 1) AS BAY_GP,
              SUBSTR(A.YD_STK_COL_GP, 3, 2) AS SPAN_GP,
              A.STL_NO AS SLAB_NO, -- 저장품 ID
              A.YD_STK_COL_GP||A.YD_STK_BED_NO||A.YD_STK_LYR_NO AS EXPECT_YD_STK_LOC, --저장위치,
              C.BUY_SLAB_NO, --구입슬라브 번호
              C.SPEC_ABBSYM,  -- 규격약호
              TO_CHAR(C.SLAB_T, '99,999,990')    AS SLAB_T,      --두께
              TO_CHAR(C.SLAB_W, '99,999,990')    AS SLAB_W,      --폭
              TO_CHAR(C.SLAB_LEN, '99,999,990')  AS SLAB_LEN,    --길이
              TO_CHAR(DECODE(C.YD_GP,'4',C.MS_SLAB_ALLOC_WT,C.CAL_SLAB_WT), '99,999,990') AS SLAB_WT,--중량,
              TO_CHAR(C.BUY_ORD_T, '99,999,990') AS BUY_ORD_T,   --구매주문두께
              TO_CHAR(C.BUY_ORD_W, '99,999,990') AS BUY_ORD_W,   --구매주문폭 
              C.MAKER_NAME,  --구매처,
              C.CURR_PROG_CD, --재료진도,
              (
              SELECT CD_MNNG 
                FROM BRE.VW_CM_CODES
               WHERE CD_EN_ID = 'CURR_PROG_CD'
                 AND CD_CAT_ID = 'HS0000'
                 AND CD_EN_ID = C.CURR_PROG_CD)AS CURR_PROG_NAME, -- 재료진도명
              C.COST_SPEC_ABBSYM, -- 원가규격약호
              C.DESIGN_SPEC_ABBSYM, --설계규격약호
              C.ORD_YEOJAE_GP, --주여구분
              C.INGRHOLD_YN, --성분보류우무
              NVL(C.SURFACE_STAMP_GRADE,' ') AS SURFACE_STAMP_GRADE, --표면판정등급
              NVL(C.FORM_STAMP_GRADE,' ') AS FORM_STAMP_GRADE, --형상판정등급
              NVL(C.INSPECT_GRADE,' ') AS INSPECT_GRADE, --검사등급
              NVL(C.INGR_STAMP_GRADE,' ') AS INGR_STAMP_GRADE, --성분판정등급
              C.RECEIPT_DATE, --입고일자
              C.C_WRSLT, --탄소수치
              C.ITEMNAME_CD, --품명
              C.SLAB_WO_RT_CD
        FROM TB_YF_STKLYR A, 
             TB_YF_STOCK B, 
             (SELECT 
                A.SLAB_NO,
                B.BUY_SLAB_NO, 
                A.SPEC_ABBSYM,
                A.REAL_MEASURE_SLAB_T AS SLAB_T,
                A.REAL_MEASURE_SLAB_W AS SLAB_W,
                A.REAL_MEASURE_SLAB_LEN AS SLAB_LEN,
                A.CAL_SLAB_WT,
                A.MS_SLAB_ALLOC_WT,
                DECODE(B.BUY_ORD_T,NULL,A.SLAB_T,B.BUY_ORD_T) AS BUY_ORD_T,
                DECODE(B.BUY_ORD_W,NULL,A.SLAB_W,B.BUY_ORD_W) AS BUY_ORD_W,
                DECODE(B.MAKER_NAME,NULL,'HYUNDAI STEEL',B.MAKER_NAME) AS MAKER_NAME,
                A.PLAN_SLAB_NO,
                A.YD_GP,
                A.HEAT_NO,
                A.RECORD_PROG_STAT,
                A.RECEIPT_DATE,
                A.INGR_STAMP_GRADE,
                A.INSPECT_GRADE,
                A.FORM_STAMP_GRADE,
                A.SURFACE_STAMP_GRADE,
                A.INGRHOLD_YN,
                A.ORD_YEOJAE_GP,
                A.DESIGN_SPEC_ABBSYM,
                A.MS_SPEC_ABBSYM AS COST_SPEC_ABBSYM,
                A.CURR_PROG_CD,
                A.ITEMNAME_CD,
                A.SLAB_WO_RT_CD,
                D.C_WRSLT --탄소수치
              FROM VW_YD_SLABCOMM A, TB_PT_HEATCOMM D,  TB_QM_BUYSLABINFO B
              WHERE A.MSLAB_NO = B.MSLAB_NO(+)
               AND A.RECORD_PROG_STAT in ('1','2')
               AND A.HEAT_NO = D.HEAT_NO
             )C
        WHERE A.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'-- 야드구분+동구분+열구분(1A01)
          AND A.YD_STK_LYR_STAT IN ('L', 'S', 'U')
          AND A.STL_NO = B.STL_NO
          AND A.STL_NO = C.SLAB_NO(+)
        ORDER BY A.YD_STK_COL_GP, A.YD_STK_BED_NO, A.YD_STK_LYR_NO 
    )A 
 </pre> */
public final static String getExcel01 = "com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabProducList.getExcel01";

