 /** <pre> 2020-04-27
SELECT
    *
FROM
(
     SELECT
        CASE PROC_GP
            WHEN 'F' THEN 'HFL'
            WHEN 'K' THEN 'SPM'
            WHEN 'Q' THEN 'EQL'
        END ||' ' || YD_BAY_GP || '동'||' ['|| '1' || YD_BAY_GP || PROC_GP || 'E' || '01'||']' AS CD_NM,
        '1'||YD_BAY_GP || PROC_GP || 'E' || '01'   AS CD_VAL
     FROM TB_YF_EQPTRACKING
     WHERE PROC_GP IN ( 'K', 'F', 'Q')
     AND YD_STK_COL_GP||' '|| YD_STK_BED_NO  
        IN ( '1BFE01 01',
             '1DKE01 01','1DKE01 02','1DKE01 03','1DKE01 04', '1EKE01 01',
             '1EQE01 01','1EQE01 02','1EQE01 03','1EQE01 04','1EQE01 05','1EQE01 06','1EQE01 07','1FQE01 01','1FQE01 02')
     GROUP BY YD_BAY_GP, PROC_GP
     ORDER BY PROC_GP, YD_BAY_GP
 ) 
 </pre> */
public final static String getTakeInOutEqpCd = "com.inisteel.cim.yf.common.dao.YfCommDAO.getTakeInOutEqpCd";

 /** <pre> 2020-11-10
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.getYdCarPnt 
SELECT YD_CARPNT_DESC AS GATE_NM
      ,WLOC_CD
      ,YD_PNT_CD
      ,YD_STK_COL_GP
      ,YD_CARPNT_CD
      ,YD_CAR_USETYPE_GP
      ,YD_STK_COL_ACT_STAT
      ,YD_SPAN_FROM
      ,YD_SPAN_TO
      ,TRN_EQP_CD
      ,CAR_NO
      ,CARD_NO
      ,(SELECT YD_CAR_PROG_STAT FROM TB_YD_CARSCH CS WHERE CS.DEL_YN = 'N' AND CS.TRN_EQP_CD = CP.TRN_EQP_CD AND ROWNUM = 1) AS YD_CAR_PROG_STAT
      ,(SELECT YD_CAR_SCH_ID FROM TB_YD_CARSCH CS WHERE CS.DEL_YN = 'N' AND CS.TRN_EQP_CD = CP.TRN_EQP_CD AND ROWNUM = 1) AS YD_CAR_SCH_ID
      ,(SELECT COUNT(*) FROM TB_YM_STACKLAYER LYR WHERE LYR.STACK_COL_GP = CP.YD_STK_COL_GP AND STOCK_ID IS NOT NULL AND STACK_LAYER_STAT <> 'C' ) AS SCH_CNT
      ,(SELECT COUNT(*) FROM TB_YM_STACKLAYER LYR WHERE LYR.STACK_COL_GP = CP.YD_STK_COL_GP AND STOCK_ID IS NOT NULL ) AS STOCK_CNT
      ,(SELECT REGISTER FROM TB_YD_CARSCH CS WHERE CS.DEL_YN = 'N' AND CS.TRN_EQP_CD = CP.TRN_EQP_CD AND ROWNUM = 1) AS REGISTER
  FROM TB_YD_CARPOINT CP
 WHERE YD_STK_COL_GP LIKE :V_YD_GP || '%01'
   AND DEL_YN = 'N'
 ORDER BY YD_STK_COL_GP   
 </pre> */
public final static String getYdCarPnt = "com.inisteel.cim.yf.aslab.dao.ASlabDAO.getYdCarPnt";

 /** <pre> 2019-10-23
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getInitTrgtWrkList 
SELECT WM.STL_NO
     , WB.*
  FROM TB_YF_WRKBOOK     WB
     , TB_YF_WRKBOOKMTL  WM
     , TB_YF_TCARFTMVMTL TM
 WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
   AND WB.DEL_YN = 'N'
   AND WM.DEL_YN = 'N'
   AND WM.STL_NO = TM.STL_NO
   AND TM.YD_TCAR_SCH_ID IN (SELECT YD_TCAR_SCH_ID
                               FROM TB_YF_TCARSCH
                              WHERE YD_EQP_ID = :V_YD_EQP_ID
                                AND DEL_YN    = 'N')
   AND NOT EXISTS (SELECT 1
                     FROM TB_YF_CRNSCH     CS
                        , TB_YF_CRNWRKMTL  CM
                    WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
                      AND CS.DEL_YN = 'N'
                      AND CS.DEL_YN = 'N'
                      AND CM.STL_NO = TM.STL_NO
                   )
 </pre> */
