 /** <pre> 2020-04-06
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getACoilToLocLogSearch
SELECT
    A.*
    , B.CD_CONTENTS AS YD_SCH_CD_NM
FROM
(
    SELECT 
         YF_SCHLOG_ID
        ,STL_NO
        ,YD_CRN_SCH_ID
        ,YD_GP
        ,YD_SCH_CD
        ,REGISTER
        ,REG_DDTT
        ,MODIFIER
        ,TO_CHAR(MOD_DDTT,'YYYY-MM-DD HH24:MI:SS') AS MOD_DDTT
        ,DEL_YN
        ,SORT_SEQ 
        ,CASE WHEN SCH_CONTENTS LIKE '대상코일위치검색실패%' THEN DBMS_LOB.SUBSTR(SCH_CONTENTS)
        ELSE DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,2)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,1)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,1)+1) END AS LOC_ABLE_CHK
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,3)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,2)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,2)+1) AS GRIDE
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,4)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,3)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,3)+1) AS PRIOR0
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,5)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,4)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,4)+1) AS PRIOR1
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,6)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,5)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,5)+1) AS PRIOR2
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,7)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,6)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,6)+1) AS PRIOR3
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,8)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,7)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,7)+1) AS PRIOR4
        
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,9)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,8)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,8)+1) AS YD_EQP_ID
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,10)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,9)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,9)+1) AS TAG_YD_STK_COL_GP
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,11)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,10)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,10)+1) AS TAG_YD_STK_BED_NO
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,12)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,11)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,11)+1) AS TAG_YD_STK_LYR_NO
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,13)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,12)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,12)+1) AS TAG_COL_USE_CD
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,14)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,13)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,13)+1) AS C_OUTDIA
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,15)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,14)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,14)+1) AS C_WIDTH
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,16)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,15)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,15)+1) AS C_WEIGTH
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,17)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,16)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,16)+1) AS C_THICK
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,18)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,17)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,17)+1) AS L_COIL_NO
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,19)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,18)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,18)+1) AS L_OUTDIA
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,20)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,19)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,19)+1) AS L_WIDTH
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,21)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,20)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,20)+1) AS L_WEIGTH
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,22)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,21)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,21)+1) AS L_THICK
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,23)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,22)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,22)+1) AS R_COIL_NO
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,24)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,23)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,23)+1) AS R_OUTDIA
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,25)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,24)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,24)+1) AS R_WIDTH
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,26)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,25)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,25)+1) AS R_WEIGTH
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,27)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,26)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,26)+1) AS R_THICK
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,28)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,27)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,27)+1) AS L_WB
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,29)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,28)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,28)+1) AS R_WB
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,30)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,29)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,29)+1) AS L_ISHOT
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,31)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,30)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,30)+1) AS R_ISHOT
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,32)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,31)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,31)+1) AS C_JJANG_GP
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,33)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,32)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,32)+1) AS R_JJANG_GP
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,34)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,33)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,33)+1) AS L_JJANG_GP
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,35)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,34)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,34)+1) AS BEFORE_COL_WID
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,36)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,35)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,35)+1) AS NEXT_COL_WID
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,37)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,36)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,36)+1) AS BEFORE_COL_X_AXIS
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,38)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,37)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,37)+1) AS NEXT_COL_X_AXIS
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,39)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,38)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,38)+1) AS L2DAN_OUTDIA
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,40)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,39)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,39)+1) AS R2DAN_OUTDIA
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,41)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,40)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,40)+1) AS C_YAXIS_AUTO
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,42)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,41)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,41)+1) AS L_YAXIS_AUTO
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,43)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,42)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,42)+1) AS R_YAXIS_AUTO
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,44)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,43)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,43)+1) AS INCLINE_CHK
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,45)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,44)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,44)+1) AS BIZ_GP
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,46)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,45)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,45)+1) AS YD_ZONE_GP
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,47)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,46)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,46)+1) AS YD_EQP_PROG_STAT
        ,DBMS_LOB.SUBSTR(SCH_CONTENTS, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,48)-DBMS_LOB.INSTR(SCH_CONTENTS,',',1,47)-1, DBMS_LOB.INSTR(SCH_CONTENTS,',',1,47)+1) AS USAGE_PRIOR   
    FROM TB_YF_SCHLOG
    WHERE STL_NO        LIKE :V_STL_NO || '%' 
      AND YD_SCH_CD     LIKE :V_YD_SCH_CD ||'%'
      AND YD_CRN_SCH_ID LIKE :V_YD_CRN_SCH_ID || '%'
) A, TB_YF_SCHRULE B
WHERE A.YD_SCH_CD = B.YD_SCH_CD
ORDER BY YD_CRN_SCH_ID DESC, SORT_SEQ
 </pre> */
public final static String getACoilToLocLogSearch = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getACoilToLocLogSearch";

 /** <pre> 2019-12-11
 -- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getSumProgCoilInfoNEW15 
WITH TEMP_TABLE AS (
    SELECT A.YD_GP
            ,A.YD_BAY_GP
            ,A.STL_NO
            ,B.COIL_WT
            ,(CASE 
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  IN ('BK','CK','EK','HK') THEN 'BK~HK' 
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  IN ('BH','CH','DH','EH','FH','GH','HH') THEN 'AH~HH' 
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9C' AND  C.CR_PLNT_GP ='1' THEN '1냉연'
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9C' AND  C.CR_PLNT_GP IN('*','2') THEN '2냉연'
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9C' AND  C.CR_PLNT_GP='4' THEN '순천'
                --           WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9C' AND  C.CR_PLNT_GP='5' THEN '삼우당POL'
                --           WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9C' AND  C.CR_PLNT_GP='6' THEN '삼우울POL'
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9C' AND  C.CR_PLNT_GP NOT IN ('1','2','4','*') THEN '임가공-냉'
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9S'AND CURR_PROG_CD IN ('F','G')  THEN '9S'
                WHEN NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  ='9S' THEN '임가공'
                ELSE NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1)  
             END) AS NEXT_PROC
            ,B.CURR_PROG_CD
            ,(CASE 
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '%K'  THEN 'SPM'
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '%H'  THEN 'HFL'
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '%Q'  THEN 'EQL'
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '5A'  THEN '공냉재'
                WHEN CURR_PROG_CD IN ('F','G') THEN '보류재'
            ELSE '이송재' END) AS GP
            ,(CASE  
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '%K' THEN 1
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '%H' THEN 2
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '%Q' THEN 3
                WHEN CURR_PROG_CD NOT IN ('F','G') AND NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),PLAN_PROC1) LIKE '5A' THEN 4
                WHEN CURR_PROG_CD IN ('F','G') THEN 5
             ELSE 5 END) AS GP_RANK    
    FROM (
            SELECT  SUBSTR(A.YD_STK_COL_GP,1,1) AS YD_GP
                  , SUBSTR(A.YD_STK_COL_GP,2,1) AS YD_BAY_GP
                  , A.STL_NO
            FROM TB_YF_STKLYR A
            WHERE A.YD_STK_COL_GP LIKE '1%'
            AND SUBSTR(A.YD_STK_COL_GP,3,2) BETWEEN '00' AND '99'
            AND A.YD_STK_LYR_STAT IN('L','U','S','C') -- 적치가능, UP 스케쥴, 스케쥴예정, 적치중 
        ) A
        , TB_PT_COILCOMM B
        , TB_PT_COILCOMMSUB C
    WHERE A.STL_NO=B.COIL_NO
    AND B.COIL_NO=C.COIL_NO
    AND CURR_PROG_CD IN ('A','B','C','D','E','F','G')
)  
,TEMP_TABLE2 AS (
    SELECT *
     FROM (
        SELECT 1 AS CHK
                    , GP_RANK
                    ,RANK() OVER (PARTITION BY GP ORDER BY GP, NEXT_PROC) AS CHK_RANK
                    , GP
                    , NEXT_PROC
                    , SUM(CASE WHEN YD_BAY_GP='A' THEN 1 ELSE 0 END) AS A_CNT
                    , SUM(CASE WHEN YD_BAY_GP='A' THEN COIL_WT ELSE 0 END) AS  A_WT
                    
                    , SUM(CASE WHEN YD_BAY_GP='B' THEN 1 ELSE 0 END) AS B_CNT
                    , SUM(CASE WHEN YD_BAY_GP='B' THEN COIL_WT ELSE 0 END) AS B_WT
                    
                    , SUM(CASE WHEN YD_BAY_GP='C' THEN 1 ELSE 0 END) AS C_CNT
                    , SUM(CASE WHEN YD_BAY_GP='C' THEN COIL_WT ELSE 0 END) AS C_WT
                    
                    , SUM(CASE WHEN YD_BAY_GP='D' THEN 1 ELSE 0 END) AS D_CNT
                    , SUM(CASE WHEN YD_BAY_GP='D' THEN COIL_WT ELSE 0 END) AS D_WT
                    
                    , SUM(CASE WHEN YD_BAY_GP='E' THEN 1 ELSE 0 END) AS E_CNT
                    , SUM(CASE WHEN YD_BAY_GP='E' THEN COIL_WT ELSE 0 END) AS E_WT

                    , SUM(CASE WHEN YD_BAY_GP='F' THEN 1 ELSE 0 END) AS F_CNT
                    , SUM(CASE WHEN YD_BAY_GP='F' THEN COIL_WT ELSE 0 END) AS F_WT
                    
                    , SUM(CASE WHEN YD_BAY_GP='G' THEN 1 ELSE 0 END) AS G_CNT
                    , SUM(CASE WHEN YD_BAY_GP='G' THEN COIL_WT ELSE 0 END) AS G_WT
                    
                    , SUM(CASE WHEN YD_BAY_GP='H' THEN 1 ELSE 0 END) AS H_CNT
                    , SUM(CASE WHEN YD_BAY_GP='H' THEN COIL_WT ELSE 0 END) AS H_WT
                    
                    , SUM(1) AS TOT_CNT
                    , SUM(COIL_WT) AS TOT_WT
           FROM TEMP_TABLE
         GROUP BY GP, NEXT_PROC ,GP_RANK
     ) A
     ORDER BY GP_RANK,CHK_RANK
) 

SELECT
    T.*
  , COUNT(*) OVER(PARTITION BY GP) AS GROUP_CNT
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY GP ORDER BY GP_RANK, CHK_RANK, NEXT_PROC) = 1 THEN 'Y'
    ELSE 'N' END AS SHOW_ROWSPAN
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY GP ORDER BY GP_RANK, GP) = COUNT(*) OVER(PARTITION BY GP) THEN 'Y'
    ELSE 'N' END AS SHOW_SUM
  , CASE WHEN GP = NEXT_PROC THEN 'Y' ELSE 'N' END AS SHOW_COLSPAN
FROM 
(
    SELECT 
         GP_RANK
        ,CHK_RANK 
        ,GP 
        ,NEXT_PROC
        ,TO_CHAR(A_CNT, '9,999,999,999')  AS A_CNT
        ,TO_CHAR(ROUND(A_WT/1000), '9,999,999,999')  AS A_WT
        ,TO_CHAR(B_CNT, '9,999,999,999')  AS B_CNT
        ,TO_CHAR(ROUND(B_WT/1000), '9,999,999,999')  AS B_WT
        ,TO_CHAR(C_CNT, '9,999,999,999')  AS C_CNT
        ,TO_CHAR(ROUND(C_WT/1000), '9,999,999,999')  AS C_WT
        ,TO_CHAR(D_CNT, '9,999,999,999')  AS D_CNT
        ,TO_CHAR(ROUND(D_WT/1000), '9,999,999,999')  AS D_WT
        ,TO_CHAR(E_CNT, '9,999,999,999')  AS E_CNT
        ,TO_CHAR(ROUND(E_WT/1000), '9,999,999,999')  AS E_WT
        ,TO_CHAR(F_CNT, '9,999,999,999')  AS F_CNT
        ,TO_CHAR(ROUND(E_WT/1000), '9,999,999,999')  AS F_WT
        ,TO_CHAR(G_CNT, '9,999,999,999')  AS G_CNT
        ,TO_CHAR(ROUND(E_WT/1000), '9,999,999,999')  AS G_WT
        ,TO_CHAR(H_CNT, '9,999,999,999')  AS H_CNT
        ,TO_CHAR(ROUND(E_WT/1000), '9,999,999,999')  AS H_WT
        ,TO_CHAR(TOT_CNT, '9,999,999,999')  AS TOT_CNT
        ,TO_CHAR(ROUND(TOT_WT/1000), '9,999,999,999')  AS  TOT_WT
    FROM (
            SELECT GP 
                ,GP_RANK
                ,CHK_RANK
                ,NEXT_PROC
                ,A_CNT,A_WT
                ,B_CNT,B_WT
                ,C_CNT,C_WT
                ,D_CNT,D_WT
                ,E_CNT,E_WT
                ,F_CNT,F_WT
                ,G_CNT,G_WT
                ,H_CNT,H_WT
                ,TOT_CNT,TOT_WT
            FROM TEMP_TABLE2
            WHERE GP='SPM'
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,9
                ,'소계'
                ,SUM(A_CNT),SUM(A_WT)
                ,SUM(B_CNT),SUM(B_WT)
                ,SUM(C_CNT),SUM(C_WT)
                ,SUM(D_CNT),SUM(D_WT)
                ,SUM(E_CNT),SUM(E_WT)
                ,SUM(F_CNT),SUM(F_WT)
                ,SUM(G_CNT),SUM(G_WT)
                ,SUM(H_CNT),SUM(H_WT)
                ,SUM(TOT_CNT),SUM(TOT_WT)
            FROM TEMP_TABLE2
            WHERE GP='SPM'
            GROUP BY GP ,GP_RANK
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,CHK_RANK
                ,NEXT_PROC
                ,A_CNT,A_WT
                ,B_CNT,B_WT
                ,C_CNT,C_WT
                ,D_CNT,D_WT
                ,E_CNT,E_WT
                ,F_CNT,F_WT
                ,G_CNT,G_WT
                ,H_CNT,H_WT
                ,TOT_CNT,TOT_WT
            FROM TEMP_TABLE2
            WHERE GP='EQL'
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,9
                ,'소계'
                ,SUM(A_CNT),SUM(A_WT)
                ,SUM(B_CNT),SUM(B_WT)
                ,SUM(C_CNT),SUM(C_WT)
                ,SUM(D_CNT),SUM(D_WT)
                ,SUM(E_CNT),SUM(E_WT)
                ,SUM(F_CNT),SUM(F_WT)
                ,SUM(G_CNT),SUM(G_WT)
                ,SUM(H_CNT),SUM(H_WT)
                ,SUM(TOT_CNT),SUM(TOT_WT)
            FROM TEMP_TABLE2
            WHERE GP='EQL'
            GROUP BY GP ,GP_RANK
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,CHK_RANK
                ,NEXT_PROC
                ,A_CNT,A_WT
                ,B_CNT,B_WT
                ,C_CNT,C_WT
                ,D_CNT,D_WT
                ,E_CNT,E_WT
                ,F_CNT,F_WT
                ,G_CNT,G_WT
                ,H_CNT,H_WT
                ,TOT_CNT,TOT_WT
            FROM TEMP_TABLE2
            WHERE GP='HFL'
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,9
                ,'소계'
                ,SUM(A_CNT),SUM(A_WT)
                ,SUM(B_CNT),SUM(B_WT)
                ,SUM(C_CNT),SUM(C_WT)
                ,SUM(D_CNT),SUM(D_WT)
                ,SUM(E_CNT),SUM(E_WT)
                ,SUM(F_CNT),SUM(F_WT)
                ,SUM(G_CNT),SUM(G_WT)
                ,SUM(H_CNT),SUM(H_WT)
                ,SUM(TOT_CNT),SUM(TOT_WT)
            FROM TEMP_TABLE2
            WHERE GP='HFL'
            GROUP BY GP ,GP_RANK
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,CHK_RANK
                ,NEXT_PROC
                ,A_CNT,A_WT
                ,B_CNT,B_WT
                ,C_CNT,C_WT
                ,D_CNT,D_WT
                ,E_CNT,E_WT
                ,F_CNT,F_WT
                ,G_CNT,G_WT
                ,H_CNT,H_WT
                ,TOT_CNT,TOT_WT
            FROM TEMP_TABLE2
            WHERE GP IN('공냉재','보류재')
            UNION ALL
            SELECT '보류재' 
                ,5
                ,9
                ,'소계'
                ,SUM(A_CNT),SUM(A_WT)
                ,SUM(B_CNT),SUM(B_WT)
                ,SUM(C_CNT),SUM(C_WT)
                ,SUM(D_CNT),SUM(D_WT)
                ,SUM(E_CNT),SUM(E_WT)
                ,SUM(F_CNT),SUM(F_WT)
                ,SUM(G_CNT),SUM(G_WT)
                ,SUM(H_CNT),SUM(H_WT)
                ,SUM(TOT_CNT),SUM(TOT_WT)
            FROM TEMP_TABLE2
            WHERE GP IN('보류재')
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,CHK_RANK
                ,NEXT_PROC
                ,A_CNT,A_WT
                ,B_CNT,B_WT
                ,C_CNT,C_WT
                ,D_CNT,D_WT
                ,E_CNT,E_WT
                ,F_CNT,F_WT
                ,G_CNT,G_WT
                ,H_CNT,H_WT
                ,TOT_CNT,TOT_WT
            FROM TEMP_TABLE2
            WHERE GP='이송재'
            UNION ALL
            SELECT GP 
                ,GP_RANK
                ,9
                ,'소계'
                ,SUM(A_CNT),SUM(A_WT)
                ,SUM(B_CNT),SUM(B_WT)
                ,SUM(C_CNT),SUM(C_WT)
                ,SUM(D_CNT),SUM(D_WT)
                ,SUM(E_CNT),SUM(E_WT)
                ,SUM(F_CNT),SUM(F_WT)
                ,SUM(G_CNT),SUM(G_WT)
                ,SUM(H_CNT),SUM(H_WT)
                ,SUM(TOT_CNT),SUM(TOT_WT)
            FROM TEMP_TABLE2
            WHERE GP='이송재'
            GROUP BY GP ,GP_RANK
            UNION ALL
            SELECT '합계' 
                ,99
                ,99
                ,'합계'
                ,SUM(A_CNT),SUM(A_WT)
                ,SUM(B_CNT),SUM(B_WT)
                ,SUM(C_CNT),SUM(C_WT)
                ,SUM(D_CNT),SUM(D_WT)
                ,SUM(E_CNT),SUM(E_WT)
                ,SUM(F_CNT),SUM(F_WT)
                ,SUM(G_CNT),SUM(G_WT)
                ,SUM(H_CNT),SUM(H_WT)
                ,SUM(TOT_CNT),SUM(TOT_WT)
            FROM TEMP_TABLE2
        ) A
) T
ORDER BY GP_RANK, CHK_RANK
 </pre> */
