 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilTcarWrkStatInqpp.getTcarSchMgtTC 
--대차스케줄관리 대차정보조회 
WITH TS_TBL AS (
SELECT EQ.YD_EQP_ID
      ,EQ.YD_CURR_BAY_GP
      ,EQ.YD_HOME_BAY_GP
      ,EQ.YD_EQP_PROG_STAT AS YD_EQP_STAT
      ,EQ.YD_EQP_WRK_MODE
      --,NVL(EQ.RCPT_TCAR_USE_YN,'N') AS AUTO_TCAR_SCH_YN --자동대차스케줄여부
      ,TS.YD_CAR_PROG_STAT
      ,TS.YD_CARLD_STOP_LOC
      ,TS.YD_CARUD_STOP_LOC
      ,TS.YD_EQP_WRK_SH
      ,TS.YD_EQP_WRK_WT
      ,CASE WHEN TS.YD_CAR_PROG_STAT BETWEEN '0' AND '4' THEN YD_CARLD_WRK_BOOK_ID
            WHEN TS.YD_CAR_PROG_STAT BETWEEN '5' AND 'D' THEN YD_CARUD_WRK_BOOK_ID
        END AS YD_WBOOK_ID
      ,TS.YD_TCAR_SCH_ID
  FROM TB_YF_EQP     EQ
      ,(SELECT --+ INDEX(A IDX_YD_TB_YF_TCARSCH5) * FROM TB_YF_TCARSCH A WHERE DEL_YN='N') TS
 WHERE EQ.YD_EQP_ID = TS.YD_EQP_ID(+)
   --AND 'N'         = TS.DEL_YN(+)
   AND EQ.YD_EQP_ID =:V_YD_EQP_ID
)
SELECT TS.YD_EQP_ID
      ,TS.YD_CURR_BAY_GP
      ,TS.YD_HOME_BAY_GP
      ,DECODE(TS.YD_EQP_STAT,'B','B'   ,'N'   ) AS YD_EQP_STAT
      ,DECODE(TS.YD_EQP_STAT,'B','고장','정상') AS YD_EQP_STAT_NM
      ,TS.YD_EQP_WRK_MODE
      ,DECODE(TS.YD_EQP_WRK_MODE,'1','ON-LINE','OFF-LINE') AS YD_EQP_WRK_MODE_NM
      --,TS.AUTO_TCAR_SCH_YN
      ,TS.YD_CAR_PROG_STAT
      ,(SELECT BR.CD_MNNG
          FROM BRE.VW_CM_CODES BR
         WHERE BR.CD_EN_ID  = 'YD_CAR_PROG_STAT'
           AND BR.CD_CAT_ID = 'HS0000'
           AND BR.CD_VAL    = TS.YD_CAR_PROG_STAT) AS YD_CAR_PROG_STAT_NM
      ,CASE WHEN TS.YD_CAR_PROG_STAT = '0' THEN TS.YD_CURR_BAY_GP
            ELSE SUBSTR(TS.YD_CARLD_STOP_LOC,2,1) END  AS YD_LD_BAY_GP --상차동
      ,SUBSTR(TS.YD_CARUD_STOP_LOC,2,1) AS YD_UD_BAY_GP --하차동
      ,NULLIF(WB.WB_MTL_SH,0)           AS WB_MTL_SH
      ,NULLIF(WB.WB_MTL_WT,0)           AS WB_MTL_WT
      ,NULLIF(TM.TC_MTL_SH,0)           AS TC_MTL_SH
      ,NULLIF(TM.TC_MTL_WT,0)           AS TC_MTL_WT
      ,WB.YD_SCH_CD
      ,(SELECT MAX(YD_SCH_CD_NM)
        FROM   TB_YS_SCHRULE
        WHERE  YD_SCH_CD =  WB.YD_SCH_CD) AS YD_SCH_CD_NM
      ,TS.YD_WBOOK_ID
      ,TS.YD_TCAR_SCH_ID
  FROM TS_TBL   TS
      ,(SELECT WB.YD_WBOOK_ID
              ,MIN(WB.YD_SCH_CD) AS YD_SCH_CD
              ,COUNT(SC.STL_NO) AS WB_MTL_SH
              ,SUM(CC.COIL_WT) AS WB_MTL_WT
          FROM TB_YF_WRKBOOK    WB
              ,TB_YF_WRKBOOKMTL WM
              ,TB_YF_STOCK      SC
              ,VW_YF_COILCOMM CC
         WHERE WB.YD_WBOOK_ID IN (SELECT YD_WBOOK_ID FROM TS_TBL WHERE YD_WBOOK_ID IS NOT NULL)
           AND WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
           AND WM.STL_NO    = SC.STL_NO
           AND WM.STL_NO       = CC.COIL_NO
           AND WB.DEL_YN      = 'N'
           AND WM.DEL_YN      = 'N'
         GROUP BY WB.YD_WBOOK_ID) WB
      ,(SELECT --+ INDEX( TM PK_YF_TCARFTMVMTL) 
                TS.YD_TCAR_SCH_ID
              ,COUNT(SC.STL_NO) AS TC_MTL_SH
              ,SUM(CC.COIL_WT)    AS TC_MTL_WT
          FROM TB_YF_TCARFTMVMTL TM
              ,TS_TBL TS
              ,TB_YF_STOCK       SC
              ,VW_YF_COILCOMM CC
         WHERE TM.YD_TCAR_SCH_ID = TS.YD_TCAR_SCH_ID
           AND TM.STL_NO       = SC.STL_NO
           AND TM.STL_NO       = CC.COIL_NO
           AND TM.DEL_YN         = 'N'
         GROUP BY TS.YD_TCAR_SCH_ID) TM
 WHERE TS.YD_TCAR_SCH_ID = TM.YD_TCAR_SCH_ID(+)
   AND TS.YD_WBOOK_ID    = WB.YD_WBOOK_ID(+)
 ORDER BY TS.YD_EQP_ID
 </pre> */
public final static String getTcarSchMgtTC = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilTcarWrkStatInqpp.getTcarSchMgtTC";

