 /** <pre> 2019-11-05
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAdvSchRuleList 
-- 고도화크레인스케줄기준조회 
SELECT X.*
  FROM(SELECT ROWNUM AS RNUM
            , A.*
         FROM(SELECT COUNT(*) OVER() AS TOTALCOUNT
                   , YD_SCH_CD
                   , TERM1
                   , TERM2
                   , TERM3
                   , TERM4
                   , TERM5
                   , REGISTER
                   , REG_DDTT
                   , MODIFIER
                   , MOD_DDTT
                   , DEL_YN
                   , YD_GP
                   , YD_BAY_GP
                   , YD_WRK_CRN_PRIOR
                   , CD_CONTENTS
                   , TERM_CONTENTS
                FROM TB_YF_ADV_SCHRULE
               WHERE YD_GP     LIKE '%' || :V_YD_GP || '%'
                 AND YD_BAY_GP LIKE '%' || :V_YD_BAY_GP || '%'
               ORDER BY YD_BAY_GP, YD_SCH_CD, SORT_SEQ
             ) A
        WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE) X
 WHERE RNUM >= ((:V_PAGE_NO-1)* :V_PAGE_SIZE)+1
 </pre> */
public final static String getAdvSchRuleList = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAdvSchRuleList";

