 /** <pre> 2019-10-31
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getWrkBookIdByStlNo 
SELECT WB.YD_WBOOK_ID 
     , WB.YD_SCH_CD 
     ,(SELECT C.YD_CRN_SCH_ID FROM TB_YF_CRNSCH C WHERE C.YD_WBOOK_ID = WB.YD_WBOOK_ID AND ROWNUM = 1) AS YD_CRN_SCH_ID
  FROM TB_YF_WRKBOOK    WB
     , TB_YF_WRKBOOKMTL WM
 WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
   AND WM.STL_NO = :V_STL_NO
   AND WB.DEL_YN = 'N'
   AND WM.DEL_YN = 'N'
 </pre> */
