 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjl 
SELECT A.YD_GP 
     , A.YD_EQP_ID
     , A.YD_CURR_BAY_GP
     , '1'||A.YD_CURR_BAY_GP||A.YD_EQP_GP||A.YD_EQP_NO AS CURR_STOP_LOC
     , '1'||A.YD_HOME_BAY_GP||A.YD_EQP_GP||A.YD_EQP_NO AS WAIT_STOP_LOC
     , A.YD_EQP_NAME                                    -- 설비명
     , CASE WHEN A.YD_EQP_PROG_STAT = 'B' THEN '고장' ELSE '정상' END AS YD_EQP_STAT --설비상태
     , A.YD_EQP_WRK_MODE      -- 작업상태   
     , NVL(C.YD_CAR_PROG_STAT,0)  AS  YD_CAR_PROG_STAT -- 진행상태
     , C.YD_EQP_WRK_STAT
     , C.YD_WRK_PROG_STAT
     , (SELECT 
            COUNT(*) 
        FROM TB_YF_TCARFTMVMTL 
        WHERE YD_TCAR_SCH_ID = C.YD_TCAR_SCH_ID
        AND DEL_YN = 'N'
       ) AS YD_EQP_WRK_SH
     , (SELECT SUM(CC.COIL_WT )        
	      FROM TB_YF_TCARFTMVMTL     TM
             , USRYFA.VW_YF_COILCOMM CC
	     WHERE TM.STL_NO = CC.COIL_NO
           AND TM.YD_TCAR_SCH_ID = C.YD_TCAR_SCH_ID
           AND DEL_YN = 'N'
	   ) AS  YD_EQP_WRK_WT
     , SUBSTR(C.YD_CARLD_STOP_LOC,2,1) AS LD_BAY  --상차동
     , SUBSTR(C.YD_CARUD_STOP_LOC,2,1) AS UD_BAY  --하차동
     , REPLACE(A.YD_GP||SUBSTR(A.YD_EQP_ID,2,5),'X',C.YD_CARLD_STOP_LOC) AS EQP_CHK
     , A.STK_MAX_QNTY
     , A.STK_MAX_WT
     , '' AS EQP_DIR_TO_LOC -- 박판열연없음
     , C.YD_TCAR_SCH_ID
  FROM TB_YF_EQP A         
     , (SELECT * FROM TB_YF_TCARSCH WHERE DEL_YN = 'N') C
 WHERE 1 = 1
   AND A.YD_GP = '1'
   AND A.YD_EQP_GP = 'TC'
   AND A.YD_EQP_ID LIKE :V_HOGI||'%'
   AND A.YD_EQP_ID = C.YD_EQP_ID(+)
 ORDER BY A.YD_EQP_ID
 </pre> */
public final static String getacoilTcarWrkStatInqjl = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjl";

