 /** <pre> 2021-01-04
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfCarMvMtlBySchIdLyr 
WITH CARFTMVMTL AS (
    SELECT MV.YD_STK_BED_NO 
          ,SUBSTR(NVL(MV.YD_STK_LYR_NO,'001'),-2) AS YD_STK_LYR_NO 
          ,MV.STL_NO
          ,MV.STL_NO AS OLD_SSTL_NO
          ,COIL.COIL_T 
          ,COIL.COIL_W
          ,COIL.COIL_OUTDIA 
          ,COIL.COIL_WT 
          ,COIL.COIL_T AS COIL_T2
          ,TRIM(TO_CHAR(COIL.COIL_W,'9,999,999'))  AS COIL_W2
          ,TRIM(TO_CHAR(COIL.COIL_OUTDIA,'9,999,999')) AS COIL_OUTDIA2
          ,TRIM(TO_CHAR(COIL.COIL_WT,'9,999,999')) AS COIL_WT2
          ,COIL.STL_APPEAR_GP
          ,COIL.ITEMNAME_CD
          ,COIL.CURR_PROG_CD
          ,COIL.NEXT_PROC
          ,COIL.SPEC_ABBSYM
          ,MV.YD_CAR_SCH_ID
    FROM   TB_YD_CARFTMVMTL MV
          ,VW_YF_COILCOMM COIL
    WHERE  MV.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
    AND    MV.STL_NO = COIL.COIL_NO(+)
    AND    MV.DEL_YN = 'N'
    ORDER BY MV.YD_STK_LYR_NO        
)
SELECT SL.*
      ,MA.*
FROM   (
            SELECT YD_STK_BED_NO
                  ,YD_STK_LYR_NO 
            FROM   TB_YF_STKLYR
            WHERE  YD_STK_COL_GP LIKE  :V_YD_GP || 'APT01' || '%'
            ORDER BY YD_STK_LYR_NO, YD_STK_BED_NO
       ) SL
      ,CARFTMVMTL MA
WHERE  SL.YD_STK_BED_NO = MA.YD_STK_BED_NO(+)
AND    SL.YD_STK_LYR_NO = MA.YD_STK_LYR_NO(+)
 </pre> */
public final static String getYfCarMvMtlBySchIdLyr = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfCarMvMtlBySchIdLyr";

 /** <pre> 2020-04-01
-- com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPOJ161BackUp 
SELECT 'YMPOJ161'                          AS JMS_TC_CD          --JMSTC코드  
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTC생성일시  
     , 'YMPOJ161'                          AS tcCode
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),1,8) AS tcDate
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),9,6) AS tcTime
     , 'B'                                 AS plantGbn  
     , SUBSTR(A.TRK_INFO,1,1)              AS procGbn            --S:1SPM,N:EQL,H:HFL 
     , A.STL_NO                          AS coilNo  
     , SUBSTR(A.TRK_INFO,2,1)              AS processId  
     , TO_CHAR(SYSDATE,'YYYYMMDD')         AS downDate  
     , TO_CHAR(SYSDATE,'HH24MISS')         AS downTime  
     , SUBSTR(A.TRK_INFO,2,1)              AS positionNo  
  FROM (SELECT CASE WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,6,2) IN ('1U') THEN 'S1'  --1SPM 보급존
                    WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,6,2) IN ('2U') THEN 'S5'  --1SPM TAKE IN 
                    WHEN SUBSTR(LOC,3,2) IN ('FE') AND SUBSTR(YD_SCH_CD,6,2) IN ('1U') THEN 'H1'  --HFL  보급존 
                    WHEN SUBSTR(LOC,3,2) IN ('FE') AND SUBSTR(YD_SCH_CD,6,2) IN ('2U') THEN 'H5'  --HFL  TAKE IN 
                    WHEN SUBSTR(LOC,3,2) IN ('QE') AND SUBSTR(YD_SCH_CD,6,2) IN ('1U') THEN 'N1'  --EQL  보급존 
                    WHEN SUBSTR(LOC,3,2) IN ('QE') AND SUBSTR(YD_SCH_CD,6,2) IN ('2U') THEN 'N5'  --EQL  TAKE IN 
                    ELSE '' END AS TRK_INFO
            , STL_NO 
         FROM (SELECT :V_YD_DN_WR_LOC  AS LOC  
                    , STL_NO         AS STL_NO
                    , (SELECT YD_SCH_CD FROM TB_YF_CRNSCH WHERE YD_CRN_SCH_ID = C.YD_CRN_SCH_ID) AS YD_SCH_CD
                 FROM TB_YF_CRNWRKMTL C 
                WHERE C.YD_CRN_SCH_ID = (
                                        SELECT MAX(CM.YD_CRN_SCH_ID) AS YD_CRN_SCH_ID
                                          FROM TB_YF_CRNWRKMTL CM
                                             , TB_YF_CRNSCH    CR
                                         WHERE CM.YD_CRN_SCH_ID = CR.YD_CRN_SCH_ID
                                           AND CM.STL_NO = :V_STL_NO
                                        )
                
              ) 
       ) A
 </pre> */
public final static String TcYMPOJ161BackUp = "com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPOJ161BackUp";

