 /** <pre> 2019-12-03
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getSumProgCoilInfoNEW14_PIDEV 
WITH TEMP_TABLE AS (
SELECT '소재' AS CHK,
        (CASE WHEN SPOS_WLOC_CD IN('D2Y44','D2Y45')  THEN '박판열연'
                       WHEN SPOS_WLOC_CD IN('D3Y41','D3Y42') THEN '1열연'
                       WHEN SPOS_WLOC_CD IN('DJY1E','DJY21','DJY22')  THEN '2열연'
                       ELSE '2열연'
                END ) AS YD_GP_SPOS 
                ,(CASE  WHEN ARR_WLOC_CD IN('D2Y44','D2Y45') THEN '박판열연' 
                        WHEN ARR_WLOC_CD IN('D3Y41','D3Y42') THEN '1열연' 
                        WHEN ARR_WLOC_CD IN('DJY1E','DJY21','DJY22') THEN '2열연' 
                        END) AS YD_GP_ARR 
                , COIL_WT
                ,A.FTMV_HDS_DD
                ,A.STL_NO 
FROM  USRPTA.TB_PT_STLFRTOMOVE A
   ,TB_PT_COILCOMM B
   , USRPTA.TB_PT_COILCOMMSUB C
WHERE A.STL_NO=B.COIL_NO
   AND B.COIL_NO=C.COIL_NO
   AND A.FRTOMOVE_STAT_CD='*' 
   AND A.SPOS_WLOC_CD IN('D2Y44','D2Y45','D3Y41','D3Y42','DJY1E','DJY21','DJY22')
   AND A.ARR_WLOC_CD IN('D2Y44','D2Y45','D3Y41','D3Y42','DJY1E','DJY21','DJY22')
   AND A.FRTOMOVE_DONE_DATE>=TO_CHAR(SYSDATE-32,'YYYYMMDD') 
   AND A.FTMV_HDS_DD LIKE TO_CHAR((CASE WHEN TO_CHAR(SYSDATE,'DD')='01' and SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN SYSDATE-1 ELSE SYSDATE END),'YYYYMM')||'%' 
   AND A.FTMV_HDS_DD <=TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
UNION ALL
SELECT '제품' AS CHK,
                (CASE WHEN CARLD_PNT_CD LIKE '1%'  THEN '박판열연'
                       WHEN CARLD_PNT_CD LIKE '3%' THEN '1열연'
                       WHEN CARLD_PNT_CD LIKE 'J%'  THEN '2열연'             
                END ) AS YD_GP_SPOS 
                ,(CASE  WHEN CARUD_PNT_CD LIKE '1%'   THEN '박판열연' 
                        WHEN CARUD_PNT_CD LIKE '3%' THEN '1열연' 
                        WHEN CARUD_PNT_CD LIKE 'J%' THEN '2열연' 
                        END) AS YD_GP_ARR
               , TRANS_GOODS_WT AS GOODS_WT
               , TRANS_WORD_DATE AS FRTOMOVE_WORD_DATE
               , GOODS_NO
 FROM  VW_LM_P_TRANSWORDGOODS A
  WHERE  A.TRANS_WORD_DATE>=TO_CHAR(SYSDATE-32,'YYYYMMDD') 
   AND A.TRANS_WORD_DATE LIKE TO_CHAR((CASE WHEN TO_CHAR(SYSDATE,'DD')='01' and SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN SYSDATE-1 ELSE SYSDATE END),'YYYYMM')||'%' 
   AND A.TRANS_WORD_DATE <=TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
) 
, TEMP_TABLE2 AS ( --일계 집계
SELECT CHK ,YD_NAME
           , NVL(A_YD,0) AS SA_YD
           , NVL(B_YD,0) AS SB_YD            
           , NVL(C_YD,0) AS SC_YD
           , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0) AS STOT_YD
           , NVL(MA_YD,0) AS EA_YD
           , NVL(MB_YD,0) AS EB_YD            
           , NVL(MC_YD,0) AS EC_YD 
           , NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS ETOT_YD
            , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0)+NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS TOT_YD
 
FROM (
        SELECT 1 AS CHK , '박판열연' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='박판열연'
            AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
         UNION ALL
         SELECT 2 AS CHK , '1열연' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='1열연'
         AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
          UNION ALL
         SELECT 3 AS CHK , '2열연' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='2열연'
           AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
      UNION ALL
        SELECT 4 AS CHK , '계' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
     
           
       )
 ) 
 , TEMP_TABLE3 AS (
SELECT CHK  ,YD_NAME
           , NVL(A_YD,0) AS SA_YD
           , NVL(B_YD,0) AS SB_YD            
           , NVL(C_YD,0) AS SC_YD
           , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0) AS STOT_YD
           , NVL(MA_YD,0) AS EA_YD
           , NVL(MB_YD,0) AS EB_YD            
           , NVL(MC_YD,0) AS EC_YD 
           , NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS ETOT_YD
            , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0)+NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS TOT_YD
 
FROM (
        SELECT 11 AS CHK , '박판열연' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='박판열연'
             UNION ALL
         SELECT 12 AS CHK , '1열연' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='1열연'
           UNION ALL
         SELECT 13 AS CHK ,  '2열연' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='2열연'
            UNION ALL
        SELECT 14 AS CHK , '계' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='소재' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' AND CHK='제품' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
          
       )
 )
SELECT
    T.*
  , COUNT(*) OVER(PARTITION BY YD_NAME2) AS GROUP_CNT
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY YD_NAME2 ORDER BY CHK, YD_NAME) = 1 THEN 'Y'
    ELSE 'N' END AS SHOW_ROWSPAN
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY YD_NAME2 ORDER BY CHK, YD_NAME2) = COUNT(*) OVER(PARTITION BY YD_NAME2) THEN 'Y'
    ELSE 'N' END AS SHOW_SUM
  , CASE WHEN YD_NAME2 = YD_NAME THEN 'Y' ELSE 'N' END AS SHOW_COLSPAN
FROM
(
    SELECT CHK
            ,'일계' AS YD_NAME2
             ,YD_NAME
            , TO_CHAR(ROUND(SA_YD/1000), '9,999,999,999') AS SA_YD
            , TO_CHAR(ROUND(SB_YD/1000), '9,999,999,999') AS SB_YD            
            , TO_CHAR(ROUND(SC_YD/1000), '9,999,999,999') AS SC_YD
            , TO_CHAR(ROUND(STOT_YD/1000), '9,999,999,999') AS STOT_YD
            , TO_CHAR(ROUND(EA_YD/1000), '9,999,999,999') AS EA_YD
            , TO_CHAR(ROUND(EB_YD/1000), '9,999,999,999') AS EB_YD            
            , TO_CHAR(ROUND(EC_YD/1000), '9,999,999,999') AS EC_YD
            , TO_CHAR(ROUND(ETOT_YD/1000), '9,999,999,999') AS ETOT_YD
            , TO_CHAR(ROUND(TOT_YD/1000), '9,999,999,999') AS TOT_YD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD') AS FTMV_HDS_DD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD HH24:MI:SS') AS HDS_DATE
       FROM (
             SELECT  CHK, YD_NAME
                        , SA_YD
                        , SB_YD
                        , SC_YD
                        , STOT_YD
                        , EA_YD
                        , EB_YD
                        , EC_YD
                        , ETOT_YD                        
                        , TOT_YD
                FROM TEMP_TABLE2      
          )
    UNION ALL
    SELECT CHK
            ,'월계' AS YD_NAME2
             ,YD_NAME
            , TO_CHAR(ROUND(SA_YD/1000), '9,999,999,999') AS SA_YD
            , TO_CHAR(ROUND(SB_YD/1000), '9,999,999,999') AS SB_YD            
            , TO_CHAR(ROUND(SC_YD/1000), '9,999,999,999') AS SC_YD
            , TO_CHAR(ROUND(STOT_YD/1000), '9,999,999,999') AS STOT_YD
            , TO_CHAR(ROUND(EA_YD/1000), '9,999,999,999') AS EA_YD
            , TO_CHAR(ROUND(EB_YD/1000), '9,999,999,999') AS EB_YD            
            , TO_CHAR(ROUND(EC_YD/1000), '9,999,999,999') AS EC_YD
            , TO_CHAR(ROUND(ETOT_YD/1000), '9,999,999,999') AS ETOT_YD
            , TO_CHAR(ROUND(TOT_YD/1000), '9,999,999,999') AS TOT_YD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD') AS FTMV_HDS_DD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD HH24:MI:SS') AS HDS_DATE
       FROM (
             SELECT  CHK
                         , YD_NAME
                        , SA_YD
                        , SB_YD
                        , SC_YD
                        , STOT_YD
                        , EA_YD
                        , EB_YD
                        , EC_YD
                        , ETOT_YD                        
                        , TOT_YD
                FROM TEMP_TABLE3            
          )
) T
ORDER BY T.CHK
 </pre> */
