 /** <pre> 2019-11-01
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getCF1BP04BackUp 
--분기 LINE OFF 실적
SELECT NEW_TC_CD                           AS JMS_TC_CD          --JMSTC코드
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTC생성일시
      ,JMS_TC_CD                                     --전문ID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DD')       --생성일시
     ||TO_CHAR(SYSDATE,'HH24-MI-SS')       --생성일시
     ||RPAD(NVL(TC_ID                 ,'I'), 1,' ') --전문구분
     ||'0012'                                        --전문길이
     ||RPAD(NVL(STL_NO              ,' '),10,' ') --COILNO
     ||RPAD(' ',2,' ')                              --임시
       AS JMS_TC_MESSAGE --JMSTCMESSAGE
FROM (
        SELECT 'POCFL104'           AS NEW_TC_CD  -- CF1BP04 --> POCFL104
             , 'CF1BP04'            AS JMS_TC_CD    --전문ID
             , 'I'                  AS TC_ID        --전문구분
             , A.STL_NO             AS STL_NO
          FROM TB_YF_CRNWRKMTL A
         WHERE YD_CRN_SCH_ID = (
                                  SELECT MAX(CM.YD_CRN_SCH_ID) AS YD_CRN_SCH_ID
                                    FROM TB_YF_CRNWRKMTL CM
                                       , TB_YF_CRNSCH    CR
                                   WHERE CM.YD_CRN_SCH_ID = CR.YD_CRN_SCH_ID
                                     AND CM.STL_NO = :V_STL_NO
                               )
        )
 </pre> */
