 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjlSub1 
SELECT A.YD_SCH_CD
      ,(SELECT CD_CONTENTS FROM TB_YF_SCHRULE WHERE YD_SCH_CD = A.YD_SCH_CD AND ROWNUM = 1) AS YD_SCH_CD_NM
      ,A.YD_SCH_PRIOR
      ,A.YD_BAY_GP     AS LD_BAY --상차동
      ,A.YD_AIM_BAY_GP AS UD_BAY --하차동      
      
      ,COUNT(C.CNT)         AS CNT
      ,SUM(C.SUM_YD_MTL_WT) AS SUM_YD_MTL_WT
      ,YD_WRK_PLAN_TCAR 
  FROM TB_YF_WRKBOOK A
      ,( SELECT A.* 
               ,B.YD_WBOOK_ID
          FROM TB_YF_TCARSCH A
              ,TB_YF_WRKBOOK B
         WHERE 1=1
           AND ( B.YD_WBOOK_ID = A.YD_CARLD_WRK_BOOK_ID OR B.YD_WBOOK_ID = A.YD_CARUD_WRK_BOOK_ID)
           AND A.DEL_YN ='N'
           AND B.DEL_YN ='N'
         ) B
       , (SELECT SB.YD_WBOOK_ID                          
                 ,COUNT(*) AS CNT   
                 ,SUM(SB.COIL_WT) AS SUM_YD_MTL_WT
             FROM (SELECT  SSA.* 
                          ,P.COIL_WT 
                    FROM TB_YF_WRKBOOKMTL SSA
                        ,TB_YF_STOCK SSB
                        ,VW_YF_COILCOMM P
                   WHERE SSA.STL_NO = SSB.STL_NO
                     AND SSB.STL_NO = P.COIL_NO) SB
            WHERE DEL_YN = 'N' 
            GROUP BY SB.YD_WBOOK_ID
           ) C
 WHERE 1=1   
   AND A.YD_WRK_PLAN_TCAR = :V_YD_WRK_PLAN_TCAR
   AND A.YD_WBOOK_ID = B.YD_WBOOK_ID(+)  
   AND A.YD_WBOOK_ID = C.YD_WBOOK_ID(+) 
   AND A.DEL_YN ='N'  
   AND A.YD_GP = :V_YD_GP
   AND A.YD_BAY_GP LIKE :V_YD_BAY_GP ||'%'
   AND A.YD_WBOOK_ID <> NVL(:V_YD_WBOOK_ID,'1')
 GROUP BY YD_WRK_PLAN_TCAR, YD_SCH_CD, YD_SCH_PRIOR, A.YD_BAY_GP, A.YD_AIM_BAY_GP
 ORDER BY A.YD_SCH_PRIOR 
 </pre> */
public final static String getacoilTcarWrkStatInqjlSub1 = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjlSub1";

