 /** <pre> 2019-12-03
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getSumProgCoilInfoNEW13_PIDEV
WITH TEMP_TABLE AS (
SELECT '소재' AS STL_CHK, (CASE WHEN SPOS_WLOC_CD IN('D2Y44','D2Y45')  THEN '박판열연'
                       WHEN SPOS_WLOC_CD IN('D3Y41','D3Y42') THEN '1열연'
                       WHEN SPOS_WLOC_CD IN('DJY1E','DJY21','DJY22')  THEN '2열연'
                       ELSE '2열연'
                END ) AS YD_GP_SPOS 
                ,(CASE WHEN ARR_WLOC_CD ='LB00' THEN '1냉연'
                        WHEN ARR_WLOC_CD ='LA00' THEN '순천'
                        WHEN ARR_WLOC_CD ='LC00' THEN '2냉연'
                        WHEN ARR_WLOC_CD IN('LD00','LE00','HV0K') AND  NVL(NVL(B.NEXT_DEMAND_PROC,B.NEXT_PROC),B.PLAN_PROC1)  ='9S' THEN '열연임가공'
                        WHEN ARR_WLOC_CD IN('LD00','LE00','HV0K') AND  NVL(NVL(B.NEXT_DEMAND_PROC,B.NEXT_PROC),B.PLAN_PROC1)  ='9C' THEN '냉연임가공'
                        WHEN ARR_WLOC_CD IN('D2Y44','D2Y45') THEN '박판열연' 
                        WHEN ARR_WLOC_CD IN('D3Y41','D3Y42') THEN '1열연' 
                        WHEN ARR_WLOC_CD IN('DJY1E','DJY21','DJY22') THEN '2열연' 
                        END) AS YD_GP_ARR    
             
                , COIL_WT
                ,A.FTMV_HDS_DD
                ,A.STL_NO 
FROM  TB_PT_STLFRTOMOVE A
   ,TB_PT_COILCOMM B
   , TB_PT_COILCOMMSUB C
WHERE A.STL_NO=B.COIL_NO
   AND B.COIL_NO=C.COIL_NO
   AND A.FRTOMOVE_STAT_CD='*' 
   AND A.SPOS_WLOC_CD IN('D2Y44','D2Y45','D3Y41','D3Y42','DJY1E','DJY21','DJY22')
   AND A.FRTOMOVE_DONE_DATE>=TO_CHAR(SYSDATE-32,'YYYYMMDD') 
   AND A.FTMV_HDS_DD LIKE TO_CHAR((CASE WHEN TO_CHAR(SYSDATE,'DD')='01' and SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN SYSDATE-1 ELSE SYSDATE END),'YYYYMM')||'%' 
   AND A.FTMV_HDS_DD <=TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
UNION ALL
SELECT '제품' AS CHK,
                (CASE WHEN CARLD_PNT_CD LIKE '1%'  THEN '박판열연'
                       WHEN CARLD_PNT_CD LIKE '3%' THEN '1열연'
                       WHEN CARLD_PNT_CD LIKE 'J%'  THEN '2열연'             
                END ) AS YD_GP_SPOS 
                ,(CASE  WHEN CARUD_PNT_CD LIKE '1%'   THEN '박판열연' 
                        WHEN CARUD_PNT_CD LIKE '3%' THEN '1열연' 
                        WHEN CARUD_PNT_CD LIKE 'J%' THEN '2열연' 
                        END) AS YD_GP_ARR
               , TRANS_GOODS_WT AS GOODS_WT
               , TRANS_WORD_DATE AS FRTOMOVE_WORD_DATE
               , GOODS_NO
 FROM  VW_LM_P_TRANSWORDGOODS A
  WHERE  A.TRANS_WORD_DATE>=TO_CHAR(SYSDATE-32,'YYYYMMDD') 
   AND A.TRANS_WORD_DATE LIKE TO_CHAR((CASE WHEN TO_CHAR(SYSDATE,'DD')='01' and SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN SYSDATE-1 ELSE SYSDATE END),'YYYYMM')||'%' 
   AND A.TRANS_WORD_DATE <=TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD')    
) 
, TEMP_TABLEK AS (
SELECT  DECODE(B.CR_YD_GP, 'DH0H', '박판열연', 'DH0A', '1열연', 'DH0B', '2열연') AS CR_YD_GP
       ,SUM(B.TRANS_GOODS_WT) as GOODS_WT 
  FROM VW_LM_P_TRANSWORDCOMM A
       ,VW_LM_P_TRANSWORDGOODS B
 WHERE A.TRANS_WORD_DATE = B.TRANS_WORD_DATE
   AND A.TRANS_WORD_SEQNO = B.TRANS_WORD_SEQNO   
   AND A.DEL_YN= 'N'
   AND B.DEL_YN= 'N'   
   AND A.H_ISSUE_GP IN ('0', '4')  --일반운송, 보관매출정리
   AND A.H_DIST_GOODS_GP IN ('H')  --열연제품
   AND B.CR_YD_GP IN ('DH0H','DH0A','DH0B') --A,B,2열연공장   
   AND A.TRANS_WORD_DATE =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
   GROUP BY B.CR_YD_GP
)
, TEMP_TABLEK2 AS (
SELECT  DECODE(B.CR_YD_GP, 'DH0H', '박판열연', 'DH0A', '1열연', 'DH0B', '2열연') AS CR_YD_GP
       ,SUM(B.TRANS_GOODS_WT) as GOODS_WT 
  FROM VW_LM_P_TRANSWORDCOMM A
       ,VW_LM_P_TRANSWORDGOODS B
 WHERE A.TRANS_WORD_DATE = B.TRANS_WORD_DATE
   AND A.TRANS_WORD_SEQNO = B.TRANS_WORD_SEQNO   
   AND A.DEL_YN= 'N'
   AND B.DEL_YN= 'N'   
   AND A.H_ISSUE_GP IN ('0', '4')  --일반운송, 보관매출정리
   AND A.H_DIST_GOODS_GP IN ('H')  --열연제품
   AND B.CR_YD_GP IN ('DH0H','DH0A','DH0B') --A,B,2열연공장   
   AND A.TRANS_WORD_DATE LIKE TO_CHAR((CASE WHEN TO_CHAR(SYSDATE,'DD')='01' and SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN SYSDATE-1 ELSE SYSDATE END),'YYYYMM')||'%'
   AND A.TRANS_WORD_DATE <=TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
   GROUP BY B.CR_YD_GP
)
, TEMP_TABLE2 AS (
SELECT CHK
             ,YD_NAME
             , NVL(A_YD,0) AS A_YD
            , NVL(B_YD,0) AS B_YD
            
            , NVL(C_YD,0) AS C_YD
            , NVL(H1_YD,0) AS H1_YD
            , NVL(H2_YD,0) AS H2_YD
            , NVL(S_YD,0) AS S_YD
            , NVL(M_YD,0) AS M_YD
            , NVL(HM_YD,0) AS HM_YD
            , NVL(K_YD,0) AS K_YD
            
            , NVL(B_YD,0) + NVL(A_YD,0) + NVL(C_YD,0) + NVL(H1_YD,0) +NVL(H2_YD,0) +NVL(S_YD,0) +NVL(M_YD,0)+NVL(HM_YD,0) +NVL(K_YD,0) AS TOT_YD
 
FROM (
        SELECT 2 AS CHK ,  '1열연' AS YD_NAME 
                  ,  0 AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' THEN COIL_WT ELSE 0 END) AS C_YD
                  , SUM(CASE WHEN YD_GP_ARR='1냉연' THEN COIL_WT ELSE 0 END) AS H1_YD
                  , SUM(CASE WHEN YD_GP_ARR='2냉연' THEN COIL_WT ELSE 0 END) AS H2_YD
                  , SUM(CASE WHEN YD_GP_ARR='순천' THEN COIL_WT ELSE 0 END) AS S_YD
                  , SUM(CASE WHEN YD_GP_ARR='열연임가공' THEN COIL_WT ELSE 0 END) AS M_YD
                  , SUM(CASE WHEN YD_GP_ARR='냉연임가공' THEN COIL_WT ELSE 0 END) AS HM_YD
                  , MAX(B.GOODS_WT) AS K_YD
          FROM TEMP_TABLE A
              ,TEMP_TABLEK B
         WHERE YD_GP_SPOS='1열연'
            AND B.CR_YD_GP(+)=A.YD_GP_SPOS
            AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
         UNION ALL
         SELECT  1 AS CHK , '박판열연' AS YD_NAME 
                  ,  SUM(CASE WHEN YD_GP_ARR='1열연' THEN COIL_WT ELSE 0 END) AS B_YD
                  , 0 AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' THEN COIL_WT ELSE 0 END) AS C_YD
                  , SUM(CASE WHEN YD_GP_ARR='1냉연' THEN COIL_WT ELSE 0 END) AS H1_YD
                  , SUM(CASE WHEN YD_GP_ARR='2냉연' THEN COIL_WT ELSE 0 END) AS H2_YD
                  , SUM(CASE WHEN YD_GP_ARR='순천' THEN COIL_WT ELSE 0 END) AS S_YD
                  , SUM(CASE WHEN YD_GP_ARR='열연임가공' THEN COIL_WT ELSE 0 END) AS M_YD
                  , SUM(CASE WHEN YD_GP_ARR='냉연임가공' THEN COIL_WT ELSE 0 END) AS HM_YD
                  , MAX(B.GOODS_WT) AS K_YD
          FROM TEMP_TABLE A
            ,TEMP_TABLEK B
         WHERE YD_GP_SPOS='박판열연'
         AND B.CR_YD_GP(+)=A.YD_GP_SPOS
         AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
          UNION ALL
         SELECT  3 AS CHK ,  '2열연' AS YD_NAME 
                  ,  SUM(CASE WHEN YD_GP_ARR='1열연' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' THEN COIL_WT ELSE 0 END) AS A_YD
                  , 0 AS C_YD
                  , SUM(CASE WHEN YD_GP_ARR='1냉연' THEN COIL_WT ELSE 0 END) AS H1_YD
                  , SUM(CASE WHEN YD_GP_ARR='2냉연' THEN COIL_WT ELSE 0 END) AS H2_YD
                  , SUM(CASE WHEN YD_GP_ARR='순천' THEN COIL_WT ELSE 0 END) AS S_YD
                  , SUM(CASE WHEN YD_GP_ARR='열연임가공' THEN COIL_WT ELSE 0 END) AS M_YD
                  , SUM(CASE WHEN YD_GP_ARR='냉연임가공' THEN COIL_WT ELSE 0 END) AS HM_YD
                  , MAX(B.GOODS_WT) AS K_YD
          FROM TEMP_TABLE A
                ,TEMP_TABLEK B
         WHERE YD_GP_SPOS='2열연'
           AND B.CR_YD_GP(+)=A.YD_GP_SPOS
           AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
       )
 ), TEMP_TABLE3 AS (
SELECT CHK
             ,YD_NAME
             , NVL(A_YD,0) AS A_YD
            , NVL(B_YD,0) AS B_YD
            
            , NVL(C_YD,0) AS C_YD
            , NVL(H1_YD,0) AS H1_YD
            , NVL(H2_YD,0) AS H2_YD
            , NVL(S_YD,0) AS S_YD
            , NVL(M_YD,0) AS M_YD
            , NVL(HM_YD,0) AS HM_YD
            , NVL(K_YD,0) AS K_YD
            
            , NVL(B_YD,0) + NVL(A_YD,0) + NVL(C_YD,0) + NVL(H1_YD,0) +NVL(H2_YD,0) +NVL(S_YD,0) +NVL(M_YD,0) +NVL(HM_YD,0) +NVL(K_YD,0) AS TOT_YD
 
FROM (
        SELECT 6 AS CHK ,  '1열연' AS YD_NAME 
                  ,  0 AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' THEN COIL_WT ELSE 0 END) AS C_YD
                  , SUM(CASE WHEN YD_GP_ARR='1냉연' THEN COIL_WT ELSE 0 END) AS H1_YD
                  , SUM(CASE WHEN YD_GP_ARR='2냉연' THEN COIL_WT ELSE 0 END) AS H2_YD
                  , SUM(CASE WHEN YD_GP_ARR='순천' THEN COIL_WT ELSE 0 END) AS S_YD
                  , SUM(CASE WHEN YD_GP_ARR='열연임가공' THEN COIL_WT ELSE 0 END) AS M_YD
                  , SUM(CASE WHEN YD_GP_ARR='냉연임가공' THEN COIL_WT ELSE 0 END) AS HM_YD
                  , MAX(B.GOODS_WT) AS K_YD
         
          FROM TEMP_TABLE A
              ,TEMP_TABLEK2 B
         WHERE YD_GP_SPOS='1열연'
           AND B.CR_YD_GP(+)=A.YD_GP_SPOS
         UNION ALL
         SELECT  5 AS CHK , '박판열연' AS YD_NAME 
                  ,  SUM(CASE WHEN YD_GP_ARR='1열연' THEN COIL_WT ELSE 0 END) AS B_YD
                  , 0 AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='2열연' THEN COIL_WT ELSE 0 END) AS C_YD
                  , SUM(CASE WHEN YD_GP_ARR='1냉연' THEN COIL_WT ELSE 0 END) AS H1_YD
                  , SUM(CASE WHEN YD_GP_ARR='2냉연' THEN COIL_WT ELSE 0 END) AS H2_YD
                  , SUM(CASE WHEN YD_GP_ARR='순천' THEN COIL_WT ELSE 0 END) AS S_YD
                  , SUM(CASE WHEN YD_GP_ARR='열연임가공' THEN COIL_WT ELSE 0 END) AS M_YD
                  , SUM(CASE WHEN YD_GP_ARR='냉연임가공' THEN COIL_WT ELSE 0 END) AS HM_YD
                  , MAX(B.GOODS_WT) AS K_YD
          FROM TEMP_TABLE A
            ,TEMP_TABLEK2 B
         WHERE YD_GP_SPOS='박판열연'
         AND B.CR_YD_GP(+)=A.YD_GP_SPOS
          UNION ALL
         SELECT  7 AS CHK ,  '2열연' AS YD_NAME 
                  ,  SUM(CASE WHEN YD_GP_ARR='1열연' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='박판열연' THEN COIL_WT ELSE 0 END) AS A_YD
                  , 0 AS C_YD
                  , SUM(CASE WHEN YD_GP_ARR='1냉연' THEN COIL_WT ELSE 0 END) AS H1_YD
                  , SUM(CASE WHEN YD_GP_ARR='2냉연' THEN COIL_WT ELSE 0 END) AS H2_YD
                  , SUM(CASE WHEN YD_GP_ARR='순천' THEN COIL_WT ELSE 0 END) AS S_YD
                  , SUM(CASE WHEN YD_GP_ARR='열연임가공' THEN COIL_WT ELSE 0 END) AS M_YD
                  , SUM(CASE WHEN YD_GP_ARR='냉연임가공' THEN COIL_WT ELSE 0 END) AS HM_YD
                  , MAX(B.GOODS_WT) AS K_YD
          FROM TEMP_TABLE A
                ,TEMP_TABLEK2 B
         WHERE YD_GP_SPOS='2열연'
           AND B.CR_YD_GP(+)=A.YD_GP_SPOS
           
       )
 )
SELECT
    T.*
  , COUNT(*) OVER(PARTITION BY YD_NAME2) AS GROUP_CNT
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY YD_NAME2 ORDER BY CHK, YD_NAME) = 1 THEN 'Y'
    ELSE 'N' END AS SHOW_ROWSPAN
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY YD_NAME2 ORDER BY CHK, YD_NAME2) = COUNT(*) OVER(PARTITION BY YD_NAME2) THEN 'Y'
    ELSE 'N' END AS SHOW_SUM
  , CASE WHEN YD_NAME2 = YD_NAME THEN 'Y' ELSE 'N' END AS SHOW_COLSPAN
FROM
    (
    SELECT CHK
            ,'일계' AS YD_NAME2
            ,YD_NAME
                , TO_CHAR(ROUND(A_YD/1000), '9,999,999,999') AS A_YD
                , TO_CHAR(ROUND(B_YD/1000), '9,999,999,999') AS B_YD            
                , TO_CHAR(ROUND(C_YD/1000), '9,999,999,999') AS C_YD
                , TO_CHAR(ROUND((A_YD+B_YD+C_YD)/1000), '9,999,999,999') AS TOT2_YD
                , TO_CHAR(ROUND(H1_YD/1000), '9,999,999,999') AS H1_YD
                , TO_CHAR(ROUND(H2_YD/1000), '9,999,999,999') AS H2_YD
                , TO_CHAR(ROUND(S_YD/1000), '9,999,999,999') AS S_YD
                , TO_CHAR(ROUND((H1_YD+H2_YD+S_YD)/1000), '9,999,999,999') AS HTOT_YD
                , TO_CHAR(ROUND(M_YD/1000), '9,999,999,999') AS M_YD
                , TO_CHAR(ROUND(HM_YD/1000), '9,999,999,999') AS HM_YD
                , TO_CHAR(ROUND((M_YD+HM_YD)/1000), '9,999,999,999') AS MTOT_YD
                , TO_CHAR(ROUND(K_YD      /1000), '9,999,999,999') AS K_YD       
                , TO_CHAR(ROUND(TOT_YD/1000), '9,999,999,999') AS TOT_YD
                ,TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYY.MM.DD') AS FTMV_HDS_DD
                ,TO_CHAR(SYSDATE,'YYYY.MM.DD HH24:MI:SS') AS HDS_DATE
       FROM (
             SELECT  CHK
                        , YD_NAME
                        ,  B_YD
                        ,  A_YD
                        , C_YD
                        , H1_YD
                        , H2_YD
                        , S_YD
                        , M_YD
                        , HM_YD
                        , K_YD            
                        , TOT_YD
                FROM TEMP_TABLE2
             UNION ALL
             SELECT 4 AS CHK
                         , '합계' AS YD_NAME
                        ,  SUM(B_YD) AS B_YD
                        ,  SUM(A_YD) AS A_YD
                        , SUM(C_YD) AS C_YD
                        , SUM(H1_YD) AS H1_YD
                        , SUM(H2_YD) AS H2_YD
                        , SUM(S_YD) AS S_YD
                        , SUM(M_YD) AS M_YD
                        , SUM(HM_YD) AS HM_YD
                        , SUM(K_YD) AS  K_YD    
                        , SUM(TOT_YD) AS TOT_YD
                FROM TEMP_TABLE2
          )
    UNION ALL
    SELECT CHK
            ,'월계' AS YD_NAME2
            ,YD_NAME
                , TO_CHAR(ROUND(A_YD/1000), '9,999,999,999') AS A_YD
                , TO_CHAR(ROUND(B_YD/1000), '9,999,999,999') AS B_YD            
                , TO_CHAR(ROUND(C_YD/1000), '9,999,999,999') AS C_YD
                , TO_CHAR(ROUND((A_YD+B_YD+C_YD)/1000), '9,999,999,999') AS TOT_YD
                , TO_CHAR(ROUND(H1_YD/1000), '9,999,999,999') AS H1_YD
                , TO_CHAR(ROUND(H2_YD/1000), '9,999,999,999') AS H2_YD
                , TO_CHAR(ROUND(S_YD/1000), '9,999,999,999') AS S_YD
                , TO_CHAR(ROUND((H1_YD+H2_YD+S_YD)/1000), '9,999,999,999') AS HTOT_YD
                , TO_CHAR(ROUND(M_YD/1000), '9,999,999,999') AS M_YD
                , TO_CHAR(ROUND(HM_YD/1000), '9,999,999,999') AS HM_YD
                , TO_CHAR(ROUND((M_YD+HM_YD)/1000), '9,999,999,999') AS MTOT_YD
                , TO_CHAR(ROUND(K_YD      /1000), '9,999,999,999') AS K_YD       
                , TO_CHAR(ROUND(TOT_YD/1000), '9,999,999,999') AS TOT_YD
                ,TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYY.MM.DD')  AS FTMV_HDS_DD
                ,TO_CHAR(SYSDATE,'YYYY.MM.DD HH24:MI:SS') AS HDS_DATE
       FROM (
             SELECT  CHK
                        , YD_NAME
                        ,  B_YD
                        ,  A_YD
                        , C_YD
                        , H1_YD
                        , H2_YD
                        , S_YD
                        , M_YD
                        , HM_YD
                        , K_YD            
                        , TOT_YD
                FROM TEMP_TABLE3
             UNION ALL
             SELECT 9 AS CHK
                         , '합계' AS YD_NAME
                        ,  SUM(B_YD) AS B_YD
                        ,  SUM(A_YD) AS A_YD
                        , SUM(C_YD) AS C_YD
                        , SUM(H1_YD) AS H1_YD
                        , SUM(H2_YD) AS H2_YD
                        , SUM(S_YD) AS S_YD
                        , SUM(M_YD) AS M_YD
                        , SUM(HM_YD) AS HM_YD
                        , SUM(K_YD) AS  K_YD    
                        , SUM(TOT_YD) AS TOT_YD
                FROM TEMP_TABLE3
          )
) T
ORDER BY CHK
 </pre> */
public final static String getSumProgCoilInfoNEW13 = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getSumProgCoilInfoNEW13_PIDEV";

