 /** <pre> 2019-12-16
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdAdvEqp
-- 고도화 대상 크레인설비ID 조회 
SELECT A.YD_EQP_ID  AS CD_VAL
      ,A.YD_EQP_NAME AS CD_NM
  FROM TB_YF_EQP A
 WHERE A.YD_GP = :V_YD_GP
   AND A.YD_EQP_ID LIKE '_'||:V_YD_BAY_GP||'%'
   AND A.YD_EQP_GP = 'CR'
   AND A.DEL_YN = 'N'
   -- 무인 크레인만 조회
   AND A.YD_EQP_ID IN (
                        SELECT YD_EQP_ID
                         FROM TB_YF_EQP
                         WHERE YD_GP = '1'
                         AND YD_EQP_GP = 'CR'
                         -- 무인크레인 셋팅할것 
                         AND  ( A.YD_EQP_ID LIKE '_'||'A%'
                             OR A.YD_EQP_ID LIKE '_'||'C%'
                             OR A.YD_EQP_ID LIKE '_'||'E%')
                   )
 ORDER BY A.YD_EQP_ID
 </pre> */
public final static String getCodeYdAdvEqp = "com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdAdvEqp";

