 /** <pre> 2020-04-27
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockInfoList 
SELECT 
    A.*
    , A.STL_C_RATE||'% ('|| A.STL_C_CNT||'/'||A.TOT_STL_CNT||')' AS RATE
FROM (
        SELECT '1' AS YD_GP
            , A.YD_ZONE_GP 
            , A.TOT_STL_CNT
            , A.STL_C_CNT
            , A.TOT_STL_CNT - A.STL_C_CNT AS STL_ABLE_CNT
            , ROUND((A.STL_C_CNT/A.TOT_STL_CNT)*100) STL_C_RATE
            , B.STL_MAX_C_RATE  AS MAX_RATE
            , B.YD_ZONE_GP_NM
         FROM 
         (
            SELECT TO_NUMBER(DTL_ITEM1) as STL_MAX_C_RATE
                   , R.ITEM AS YD_ZONE_GP
                   , R.REPR_CD_CONTENTS AS YD_ZONE_GP_NM
            FROM TB_YF_RULE R 
            WHERE R.REPR_CD_GP='YM6001' 
            AND R.DEL_YN='N' 
            AND R.CD_GP = '1'
            AND R.ITEM <> 'GZ'
        ) B, 
        (
                SELECT A.YD_GP, A.YD_ZONE_GP  , 
                       COUNT(A.ACTIVE_STA_E + A.ACTIVE_STA_C ) AS TOT_STL_CNT,  
                       SUM(A.STK_CNT) AS STL_C_CNT
                FROM (
                       SELECT A.*
                       FROM (
                              SELECT A.YD_GP
                                    , A.BAY_GP
                                    , A.SECT_GP
                                    , A.YD_STK_COL_GP
                                    , B.STL_NO
                                    , CASE WHEN B.YD_STK_LYR_ACTIVE_STAT IN ('E') AND B.YD_STK_LYR_STAT IN ('E', 'D') THEN 1 ELSE 0 END AS ACTIVE_STA_E
                                    , CASE WHEN B.YD_STK_LYR_ACTIVE_STAT IN ('C') AND B.YD_STK_LYR_STAT IN ('E', 'D') THEN 1 ELSE 0 END AS ACTIVE_STA_C
                                    , CASE WHEN B.YD_STK_LYR_ACTIVE_STAT IN ('N') AND B.YD_STK_LYR_STAT IN ('E', 'D') THEN 1 ELSE 0 END AS ACTIVE_STA_N
                                    , CASE WHEN B.YD_STK_LYR_STAT IN ('C', 'U', 'L', 'S') AND B.YD_STK_LYR_ACTIVE_STAT IN ('E','C') THEN 1 ELSE 0 END AS STK_CNT
                                    , A.YD_ZONE_GP
                              FROM TB_YF_STKCOL A, TB_YF_STKLYR B 
                              WHERE A.YD_STK_COL_GP LIKE '1' ||'%' -- 야드구분
                                AND A.SECT_GP BETWEEN '01' AND '99'
                                AND A.YD_ZONE_GP IS NOT NULL 
                                AND A.YD_STK_COL_GP = B.YD_STK_COL_GP 
                                AND A.BAY_GP<>'X'
                            ) A  
                     ) A 
                GROUP BY A.YD_GP, A.YD_ZONE_GP  
        ) A 
        WHERE B.YD_ZONE_GP=A.YD_ZONE_GP(+)
) A
ORDER BY A.YD_GP, A.YD_ZONE_GP
 </pre> */
public final static String getStockInfoList = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockInfoList";

 /** <pre> 2020-11-25
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListACStackUsage 
SELECT  TT.ID AS YD_SPAN
      , TT.BAY_GP
      , TT.BAY_GP || ' 동  ' || TT.SECT_GP  || ' Span'   AS SPAN_NM
      , TRIM(TO_CHAR(TT.TOT_CNT      ,'99,999,999,990')) AS TOT_CNT --총수량
      , TRIM(TO_CHAR(TT.SUM_ACTIVE_STAT_E_CNT,'99,999,999,990')) AS SUM_ACTIVE_E_CNT --적치가능수량
      , TRIM(TO_CHAR(TT.SUM_ACTIVE_STAT_N_CNT,'99,999,999,990')) AS SUM_ACTIVE_N_CNT --금지수량
      , TRIM(TO_CHAR(TT.SUM_ACTIVE_STAT_C_CNT,'99,999,999,990')) AS SUM_ACTIVE_C_CNT --비활성수량      
      , TRIM(TO_CHAR(TT.SUM_STK_CNT  ,'99,999,999,990')) AS SUM_STK_CNT --적치수량
      , TRIM(TO_CHAR(TT.SUM_STK_WT   ,'99,999,999,990')) AS SUM_STK_WT --적치중량
      , TRIM(TO_CHAR(TT.STK_ABLE_CNT ,'99,999,999,990')) AS STK_ABLE_CNT 
      , TRIM(TO_CHAR(TT.STK_ABLE_CNT_01 ,'99,999,999,990')) AS STK_ABLE_CNT_01
      , TRIM(TO_CHAR(TT.STK_ABLE_CNT_02 ,'99,999,999,990')) AS STK_ABLE_CNT_02
      , TO_NUMBER(CC.DTL_ITEM1) AS MAX_STK_RT --최대적치율
      , CASE WHEN (TT.SUM_ACTIVE_STAT_E_CNT+TT.SUM_ACTIVE_STAT_C_CNT) = 0 THEN 0 ELSE ROUND((TT.SUM_STK_CNT/(TT.SUM_ACTIVE_STAT_E_CNT+TT.SUM_ACTIVE_STAT_C_CNT)) * 100) END AS ABLE_RT 
      , SUBSTR(TT.ID,2) AS YD_SPAN_TITLE
      , (SELECT MIN(Z.YD_ZONE_GP) AS YD_ZONE_GP
          FROM TB_YF_SCHLOCSRCH_ZONE Z
              ,TB_YF_RULE R
         WHERE R.REPR_CD_GP = 'YM6001' 
           AND R.ITEM = Z.YD_ZONE_GP
           AND Z.DEL_YN = 'N'
           AND R.DTL_ITEM2 IN ('Y','N') 
           AND Z.YD_STK_COL_GP LIKE TT.YD_GP || TT.BAY_GP || TT.SECT_GP || '%'
         ) AS YD_ZONE_GP
      , USE_GP
      , YD_STK_COL_USAGE_CD
FROM  (   
        SELECT BB.* 
              ,CC.DTL_ITEM1 AS USE_GP
            FROM  
                (SELECT T.YD_GP
                      , T.BAY_GP
                      , T.SECT_GP
                      , NVL(SUM(T.ACTIVE_STAT_C_CNT),0) + NVL(SUM(T.ACTIVE_STAT_E_CNT),0)  AS TOT_CNT
                      , SUM(T.ACTIVE_STAT_C_CNT) AS SUM_ACTIVE_STAT_C_CNT
                      , SUM(T.ACTIVE_STAT_N_CNT) AS SUM_ACTIVE_STAT_N_CNT
                      , SUM(T.ACTIVE_STAT_E_CNT) AS SUM_ACTIVE_STAT_E_CNT
                      , SUM(CASE WHEN T.YD_STK_LYR_NO = '01' THEN CASE WHEN T.YD_STK_LYR_STAT IN ('D', 'E') AND T.YD_STK_LYR_ACTIVE_STAT IN('E') THEN 1 ELSE 0 END END) AS STK_ABLE_CNT_01
                      , SUM(CASE WHEN T.YD_STK_LYR_NO = '02' THEN CASE WHEN T.YD_STK_LYR_STAT IN ('D', 'E') AND T.YD_STK_LYR_ACTIVE_STAT IN('E') THEN 1 ELSE 0 END END) AS STK_ABLE_CNT_02
                      , SUM(T.STK_CNT) AS SUM_STK_CNT
                      , SUM(NVL(T.COIL_WT,0)) AS SUM_STK_WT
                      , T.YD_GP || T.BAY_GP || T.SECT_GP AS ID
                      , SUM(CASE WHEN T.YD_STK_LYR_STAT IN ('D', 'E') AND T.YD_STK_LYR_ACTIVE_STAT IN('E') THEN 1 ELSE 0 END) AS STK_ABLE_CNT
                      , MAX(YD_STK_COL_USAGE_CD) AS YD_STK_COL_USAGE_CD
              FROM  (   SELECT  A.YD_GP
                              , A.BAY_GP 
                              , A.SECT_GP
                              , A.YD_STK_COL_GP
                              , B.YD_STK_BED_NO
                              , B.STL_NO
                              , B.YD_STK_LYR_ACTIVE_STAT 
                              , CASE WHEN B.YD_STK_LYR_ACTIVE_STAT IN ('N')  THEN 1 ELSE 0 END AS ACTIVE_STAT_N_CNT
                              , CASE WHEN B.YD_STK_LYR_ACTIVE_STAT IN ('C')  THEN 1 ELSE 0 END AS ACTIVE_STAT_C_CNT
                              , CASE WHEN B.YD_STK_LYR_ACTIVE_STAT IN ('E')  THEN 1 ELSE 0 END AS ACTIVE_STAT_E_CNT
                              , B.YD_STK_LYR_STAT 
                              , CASE WHEN B.YD_STK_LYR_STAT IN ('C', 'S', 'U') THEN 1 ELSE 0 END  AS STK_CNT
                              , D.COIL_WT
                              , B.YD_STK_LYR_NO
                              , A.YD_ZONE_GP AS YD_STK_COL_USAGE_CD
                          FROM  TB_YF_STKCOL A
                              , TB_YF_STKLYR B
                              , VW_YF_COILCOMM D
                         WHERE  A.YD_GP = '1'
                           AND  A.SECT_GP BETWEEN '01' AND '99'
                           AND  A.YD_STK_COL_GP = B.YD_STK_COL_GP
                           AND  A.BAY_GP NOT IN ('X')
                           AND  B.STL_NO = D.COIL_NO(+) 
                    ) T
                 GROUP BY T.YD_GP, T.BAY_GP, T.SECT_GP 
               ) BB
               ,TB_YF_RULE CC
               WHERE CC.REPR_CD_GP(+) = 'YF0010'
                 AND BB.YD_GP||BB.BAY_GP||BB.SECT_GP = CC.ITEM(+)                
        ) TT 
      , TB_YF_RULE CC
 WHERE  CC.REPR_CD_GP(+) = 'MAXR' -- 최대적치율(%)
   AND  CC.CD_GP(+) = TT.YD_GP
   AND  CC.ITEM(+) = TT.BAY_GP 
ORDER BY TT.ID
 </pre> */
public final static String getListACStackUsage = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListACStackUsage";

 /** <pre> 2019-11-12
--yf.facilitystatus.facilityinquiry.CraneSchDAO.getCoilCommonInfo2
SELECT A.*
      ,(CASE 
        WHEN YD_BAY_GP IN ('A','C') THEN '2'
        WHEN YD_BAY_GP IN ('B','E','F') AND YD_ZONE_GP IS NOT NULL THEN '2' 
        WHEN YD_BAY_GP IN ('G','H') 
              AND (SELECT TO_NUMBER(SUBSTR(YD_STK_COL_GP,3,2))
                     FROM TB_YF_STKCOL B 
                    WHERE B.YD_ZONE_GP=A.YD_ZONE_GP 
                      AND B.BAY_GP=A.YD_BAY_GP 
                      AND ROWNUM<=1) > 6 
                THEN '2'
                ELSE '1' 
         END) AS YD_GATE_GP --통로구분
FROM (
        SELECT DECODE(YD_GP,'1','A',HR_PLNT_GP) 		AS HR_PLNT_GP   -- 공장구분
              ,ORD_NO 			                        AS ORD_NO       -- 제작번호,
              ,ORD_DTL 		                            AS ORD_DTL      -- 제작행번,
              ,COIL_T 			                        AS COIL_T       -- 코일두께,
              ,COIL_W 			                        AS COIL_W       -- 코일폭,
              ,CURR_COIL_LEN	                        AS CURR_COIL_LEN--코일길이,
              ,COIL_INDIA 		                        AS COIL_INDIA   --코일내경,
              ,COIL_OUTDIA 	                            AS COIL_OUTDIA  --코일외경,
              ,decode(COIL_WT,0,NET_CAL_WT,COIL_WT)     AS COIL_WT      --코일중량,
              ,NEXT_PROC 		                        AS NEXT_PROC    --차공정,
              ,PLAN_PROC1                               AS PLAN_PROC1   --계획공정,
              ,BRANCH_CD 		                        AS BRANCH_CD    --분기위치코드,
              ,EXTEND_CONVEYOR_BRANCH_CD                AS EXTEND_CONVEYOR_BRANCH_CD    --확장분기위치코드,
              ,HYSCO_TRANS_GP 	                        AS HYSCO_TRANS_GP               --HYSCO이송수단,
              ,COOL_METHOD 	                            AS COOL_METHOD                  --냉각방법,
              ,decode(CURR_PROG_CD,'2','H','3','D','4','E','6','L','7','K',CURR_PROG_CD) AS CURR_PROG_CD
              ,RETURN_GP
              ,(SELECT  SUBSTR(YD_STK_COL_GP,2,1)
                  FROM  TB_YF_STKLYR LYR 
                 WHERE LYR.STL_NO=A.COIL_NO 
                   AND ROWNUM <= 1 )                    AS YD_BAY_GP   
              ,(CASE WHEN (SELECT DTL_ITEM1 FROM TB_YF_RULE B WHERE B.REPR_CD_GP='YM6002' AND DEL_YN='N')='Y' 
                        THEN NVL( (SELECT C.YD_ZONE_GP 
                                     FROM TB_YF_STOCK C 
                                    WHERE C.STL_NO=A.COIL_NO)      
                                                              ,(SELECT YD_ZONE_GP 
                                                                  FROM VW_YF_CONDENSATIONLOC D 
                                                                 WHERE D.COIL_NO=A.COIL_NO) 
                                 )
                        ELSE '' 
                      END)                              AS YD_ZONE_GP   
         FROM TB_PT_COILCOMM A 
        WHERE COIL_NO = :V_COIL_NO   
 ) A
 </pre> */
public final static String getCoilCommonInfo2 = "yf.facilitystatus.facilityinquiry.CraneSchDAO.getCoilCommonInfo2";

