 /** <pre> 2019-11-19
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabProducList.getExcel02  
SELECT 
     TO_CHAR(TO_DATE(SF_YD_WRK_HDS_DD(NULL),'YYYYMMDD'),'YYYY"년 "MM"월 "DD"일"') ||' '|| SF_YD_WRK_DUTY(NULL) || '근조' AS DOC_TITLE
    , A.*
    FROM
    (
        SELECT
           A.*
           , C.PLAN_SLAB_NO --AS 예정SLABNO
           , (CASE WHEN USRPMA.FN_PM_B_냉연품명찾기(C.ITEMNAME_CD) = 'Y' THEN C.HR_SPEC_ABBSYM ELSE C.SPEC_ABBSYM END) AS SPEC_ABBSYM  -- 규격약호
           , TO_CHAR(C.REAL_MEASURE_SLAB_T, '99,999,990')    AS SLAB_T      --두께
           , TO_CHAR(C.REAL_MEASURE_SLAB_W, '99,999,990')    AS SLAB_W      --폭
           , TO_CHAR(C.REAL_MEASURE_SLAB_LEN, '99,999,990')  AS SLAB_LEN    --길이
           , TO_CHAR(C.SLAB_WT, '99,999,990')   AS SLAB_WT     --중량
           , CASE NVL(SUBSTR(C.STACK_LOT_NO,1,2),'XXXXXX')
                WHEN 'XXXXXX' THEN ''
                WHEN 'HC' THEN 'C열연'
                WHEN 'HB' THEN 'B열연'
             ELSE '통합'  END AS SLAB_WO_RT_CD_NM
           , C.SLAB_WO_RT_CD
           , SUBSTR(C.STACK_LOT_NO,1,2) AS STACK_LOT_NO
           , C.WO_MSLAB_RPR_MTD
        FROM 
        (
            SELECT SUBSTR(A.YD_STK_COL_GP, 1, 1) AS YD_GP,
                   SUBSTR(A.YD_STK_COL_GP, 2, 1) AS BAY_GP,
                   SUBSTR(A.YD_STK_COL_GP, 3, 2) AS SPAN_GP,
                   A.YD_STK_COL_GP||A.YD_STK_BED_NO||A.YD_STK_LYR_NO AS EXPECT_YD_STK_LOC, -- 저장위치
                   A.STL_NO, -- 저장품 ID(SLAB_NO)
                   A.YD_STK_COL_GP, A.YD_STK_BED_NO, A.YD_STK_LYR_NO
              FROM TB_YF_STKLYR A 
                WHERE A.YD_STK_COL_GP LIKE '0%'
                AND A.YD_STK_BED_NO BETWEEN '07' AND '20'
                AND A.YD_STK_LYR_NO = '01'
        ) A, VW_YD_SLABCOMM C
    WHERE A.STL_NO = C.SLAB_NO(+)
) A
ORDER BY A.YD_STK_COL_GP, A.YD_STK_BED_NO, A.YD_STK_LYR_NO
 </pre> */
public final static String getExcel02 = "com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabProducList.getExcel02";

