 /** <pre> 2020-11-25
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfColInfo 
-- 적치열col 정보 조회 
SELECT
    A.*
  , (
        SELECT 
            S.REPR_CD_CONTENTS || '(' || (SELECT REPR_CD_CONTENTS FROM TB_YF_RULE WHERE REPR_CD_GP ='YF0014' AND CD_GP = '1' AND ITEM = S.DTL_ITEM2) ||')'
        FROM TB_YF_RULE S
        WHERE S.REPR_CD_GP = 'YM6001'
        AND S.CD_GP = '1'
        AND S.DEL_YN = 'N'
        AND S.ITEM = R.YD_ZONE_GP
    ) AS YD_ZONE_GP_NM
   , R.YD_ZONE_GP
FROM (
        SELECT A.YD_STK_COL_GP -- 열구분
             , A.YD_STK_COL_USAGE_CD -- 열용도
             ,(SELECT MAX(Z.COL_GP) 
                 FROM TB_YF_STKCOL Z
                WHERE Z.YD_GP = A.YD_GP
                  AND Z.BAY_GP = A.BAY_GP
                  AND Z.SECT_GP = A.SECT_GP ) AS COL_CNT
             , SUM(CASE WHEN NVL(B.YD_STK_LYR_YD_STK_LOT_NO2, ' ') <> 'Y' THEN 1 ELSE 0 END) AS BED_CNT --배드수
             , SUM(DECODE(B.YD_STK_LYR_ACTIVE_STAT, 'E', 1, 0)) AS TOTAL_CNT --총매수
             , SUM(DECODE(B.YD_STK_LYR_STAT, 'C', 1, 'L', 1, 'U', 1, 'S', 1, 0)) AS STK_CNT --적치매수
             , SUM(DECODE(B.YD_STK_LYR_ACTIVE_STAT, 'E', DECODE(B.YD_STK_LYR_STAT, 'C', 0, 'L', 0, 'U', 0, 'S', 0, 1), 0)) AS STK_ABLE_CNT--적치가능매수
             , SUBSTR(A.YD_STK_COL_GP,5,2) AS COL_NO
             , 'C' || SUBSTR(A.YD_STK_COL_GP,5,2) AS COL_ID
             , MAX(B.YD_STK_LYR_NO) AS MAX_YD_STK_LYR_NO
             , CASE WHEN MIN(A.YD_ZONE_GP) = 'EZ' THEN '외경큰' ELSE '' END AS YD_STK_COL_USAGE_CD_NM
          FROM TB_YF_STKCOL   A
             , TB_YF_STKLYR B
         WHERE A.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP||'%' -- 야드+동+스판:(2A01 ...)
           AND B.YD_STK_BED_NO NOT IN ('00')
           AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
         GROUP BY A.YD_GP,A.BAY_GP,A.SECT_GP,A.YD_STK_COL_GP, A.YD_STK_COL_USAGE_CD
) A
, TB_YF_SCHLOCSRCH_ZONE R
WHERE  A.YD_STK_COL_GP = R.YD_STK_COL_GP(+) 
AND R.DEL_YN(+) = 'N'
ORDER BY A.YD_STK_COL_GP
 </pre> */
public final static String getYfColInfo = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfColInfo";

 /** <pre> 2020-02-05
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getRequstPassTimeByEqp 
SELECT
    T1.YD_WRK_CRN
    , T1.YD_EQP_GP
    , T2.YD_EQP_NO
    , T2.YD_EQP_NAME
    , T2.YD_BAY_GP
    , TO_CHAR(T1.WBOOK_REG_DATE, 'YYYYMMDDHH24MISS') AS WBOOK_REG_DATE
    , TO_CHAR(T1.WBOOK_REG_DATE, 'HH24') AS WBOOK_REG_HH24
    , TO_CHAR(T1.WBOOK_REG_DATE, 'MI') AS WBOOK_REG_MI
    , TO_CHAR(T1.WBOOK_REG_DATE, 'SS') AS WBOOK_REG_SS
    ,REPLACE(( 
       REPLACE('('||TRUNC(SYSDATE - T1.WBOOK_REG_DATE) ||')','()','')||
       LPAD(TRUNC(MOD(SYSDATE - T1.WBOOK_REG_DATE,1)*24), 2, '0') || ':' ||  
       LPAD(TRUNC(MOD((SYSDATE - T1.WBOOK_REG_DATE)*24,1)*60), 2, '0') ||':'||  
       LPAD(TRUNC(MOD((SYSDATE - T1.WBOOK_REG_DATE)*24*60,1)*60), 2, '0')
     ),'::','') AS PASS_TIME 
    ,(CASE WHEN T1.YD_EQP_GP = 'FD' THEN  (CASE WHEN TRUNC((SYSDATE - T1.WBOOK_REG_DATE)*24) >= 1 THEN 'Y' ELSE 'N' END )   --결속장 1시간 이상 알람
           WHEN T1.YD_EQP_GP IN ('KD','QD') THEN  (CASE WHEN TRUNC((SYSDATE - T1.WBOOK_REG_DATE)*24*60)>=20 THEN 'Y' ELSE 'N' END ) -- 설비 20분 이상 알람
           ELSE 'N' END
      ) PASS_TIME_YN
FROM
(
    SELECT  
         B.YD_WRK_CRN
        ,SUBSTR(B.YD_SCH_CD,3,2) AS YD_EQP_GP
        ,MIN(A.REG_DDTT  ) AS WBOOK_REG_DATE         
    FROM  TB_YF_SCHRULE B
        , TB_YF_WRKBOOK A
    WHERE B.YD_SCH_CD = A.YD_SCH_CD(+)
      AND B.DEL_YN = 'N'
      AND B.YD_GP = '1'
      AND A.DEL_YN(+) = 'N'
      --
        우선 TAKE-OUT은 제외 
        추출만 대상으로 진행한다.
      
      AND 
      ( B.YD_SCH_CD LIKE '1_FD01LM'
        OR B.YD_SCH_CD LIKE '1_KD01LM'
        OR B.YD_SCH_CD LIKE '1_QD01LM'
      ) 
    GROUP BY B.YD_WRK_CRN, SUBSTR(B.YD_SCH_CD,3,2)
) T1, TB_YF_EQP T2
WHERE T1.YD_WRK_CRN = T2.YD_EQP_ID
ORDER BY T2.YD_EQP_ID ASC, T1.YD_EQP_GP
 </pre> */
public final static String getRequstPassTimeByEqp = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getRequstPassTimeByEqp";

