 /** <pre> 2020-09-14
--com.inisteel.cim.yf.common.dao.YfCommDAO.getA7YML009TCarSchLd
-- 크레인권하실적 상차 대차스케줄 조회
SELECT YD_TCAR_SCH_ID 
     , CASE WHEN TC_LYR_SH      >= TC_MAX_QNTY THEN 'Y' --최대적치매수보다 크거나 같으면 완료
            WHEN YD_EQP_WRK_WT  >= TC_MAX_WT   THEN 'Y' --최대적치중량보다 크거나 같으면 완료
            ELSE 'N'

            END AS TCAR_LD_CMPL_YN --대차상차완료여부
     , TC_LYR_SH
     , YD_CARUD_STOP_LOC    -- 1냉연 J/C 권상시 필요   
     , YD_EQP_ID
     , YD_CURR_BAY_GP
     , YD_EQP_PROG_STAT
  FROM  
        (
        SELECT TS.YD_TCAR_SCH_ID
             , TS.YD_EQP_ID
             , (SELECT COUNT(*) + 1 --현재 권하 실적 +1
                  FROM TB_YF_STKLYR
                 WHERE YD_STK_COL_GP = SUBSTR(:V_YD_DN_WR_LOC,1,6)
                   AND STL_NO IS NOT NULL
                   AND DEL_YN = 'N'
                   AND YD_STK_LYR_STAT = 'C' ) AS TC_LYR_SH --현재대차적치매수
                   
             , NVL(TS.YD_EQP_WRK_WT,0) + NVL((SELECT SUM(COIL_WT) 
                                                FROM USRYFA.VW_YF_COILCOMM A
                                                    ,TB_YF_WRKBOOKMTL B
                                                WHERE A.COIL_NO = B.STL_NO
                                                AND B.YD_WBOOK_ID = :V_YD_WBOOK_ID
                                                AND B.DEL_YN ='N'),0) AS YD_EQP_WRK_WT--대차적재 실적중량
                   
             , EQ.STK_MAX_QNTY AS TC_MAX_QNTY
             , EQ.STK_MAX_WT   AS TC_MAX_WT
             , CASE WHEN (SELECT COUNT(*) 
                            FROM TB_YF_TCARFTMVMTL 
                           WHERE YD_TCAR_SCH_ID = TS.YD_TCAR_SCH_ID )  = 0 THEN
                    
                               ('1' || ( CASE WHEN SUBSTR(:V_YD_DN_WR_LOC,2,1) = 'A' THEN 'B'
                                              WHEN SUBSTR(:V_YD_DN_WR_LOC,2,1) = 'B' THEN 'A'
                                          END ) ||SUBSTR(TS.YD_EQP_ID,3,4))
                ELSE  TS.YD_CARUD_STOP_LOC END AS YD_CARUD_STOP_LOC                    --야드하차정지위치
             , EQ.YD_CURR_BAY_GP
             , EQ.YD_EQP_PROG_STAT
          FROM TB_YF_TCARSCH TS
              ,TB_YF_EQP EQ
         WHERE TS.YD_EQP_ID = :V_YD_WRK_PLAN_TCAR
           AND TS.YD_EQP_ID = EQ.YD_EQP_ID 
           AND TS.DEL_YN    = 'N'
        )

 </pre> */
public final static String getA7YML009TCarSchLd = "com.inisteel.cim.yf.common.dao.YfCommDAO.getA7YML009TCarSchLd";

 /** <pre> 2020-02-19
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.selectCTSLyr
SELECT *
FROM
(
SELECT A.STL_NO
      ,C.YD_WBOOK_ID
      ,A.YD_STK_COL_GP AS YD_CARLD_WO_LOC
      ,C.YD_AIM_BAY_GP
      ,C.YD_TO_LOC_GUIDE
      ,RANK() OVER(PARTITION BY A.STL_NO ORDER BY B.YD_WBOOK_ID DESC) AS RNK
FROM TB_YF_STKLYR A,
     TB_YF_WRKBOOKMTL B,
     TB_YF_WRKBOOK C
WHERE (A.YD_STK_COL_GP LIKE '%SR%'
       OR 
       A.YD_STK_COL_GP LIKE '%SL%'
      )
  AND A.STL_NO IS NOT NULL 
  AND C.YD_AIM_BAY_GP IS NOT NULL
  AND A.YD_STK_LYR_STAT = 'C'
  AND A.STL_NO      = B.STL_NO
  AND B.YD_WBOOK_ID = C.YD_WBOOK_ID
  AND C.YD_WRK_PLAN_TCAR = '1XTC01'
)
WHERE RNK = 1
 </pre> */
public final static String selectCTSLyr = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.selectCTSLyr";

 /** <pre> 2020-09-14
-- COIL상세조회(품보용)화면 com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getCoilStepAllDetailRead_PIDEV
WITH DD AS(
    SELECT
        :V_COIL_NO AS DD_COIL_NO
       ,:V_STEP_NO AS DD_STEP_NO
    FROM   DUAL
)

SELECT
    A.STEP_NO,                         -- 차수
    A.COIL_NO,                         -- 코일번호
    A.WORK_STAT,                       -- 작업상태코드  sWorkStat
    A.SHEAR_WORD_DT,                  -- 정정지시일자
    A.ORD_OUTDIA,                      -- 주문외경
    A.ORD_INDIA,                       -- 주문내경
    A.WORD_OUTDIA,                     -- 작업지시 외경
    A.WORD_INDIA,                      -- 작업지시 내경
    A.WRSLT_OUTDIA,                    -- 실적 외경
    A.WRSLT_INDIA,                     -- 실적 내경
    A.COIL_SUPPLY_DT,                -- 코일보급일자
    A.RECEIPT_HOLD_SCRAP_CAUSE_GP,     -- 결번, 보류, 스크랩원인구분
    A.SHEAR_CAUSE_CD,                  -- 정정원인코드
    A.WORD_UNIT_NAME,             -- 공정작업단위명
    A.WORD_UNIT_SEQNO,              -- 공정작업단위순위
    A.WORD_UNIT_NAME2,              -- 작업지시단위명
    A.WORD_UNIT_SEQNO2,             -- 작업지시단위순위
    A.REAGENT_PICK_YN,                 -- 정정지시 시편채취유무
    A.SHEAR_REAGENT_PICK_YN,           -- 정정실적 시편채취유무
    A.MISSNO_DT as MISSNO_OCCUR_DATE,               -- 결번발생일자
    A.MISSNO_CAUSE_CD,           -- 결번발생원인
    A.WRSLT_T_TOP,                     -- 실적 두께 TOP
    A.WRSLT_T_MIDDLE,                  -- 실적 두께
    A.WRSLT_T_BOTTOM,                  -- 실적 두께
    A.SURFACE_INSPECT_RULE,            -- 표면검사기준
    A.EVEN_INSPECT_RULE,               -- 평탄검사기준
    A.COLOR_STROKE_GP,                    -- COLOR_STROKE_GP
    A.SHEAR_WORK_INSPECT_DT,         -- 정정작업 검사일자
    A.WRSLT_T_AVG,                     -- 실적 두께 AVG
    A.WRSLT_T_MIN,                     -- 실적 두께 최소
    A.WRSLT_T_MAX,                     -- 실적 두께 최대
    A.WRSLT_W_AVG,                     -- 실적 AVG
    A.WRSLT_W_MIN,                     -- 실적 폭 최소
    A.WRSLT_W_MAX,                     -- 실적 폭 최대
    A.WRSLT_W_TOP,                     -- 실적 폭
    A.WRSLT_W_MIDDLE,                  -- 실적 폭
    A.WRSLT_W_BOTTOM,                  -- 실적 폭
    A.AIM_T,                           -- 목표두께
    A.AIM_W,                           -- 목표폭
    A.WT_DECISION_CD,                  -- 중량구분
    A.REAL_WT,                         -- 실중량
    A.CAL_WT,                          -- 이론중량
    A.SHEAR_INI_DATE,                  -- 정정계상일자
    A.DUTY_GP,                            -- 정정근
    A.PARTY,                           -- 정정조
    A.WRSLT_T,                         -- 실적두께
    A.WRSLT_W,                         -- 실적 폭 WRSLT_T WRSLT_W
    A.WRSLT_LEN,                       -- 실적 길이
    A.WRSLT_WT_DECISION_CD,            -- 실적중량구분
    A.WRSLT_REAL_WT,                   -- 실적실중량
    A.WRSLT_CAL_WT,                    -- 실적이론중량
    A.T_TOL_MIN,                       -- 두께 허용공차하한
    A.T_TOL_MAX,                       -- 두께 허용공차상한
    A.W_TOL_MIN,                       -- 폭 허용공차하한
    A.W_TOL_MAX,                       -- 폭 허용공차상한
    A.GOODS_UNIT_WT_RANGE_MIN,         -- 제품단위중량하한
    A.GOODS_UNIT_WT_RANGE_MAX,         -- 제품단위중량상한
    TO_CHAR(A.SHEAR_WORK_ST_DT, 'YYYYMMDDHH24MISS') as SHEAR_WORK_ST_DT,
    TO_CHAR(A.SHEAR_WORK_CMPL_DT, 'YYYYMMDDHH24MISS') as SHEAR_WORK_CMPL_DT,
    TO_CHAR(A.SHEAR_WORK_DT, 'YYYYMMDDHH24MISS') as SHEAR_WORK_DT,
    A.GOODS_DIVIDE_QNTY,               -- 제품분할수
    A.WRAP_METHOD_CD,                  -- 포장방법 코드
    A.WRAP_METHOD_OD,                  -- 포장방법 OD
    A.WRAP_METHOD_EYE,                 -- 포장방법 EYE
    A.WRAPUNIT_WT_EA_UNIT,               -- 포장단중 단위
    A.WRAPUNIT_WT_EA_MIN,                -- 포장단중 하한
    A.WRAPUNIT_WT_EA_MAX,                -- 포장단중 상한
    A.HOLD_PROG_STAT,                  -- 보류진행상태
    A.HOLD_CAUSE_CD,                   -- 보류원인코드
    A.HOLD_TREAT_GP_ICS,               -- 보류 처리 구분 ICS
    A.HOLD_CAUSE_CD_QM,                -- 보류이유코드 QM
    A.HOLD_CAUSE_CD_PM1,               -- 보류이유코드 PM1
    A.HOLD_CAUSE_CD_PM2,               -- 보류이유코드 PM2
    A.HOLD_CAUSE_CD_PM3,               -- 보류이유코드 PM3
    A.HOLD_CAUSE_CD_PM4,               -- 보류이유코드 PM4
    A.HOLD_STAMP_GRADE,                -- 보류판정등급
    TO_CHAR(A.HOLD_STAMP_DT, 'YYYYMMDDHH24MISS') as HOLD_STAMP_DT,
    TO_CHAR(A.HOLD_RELEASE_DT, 'YYYYMMDDHH24MISS') as HOLD_RELEASE_DT,
    TO_CHAR(A.HOLD_TREAT_DT, 'YYYYMMDDHH24MISS') as HOLD_TREAT_DT,
    A.ORD_NO,                          -- 주문 번호
    A.ORD_DTL,                         -- 주문 행번
        A.CUST_CD,                         -- 정정 고객CODE
        A.DEMANDER_CD,                     -- 정정 수요가CODE
        USRHRA.SF_HR_고객명_코일(DD.DD_COIL_NO, A.ORD_NO, A.ORD_DTL, 'CUST') AS CUST_NAME,         --정정 고객명
        USRHRA.SF_HR_고객명_코일(DD.DD_COIL_NO, A.ORD_NO, A.ORD_DTL, 'DEMANDER') AS DEMANDER_NAME, --정정 수요가명

    A.SHEAR_DEMAND_NEXT_PROC,          -- 정정 요구 다음 공정
    A.LAST_CHILD_COIL_GP,              -- LAST 자 COIL 구분
    A.PARENT_COIL_NO,                  -- 모 COIL 번호
    (SELECT REPLACE(MSG_CONTENTS, CHR(13)||CHR(10) , '')
      FROM TB_HR_C_SHEARWOWR_MSG_LOG SR_LOG
     WHERE COIL_NO = A.COIL_NO
       AND REG_DDTT = (SELECT MAX(REG_DDTT) FROM TB_HR_C_SHEARWOWR_MSG_LOG WHERE SHEAR_WRK_MSG_GP NOT IN ('A') AND COIL_NO = SR_LOG.COIL_NO AND  MSG_CONTENTS IS NOT NULL)
       AND MSG_CONTENTS IS NOT NULL) AS SHEAR_INSPECT_MSG,
--    A.SHEAR_INSPECT_MSG,           -- 정정검사 메세지

    B.RETURN_TREAT_DATE,               -- 제품반납날짜
    B.RETURN_TREAT_TIME,               -- 제품반납시각
    B.RETURN_T,                        -- 제품반납두께
    B.RETURN_W,                        -- 제품반납폭
    B.RETURN_WT,                        -- 제품반납중량
    A.SHEAR_INSPECT_MODIFIER,
        A.INSPECTOR,
    A.FNL_SHEAR_DEFECT_CD1,
    A.FNL_SHEAR_DEFECT_CD2,
    A.FNL_SHEAR_DEFECT_CD3,
    A.FNL_SHEAR_DEFECT_CD4,
    A.FNL_SHEAR_DEFECT_CD5,
        (SELECT CD_MNNG  FROM BRE.VW_CM_CODES WHERE CD_CAT_ID = 'HS0000' AND CD_EN_ID  = 'HR_DF_CD' AND CD_VAL = SUBSTR(A.FNL_SHEAR_DEFECT_CD1,0,2)) AS FNL_SHEAR_DEFECT_NM1,
        (SELECT CD_MNNG  FROM BRE.VW_CM_CODES WHERE CD_CAT_ID = 'HS0000' AND CD_EN_ID  = 'HR_DF_CD' AND CD_VAL = SUBSTR(A.FNL_SHEAR_DEFECT_CD2,0,2)) AS FNL_SHEAR_DEFECT_NM2,
        (SELECT CD_MNNG  FROM BRE.VW_CM_CODES WHERE CD_CAT_ID = 'HS0000' AND CD_EN_ID  = 'HR_DF_CD' AND CD_VAL = SUBSTR(A.FNL_SHEAR_DEFECT_CD3,0,2)) AS FNL_SHEAR_DEFECT_NM3,
        (SELECT CD_MNNG  FROM BRE.VW_CM_CODES WHERE CD_CAT_ID = 'HS0000' AND CD_EN_ID  = 'HR_DF_CD' AND CD_VAL = SUBSTR(A.FNL_SHEAR_DEFECT_CD4,0,2)) AS FNL_SHEAR_DEFECT_NM4,
        (SELECT CD_MNNG  FROM BRE.VW_CM_CODES WHERE CD_CAT_ID = 'HS0000' AND CD_EN_ID  = 'HR_DF_CD' AND CD_VAL = SUBSTR(A.FNL_SHEAR_DEFECT_CD5,0,2)) AS FNL_SHEAR_DEFECT_NM5,

    A.MODIFIER,
    A.QT_TRK_AB_TRT_CD1||' - '|| A.QT_TRK_AB_TRT_MSG1 AS QT_TRK_AB_TRT_CD1,     --품질Trk1
    A.QT_TRK_AB_TRT_CD2||' - '|| A.QT_TRK_AB_TRT_MSG2 AS QT_TRK_AB_TRT_CD2,     --품질Trk2
    A.QT_TRK_AB_TRT_CD3||' - '|| A.QT_TRK_AB_TRT_MSG3 AS QT_TRK_AB_TRT_CD3,     --품질Trk3
    A.HRSHR_QT_MSG_CD1 ||' - '|| NVL(BR1.CD_MNNG,'')   AS QT_MSG_CD1_MNNG,  --품질MSG1
    A.HRSHR_QT_MSG_CD2 ||' - '|| NVL(BR2.CD_MNNG,'')   AS QT_MSG_CD2_MNNG,  --품질MSG2
    A.SDD_STMP_RS_MSG,         --SDD판정결과메시지
        QS.QS_HR_DF_CD   , --품질상황실검사흠코드
        QS.QS_HR_DF_CD_1 , --품질상황실검사흠코드_1
        QS.QS_HR_DF_CD_2 , --품질상황실검사흠코드_2
        QS.APPEAR_GRADE  , --외관종합판정등급
    A.GOODS_TENSILE_STRENGTH,
      -- ,CC.MID_INSPECT_DEFECT_CD1||' '||MID_INSPECT_DEFECT_CD2  ||' '|| MID_INSPECT_DEFECT_CD3||' '|| MID_INSPECT_DEFECT_CD4||' '||MID_INSPECT_DEFECT_CD5 AS MID_INSPECT_DEFECT_CD
        D.TOP_SCRAP_YN||D.TOP_SCRAP_DEFECT_CD1||D.TOP_SCRAP_DEFECT_CD2||D.TOP_SCRAP_DEFECT_CD3||D.TOP_WRSLT_LEN||D.TOP_WRSLT_REAL_WT||
        D.TAIL_SCRAP_YN||D.TAIL_SCRAP_DEFECT_CD1||D.TAIL_SCRAP_DEFECT_CD2||D.TAIL_SCRAP_DEFECT_CD3||D.TAIL_WRSLT_LEN||D.TAIL_WRSLT_REAL_WT AS SHEAR_SCRAP_LOG,

        --B열연 코일상세조회 SPM챠트리스트 링크 위한 SPM작업여부 항목 추가 (2015.07.07 이강현) / 이효원부장님 요청으로 EQ작업도 'Y'로 설정 (2015.07.09 이강현)
        CASE WHEN SUBSTR(CC.PASS_PROC1, 2, 1) IN ('K', 'Q') OR SUBSTR(CC.PASS_PROC2, 2, 1) IN ('K', 'Q') OR SUBSTR(CC.PASS_PROC3, 2, 1) IN ('K', 'Q') OR
                  SUBSTR(CC.PASS_PROC4, 2, 1) IN ('K', 'Q') OR SUBSTR(CC.PASS_PROC5, 2, 1) IN ('K', 'Q') THEN 'Y'
             ELSE 'N'
             END AS PASS_SPM_YN

FROM    TB_HR_C_SHEARWOWR A,
        VW_YF_COILCOMM   CC,
        USRQMA.TB_QM_SDDSTMPMANAGE QS,
        VW_LM_P_GOODSRETURN B,
       (SELECT BR.CD_VAL,
                BR.CD_MNNG
        FROM BRE.VW_CM_CODES BR
        WHERE CD_EN_ID  = 'HRSHR_QT_MSG_CD1'
        AND CD_CAT_ID = 'HS0000') BR1,
        (SELECT BR.CD_VAL
                ,BR.CD_MNNG
        FROM BRE.VW_CM_CODES BR
        WHERE CD_EN_ID  = 'HRSHR_QT_MSG_CD2'
        AND CD_CAT_ID = 'HS0000') BR2,
        (SELECT
                D.COIL_NO
               ,D.STEP_NO
               ,CASE WHEN D.START_WRSLT_LEN IS NOT NULL AND D.START_WRSLT_LEN <> 0 OR D.START_WRSLT_REAL_WT IS NOT NULL AND D.START_WRSLT_REAL_WT <> 0 THEN 'Top스크랩 '
                     ELSE ''
                     END AS TOP_SCRAP_YN
               ,CASE WHEN D.END_WRSLT_LEN IS NOT NULL AND D.END_WRSLT_LEN <> 0 OR D.END_WRSLT_REAL_WT IS NOT NULL AND D.END_WRSLT_REAL_WT <> 0 THEN 'Tail스크랩 '
                     ELSE ''
                     END AS TAIL_SCRAP_YN

               ,CASE WHEN D.START_SHEAR_DEFECT_CD1 IS NOT NULL THEN (SELECT BR3.CD_NM FROM BRE.VW_HR_POB003 BR3 WHERE BR3.CD_VAL = D.START_SHEAR_DEFECT_CD1)||' '
                     ELSE ''
                     END AS TOP_SCRAP_DEFECT_CD1
               ,CASE WHEN D.START_SHEAR_DEFECT_CD2 IS NOT NULL THEN (SELECT BR3.CD_NM FROM BRE.VW_HR_POB003 BR3 WHERE BR3.CD_VAL = D.START_SHEAR_DEFECT_CD2)||' '
                     ELSE ''
                     END AS TOP_SCRAP_DEFECT_CD2
               ,CASE WHEN D.START_SHEAR_DEFECT_CD3 IS NOT NULL THEN (SELECT BR3.CD_NM FROM BRE.VW_HR_POB003 BR3 WHERE BR3.CD_VAL = D.START_SHEAR_DEFECT_CD3)||' '
                     ELSE ''
                     END AS TOP_SCRAP_DEFECT_CD3

               ,CASE WHEN D.END_SHEAR_DEFECT_CD1 IS NOT NULL THEN (SELECT BR3.CD_NM FROM BRE.VW_HR_POB003 BR3 WHERE BR3.CD_VAL = D.END_SHEAR_DEFECT_CD1)||' '
                     ELSE ''
                     END AS TAIL_SCRAP_DEFECT_CD1
               ,CASE WHEN D.END_SHEAR_DEFECT_CD2 IS NOT NULL THEN (SELECT BR3.CD_NM FROM BRE.VW_HR_POB003 BR3 WHERE BR3.CD_VAL = D.END_SHEAR_DEFECT_CD2)||' '
                     ELSE ''
                     END AS TAIL_SCRAP_DEFECT_CD2
               ,CASE WHEN D.END_SHEAR_DEFECT_CD3 IS NOT NULL THEN (SELECT BR3.CD_NM FROM BRE.VW_HR_POB003 BR3 WHERE BR3.CD_VAL = D.END_SHEAR_DEFECT_CD3)||' '
                     ELSE ''
                     END AS TAIL_SCRAP_DEFECT_CD3

               ,CASE WHEN D.START_WRSLT_LEN IS NOT NULL AND D.START_WRSLT_LEN <> 0 THEN D.START_WRSLT_LEN||'m '
                     ELSE ''
                     END AS TOP_WRSLT_LEN
               ,CASE WHEN D.START_WRSLT_REAL_WT IS NOT NULL AND D.START_WRSLT_REAL_WT <> 0 THEN ROUND(D.START_WRSLT_REAL_WT/1000, 1)||'ton '
                     ELSE ''
                     END AS TOP_WRSLT_REAL_WT
               ,CASE WHEN D.END_WRSLT_LEN IS NOT NULL AND D.END_WRSLT_LEN <> 0 THEN D.END_WRSLT_LEN||'m '
                     ELSE ''
                     END AS TAIL_WRSLT_LEN
               ,CASE WHEN D.END_WRSLT_REAL_WT IS NOT NULL AND D.END_WRSLT_REAL_WT <> 0 THEN ROUND(D.END_WRSLT_REAL_WT/1000, 1)||'ton '
                     ELSE ''
                     END AS TAIL_WRSLT_REAL_WT
           FROM
                (SELECT COIL_NO
                      , STEP_NO
                      , SUM(DECODE(PROC_GP, 'S', WRSLT_LEN , 0))     AS START_WRSLT_LEN
                      , SUM(DECODE(PROC_GP, 'S', WRSLT_REAL_WT , 0)) AS START_WRSLT_REAL_WT
                      , SUM(DECODE(PROC_GP, 'E', WRSLT_LEN , 0))     AS END_WRSLT_LEN
                      , SUM(DECODE(PROC_GP, 'E', WRSLT_REAL_WT , 0)) AS END_WRSLT_REAL_WT

                      , MIN(DECODE(PROC_GP, 'S', SHEAR_DEFECT_CD1)) AS START_SHEAR_DEFECT_CD1
                      , MIN(DECODE(PROC_GP, 'S', SHEAR_DEFECT_CD2)) AS START_SHEAR_DEFECT_CD2
                      , MIN(DECODE(PROC_GP, 'S', SHEAR_DEFECT_CD3)) AS START_SHEAR_DEFECT_CD3

                      , MIN(DECODE(PROC_GP, 'E', SHEAR_DEFECT_CD1)) AS END_SHEAR_DEFECT_CD1
                      , MIN(DECODE(PROC_GP, 'E', SHEAR_DEFECT_CD2)) AS END_SHEAR_DEFECT_CD2
                      , MIN(DECODE(PROC_GP, 'E', SHEAR_DEFECT_CD3)) AS END_SHEAR_DEFECT_CD3
                   FROM TB_PO_COILSHEARORD_SCRAP D
                       ,DD
                  WHERE COIL_NO IN (SELECT COIL_NO
                                      FROM TB_HR_C_SHEARWOWR SR
                                     WHERE COIL_NO = DD.DD_COIL_NO)
                  GROUP BY COIL_NO , STEP_NO ) D
        ) D
       ,DD
WHERE A.COIL_NO = B.GOODS_NO(+)
  AND A.COIL_NO = CC.COIL_NO
  AND CC.MILL_COIL_NO = QS.STL_NO (+)
  AND A.STEP_NO = B.GOODS_RETURN_STEP_NO(+)
  AND A.COIL_NO = D.COIL_NO(+)
  AND A.STEP_NO = D.STEP_NO(+)
  AND A.HRSHR_QT_MSG_CD1 = BR1.CD_VAL(+)
  AND A.HRSHR_QT_MSG_CD2 = BR2.CD_VAL(+)
  AND A.COIL_NO    = DD.DD_COIL_NO
  AND A.STEP_NO    = DD.DD_STEP_NO
  AND A.REG_DDTT >=(SELECT REG_DDTT FROM USRYMA.TB_YM_STACKRULE WHERE YD_GP ='X' AND ROWNUM<=1)
 </pre> */
public final static String getCoilStepAllDetailRead = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCommDtlInqjl.getCoilStepAllDetailRead_PIDEV";

 /** <pre> 2020-03-18
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.selectCTSSchRank
WITH PARAM AS(
SELECT :V_YD_EQP_ID AS YD_EQP_ID
      ,:V_YD_CTS_WRK_SEQ AS YD_CTS_WRK_SEQ
      ,:V_STL_NO AS STL_NO
  FROM DUAL )

SELECT A.YD_CTS_WRK_SEQ - 40 AS YD_CTS_WRK_SEQ
      ,CASE TO_CHAR(A.YD_CTS_WRK_SEQ)
       WHEN P.YD_CTS_WRK_SEQ
       THEN P.STL_NO
       ELSE A.STL_NO
        END AS STL_NO
  FROM (SELECT ROW_NUMBER() OVER (PARTITION BY A.YD_EQP_ID ORDER BY A.YD_CTS_WRK_SEQ,A.YD_CARLD_WO_LOC) AS YD_CTS_WRK_SEQ
              ,A.STL_NO
         FROM TB_YF_CTS_SCH A
             ,PARAM P 
        WHERE A.DEL_YN = 'N'
          AND A.YD_EQP_ID = P.YD_EQP_ID) A
      ,PARAM P
 WHERE A.YD_CTS_WRK_SEQ <= P.YD_CTS_WRK_SEQ
   

 </pre> */
public final static String selectCTSSchRank = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.selectCTSSchRank";

 /** <pre> 2020-12-15
/-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilCarldInfoInqjl.getCoilCarInfo_PIDEV --/
WITH PARAM AS (
SELECT :V_CAR_NO AS TRN_EQP_CD
  FROM DUAL
 )
--출하차량
SELECT
    T.--
    ,(SELECT BR.CD_MNNG
        FROM BRE.VW_CM_CODES BR
       WHERE BR.CD_EN_ID  = 'YD_CAR_PROG_STAT'
         AND BR.CD_CAT_ID = 'HS0000'
         AND BR.CD_VAL    = T.YD_CAR_PROG_STAT) AS YD_CAR_PROG_STAT_NM
FROM
(
        SELECT  B.TRANS_ORD_DATE  AS TRANS_WORD_DATE /-- 운송지시일자 --/
               ,B.TRANS_ORD_SEQNO||NVL((SELECT MAX(','||TRANS_WORD_SEQNO)
                                          FROM VW_LM_P_TRANSWORDCOMM F
                                         WHERE F.TRANS_WORD_DATE = A.TRANS_WORD_DATE
                                           AND F.CMBN_CARLD_NO = A.CMBN_CARLD_NO
                                           AND F.CMBN_CARLD_NO IS NOT NULL
                                      ),'') AS TRANS_WORD_SEQNO    /-- 운송지시순번 --/
               ,A.CMBN_CARLD_NO /-- 조합상차번호 --/
               ,(SELECT TRANS_COM_NAME FROM VW_LM_Z_TRANSCOMCD E WHERE E.TRANS_COM_CD=a.TRANS_COM_CD) AS TRANS_COM_NAME /--운송사--/
               ,B.CAR_NO    /-- 차량번호 --/
               ,A.DRIVER_NAME   /-- 운전기사명 --/
               ,A.DRIVER_TEL_NO /-- 운전기사전화번호 --/
               ,'' AS LOT_NO    /-- LOT번호 --/
               ,REPLACE(SUBSTR(CARASSIGN_REG_DATE,1,4)||'-'|| SUBSTR(CARASSIGN_REG_DATE,5,2)||'-'||SUBSTR(CARASSIGN_REG_DATE,7,2)
                 ||' '|| SUBSTR(CARASSIGN_REG_TIME,1,2)||':'||SUBSTR(CARASSIGN_REG_TIME,3,2)||':'||SUBSTR(CARASSIGN_REG_TIME,4,2)
                       ,'-- ::','') AS CARASSIGN_REG_DDTT /--배차일시--/
               ,REPLACE(SUBSTR(D.ENTGT_REQ_DDTT,1,4)||'-'|| SUBSTR(D.ENTGT_REQ_DDTT,5,2)||'-'||SUBSTR(D.ENTGT_REQ_DDTT,7,2)
                 ||' '|| SUBSTR(D.ENTGT_REQ_DDTT,9,2)||':'||SUBSTR(D.ENTGT_REQ_DDTT,11,2)||':'||SUBSTR(D.ENTGT_REQ_DDTT,13,2)
                       ,'-- ::','') AS ENTGT_ORDR_DDTT /-- 입문지시일시 --/
               ,REPLACE(SUBSTR(A.WAITLOC_ARR_DATE,1,4)||'-'|| SUBSTR(A.WAITLOC_ARR_DATE,5,2)||'-'||SUBSTR(A.WAITLOC_ARR_DATE,7,2)
                 ||' '|| SUBSTR(A.WAITLOC_ARR_TIME,1,2)||':'||SUBSTR(A.WAITLOC_ARR_TIME,3,2)||':'||SUBSTR(A.WAITLOC_ARR_TIME,4,2)
                       ,'-- ::','') AS WAITLOC_ARR_DDTT    /-- 대기장도착일시 --/
               ,TO_CHAR(B.YD_CARLD_ARR_DT, 'YYYY-MM-DD HH24:MI:SS')  AS BAYIN_DDTT  /-- 입동일시 --/
               ,TO_CHAR(B.YD_CARLD_ST_DT, 'YYYY-MM-DD HH24:MI:SS') AS CARLOAD_START_DDTT  /-- 상차개시일시 --/
               ,TO_CHAR(B.YD_CARLD_CMPL_DT, 'YYYY-MM-DD HH24:MI:SS') AS CARLOAD_DONE_DDTT /-- 상차완료일시 --/
               ,(
                SELECT MAX( REPLACE(SUBSTR(Z2.ISSUE_CHK_DATE,1,4)||'-'|| SUBSTR(Z2.ISSUE_CHK_DATE,5,2)||'-'||SUBSTR(Z2.ISSUE_CHK_DATE,7,2)
                                     ||' '|| SUBSTR(Z2.ISSUE_CHK_TIME,1,2)||':'||SUBSTR(Z2.ISSUE_CHK_TIME,3,2)||':'||SUBSTR(Z2.ISSUE_CHK_TIME,4,2)
                                           ,'-- ::','')
                             ) AS CHK_DONE_DDTT
                  FROM VW_LM_P_TRANSWORDCOMM Z2
                 WHERE Z2.TRANS_WORD_DATE = A.TRANS_WORD_DATE
                   AND Z2.TRANS_WORD_SEQNO = A.TRANS_WORD_SEQNO
                ) AS CHK_DONE_DDTT  /-- 검수완료일시 --/
                , B.YD_CAR_PROG_STAT
           FROM USRYDA.TB_YD_CARSCH B
                , PARAM P
                , ( SELECT -- FROM VW_LM_P_TRANSWORDCOMM A
                     WHERE A.TRANS_WORD_DATE    >= TO_CHAR(SYSDATE - 1, 'YYYYMMDD')
                       AND A.TRANS_WORD_DATE    <= TO_CHAR(SYSDATE, 'YYYYMMDD')
                       --AND A.LDTRN_CAR_STAT_CD IN ('R2','R3','R4', 'R5', 'R6', 'R7')
                       AND A.LDTRN_CAR_STAT_CD IN ('C0','D0','E0', 'E1', 'F0', 'G0')
                       AND A.DEL_YN(+) = 'N'
                  ) A
                , TB_LM_P_ENTGT_PLN_TIME_T D
          WHERE B.DEL_YN='N'
            AND B.CAR_NO  = P.TRN_EQP_CD
            AND B.TRANS_ORD_DATE = A.TRANS_WORD_DATE(+)
            AND B.TRANS_ORD_SEQNO = A.TRANS_WORD_SEQNO(+)
            AND B.TRANS_ORD_DATE = D.TRN_REQ_DATE(+)
            AND B.TRANS_ORD_SEQNO = D.TRN_REQ_SEQ(+)

        UNION

        --구내운송차량
        SELECT A.FRTOMOVE_WORD_NO   AS TRANS_WORD_DATE
              ,''                   AS TRANS_WORD_SEQNO
              ,''                   AS CMBN_CARLD_NO
              ,C.TRNSACT_LOC_KONM   AS TRANS_COM_NAME
              ,A.TRN_EQP_CD         AS CAR_NO
              ,C.OPRNER_NM          AS DRIVER_NAME
              ,C.TEL_NO             AS DRIVER_TEL_NO
              ,''                   AS LOT_NO
              , TO_CHAR(NVL(C.TRN_WRK_DMD_TT,A.YD_CARLD_PNT_WO_DT), 'YYYY-MM-DD HH24:MI:SS')  AS CARASSIGN_REG_DDTT        --운송작업요구시각(운송지시지각)
              , TO_CHAR(NVL(C.CARLD_PAP_LEV_TT ,A.YD_CARLD_LEV_DT), 'YYYY-MM-DD HH24:MI:SS')  AS ENTGT_ORDR_DDTT           --상차지출발시각
              , TO_CHAR(NVL(C.CARLD_ARR_WAIT_TT,A.YD_CARLD_LEV_DT), 'YYYY-MM-DD HH24:MI:SS')  AS WAITLOC_ARR_DDTT          --상차지대기도착시각
              , TO_CHAR(NVL(C.CARLD_PAP_ARR_TT,A.YD_CARLD_ARR_DT),  'YYYY-MM-DD HH24:MI:SS')  AS BAYIN_DDTT                --상차지도착시각
              , TO_CHAR(NVL(C.CARLD_ST_DT,  A.YD_CARLD_ST_DT),      'YYYY-MM-DD HH24:MI:SS')  AS CARLOAD_START_DDTT        --상차개시시각--
              , TO_CHAR(NVL(C.CARLD_CMPL_DT, A.YD_CARLD_CMPL_DT),   'YYYY-MM-DD HH24:MI:SS')  AS CARLOAD_DONE_DDTT         --상차완료시각--
              ,''                   AS CHK_DONE_DDTT
              , A.YD_CAR_PROG_STAT
          FROM PARAM P
              ,TB_YD_CARSCH A
              ,(SELECT Z.OPRNER_EMPNO
                      ,Z.TS_COM_CD
                      ,Z.TRN_EQP_CD
                      ,X.TRNSACT_LOC_KONM
                      ,V.OPRNER_NM
                      ,V.TEL_NO
                      ,Z.TRN_WRK_DMD_TT
                      ,Z.CARLD_PAP_LEV_TT
                      ,Z.CARLD_ARR_WAIT_TT
                      ,Z.CARLD_PAP_ARR_TT
                      ,Z.CARLD_ST_DT
                      ,Y.CARLD_CMPL_DT
                  FROM TB_TS_CAR_TRN_WR_TRACKING Z
                      ,TB_TS_MATL_TRN_CARLD_WR Y
                      ,TB_TS_TRNSACT_LOC X
                      ,TB_TS_OPRNER_RULL V
                      ,PARAM P
                 WHERE Z.TRN_EQP_CD = P.TRN_EQP_CD
                   AND Z.DEL_YN = 'N'
                   AND Z.TRN_WRK_DMD_TT = (SELECT MAX(Y.TRN_WRK_DMD_TT)
                                             FROM TB_TS_CAR_TRN_WR_TRACKING Y
                                            WHERE Y.TRN_EQP_CD = Z.TRN_EQP_CD
                                              AND Y.DEL_YN = 'N')
                   AND Z.TS_COM_CD = X.TS_COM_CD
                   AND Z.OPRNER_EMPNO = V.OPRNER_EMPNO
                   AND Z.TS_COM_CD = V.TS_COM_CD
                   AND Z.TRN_WO_ID = Y.TRN_WO_ID(+)
                   AND Z.TRN_WRK_PROG_SEQ = Y.TRN_WRK_PROG_SEQ(+)) C
         WHERE A.TRN_EQP_CD = P.TRN_EQP_CD
           AND A.TRN_EQp_CD = C.TRN_EQP_CD(+)
           AND A.DEL_YN = 'N'

        UNION
        --차량동간이적
        SELECT A.TRANS_ORD_DATE             AS TRANS_WORD_DATE
              ,TO_CHAR(A.TRANS_ORD_SEQNO)   AS TRANS_WORD_SEQNO
              ,''                           AS CMBN_CARLD_NO
              ,''                           AS TRANS_COM_NAME
              ,'[차량동간]'|| A.CAR_NO          AS CAR_NO
              ,''                           AS DRIVER_NAME
              ,''                           AS DRIVER_TEL_NO
              ,''                           AS LOT_NO
              , TO_CHAR(A.YD_CARLD_PNT_WO_DT,   'YYYY-MM-DD HH24:MI:SS')  AS CARASSIGN_REG_DDTT    --운송작업요구시각(운송지시지각)
              , TO_CHAR(A.YD_CARLD_LEV_DT ,     'YYYY-MM-DD HH24:MI:SS')  AS ENTGT_ORDR_DDTT        --상차지출발시각
              , TO_CHAR(A.YD_CARLD_LEV_DT,      'YYYY-MM-DD HH24:MI:SS')  AS WAITLOC_ARR_DDTT       --상차지대기도착시각
              , TO_CHAR(A.YD_CARLD_ARR_DT,      'YYYY-MM-DD HH24:MI:SS')  AS BAYIN_DDTT             --상차지도착시각
              , TO_CHAR(A.YD_CARLD_ST_DT,       'YYYY-MM-DD HH24:MI:SS')  AS CARLOAD_START_DDTT     --상차개시시각
              , TO_CHAR(A.YD_CARLD_CMPL_DT,     'YYYY-MM-DD HH24:MI:SS')  AS CARLOAD_DONE_DDTT      --상차완료시각
              ,''                                   AS CHK_DONE_DDTT
              , A.YD_CAR_PROG_STAT
          FROM PARAM P
              ,TB_YD_CARSCH A
         WHERE A.CAR_NO = P.TRN_EQP_CD
           AND A.DEL_YN = 'N'
           AND A.CAR_NO IN ('9990','9991', '9992', '9993', '9994')
) T
 </pre> */
public final static String getCoilCarInfo = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilCarldInfoInqjl.getCoilCarInfo_PIDEV";

