 /** <pre> 2020-01-03
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getAcoilEqpIdMaintHistInqjl
-- 야드설비정비이력조회
SELECT 
        BASE_DATA.*
  FROM
        (
         SELECT --+ ALL_ROWS 
                ROWNUM AS RNUM
                ,BASE_DATA_ALL.*
           FROM 
               (
                SELECT
                        A.YD_EQP_ID,    
                        A.YD_EQP_PAUSE_OCCR_SEQ, --휴지 발생순서
                        B.YD_EQP_NAME,
                        TO_CHAR(A.YD_EQP_PAUSE_OCC_DT,'YYYY.MM.DD HH24:MI:SS') AS YD_EQP_PAUSE_OCC_DT, --휴지 발생일시
                        TO_CHAR(A.YD_EQP_PAUSE_END_DT,'YYYY.MM.DD HH24:MI:SS') AS YD_EQP_PAUSE_END_DT, --휴지 종료일시
                          CASE A.YD_EQP_PAUSE_CODE
                            WHEN '0001' THEN '경미한작업불가'
                            WHEN '0002' THEN '치명적작업불가'
                            WHEN '0003'THEN '정기휴지'
                            ELSE '정상상태' --END
                        END AS YD_EQP_PAUSE_CODE,
                        DECODE(B.YD_EQP_PROG_STAT,'B','고장','정상') AS YD_EQP_PROG_STAT,
                        A.REGISTER,
                        A.YD_EQP_PAUSE_RCVR_CNTS, --휴지복구내용
                        COUNT(*) OVER() AS TOTALCOUNT
                  FROM TB_YF_EQPPAUSE A, TB_YF_EQP B
                 WHERE A.YD_EQP_ID LIKE :V_YD_GP||'%' -- 박판열연(1)
                   AND A.YD_EQP_ID = B.YD_EQP_ID
                   AND B.YD_EQP_ID LIKE '%'||:V_YD_EQP_ID||'%' -- 설비종류코드(CR)
                   AND A.YD_EQP_PAUSE_OCC_DT BETWEEN TO_DATE(TO_CHAR(:V_DATE_FROM)||'000000', 'YYYYMMDDHH24MISS') 
                                                 AND TO_DATE(TO_CHAR(:V_DATE_TO)||'235959', 'YYYYMMDDHH24MISS') --야드설비휴지발생일시
                 ORDER BY A.YD_EQP_PAUSE_OCC_DT DESC
                ) BASE_DATA_ALL
          WHERE ROWNUM  <= :V_PAGE_NO * :V_PAGE_SIZE
        ) BASE_DATA
WHERE RNUM >= ((:V_PAGE_NO -1) * :V_PAGE_SIZE ) + 1
 </pre> */
public final static String getAcoilEqpIdMaintHistInqjl = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAcoilEqpIdMaintHistInqjl";

