 /** <pre> 2020-03-20
--com.inisteel.cim.yf.common.dao.YfCommDAO.getUsableBedList
--사용가능한 Bed
WITH PARAM AS
(
    SELECT
        :V_YD_STK_COL_GP AS P_YD_STK_COL_GP
       ,:V_YD_STK_LYR_NO AS P_YD_STK_LYR_NO
    FROM
        DUAL
)
SELECT
    YD_STK_BED_NO AS CD_VAL,
    YD_STK_BED_NO AS CD_NM
FROM
    TB_YF_STKLYR,
    PARAM
WHERE 1=1
AND YD_STK_COL_GP = P_YD_STK_COL_GP --야드,동,스판,열
AND YD_STK_LYR_NO LIKE NVL(P_YD_STK_LYR_NO,'%')
AND YD_STK_LYR_ACTIVE_STAT = 'E'
AND YD_STK_LYR_STAT = 'E'
AND DEL_YN = 'N'
AND YD_STK_BED_NO NOT IN('00')
AND YD_STK_COL_GP LIKE '1%'

UNION

SELECT
    YD_STK_BED_NO AS CD_VAL,
    YD_STK_BED_NO AS CD_NM
FROM
    TB_YF_STKLYR,
    PARAM
WHERE 1=1
AND YD_STK_COL_GP = P_YD_STK_COL_GP --야드,동,스판,열
AND YD_STK_LYR_NO LIKE NVL(P_YD_STK_LYR_NO,'%')
AND YD_STK_LYR_ACTIVE_STAT IN ('E', 'C')
AND YD_STK_LYR_STAT = 'E'
AND DEL_YN = 'N'
AND YD_STK_BED_NO NOT IN ('00')
AND YD_STK_COL_GP LIKE '1%'
GROUP BY YD_STK_BED_NO
 </pre> */
