 /** <pre> 2020-07-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCarPntFrmYn2_PIDEV
SELECT
    MAX
    (
        CASE
        WHEN SL.YD_STK_LYR_NO = '01' AND
        (
            SELECT
                COUNT(*)
            FROM
                TB_YF_STKLYR
            WHERE 1=1
            AND YD_STK_COL_GP   = SL.YD_STK_COL_GP
            AND YD_STK_BED_NO   IN (SL.YD_STK_BED_NO, LPAD(TO_NUMBER(SL.YD_STK_BED_NO) - 1, 2, '0'))
            AND YD_STK_LYR_NO   = '02'
            AND STL_NO IS NOT NULL
        ) > 0 THEN 'Y'
        ELSE 'N'
        END
    ) AS DUMMY_YN
FROM
    (
        SELECT
            TRN_EQP_CD,
            CAR_NO,
            YD_STK_COL_GP
        FROM
            USRYDA.TB_YD_CARPOINT
        WHERE 1=1
        AND YD_CARPNT_CD LIKE '1%'
        AND YD_STK_COL_GP = :V_YD_STK_COL_GP
    ) CP,
    TB_YF_WRKBOOK WB,
    TB_YF_WRKBOOKMTL WM,
    TB_YF_STKLYR SL
WHERE 1=1
AND
(
    (WB.YD_CAR_USE_GP = 'L' AND WB.TRN_EQP_CD = CP.TRN_EQP_CD)
    OR
    (WB.YD_CAR_USE_GP = 'G' AND WB.CAR_NO = CP.CAR_NO)
)
AND WB.DEL_YN       = 'N'
AND WB.YD_WBOOK_ID  = WM.YD_WBOOK_ID
AND SL.STL_NO       = WM.STL_NO
AND SL.YD_STK_LYR_STAT || '' IN ('C','U')
 </pre> */
public final static String getCarPntFrmYn2 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCarPntFrmYn2_PIDEV";

 /** <pre> 2020-01-17
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListStackCol2
SELECT A.YD_STK_COL_GP
      ,DECODE(E.YD_EQP_GP, 'TC', 'CTS '||E.YD_EQP_NO||'호기',
                           'SL', E.YD_BAY_GP||'동 좌측'||E.YD_EQP_NO||'열',
                           'SR', E.YD_BAY_GP||'동 우측'||E.YD_EQP_NO||'열',
                           '.T.') || '(' || E.YD_EQP_GP || ')' AS YD_STK_COL_GP_NM
      ,A.YD_STK_COL_USAGE_CD
      ,A.YD_GP
      ,B.STL_NO
      ,A.STOCK_ITEM
      ,B.YD_STK_LYR_ACTIVE_STAT
      ,B.YD_STK_LYR_STAT
      ,CASE WHEN YD_STK_LYR_ACTIVE_STAT = 'E' 
            THEN 
                CASE 
                    WHEN C.YD_CARLD_WO_LOC = B.YD_STK_COL_GP THEN 'N'
                    WHEN C.YD_CARUD_WO_LOC = B.YD_STK_COL_GP THEN 'N'
                ELSE 'Y' END 
       ELSE 'N' END AS SLT_ABLE_YN
      ,C.YD_CARLD_WO_LOC -- 상차지시
      ,C.YD_CARUD_WO_LOC -- 상차지시
      ,CASE 
            WHEN A.YD_STK_COL_GP = C.YD_CARLD_WO_LOC THEN 'LM' 
            WHEN A.YD_STK_COL_GP = C.YD_CARUD_WO_LOC THEN 'UM'
       ELSE '' END  CARLD_TYPE
  FROM TB_YF_STKCOL A
     , TB_YF_STKLYR B
     , TB_YF_CTS_SCH C
     , TB_YF_EQP E
 WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
   AND A.YD_STK_COL_GP = E.YD_EQP_ID
   AND B.STL_NO = C.STL_NO(+)
   AND A.YD_GP = :V_YD_GP   --야드구분(1)
   AND A.BAY_GP LIKE :V_BAY_GP  --동구분(A)
   AND A.SECT_GP LIKE :V_SECT_GP ||'%'  --SPAN구분(01)
   AND A.DEL_YN = 'N'
   AND B.DEL_YN = 'N'
   AND C.DEL_YN(+) = 'N'
 ORDER BY YD_STK_COL_GP
 </pre> */
public final static String getListStackCol2 = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListStackCol2";

