 /** <pre> 2020-12-16
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYfRuleMgt 
SELECT
    T.*
FROM
(
SELECT
    REPR_CD_GP,
    CD_GP,
    ITEM,
    REPR_CD_CONTENTS,
    CASE REPR_CD_GP 
        WHEN 'YF0005' THEN (SELECT S.REPR_CD_CONTENTS FROM TB_YF_RULE S  WHERE S.REPR_CD_GP = 'YM6001' AND S.CD_GP = '1' AND S.ITEM = t.ITEM ) 
    ELSE ITEM
    END AS ITEM_NM,
    REGISTER,
    REG_DDTT,
    MODIFIER,
    TO_CHAR(MOD_DDTT, 'YYYY/MM/DD HH24:MI:SS') AS MOD_DDTT,
    DEL_YN,
    ITEM1,
    ITEM_VALUE1,
    ITEM2,
    ITEM_VALUE2,
    DTL_ITEM1,
    DTL_ITEM2,
    DTL_ITEM3,
    DTL_ITEM4,
    DTL_ITEM5,
    DTL_ITEM6,
    DTL_ITEM7,
    DTL_ITEM8,
    DTL_ITEM9,
    DTL_ITEM10
FROM TB_YF_RULE t
WHERE REPR_CD_GP = :V_REPR_CD_GP
AND CD_GP LIKE NVL(:V_CD_GP, CD_GP) || '%'
AND DEL_YN = 'N'
ORDER BY CASE REPR_CD_GP  WHEN 'YF0005' THEN SUBSTR(CD_GP,2,1) ELSE CD_GP END,
         CASE REPR_CD_GP  WHEN 'YF0005' THEN SUBSTR(CD_GP,1,1) ELSE CD_GP END,
         ITEM
) T
WHERE  '1' = CASE WHEN T.REPR_CD_GP = 'YM6001' AND T.ITEM = 'ZZ' THEN '0' ELSE '1' END
 </pre> */
public final static String getYfRuleMgt = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYfRuleMgt";

