 /** <pre> 2021-02-04
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchAxYML007_2
SELECT A.*
  FROM
       (
         SELECT CS.YD_CRN_SCH_ID
              , CS.YD_WRK_PROG_STAT
              , CS.YD_UP_WO_LOC 
              , CS.YD_DN_WO_LOC 
              , CS.YD_SCH_CD              
              , CM.YD_AID_WRK_YN
              , CAR_FRM_GP
              , CS.YD_SCH_PRIOR
              , CS.YD_WBOOK_ID
              , CS.YD_UP_WO_LOC_XAXIS 
              , CM.STL_NO

           FROM TB_YF_CRNSCH CS
              , TB_YF_CRNWRKMTL CM
              , TB_YF_WRKBOOK WB
              , USRYDA.TB_YD_CARPOINT CP
          WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
            AND CS.YD_WBOOK_ID   = WB.YD_WBOOK_ID
            AND CP.YD_STK_COL_GP(+) = CASE WHEN CS.YD_SCH_CD LIKE '%PT__U%' THEN SUBSTR(CS.YD_DN_WO_LOC,1,6)
                                           WHEN CS.YD_SCH_CD LIKE '%PT__L%' THEN SUBSTR(CS.YD_UP_WO_LOC,1,6)
                                           END
            AND '1' = CASE WHEN NVL(CP.YD_FRM_YN,'N') = 'Y' AND NVL(WB.CAR_FRM_GP,'N') = 'Y' THEN '1' --형상있는데, 했으면 1
                           WHEN NVL(CP.YD_FRM_YN,'N') = 'Y' AND NVL(WB.CAR_FRM_GP,'N') = 'N' THEN '2' --형상있는데, 안했으면 2
                           ELSE '1'                                                                   --형상없으면 1
                           END
            AND CS.DEL_YN = 'N'
            AND CM.DEL_YN = 'N'
            AND WB.DEL_YN = 'N'
            AND CP.DEL_YN(+) = 'N' 
            
            AND CS.YD_EQP_ID =  :V_YD_EQP_ID 
            --AND WB.YD_WBOOK_ID LIKE :V_YD_WBOOK_ID||'%' 
            AND CS.YD_UP_WO_LOC_XAXIS IS NOT NULL   --// 물리적 좌표가 들어간 경우
                         
          ORDER BY CASE WHEN CS.YD_WRK_PROG_STAT = 'W' THEN '0'
                        WHEN CS.YD_WRK_PROG_STAT = 'S' THEN '1'
                        ELSE CS.YD_WRK_PROG_STAT END DESC   --작업상태
                 --차량 연속 작업이면
--                 , CASE WHEN CS.YD_SCH_PRIOR = 0 THEN 0
--                        WHEN WB.CAR_FRM_GP = 'Y' AND CS.YD_SCH_CD LIKE '1_PT%' THEN 1 
--                        ELSE 2 END 
                 , CS.YD_SCH_PRIOR
                 , CASE WHEN WB.YD_SCH_CD LIKE '1_PT3%' THEN 0
                        ELSE TO_NUMBER(CS.YD_WBOOK_ID)  END
                 , TO_NUMBER(YD_CRN_SCH_ID) 
       ) A   
WHERE ROWNUM = 1  
 </pre> */
public final static String getCrnSchAxYML007_2 = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchAxYML007_2";

 /** <pre> 2020-10-15
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.tsinfo.getListAimBay_ACoil3
SELECT
    SUBSTR(C.YD_STK_COL_GP, 2, 1) AS DEST_BAY,
    COUNT(*) AS CT
FROM
    (
        SELECT
            ITEM
        FROM
            TB_YF_RULE
        WHERE 1=1
        AND REPR_CD_GP = 'YF0010'   --저장위치 용도관리
        AND DTL_ITEM1 = 'HR'        --CR : 냉연, HR : 열연, * : 사용안함, - : 사용불가
        AND DTL_ITEM2 = 'Y'         --사용함 : Y, 사용안함 : N
        AND DEL_YN = 'N'
    ) A,
    TB_YD_CARPOINT B,
    TB_YF_STKLYR C
WHERE 1=1
AND B.YD_GP = SUBSTR(A.ITEM, 1, 1)
AND B.YD_BAY_GP = SUBSTR(A.ITEM, 2, 1)
AND SUBSTR(A.ITEM, 3, 2) BETWEEN B.YD_SPAN_FROM AND B.YD_SPAN_TO
AND B.YD_CAR_USETYPE_GP IN ('GT', 'TO')
AND B.DEL_YN = 'N'
AND B.TRN_EQP_CD IS NULL
AND B.CAR_NO IS NULL
AND B.CARD_NO IS NULL
AND SUBSTR(C.YD_STK_COL_GP, 1, 4) = A.ITEM
AND C.DEL_YN = 'N'
AND C.STL_NO IS NULL
AND C.YD_STK_LYR_ACTIVE_STAT = 'E' --적치가능
GROUP BY SUBSTR(C.YD_STK_COL_GP, 2, 1)
ORDER BY 2 DESC, 1
 </pre> */
