 /** <pre> 2020-03-18
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockLocHistory  
SELECT ROWNUM AS SEQ
     , A.*
  FROM (
       SELECT
              STL_NO
            , MOD_DDTT
            , MODIFIER
            , SCH_NAME
            , FR_YD
            , TO_YD
            , FR_WR_LOC
            , TO_WR_LOC
            , YD_WRK_CRN
            , YD_GP
            , CRANE_WRSLT_ID
            , YD_AID_WRK_YN
            , NVL(CASE YD_UP_WRK_MODE2 
                    WHEN 'M' THEN '유인'
                    WHEN 'R' THEN '리모컨'
                    WHEN 'A' THEN '자동'
                    WHEN 'H' THEN 'HMI'
              ELSE
                NVL(YD_UP_WRK_MODE2  ,'-')
              END,'-') AS YD_UP_WRK_MODE2  
            , CASE YD_DN_WRK_MODE2 
                    WHEN 'M' THEN '유인'
                    WHEN 'R' THEN '리모컨'
                    WHEN 'A' THEN '자동'
                    WHEN 'H' THEN 'HMI'
              ELSE
                NVL(YD_DN_WRK_MODE2 ,'-')
              END AS YD_DN_WRK_MODE2 
            , YD_WRK_HIST_ID
            , REG_DDTT
            , YD_GNT_GP
            , SPOS_WLOC_CD
            , ARR_WLOC_CD
            , YD_AIM_RT_GP
            , YD_SCH_CD
            , YD_WORD_DT  
            , CASE YD_SCH_CD
                WHEN '1X9999' THEN 'Y'
              ELSE CASE WHEN TO_WO_LOC = TO_WR_LOC THEN 'N' ELSE 'Y' END 
              END AS DN_CHG_YN
       FROM VW_YD_WRKHIST T
       WHERE T.STL_NO = :V_STL_NO
       ORDER BY MOD_DDTT DESC , YD_WRK_HIST_ID DESC
      ) A
 </pre> */
public final static String getStockLocHistory = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockLocHistory";

