 /** <pre> 2020-06-15
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getLineOffTargets2
WITH TB AS
(

    SELECT RANK() OVER(ORDER BY LINE_OFF_SEQ
                               ,CASE WHEN DC_TKIN_FR_STL_NO IS NULL     THEN STL_NO
                                     WHEN DC_TKIN_FR_STL_NO IS NOT NULL THEN DC_TKIN_FR_STL_NO||'Z'
                                END) AS RNK
          ,A.* 
    FROM TB_YF_STOCK A
    WHERE A.DEL_YN        = 'N'
      AND A.LINE_OFF_YN   = 'N'
     
)
SELECT B.*
FROM TB A, TB B
WHERE A.STL_NO = :V_DTL_ITEM2
  AND A.RNK <= B.RNK
ORDER BY B.RNK 
 </pre> */
