 /** <pre> 2020-09-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getselectStackColGp1
--YD_STK_COL_GP(적치열:첫번째자리 야드구분, 두번째 자리 동구분), YD_STK_LYR_STAT(적치단 상태 L:적치중)
SELECT
    YD_STK_COL_GP,
    SUBSTR(YD_STK_COL_GP, 1, 1) AS YD_STK_COL_GP1,
    SUBSTR(YD_STK_COL_GP, 2, 1) AS YD_STK_COL_GP2,
    YD_STK_BED_NO,
    YD_STK_LYR_STAT,
    YD_STK_LYR_NO,
    NVL((SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP022' AND ROWNUM = 1), 'N') AS APP022_YN,
    (
        CASE
        WHEN
        (
            --정정 실적 처리된 항목 중 최근 실적이 재작업인 경우 추출.
            SELECT
                COUNT(*)
            FROM
                TB_HR_C_SHEARWOWR SR
            WHERE 1=1
            AND SR.STEP_NO =
            (
                SELECT --+ INDEX_DESC(A PK_HR_C_SHEARWOWR)
                    MAX(STEP_NO)
                FROM
                    TB_HR_C_SHEARWOWR A
                WHERE 1=1
                AND COIL_NO = SR.COIL_NO
                AND WORK_STAT = '*'
                AND ROWNUM<=1
            )
            AND SR.COIL_NO = A.STL_NO
            AND SR.RECEIPT_HOLD_SCRAP_CAUSE_GP IN ('J', 'Q')
        ) = 1 THEN 'J'
        WHEN
        (
            SELECT
                COUNT(*)
            FROM
                VW_YF_COILCOMM B
            WHERE 1=1
            AND B.COIL_NO = A.STL_NO
            AND ((B.REMAIN_PROC1='1K' AND B.REMAIN_PROC2='1Q') OR B.REMAIN_PROC1='1Q')
        ) = 1 THEN 'Q'
        WHEN
        (
            SELECT
                COUNT(*)
            FROM
                VW_YF_COILCOMM B
            WHERE 1=1
            AND B.COIL_NO = A.STL_NO
            AND B.CURR_PROG_CD = 'F'    --진도코드 : 'F' (판정보류)
            AND B.HOLD_CAUSE_CD = '43'
        ) = 1 THEN '43'
        ELSE 'X' END
    ) AS CHK
FROM
    TB_YF_STKLYR A
WHERE 1=1
AND STL_NO = :V_STL_NO
 </pre> */
public final static String getselectStackColGp1 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getselectStackColGp1";

