 /** <pre> 2020-05-28
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.checkDcCnvyrByStl 
WITH SEARCH_KEY AS (
    SELECT
        :V_STL_NO AS V_STL_NO
        , :V_BIZ_GP AS V_BIZ_GP
    FROM DUAL
)
SELECT
    T.MSG
FROM 
(
 -- 생성되기 때문에 로직 체크는 필요하지 않음 
    
    SELECT '저장품정보(Stock)이 존재하지 않습니다.'  AS MSG
    FROM TB_YF_STOCK S, SEARCH_KEY K
    WHERE S.STL_NO = K.V_STL_NO
    AND S.DEL_YN = 'N'
    AND K.V_BIZ_GP = 'I' -- TAKE IN이 아닐때만 체크하자
    UNION ALL
    SELECT
        '야드에 적치된 코일만 Take In 처리를 할 수 있습니다.' AS MSG
    FROM TB_YF_STKLYR A, TB_YF_STKCOL B, SEARCH_KEY K
    WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
    AND A.STL_NO = K.V_STL_NO
    AND B.SECT_GP BETWEEN '00' AND '99'
    AND K.V_BIZ_GP = 'I' -- TAKE IN이 아닐때만 체크하자
    UNION ALL
    SELECT
        '야드에 적치된 코일입니다. 코일번호를 확인하세요' AS MSG
    FROM TB_YF_STKLYR A, TB_YF_STKCOL B, SEARCH_KEY K
    WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
    AND A.STL_NO = K.V_STL_NO
    AND B.SECT_GP BETWEEN '00' AND '99'
    AND K.V_BIZ_GP <> 'I' -- TAKE IN이 아닐때만 체크하자
    UNION ALL
    SELECT
        '작업예약이 등록되어 있는 재료입니다.'
    FROM TB_YF_WRKBOOKMTL M1, TB_YF_WRKBOOK M, SEARCH_KEY K
    WHERE M1.YD_WBOOK_ID = M.YD_WBOOK_ID 
    AND M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N'
    AND M.DEL_YN = 'N'
    AND NOT EXISTS (
        SELECT
            1
        FROM TB_YF_CRNSCH S
        WHERE S.YD_WBOOK_ID = M1.YD_WBOOK_ID
        AND S.DEL_YN = 'N'
        UNION ALL
        SELECT
            1
        FROM TB_YF_CTS_SCH S
        WHERE S.STL_NO = M1.STL_NO
        AND S.DEL_YN = 'N'
    )
    UNION ALL
    SELECT
        '크레인스케쥴이 예약되어 있는 재료입니다.'
    FROM TB_YF_CRNWRKMTL M1, TB_YF_CRNSCH M, SEARCH_KEY K
    WHERE M1.YD_CRN_SCH_ID = M.YD_CRN_SCH_ID 
    AND M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N'
    AND M.DEL_YN = 'N'
    UNION ALL
    SELECT
        'CTS 작업이 예약되어 있는 재료입니다.'
    FROM TB_YF_CTS_SCH M1, SEARCH_KEY K
    WHERE  M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N'
    UNION ALL
    SELECT
        CASE M1.PROC_GP 
            WHEN 'F' THEN 'HFL'
            WHEN 'K' THEN 'SPM'
            WHEN 'Q' THEN 'EQL'
        END  || '의 설비에 있는 재료입니다.'
    FROM TB_YF_EQPTRACKING M1, SEARCH_KEY K
    WHERE  M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N' 
    AND M1.PROC_GP IN ('K', 'Q', 'F')
) T 
 </pre> */
public final static String checkDcCnvyrByStl = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.checkDcCnvyrByStl";

