 /** <pre> 2020-06-19
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getLineOffTargets
WITH TB AS
(
    SELECT RANK() OVER(ORDER BY LINE_OFF_SEQ
                               ,CASE WHEN DC_TKIN_FR_STL_NO IS NULL     THEN STL_NO
                                     WHEN DC_TKIN_FR_STL_NO IS NOT NULL THEN DC_TKIN_FR_STL_NO||'Z'
                                END) AS RNK
          ,A.* 
    FROM TB_YF_STOCK A
    WHERE A.DEL_YN        = 'N'
      AND (A.LINE_OFF_YN   = 'N' 
          OR
          A.STL_NO        = :V_DTL_ITEM2 --턴테이블 고장 코일은 LINE OFF될수있음
          )
)
SELECT B.*
FROM (SELECT NVL(MAX(RNK),999) AS RNK
        FROM TB 
       WHERE STL_NO = :V_DTL_ITEM2 
     ) A
    ,TB B
WHERE A.RNK > B.RNK 
ORDER BY B.RNK 
 </pre> */
