 /** <pre> 2021-02-23
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarDirectInfo
WITH PARAM AS (
SELECT :V_YD_GP AS YD_GP
      ,:V_FR_BAY_GP AS FR_BAY_GP
      ,:V_TO_BAY_GP AS TO_BAY_GP
  FROM DUAL
)

SELECT CASE
       WHEN FR_DIRECT = '1' AND TO_DIRECT = '2' THEN '1'
       WHEN FR_DIRECT = '1' AND TO_DIRECT = '1' THEN '2'
       WHEN FR_DIRECT = '2' AND TO_DIRECT = '1' THEN '3'
       WHEN FR_DIRECT = '2' AND TO_DIRECT = '2' THEN '4'
        END AS CD_VAL
      , DECODE(FR_DIRECT,'1','1통로','2통로') || ' -> ' || DECODE(TO_DIRECT,'1','1통로','2통로') AS CD_NM
  FROM (SELECT DISTINCT
               CASE 
               WHEN SUBSTR(YD_CARPNT_CD,2,1) = '1' THEN '1'
               --WHEN SUBSTR(YD_CARPNT_CD,2,1) = '2' AND YD_BAY_GP = 'H' THEN '1'
               ELSE '2'
           END AS FR_DIRECT
          FROM TB_YD_CARPOINT A
              ,PARAM P
         WHERE A.DEL_YN     = 'N'
           AND A.YD_CAR_USETYPE_GP = 'MT'
           AND A.YD_GP      = P.YD_GP
           AND A.YD_BAY_GP  = P.FR_BAY_GP) A
      ,(SELECT DISTINCT
               CASE 
               WHEN SUBSTR(YD_CARPNT_CD,2,1) = '1' THEN '1'
               --WHEN SUBSTR(YD_CARPNT_CD,2,1) = '2' AND YD_BAY_GP = 'H' THEN '1'
               ELSE '2'
           END AS TO_DIRECT
          FROM TB_YD_CARPOINT A
              ,PARAM P
         WHERE A.DEL_YN     = 'N'
           AND A.YD_CAR_USETYPE_GP = 'MT'
           AND A.YD_GP      = P.YD_GP
           AND A.YD_BAY_GP != P.FR_BAY_GP
           AND A.YD_BAY_GP  = NVL(P.TO_BAY_GP,A.YD_BAY_GP)) B
 </pre> */
public final static String getCarDirectInfo = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarDirectInfo";

 /** <pre> 2020-09-14
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjlSub2  
SELECT
    ROWNUM AS SEQ 
    , TT.*
FROM
(
    SELECT DISTINCT T.STL_NO
        , T.STK_POS
        , T.CURR_PROG_CD
        , T.COIL_SIZE
        , T.NET_WEIGH_WT
        , T.COIL_OUTDIA
        , T.YD_STK_LYR_STAT
    FROM
    (
    --
        SELECT M2.STL_NO
            , SUBSTR(M2.YD_STK_COL_GP,2,5) ||SUBSTR(M2.YD_STK_LYR_NO,3,1)|| M2.YD_STK_BED_NO AS STK_POS 
            , B.CURR_PROG_CD
            , TO_CHAR(B.COIL_T,'99,999.00')  || ' X ' || TO_CHAR(B.COIL_W,'99,999')  AS COIL_SIZE
            , B.NET_WEIGH_WT
            , B.COIL_OUTDIA
            , 'S' AS YD_STK_LYR_STAT -- 상차대기
        FROM TB_YF_WRKBOOK M
            , TB_YF_WRKBOOKMTL M2
            , VW_YF_COILCOMM B  
        WHERE M.YD_WBOOK_ID = M2.YD_WBOOK_ID
        AND M2.STL_NO=B.COIL_NO  
        AND M2.DEL_YN = 'N'
        AND M.DEL_YN = 'N'
        AND M.YD_WRK_PLAN_TCAR = '1XTC03'
        AND NOT EXISTS (
            SELECT 1
            FROM TB_YF_CRNSCH S
                 , TB_YF_CRNWRKMTL S1
            WHERE S.YD_CRN_SCH_ID = S1.YD_CRN_SCH_ID
            AND S1.STL_NO = M2.STL_NO
            AND S.DEL_YN = 'N'
            AND S1.DEL_YN = 'N'
        )
        AND NOT EXISTS (
            SELECT 1
            FROM  TB_YF_TCARFTMVMTL T
            WHERE T.STL_NO = M2.STL_NO
            AND T.DEL_YN = 'N' 
        )
    
    UNION
    
        SELECT
           TCAR.STL_NO, TCAR.STK_POS, TCAR.CURR_PROG_CD, TCAR.COIL_SIZE, TCAR.NET_WEIGH_WT, TCAR.COIL_OUTDIA 
           , CASE 
                WHEN TCAR.YD_CURR_BAY_GP = SUBSTR(STK_POS,1,1) OR TCAR.YD_STK_LYR_STAT = 'M' THEN  TCAR.YD_STK_LYR_STAT 
            ELSE 'S' END AS  YD_STK_LYR_STAT
        FROM
        (
            SELECT T.STL_NO
                , SUBSTR(L.YD_STK_COL_GP,2,1) || 'TC' ||SUBSTR(T.YD_STK_LYR_NO,3,1)|| T.YD_STK_BED_NO AS STK_POS 
                , B.CURR_PROG_CD
                , TO_CHAR(B.COIL_T,'99,999.00')  || ' X ' || TO_CHAR(B.COIL_W,'99,999')  AS COIL_SIZE
                , B.NET_WEIGH_WT
                , B.COIL_OUTDIA
                , NVL(( 
                    SELECT S.YD_STK_LYR_STAT
                    FROM TB_YF_STKLYR S 
                    WHERE S.STL_NO = T.STL_NO
                    AND S.YD_STK_COL_GP LIKE '1_TC03%'
                   ),'M') AS YD_STK_LYR_STAT
                , E.YD_CURR_BAY_GP
            FROM   TB_YF_TCARSCH TS 
                , TB_YF_TCARFTMVMTL T
                , VW_YF_COILCOMM B
                , TB_YF_STKLYR L
                , TB_YF_EQP E
            WHERE TS.YD_TCAR_SCH_ID = T.YD_TCAR_SCH_ID 
            AND T.STL_NO = B.COIL_NO 
            AND TS.YD_EQP_ID = E.YD_EQP_ID
            AND T.STL_NO = L.STL_NO(+)
            AND T.YD_STK_BED_NO = L.YD_STK_BED_NO(+)
            AND T.YD_STK_LYR_NO = L.YD_STK_LYR_NO(+)
            AND TS.YD_TCAR_SCH_ID = :V_YD_TCAR_SCH_ID
            AND T.DEL_YN = 'N'
        ) TCAR
    ) T
    ORDER BY CASE WHEN ( SELECT YD_CURR_BAY_GP FROM TB_YF_EQP WHERE YD_EQP_ID = '1XTC03') = SUBSTR(T.STK_POS,1,1) THEN 1 ELSE 999 END, SUBSTR(T.STK_POS,2,4) ASC
) TT  
 </pre> */
public final static String getacoilTcarWrkStatInqjlSub2 = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjlSub2";

 /** <pre> 2020-06-05
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L021BackUp
WITH PARAM AS (
    SELECT :V_VER_ID AS VER_ID
      FROM DUAL
)

SELECT 'YFF1L021' AS JMS_TC_CD
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT
      ,'YFF1L021'
      || TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')
      || 'I'
      || '0026'
      || RPAD(' ',29,' ')
      || YD_STK_COL_GP
      || RPAD(SUBSTR(YD_ZONE_GP,1,1),1,' ')
      || RPAD(CASE YD_ZONE_GP
         WHEN 'AZ' THEN 'FF9DFF'
         WHEN 'BZ' THEN 'AFFFEE'
         WHEN 'CZ' THEN '82F987'
         WHEN 'DZ' THEN 'FF8C8C'
         WHEN 'EZ' THEN 'FFE846'
         WHEN 'GZ' THEN '74D190'
         WHEN 'HZ' THEN '64AAFF'
         ELSE 'BBBBBB'
         END,10,' ')
      || RPAD(' ',9,' ') AS JMS_TC_MESSAGE
  FROM (
        SELECT SUBSTR(A.YD_STK_COL_GP,0,4) || '01' AS YD_STK_COL_GP, NVL(MIN(A.YD_ZONE_GP),'  ') AS YD_ZONE_GP
        FROM TB_YF_STKCOL A, PARAM P
        WHERE A.YD_STK_COL_GP LIKE '1%'
        AND A.SECT_GP BETWEEN '00' AND '99'
        AND A.BAY_GP <> 'X'
        AND A.DEL_YN = 'N'
        GROUP BY SUBSTR(A.YD_STK_COL_GP,0,4)
        ORDER BY 1
  --
        SELECT YD_STK_COL_GP
              ,YD_ZONE_GP
          FROM TB_YF_SCHLOCSRCH_ZONE_V A
              ,PARAM P
         WHERE A.VER_ID = P.VER_ID
           AND A.DEL_YN = 'N'
         UNION
        SELECT A.YD_STK_COL_GP
              ,'NN' AS YD_ZONE_GP
          FROM TB_YF_SCHLOCSRCH_ZONE A
         WHERE A.DEL_YN = 'N'
           AND A.YD_STK_COL_GP NOT IN (SELECT YD_STK_COL_GP
                                         FROM TB_YF_SCHLOCSRCH_ZONE_V Z
                                             ,PARAM P
                                        WHERE Z.VER_ID = P.VER_ID
                                          AND Z.DEL_YN = 'N')
 
     )
 </pre> */
public final static String getYFF1L021BackUp = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L021BackUp";

 /** <pre> 2020-11-24
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStrlocUsgSetList  
SELECT   BAY_GP  
        ,MIN(CASE SECT_GP WHEN '16' THEN DTL_ITEM1  END) AS SP16 
        ,MIN(CASE SECT_GP WHEN '15' THEN DTL_ITEM1  END) AS SP15 
        ,MIN(CASE SECT_GP WHEN '14' THEN DTL_ITEM1  END) AS SP14 
        ,MIN(CASE SECT_GP WHEN '13' THEN DTL_ITEM1  END) AS SP13 
        ,MIN(CASE SECT_GP WHEN '12' THEN DTL_ITEM1  END) AS SP12
        ,MIN(CASE SECT_GP WHEN '11' THEN DTL_ITEM1  END) AS SP11
        ,MIN(CASE SECT_GP WHEN '10' THEN DTL_ITEM1  END) AS SP10
        ,MIN(CASE SECT_GP WHEN '09' THEN DTL_ITEM1  END) AS SP09
        ,MIN(CASE SECT_GP WHEN '08' THEN DTL_ITEM1  END) AS SP08
        ,MIN(CASE SECT_GP WHEN '07' THEN DTL_ITEM1  END) AS SP07
        ,MIN(CASE SECT_GP WHEN '06' THEN DTL_ITEM1  END) AS SP06
        ,MIN(CASE SECT_GP WHEN '05' THEN DTL_ITEM1  END) AS SP05
        ,MIN(CASE SECT_GP WHEN '04' THEN DTL_ITEM1  END) AS SP04
        ,MIN(CASE SECT_GP WHEN '03' THEN DTL_ITEM1  END) AS SP03
        ,MIN(CASE SECT_GP WHEN '02' THEN DTL_ITEM1  END) AS SP02
        ,MIN(CASE SECT_GP WHEN '01' THEN DTL_ITEM1  END) AS SP01
        ,MIN(CASE SECT_GP WHEN '16' THEN DTL_ITEM2  END) AS SP_ABLE16 
        ,MIN(CASE SECT_GP WHEN '15' THEN DTL_ITEM2  END) AS SP_ABLE15 
        ,MIN(CASE SECT_GP WHEN '14' THEN DTL_ITEM2  END) AS SP_ABLE14 
        ,MIN(CASE SECT_GP WHEN '13' THEN DTL_ITEM2  END) AS SP_ABLE13 
        ,MIN(CASE SECT_GP WHEN '12' THEN DTL_ITEM2  END) AS SP_ABLE12
        ,MIN(CASE SECT_GP WHEN '11' THEN DTL_ITEM2  END) AS SP_ABLE11
        ,MIN(CASE SECT_GP WHEN '10' THEN DTL_ITEM2  END) AS SP_ABLE10
        ,MIN(CASE SECT_GP WHEN '09' THEN DTL_ITEM2  END) AS SP_ABLE09
        ,MIN(CASE SECT_GP WHEN '08' THEN DTL_ITEM2  END) AS SP_ABLE08
        ,MIN(CASE SECT_GP WHEN '07' THEN DTL_ITEM2  END) AS SP_ABLE07
        ,MIN(CASE SECT_GP WHEN '06' THEN DTL_ITEM2  END) AS SP_ABLE06
        ,MIN(CASE SECT_GP WHEN '05' THEN DTL_ITEM2  END) AS SP_ABLE05
        ,MIN(CASE SECT_GP WHEN '04' THEN DTL_ITEM2  END) AS SP_ABLE04
        ,MIN(CASE SECT_GP WHEN '03' THEN DTL_ITEM2  END) AS SP_ABLE03
        ,MIN(CASE SECT_GP WHEN '02' THEN DTL_ITEM2  END) AS SP_ABLE02
        ,MIN(CASE SECT_GP WHEN '01' THEN DTL_ITEM2  END) AS SP_ABLE01
FROM
    (
    SELECT A.*
    FROM(
            SELECT
                COL.*,
                (CASE WHEN COL.DISABLED_SPAN = 'Y' THEN '*' ELSE  NVL(R.DTL_ITEM1,'-') END)  AS DTL_ITEM1,
                (CASE WHEN COL.DISABLED_SPAN = 'Y' THEN 'N' ELSE  NVL(R.DTL_ITEM2,'N') END) AS DTL_ITEM2
            FROM
            (
                SELECT
                    A.YD_GP || A.BAY_GP  || A.SECT_GP AS COL_DEF,
                    A.BAY_GP,
                    A.SECT_GP,
                    CASE 
                        WHEN COUNT(DISTINCT A.YD_STK_COL_GP) = SUM(CASE WHEN A.DEL_YN = 'Y' THEN 1 END) THEN 'Y' 
                        WHEN COUNT(B.YD_STK_COL_GP) = SUM(CASE WHEN B.YD_STK_LYR_ACTIVE_STAT = 'N' THEN 1 END) THEN 'Y'
                    ELSE 'N' 
                    END AS DISABLED_SPAN 
                FROM TB_YF_STKCOL A, TB_YF_STKLYR B
                WHERE A.BAY_GP LIKE :V_YD_BAY_GP || '%'
                AND A.YD_GP = :V_YD_GP
                AND A.SECT_GP BETWEEN '00' AND '99'
                AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
                GROUP BY A.YD_GP, A.BAY_GP, A.SECT_GP 
             ) COL, 
             TB_YF_RULE R
            WHERE COL.COL_DEF = R.ITEM(+)
            AND R.REPR_CD_GP(+) = 'YF0010'
            AND R.CD_GP(+) = '1' 
          ) A
      )
GROUP BY BAY_GP
ORDER BY BAY_GP
 </pre> */
public final static String getStrlocUsgSetList = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStrlocUsgSetList";

 /** <pre> 2020-07-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCarPntFrmYn3_PIDEV
SELECT
    NVL
    (
        MAX
        (
            CASE
            WHEN SL.YD_STK_LYR_NO = '01' AND
            (
                SELECT
                    COUNT(*)
                FROM
                    TB_YF_STKLYR
                WHERE 1=1
                AND YD_STK_COL_GP   = SL.YD_STK_COL_GP
                AND YD_STK_BED_NO   IN (SL.YD_STK_BED_NO, LPAD(TO_NUMBER(SL.YD_STK_BED_NO) - 1, 2, '0'))
                AND YD_STK_LYR_NO   = '02'
                AND STL_NO IS NOT NULL
            ) > 0 THEN 'Y'
            ELSE 'N'
            END
        ),
        'N'
    ) AS DUMMY_YN
FROM
    (
        SELECT
            TRN_EQP_CD,
            CAR_NO,
            YD_STK_COL_GP
        FROM
            USRYDA.TB_YD_CARPOINT
        WHERE 1=1
        AND YD_CARPNT_CD LIKE '1%'
        AND YD_STK_COL_GP = :V_YD_STK_COL_GP
    ) CP,
    (
        SELECT
            MIN(YD_WBOOK_ID) AS YD_WBOOK_ID,
            MAX(YD_CAR_USE_GP) AS YD_CAR_USE_GP,
            'N' AS DEL_YN,
            TRN_EQP_CD,
            CAR_NO
        FROM
            TB_YF_WRKBOOK
        WHERE 1=1
        AND DEL_YN = 'N'
        AND (TRN_EQP_CD IS NOT NULL OR CAR_NO IS NOT NULL)
        GROUP BY TRN_EQP_CD, CAR_NO
    ) WB,
    TB_YF_WRKBOOKMTL WM,
    TB_YF_STKLYR SL
WHERE 1=1
AND
(
    (WB.YD_CAR_USE_GP = 'L' AND WB.TRN_EQP_CD = CP.TRN_EQP_CD)
    OR
    (WB.YD_CAR_USE_GP = 'G' AND WB.CAR_NO = CP.CAR_NO)
)
AND WB.DEL_YN       = 'N'
AND WB.YD_WBOOK_ID  = WM.YD_WBOOK_ID
AND SL.STL_NO       = WM.STL_NO
AND SL.YD_STK_LYR_STAT || '' IN ('C','U')
 </pre> */
public final static String getCarPntFrmYn3 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCarPntFrmYn3_PIDEV";

 /** <pre> 2020-06-25
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListPapWrapOUT   
WITH S_KEY AS (
            SELECT
                  SUBSTR(V_GF_LOC,0,6) AS V_YD_STK_COL_GP 
                , SUBSTR(V_GF_LOC,7,2) AS V_YD_STK_BED_NO 
                , NVL(SUBSTR(V_GF_LOC,9,2),'01') AS V_YD_STK_LYR_NO
                , V_GF_LOC
                , V_STL_NO
            FROM
            (
                SELECT
                 :V_STL_NO AS V_STL_NO
                 , :V_GF_LOC AS V_GF_LOC 
                FROM DUAL
            )
)
SELECT
    T.*
FROM
(
    SELECT 
        CASE WHEN EXISTS 
                        (
                            SELECT 1
                            FROM TB_YF_WRKBOOK M, TB_YF_WRKBOOKMTL M1, S_KEY S
                            WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
                            AND M.DEL_YN = 'N'
                            AND M1.DEL_YN = 'N'
                            AND M1.STL_NO = S.V_STL_NO
                        ) THEN '작업예약이 존재합니다.'
            WHEN NOT EXISTS 
                        (
                            SELECT 1
                            FROM TB_YF_STKLYR A, S_KEY S
                            WHERE A.YD_STK_COL_GP = S.V_YD_STK_COL_GP
                            AND A.YD_STK_BED_NO = S.V_YD_STK_BED_NO
                            AND A.YD_STK_LYR_NO = S.V_YD_STK_LYR_NO
                            AND A.STL_NO = S.V_STL_NO 
                        ) THEN '요청하신 위치의 코일정보가 다릅니다. 코일번호와 위치(번지)를 확인하세요'
    END AS MSG
    FROM DUAL
) T
WHERE T.MSG IS NOT NULL
 </pre> */
public final static String getListPapWrapOUT = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListPapWrapOUT";

 /** <pre> 2020-06-24
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListPapWrapIn 
SELECT
    T.*
FROM
(
       WITH S_KEY AS (
            SELECT
                  SUBSTR(V_GF_LOC,0,6) AS V_YD_STK_COL_GP 
                , SUBSTR(V_GF_LOC,7,2) AS V_YD_STK_BED_NO 
                , NVL(SUBSTR(V_GF_LOC,9,2),'01') AS V_YD_STK_LYR_NO
                , V_GF_LOC
            FROM
            (
                SELECT
                 :V_GF_LOC AS V_GF_LOC
                FROM DUAL
            )
       )
       -- 해당 번지에 지포장 코일이 적치되어 있는건지
       SELECT DISTINCT 
            A.YD_STK_COL_GP,
            A.YD_STK_BED_NO,
            A.YD_STK_LYR_NO,
            A.YD_STK_LYR_STAT,
            A.STL_NO,
            '' AS YD_WBOOK_ID,
            '지포장 번지 [' || A.YD_STK_BED_NO ||  ']에 다른 재료가 작업중입니다. [작업중인 재료번호 :' || A.STL_NO  ||' ]' AS MSG
       FROM TB_YF_STKLYR A, S_KEY S
       WHERE A.YD_STK_COL_GP = S.V_YD_STK_COL_GP
       AND A.YD_STK_BED_NO = S.V_YD_STK_BED_NO
       AND A.YD_STK_LYR_NO = S.V_YD_STK_LYR_NO
       AND A.STL_NO IS NOT NULL
       UNION ALL
       -- 동간이적상차 및 CTS스케쥴
       SELECT
            SS.*
            ,'지포장 번지 [' || SS.YD_STK_BED_NO ||  ']에 다른 재료가 작업예약중입니다. [작업중인 재료번호 :' || SS.STL_NO  ||', CTS작업지시 :'|| SS.YD_CTS_SCH_ID ||' ]' AS MSG
       FROM
       (
           SELECT   SUBSTR(M.YD_TO_LOC_GUIDE,0,6) AS YD_STK_COL_GP 
                , SUBSTR(M.YD_TO_LOC_GUIDE,7,2) AS YD_STK_BED_NO 
                , NVL(SUBSTR(M.YD_TO_LOC_GUIDE,9,2),'01') AS YD_STK_LYR_NO
                , 'D'
                , M1.STL_NO
                , CTS.YD_CTS_SCH_ID
           FROM TB_YF_WRKBOOK M, TB_YF_WRKBOOKMTL M1, TB_YF_CTS_SCH CTS, S_KEY S
           WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
           AND M.YD_WBOOK_ID = CTS.YD_WBOOK_ID
           AND CTS.DEL_YN = 'N'
           AND M.YD_TO_LOC_GUIDE LIKE S.V_YD_STK_COL_GP || S.V_YD_STK_BED_NO ||'%'
       ) SS
       UNION ALL
       -- 동간이적상차 및 CTS스케쥴
       SELECT
            SS.*
            ,'지포장 번지 [' || SS.YD_STK_BED_NO ||  ']에 다른 재료가 작업예약중입니다. [작업중인 재료번호 :' || SS.STL_NO  ||', 작업예약ID :'|| SS.YD_WBOOK_ID ||' ]' AS MSG 
       FROM
       (
           SELECT   SUBSTR(M.YD_TO_LOC_GUIDE,0,6) AS YD_STK_COL_GP 
                , SUBSTR(M.YD_TO_LOC_GUIDE,7,2) AS YD_STK_BED_NO 
                , NVL(SUBSTR(M.YD_TO_LOC_GUIDE,9,2),'01') AS YD_STK_LYR_NO
                , 'D'
                , M1.STL_NO
                , M.YD_WBOOK_ID
           FROM TB_YF_WRKBOOK M, TB_YF_WRKBOOKMTL M1, S_KEY S
           WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
           AND M.DEL_YN = 'N'
           AND M1.DEL_YN = 'N'
           AND M.YD_TO_LOC_GUIDE LIKE S.V_YD_STK_COL_GP || S.V_YD_STK_BED_NO ||'%'
     ) SS
)  T
 </pre> */
public final static String getListPapWrapIn = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListPapWrapIn";

