 /** <pre> 2021-02-24
--com.inisteel.cim.yf.common.dao.YfCommDAO.TcYFCRJ003_PIDEV
SELECT
    'YFCRJ003'                          AS JMS_TC_CD,           --JMSTC코드
    TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT,  --JMSTC생성일시
    'YFCRJ003'                          AS TC_CODE,             --IF구분코드
    TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS TC_CREATE_DDTT,      --TC생성일시
    CR_YD_GP,                                                   --냉연야드구분
    TRN_EQP_CD,                                                 --운송장비코드
    COIL_NO1,                                                   --재료번호1
    COIL_NO2,                                                   --재료번호2
    COIL_NO3,                                                   --재료번호3
    COIL_NO4,                                                   --재료번호4
    COIL_NO5,                                                   --재료번호5
    COIL_NO6,                                                   --재료번호6
    COIL_NO7,                                                   --재료번호7
    COIL_NO8,                                                   --재료번호8
    COIL_NO9,                                                   --재료번호9
    COIL_NO10,                                                  --재료번호10
    CARUD_CMPL_DT                                               --하차완료일시
FROM
    (
        SELECT
            'DC0C'                          AS CR_YD_GP,
            MAX(DD.TRN_EQP_CD)              AS TRN_EQP_CD,
            MAX(DECODE(NO,1,DD.STL_NO,''))  AS COIL_NO1,
            MAX(DECODE(NO,2,DD.STL_NO,''))  AS COIL_NO2,
            MAX(DECODE(NO,3,DD.STL_NO,''))  AS COIL_NO3,
            MAX(DECODE(NO,4,DD.STL_NO,''))  AS COIL_NO4,
            MAX(DECODE(NO,5,DD.STL_NO,''))  AS COIL_NO5,
            MAX(DECODE(NO,6,DD.STL_NO,''))  AS COIL_NO6,
            MAX(DECODE(NO,7,DD.STL_NO,''))  AS COIL_NO7,
            MAX(DECODE(NO,8,DD.STL_NO,''))  AS COIL_NO8,
            MAX(DECODE(NO,9,DD.STL_NO,''))  AS COIL_NO9,
            MAX(DECODE(NO,10,DD.STL_NO,'')) AS COIL_NO10,
            MAX(DD.CARUD_CMPL_DT)           AS CARUD_CMPL_DT
        FROM
            (
                SELECT
                    A.YD_CAR_SCH_ID,
                    A.TRN_EQP_CD,
                    A.STL_NO,
                    TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') AS CARUD_CMPL_DT,
                    RANK() OVER(ORDER BY A.YD_STK_BED_NO ASC) AS NO
                FROM
                    (
                        SELECT
                            A.YD_CAR_SCH_ID,
                            A.TRN_EQP_CD,
                            B.STL_NO,
                            B.YD_STK_BED_NO
                        FROM
                            TB_YD_CARSCH A,
                            TB_YD_CARFTMVMTL B
                        WHERE 1=1
                        AND A.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
                        AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID(+)
                    ) A
                WHERE 1=1
            ) DD
        GROUP BY YD_CAR_SCH_ID
)
 </pre> */
public final static String TcYFCRJ003 = "com.inisteel.cim.yf.common.dao.YfCommDAO.TcYFCRJ003_PIDEV";

