 /** <pre> 2021-03-13
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getRetnTrgtGds6
WITH PARAM AS
(
    SELECT
        :V_CAR_NO   AS P_CAR_NO
    FROM
        DUAL
)
SELECT
    RNUM,
    LPAD(RNUM, 2, '0') AS YD_STK_BED_NO,
    COIL_NO AS STL_NO,
    CARD_NO,
    CURR_PROG_CD,
    ORD_NO,
    ORD_DTL,
    SPEC_ABBSYM,
    COIL_T,
    COIL_W,
    COIL_WT,
    COIL_OUTDIA,
    COIL_LEN
FROM
    (
        SELECT
            CC.*,
            RN,
            CARD_NO
        FROM
            VW_YF_COILCOMM  CC,
            (
                SELECT
                    ROW_NUMBER() OVER(PARTITION BY CM.YD_CAR_SCH_ID ORDER BY CM.YD_STK_BED_NO) AS RN,
                    CM.STL_NO,
                    CARSCH.CARD_NO
                FROM
                    USRYDA.TB_YD_CARFTMVMTL  CM,
                    USRYDA.TB_YD_CARSCH CARSCH
                WHERE 1=1
                AND CM.YD_CAR_SCH_ID = 
                (
                    SELECT
                        YD_CAR_SCH_ID
                    FROM
                        (
                            SELECT
                                Z.YD_CAR_SCH_ID
                            FROM
                                USRYDA.TB_YD_CARSCH Z,
                                PARAM
                            WHERE 1=1
                            AND (Z.CAR_NO = P_CAR_NO OR SUBSTR(Z.CAR_NO, -4) = P_CAR_NO)
                            AND Z.SPOS_WLOC_CD = 'DZY30'
                            AND Z.DEL_YN = 'Y'
                            ORDER BY Z.YD_CAR_SCH_ID DESC
                        )
                    WHERE 1=1
                    AND ROWNUM = 1
                )
                AND CM.YD_CAR_SCH_ID = CARSCH.YD_CAR_SCH_ID
            ) MTL
        WHERE 1=1
        AND CC.COIL_NO = MTL.STL_NO
    ) A,
    (
        SELECT
            ROWNUM AS RNUM
        FROM
            DUAL
        CONNECT BY LEVEL <= 15
    ) R
WHERE 1=1
AND R.RNUM = A.RN(+)
ORDER BY RNUM
 </pre> */
public final static String getRetnTrgtGds6 = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getRetnTrgtGds6";

