 /** <pre> 2020-10-15
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCM2
SELECT
    AA.*
FROM
    (
        --착지개소코드 기준으로 사용가능한 비어있는 포인트 조회
        SELECT
            MIN(A.YD_STK_COL_GP) AS YD_STK_COL_GP,
            A.YD_PNT_CD
        FROM
            (
                SELECT
                    YD_STK_COL_GP,
                    YD_PNT_CD
                FROM
                    TB_YF_STKCOL A
                WHERE 1=1
                AND SUBSTR(YD_STK_COL_GP, 3, 2) IN ('PT')
                AND WLOC_CD = :V_WLOC_CD
                AND BAY_GP  = :V_BAY_GP
                AND TRN_EQP_CD  IS NULL --현재차량정지위치
                AND CAR_CARD_NO IS NULL --예약차량정지위치
                AND CARD_NO     IS NULL
            )A
        GROUP BY YD_PNT_CD
    ) AA,
    (
        --저장위치 용도관리 화면 등록 기준으로 냉연 하차 가능한 포인트 검색
        --TB_YD_CARPOINT 의 FROM~TO스판기준이랑 조인함 조회
        SELECT DISTINCT
            B.*
        FROM
            (
                SELECT
                    ITEM
                FROM
                    TB_YF_RULE
                WHERE 1=1
                AND REPR_CD_GP = 'YF0010'   --저장위치 용도관리
                AND DTL_ITEM1 = 'HR'        --CR : 냉연, HR : 열연, * : 사용안함, - : 사용불가
                AND DTL_ITEM2 = 'Y'         --사용함 : Y, 사용안함 : N
                AND DEL_YN = 'N'
            ) A,
            TB_YD_CARPOINT B
        WHERE 1=1
        AND B.YD_GP = SUBSTR(A.ITEM, 1, 1)
        AND B.YD_BAY_GP = SUBSTR(A.ITEM, 2, 1)
        AND SUBSTR(A.ITEM, 3, 2) BETWEEN B.YD_SPAN_FROM AND B.YD_SPAN_TO
    ) BB
WHERE 1=1
AND AA.YD_STK_COL_GP = BB.YD_STK_COL_GP
AND BB.YD_CAR_USETYPE_GP IN ('GT', 'TO')
AND BB.DEL_YN = 'N'
ORDER BY AA.YD_PNT_CD DESC
 </pre> */
public final static String getListloadStoppointCM2 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCM2";

 /** <pre> 2020-12-14
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarPoint2
SELECT
    *
FROM
    (
        SELECT
            CASE
            --크레인설비가 고장이거나 OFF라인이 아님 + 해당포인트가 전문에서받은 포인트와 동일 1순위
            WHEN A.YD_CARPNT_CD != NVL(D.YD_CARPNT_CD, ' ') THEN 1
            --그외는 2순위
            ELSE 2 END AS RNK1,
            CASE
            WHEN A.YD_CARPNT_CD = :V_YD_CARPNT_CD THEN 1
            WHEN SUBSTR(A.YD_CARPNT_CD, 1, 3) = SUBSTR(:V_YD_CARPNT_CD, 1, 3) THEN 2
            ELSE 3 END AS RNK2,
            SUBSTR(A.YD_STK_COL_GP, 1, 4) || '0' || SUBSTR(A.YD_STK_COL_GP, 6, 1) AS YD_STK_COL_GP2,
            DECODE(A.YD_STK_COL_ACT_STAT, 'R', 'C', A.YD_STK_COL_ACT_STAT) AS YD_STK_COL_ACT_STAT,
            A.YD_CARPNT_CD,
            A.REG_DDTT,
            A.REGISTER,
            A.MOD_DDTT,
            A.MODIFIER,
            A.DEL_YN,
            A.YD_CAR_USETYPE_GP,
            A.YD_GP,
            A.YD_BAY_GP,
            A.YD_STK_COL_GP,
            A.TRN_EQP_CD,
            A.CAR_NO,
            A.CARD_NO,
            A.WLOC_CD,
            A.YD_PNT_CD,
            A.YD_CARPNT_DESC,
            A.YD_SPAN_FROM,
            A.YD_SPAN_TO,
            (
                SELECT
                    ITEM1
                FROM
                    USRYDA.TB_YD_RULE
                WHERE 1=1
                AND REPR_CD_GP = 'J00005'
                AND CD_GP = A.YD_GP
                AND ITEM = '*'
                AND DEL_YN = 'N'
            ) AS MOV_YN
        FROM
            TB_YD_CARPOINT A,
            (
                --크레인이 고장이거나 OFF라인상태인 해당크레인쪽 포인트
                SELECT
                    '1' || SUBSTR(A.YD_EQP_ID, 6, 1) || A.YD_BAY_GP || B.CT AS YD_CARPNT_CD
                FROM
                    TB_YF_EQP A,
                    (
                        SELECT
                            LEVEL AS CT
                        FROM
                            DUAL
                        CONNECT BY LEVEL <= 2
                    ) B
                WHERE 1=1
                AND A.YD_GP = SUBSTR(:V_YD_CARPNT_CD, 1, 1)
                AND A.YD_BAY_GP = SUBSTR(:V_YD_CARPNT_CD, 3, 1)
                AND A.YD_EQP_GP = 'CR'
                AND
                (
                    A.YD_EQP_PROG_STAT  = 'B'   --고장
                    OR
                    A.YD_EQP_WRK_MODE   = '2'   --OFF라인
                )
            ) D
        WHERE 1=1
        AND A.YD_CARPNT_CD = D.YD_CARPNT_CD(+)
        AND A.YD_CARPNT_CD LIKE SUBSTR(:V_YD_CARPNT_CD, 1, 1) || '_' || SUBSTR(:V_YD_CARPNT_CD, 3, 1) || '%'
        AND A.DEL_YN = 'N'
        AND A.YD_STK_COL_ACT_STAT != 'N'
        ORDER BY 1, 2, A.YD_STK_COL_GP
    )
WHERE ROWNUM = 1
 </pre> */
public final static String getYdCarPoint2 = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarPoint2";

