 /** <pre> 2021-02-25
 -- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYardBasicInfo 
SELECT
      '"'|| A.BAY_GP ||'"'|| ': { "MAX":"'|| A.MAX_SPAN ||'"' || ', "MIN":"'|| A.MIN_SPAN ||'", "DISABLED_SECT": "'|| A.DISABLED_SECT ||'"'
            || ', "CARPOINT_M" : {"CNT":"' || NVL(B.CARPOINT_M, 0) ||'" , "SPAN": "'|| CASE WHEN A.BAY_GP IN ('E','F','G') THEN '5" }' 
                                                                                            WHEN A.BAY_GP IN ('A','B') THEN '10" }'
                                                                                            WHEN A.BAY_GP IN ('H') THEN '8" }'
                                                                                        ELSE '0" }'
                                                                                        END 
            || ', "CARPOINT_L" : {"CNT":"' || CASE 
                                                  WHEN A.BAY_GP IN ('E','F','G') AND A.MIDDLE_YN = 'Y' THEN 0 
                                              ELSE NVL(B.CARPOINT_L, 0) END ||'" , "SPAN": "'|| '5" }' 
--            || ', "CARPOINT_R" : {"CNT":"' || NVL(B.CARPOINT_R, 0) ||'" , "SPAN": "'|| A.MAX_SPAN || '" }' 
            || ', "CARPOINT_R" : {"CNT":"' || NVL(B.CARPOINT_R, 0) ||'" , "SPAN": "'|| CASE 
                                                                                            WHEN A.BAY_GP IN ('A','B','C','D') THEN A.MAX_SPAN
                                                                                            
                                                                                            ELSE 16 END ||'" }' 
            || ', "MIDDLE_YN": "'|| A.MIDDLE_YN ||'" '
            || '}' AS J_OBJECT
FROM
(
    SELECT 
        T1.BAY_GP
        , TO_NUMBER(CASE WHEN T1.BAY_GP IN ('D') THEN TO_CHAR('07') ELSE MIN(T1.SECT_GP) END) AS MIN_SPAN
        , TO_NUMBER(CASE  T1.BAY_GP 
                    WHEN 'D' THEN '-1'  
                    WHEN 'C' THEN '-1'  
                    ELSE MAX(T1.SECT_GP)  END)  AS MAX_SPAN 
        , (
                SELECT
                    WM_CONCAT( DISTINCT CASE WHEN SUM(CASE WHEN S2.YD_STK_LYR_ACTIVE_STAT = 'N' THEN 1 END) = COUNT(*) THEN TO_NUMBER(S1.SECT_GP) END )
                FROM TB_YF_STKCOL S1, TB_YF_STKLYR S2
                WHERE S1.YD_STK_COL_GP = S2.YD_STK_COL_GP  
                AND S1.SECT_GP BETWEEN '00' AND '99'
                AND S1.YD_GP = '1'
                AND S1.BAY_GP =  T1.BAY_GP
                GROUP BY S1.BAY_GP, S1.SECT_GP
        ) AS DISABLED_SECT
        , CASE 
                WHEN T1.BAY_GP IN ('11') THEN 'N' -- 중앙통로 계통되면 그때 변경처리해야함  
                WHEN T1.BAY_GP IN ('A','B','H','G','E','F') THEN 'Y'
         ELSE 'N' END AS MIDDLE_YN
    FROM TB_YF_STKCOL T1, TB_YF_STKLYR T2
    WHERE T1.YD_STK_COL_GP = T2.YD_STK_COL_GP 
    AND T1.SECT_GP BETWEEN '00' AND '99'
    AND ( T1.DEL_YN = 'N' OR T1.BAY_GP IN ('D') )
    AND ( 
            T2.YD_STK_LYR_ACTIVE_STAT <> 'N'
        OR
            T2.YD_STK_LYR_STAT IN ('C', 'U', 'S')
        OR  T2.DEL_YN = 'N'
        ) 
    GROUP BY T1.BAY_GP
    ORDER BY T1.BAY_GP
) A
, (
        SELECT
            T1.YD_BAY_GP
            , NVL(CARPOINT_M,0) AS CARPOINT_M
            , NVL(CARPOINT_L,0) AS CARPOINT_L
            , NVL(CARPOINT_R,0) AS CARPOINT_R
        FROM 
        (
            SELECT
                YD_BAY_GP
                ,SUM(
                        CASE 
                            WHEN YD_BAY_GP IN ('E','F','G') THEN CASE WHEN SUBSTR(YD_CARPNT_CD,2,1) = '1' THEN 1 END
                            WHEN YD_BAY_GP IN ('H','A','B') THEN CASE WHEN SUBSTR(YD_CARPNT_CD,2,1) = '2'  THEN 1 END
                        ELSE NULL  END
                    ) AS CARPOINT_M
                , SUM(
                        CASE WHEN SUBSTR(YD_CARPNT_CD,2,1) = '1'  THEN 1  END 
                    ) AS CARPOINT_L
                , SUM(
                         CASE 
                            WHEN YD_BAY_GP IN ('H') THEN 
                            CASE WHEN SUBSTR(YD_CARPNT_CD,2,1) = '3' THEN 1 END 
                        ELSE CASE WHEN SUBSTR(YD_CARPNT_CD,2,1) = '2'  THEN 1  END END
                    ) AS CARPOINT_R
            FROM TB_YD_CARPOINT
            WHERE YD_GP = '1'
            AND DEL_YN = 'N'
            GROUP BY YD_BAY_GP
        ) T1
        ORDER BY T1.YD_BAY_GP
) B
WHERE A.BAY_GP = B.YD_BAY_GP(+)
ORDER BY A.BAY_GP 
 </pre> */
public final static String getYardBasicInfo = "com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYardBasicInfo";

