 /** <pre> 2020-10-14
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getNumberColList
WITH 
 PARAM AS (
    SELECT :V_YD_GP         AS V_YD_GP
          ,:V_YD_BAY_GP     AS V_YD_BAY_GP
      FROM DUAL
)

,HD_INFO AS (
           SELECT SECT_GP 
            FROM TB_YF_STKCOL
                ,PARAM P
           WHERE YD_GP     = P.V_YD_GP
             AND BAY_GP    LIKE P.V_YD_BAY_GP || '%'
             AND REGEXP_INSTR(SECT_GP,'[^0-9]')   = 0
             AND SECT_GP < '17'
           GROUP BY SECT_GP
           ORDER BY SECT_GP
)

,LOW_CHK AS( 
    SELECT  BAY_GP
          , COL_GP
          , (CASE WHEN HD_INFO.SECT_GP = '01' THEN '' ELSE '' END) AS SP01 
          , (CASE WHEN HD_INFO.SECT_GP = '02' THEN '' ELSE '' END) AS SP02 
          , (CASE WHEN HD_INFO.SECT_GP = '03' THEN '' ELSE '' END) AS SP03 
          , (CASE WHEN HD_INFO.SECT_GP = '04' THEN '' ELSE '' END) AS SP04 
          , (CASE WHEN HD_INFO.SECT_GP = '05' THEN '' ELSE '' END) AS SP05 
          , (CASE WHEN HD_INFO.SECT_GP = '06' THEN '' ELSE '' END) AS SP06 
          , (CASE WHEN HD_INFO.SECT_GP = '07' THEN '' ELSE '' END) AS SP07 
          , (CASE WHEN HD_INFO.SECT_GP = '08' THEN '' ELSE '' END) AS SP08 
          , (CASE WHEN HD_INFO.SECT_GP = '09' THEN '' ELSE '' END) AS SP09 
          , (CASE WHEN HD_INFO.SECT_GP = '10' THEN '' ELSE '' END) AS SP10 
          , (CASE WHEN HD_INFO.SECT_GP = '11' THEN '' ELSE '' END) AS SP11 
          , (CASE WHEN HD_INFO.SECT_GP = '12' THEN '' ELSE '' END) AS SP12 
          , (CASE WHEN HD_INFO.SECT_GP = '13' THEN '' ELSE '' END) AS SP13 
          , (CASE WHEN HD_INFO.SECT_GP = '14' THEN '' ELSE '' END) AS SP14 
          , (CASE WHEN HD_INFO.SECT_GP = '15' THEN '' ELSE '' END) AS SP15 
          , (CASE WHEN HD_INFO.SECT_GP = '16' THEN '' ELSE '' END) AS SP16 
         
        
      FROM (SELECT E.SECT_GP  AS SPAN 
                 , E.BAY_GP
                 , E.COL_GP   
                 , E.YD_STK_COL_GP
                 , (CASE WHEN E.YD_STK_COL_GP IS NULL THEN '0' ELSE '0' END) AS CHK
                 
              FROM TB_YF_STKCOL   E
                
                 , PARAM P
             WHERE E.YD_GP        = P.V_YD_GP 
               AND E.BAY_GP     LIKE P.V_YD_BAY_GP || '%'
               AND E.DEL_YN = 'N'
               AND E.YD_STK_COL_ACTIVE_STAT IN ('L')
               AND REGEXP_INSTR(E.SECT_GP,'[^0-9]')   = 0
               AND E.SECT_GP < '17'
               AND ((REGEXP_LIKE(E.COL_GP, '[[:digit:]]') AND E.COL_GP BETWEEN '00' AND '10'))
           ) T
           ,HD_INFO
      WHERE T.SPAN = HD_INFO.SECT_GP
)

SELECT LPAD(TO_CHAR(ROWNUM),2,'0') AS RN
      , A.*
  FROM (SELECT BAY_GP
             , MAX(COL_GP) OVER(ORDER BY BAY_GP) AS MAXLOW
             , MAX(COL_GP) AS COL_GP
             , NVL(MAX(SP01),'*') AS SP01     
             , NVL(MAX(SP02),'*') AS SP02
             , NVL(MAX(SP03),'*') AS SP03     
             , NVL(MAX(SP04),'*') AS SP04
             , NVL(MAX(SP05),'*') AS SP05     
             , NVL(MAX(SP06),'*') AS SP06
             , NVL(MAX(SP07),'*') AS SP07     
             , NVL(MAX(SP08),'*') AS SP08
             , NVL(MAX(SP09),'*') AS SP09     
             , NVL(MAX(SP10),'*') AS SP10
             , NVL(MAX(SP11),'*') AS SP11     
             , NVL(MAX(SP12),'*') AS SP12
             , NVL(MAX(SP13),'*') AS SP13     
             , NVL(MAX(SP14),'*') AS SP14
             , NVL(MAX(SP15),'*') AS SP15     
             , NVL(MAX(SP16),'*') AS SP16 
          FROM LOW_CHK  
         GROUP BY BAY_GP,COL_GP
         ORDER BY BAY_GP) A
 </pre> */
public final static String getNumberColList = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getNumberColList";

