 /** <pre> 2021-01-26
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListStkColgp2
SELECT
    A.YD_STK_COL_GP,
    A.YD_PNT_CD
FROM
    TB_YD_CARPOINT A,
    (
        SELECT
            CASE
            WHEN A.YD_EQP_WRK_STAT = 'L' THEN A.YD_PNT_CD3
            WHEN A.YD_EQP_WRK_STAT = 'U' THEN A.YD_PNT_CD1
            END AS YD_PNT_CD,
            A.YD_CAR_SCH_ID
        FROM
            TB_YD_CARSCH A
        WHERE 1=1
        AND A.YD_CAR_USE_GP = 'L'   --구내운송
        AND A.DEL_YN = 'N'
        AND
        (
            -- L(영차)인경우 착지개소코드 U(공차)인경우 발지개소코드 와 비교
            CASE
            WHEN A.YD_EQP_WRK_STAT = 'L' THEN A.ARR_WLOC_CD
            WHEN A.YD_EQP_WRK_STAT = 'U' THEN A.SPOS_WLOC_CD
            END
        ) = :V_WLOC_CD
        AND A.YD_CAR_PROG_STAT =
        (
            -- 차량진행상태 A:하차출발, 1:상차출발
            CASE
            WHEN :V_TRN_WRK_FULLVOID_GP = 'F' THEN 'A'
            WHEN :V_TRN_WRK_FULLVOID_GP = 'E' THEN '1'
            END
        )
        AND A.TRN_EQP_CD = :V_TRN_EQP_CD    --운송설비코드
    ) B
WHERE 1=1
AND A.WLOC_CD = :V_WLOC_CD
AND A.YD_PNT_CD LIKE SUBSTR(B.YD_PNT_CD, 1, 2) || '%'
AND A.YD_CAR_USETYPE_GP IN ('GT', 'TO')
--AND A.YD_STK_COL_ACT_STAT != 'N'  --사용불가가 아닌곳
AND A.DEL_YN = 'N'
ORDER BY YD_STK_COL_GP DESC
 </pre> */
