 /** <pre> 2021-01-13
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarPoint1
SELECT
    CASE WHEN A.YD_CARPNT_CD = :V_YD_CARPNT_CD THEN 1 ELSE 2 END AS RNK,
    SUBSTR(A.YD_STK_COL_GP, 1, 4) || '0' || SUBSTR(A.YD_STK_COL_GP, 6, 1) AS YD_STK_COL_GP2,
    DECODE(A.YD_STK_COL_ACT_STAT, 'R', 'C', A.YD_STK_COL_ACT_STAT) AS YD_STK_COL_ACT_STAT,
    A.YD_CARPNT_CD,
    A.REG_DDTT,
    A.REGISTER,
    A.MOD_DDTT,
    A.MODIFIER,
    A.DEL_YN,
    A.YD_CAR_USETYPE_GP,
    A.YD_GP,
    A.YD_BAY_GP,
    A.YD_STK_COL_GP,
    A.TRN_EQP_CD,
    A.CAR_NO,
    A.CARD_NO,
    A.WLOC_CD,
    A.YD_PNT_CD,
    A.YD_CARPNT_DESC,
    A.YD_SPAN_FROM,
    A.YD_SPAN_TO,
    (
        SELECT
            ITEM1
        FROM
            USRYDA.TB_YD_RULE
        WHERE 1=1
        AND REPR_CD_GP = 'J00005'
        AND CD_GP = A.YD_GP
        AND ITEM = '*'
        AND DEL_YN = 'N'
    ) AS MOV_YN
FROM
    TB_YD_CARPOINT A,
    (
        SELECT
            SUBSTR(YD_STK_COL_GP, 1, 1) AS YD_GP,
            SUBSTR(YD_STK_COL_GP, 2, 1) AS YD_BAY_GP,
            SUBSTR(YD_STK_COL_GP, 3, 2) AS YD_SPAN
        FROM
            TB_YF_STKLYR
        WHERE 1=1
        AND STL_NO = :V_STL_NO  
    ) B
WHERE 1=1
AND A.YD_GP = B.YD_GP
AND A.YD_BAY_GP = B.YD_BAY_GP
AND A.DEL_YN = 'N'					--삭제되지 않은 포인트
AND A.YD_STK_COL_ACT_STAT != 'N'	--사용불가 포인트 제외
AND B.YD_SPAN BETWEEN A.YD_SPAN_FROM AND A.YD_SPAN_TO
ORDER BY 1 ASC
 </pre> */
public final static String getYdCarPoint1 = "com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarPoint1";

