 /** <pre> 2021-03-05
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCMCR
SELECT
    BB.YD_STK_COL_GP,
    SUBSTR(BB.YD_STK_COL_GP, 1, 4) || '00' AS YD_STK_COL_GP2,
    BB.YD_PNT_CD,
    SUBSTR(BB.YD_PNT_CD, 1, 2) || '00' AS YD_PNT_CD2
FROM
    (
        --저장위치 용도관리 화면 등록 기준으로 냉연 하차 가능한 포인트 검색
        --TB_YD_CARPOINT 의 FROM~TO스판기준이랑 조인함 조회...주석으로 조건 제외함
        SELECT DISTINCT
            CASE
            WHEN
                CASE
                WHEN SUBSTR(B.YD_STK_COL_GP, 5, 2) = '01' THEN 1
                WHEN SUBSTR(B.YD_STK_COL_GP, 5, 2) = '02' THEN 1
                WHEN SUBSTR(B.YD_STK_COL_GP, 5, 2) = '03' THEN 2
                WHEN SUBSTR(B.YD_STK_COL_GP, 5, 2) = '04' THEN 2
                ELSE 2 END = NVL(C.PNT_RNK, 1) THEN 1
            ELSE 2 END PNT_RNK,
            B.*
        FROM
            TB_YD_CARPOINT B,
            (
                --동별 통로 순위 : 0(동별로 통로에 차량 적은통로 그외는 1통로), 1(1통로 우선), 2(2통로 우선)
                SELECT
                    A.ITEM AS DONG,
                    CASE
                    WHEN A.DTL_ITEM1 = 0 THEN
                    (
                        CASE
                        WHEN B.YD_BAY_GP IS NOT NULL AND B.GATE_WAY1 > B.GATE_WAY2 THEN '2'   --1통로에 차량이 많을때 2통로
                        WHEN B.YD_BAY_GP IS NOT NULL AND B.GATE_WAY1 < B.GATE_WAY2 THEN '1'   --2통로에 차량이 많을때 1통로
                        ELSE '1' END  --그외는 1통로로 셋팅
                    )
                    ELSE A.DTL_ITEM1
                    END AS PNT_RNK
                FROM
                    TB_YF_RULE A,
                    (
                        --동별 통로별 차량대수
                        SELECT
                            YD_BAY_GP,
                            SUM(CASE WHEN GATE_WAY = 1 THEN 1 ELSE 0 END) AS GATE_WAY1,
                            SUM(CASE WHEN GATE_WAY = 2 THEN 1 ELSE 0 END) AS GATE_WAY2
                        FROM
                            (
                                --종료안된 차량스케줄 중에 박판창고에 있는 차량 포인트별로 체크
                                SELECT
                                    P.YD_BAY_GP,
                                    CASE
                                    WHEN SUBSTR(P.YD_STK_COL_GP, 5, 2) = '01' THEN 1
                                    WHEN SUBSTR(P.YD_STK_COL_GP, 5, 2) = '02' THEN 1
                                    WHEN SUBSTR(P.YD_STK_COL_GP, 5, 2) = '03' THEN 2
                                    WHEN SUBSTR(P.YD_STK_COL_GP, 5, 2) = '04' THEN 2
                                    ELSE 2 END AS GATE_WAY
                                FROM
                                    (SELECT YD_EQP_WRK_STAT, YD_PNT_CD1, YD_PNT_CD3 FROM TB_YD_CARSCH WHERE DEL_YN = 'N') C,
                                    (SELECT YD_PNT_CD, YD_BAY_GP, YD_STK_COL_GP FROM TB_YD_CARPOINT WHERE YD_GP = '1') P
                                WHERE 1=1
                                AND (CASE
                                     WHEN C.YD_EQP_WRK_STAT = 'L' THEN  NVL(C.YD_PNT_CD3, ' ')    --영차(하차포인트)
                                     WHEN C.YD_EQP_WRK_STAT = 'U' THEN  NVL(C.YD_PNT_CD1, ' ')    --공차(상차포인트)
                                     END) = P.YD_PNT_CD
                            )
                        GROUP BY YD_BAY_GP
                    ) B
                WHERE 1=1
                AND A.REPR_CD_GP = 'MATL03'
                AND A.ITEM = B.YD_BAY_GP(+)
            ) C
        WHERE 1=1
        AND B.YD_BAY_GP = C.DONG(+)
        AND B.WLOC_CD = :V_WLOC_CD
        AND B.YD_BAY_GP = :V_BAY_GP
    ) BB
WHERE 1=1
AND BB.YD_CAR_USETYPE_GP IN ('GT', 'TO')
AND BB.YD_STK_COL_ACT_STAT != 'N'    --사용불가가 아닌곳
AND BB.DEL_YN = 'N'
ORDER BY BB.PNT_RNK
 </pre> */
public final static String getListloadStoppointCMCR = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCMCR";

 /** <pre> 2021-03-07
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcCRDMJ009_PIDEV
--냉연코일하차개시 전문
SELECT
    'CRDMJ009'                          AS JMS_TC_CD,           --JMSTC코드
    TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT,  --JMSTC생성일시
    --'LD00'                              AS CR_YD_GP,            --냉연야드구분
    'DC0C'                              AS CR_YD_GP,            --냉연야드구분
    CT.TRANS_ORD_DATE                   AS FRTOMOVE_WORD_DATE,  --이송작업지시일자
    CT.TRANS_ORD_SEQNO                  AS FRTOMOVE_WORD_SEQNO, --이송작업지시순번
    CS.CAR_NO                           AS CAR_NO,              --차량번호
    CS.CARD_NO                          AS CR_CAR_NO,           --냉연차량번호
    TO_CHAR(SYSDATE,'YYYYMMDD')         AS CARUD_ST_DATE,       --하차 개시 일자
    TO_CHAR(SYSDATE,'HH24MISS')         AS CARUD_ST_TIME,       --하차 개시 시각
    'F1YFL008'                          AS REGISTER             --등록자
FROM
    TB_YD_CARSCH CS,
    (
        SELECT
            TRANS_ORD_DATE,
            TRANS_ORD_SEQNO
        FROM
            TB_YD_CARSCH
        WHERE 1=1
        AND YD_CAR_SCH_ID = 
        (
            SELECT
                MAX(A.YD_CAR_SCH_ID)
            FROM
                TB_YD_CARSCH A,
                TB_YD_CARSCH B
            WHERE 1=1
            AND A.CAR_NO = B.CAR_NO
            AND A.YD_CAR_SCH_ID != B.YD_CAR_SCH_ID
            AND B.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
        )
    ) CT
WHERE 1=1
AND CS.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
 </pre> */
public final static String TcCRDMJ009 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcCRDMJ009_PIDEV";

