 /** <pre> 2021-03-19
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.acoilProductTransStatusjl
SELECT
    *
FROM
    (
        SELECT
            ROWNUM AS RNUM,
            A.*
        FROM
            (
                SELECT
                    COUNT(*) OVER() AS TOTALCOUNT,
                    NVL(B.FRTOMOVE_WORD_NO, B.TRANS_ORD_DATE || '-' || B.TRANS_ORD_SEQNO) AS FRTOMOVE_WORD_NO,  --이송 작업지시 번호
                    A.STL_NO,               --재료번호
                    (
                        CASE
                        WHEN A.SPOS_WLOC_CD LIKE 'DXY%' THEN  '1냉연'
                        WHEN A.SPOS_WLOC_CD LIKE 'DYY%' THEN '2냉연'
                        WHEN A.SPOS_WLOC_CD ='D2Y45' THEN '박판열연'
                        WHEN A.SPOS_WLOC_CD = 'S0001' THEN '순천공장'
                        WHEN A.SPOS_WLOC_CD = 'DZY30' THEN '사외창고'
                        END
                    ) AS SPOS_WLOC_CD,      --발지개소코드
                    (
                        CASE
                        WHEN A.ARR_WLOC_CD LIKE 'DXY%' THEN '1냉연'
                        WHEN A.ARR_WLOC_CD LIKE 'DYY%' THEN '2냉연'
                        WHEN A.ARR_WLOC_CD ='D2Y45' THEN '박판열연'
                        WHEN A.ARR_WLOC_CD = 'S0001' THEN '순천공장'
                        WHEN A.SPOS_WLOC_CD = 'DZY30' THEN '사외창고'
                        END
                    ) AS ARR_WLOC_CD,       --착지개소코드
                    A.YD_UP_WR_LOC,         --권상실적위치,
                    A.YD_DN_WR_LOC,         --권하실적위치,
                    NVL(D.YD_STK_COL_GP || YD_STK_BED_NO || YD_STK_LYR_NO, C.LOD_LOC) AS YD_REAL_LOC,   --현재위치
                    NVL(A.TRN_EQP_CD, A.CAR_NO) AS TRN_EQP_CD,                          --운송설비코드
                    TO_CHAR(A.YD_DN_CMPL_DT, 'YYYY-MM-DD HH24:MI:SS') AS YD_DN_CMPL_DT, --권하일시(작업완료일시)
                    A.YD_MTL_T,             --두께
                    A.YD_MTL_W,             --폭
                    A.YD_MTL_L,             --길이
                    A.YD_MTL_WT,            --중량
                    A.COIL_INDIA,           --내경
                    A.COIL_OUTDIA,          --외경
                    CASE
                    WHEN C.PRD_WHS_APT_DD IS NOT NULL THEN '제품' --제품입고계상일
                    ELSE '재공품' END AS STL_APPEAR_GP,
                    SUM(A.YD_MTL_WT) OVER() AS TOTAL_WGT
                FROM
                    TB_YF_WRKHIST A,
                    TB_YD_CARSCH B,
                    TB_YF_CR_COILCOMM C,
                    TB_YF_STKLYR D
                WHERE 1=1
                AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
                AND NVL(A.TRN_EQP_CD, A.CAR_NO) LIKE :V_TRN_EQP_CD || '%'
                AND (A.TRN_EQP_CD IS NOT NULL OR A.SPOS_WLOC_CD = 'S0001')
                AND A.YD_GP = '1'
                AND A.YD_AID_WRK_YN = 'N'
                AND A.STL_NO = C.COIL_NO
                AND A.STL_NO = D.STL_NO(+)
                AND A.SPOS_WLOC_CD LIKE :V_SPOS_WLOC_CD || '%'
                AND A.ARR_WLOC_CD LIKE :V_ARR_WLOC_CD || '%'
                AND A.YD_WRK_HIST_ID  BETWEEN :V_DATE_FROM || '00000000'  AND :V_DATE_TO || '99999999'
                AND CASE
                    WHEN C.PRD_WHS_APT_DD IS NOT NULL THEN '제품' --제품입고계상일
                    ELSE '재공품' END LIKE :V_STL_APPEAR_GP || '%'
                ORDER BY A.YD_WRK_HIST_ID
            ) A
        WHERE 1=1
        AND ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE
	)
WHERE 1=1
AND RNUM >= ((:V_PAGE_NO -1) * :V_PAGE_SIZE ) + 1
 </pre> */
public final static String acoilProductTransStatusjl = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.acoilProductTransStatusjl";

 /** <pre> 2021-04-15
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStockTransOrdDTWbook2
SELECT
    A.STL_NO,
    SUBSTR(B.YD_STK_COL_GP, 2, 1) AS YD_BAY_GP,
    B.YD_STK_COL_GP,
    B.YD_STK_BED_NO,
    B.YD_STK_LYR_NO,
    B.DUMMY_CT
FROM
    USRYFA.TB_YF_STOCK A,
    (
        SELECT
            (NVL2(B.STL_NO, 1, 0) + NVL2(C.STL_NO, 1, 0)) AS DUMMY_CT,
            A.*
        FROM
            USRYFA.TB_YF_STKLYR A,
            USRYFA.TB_YF_STKLYR B,
            USRYFA.TB_YF_STKLYR C
        WHERE 1=1
        AND A.YD_STK_COL_GP = B.YD_STK_COL_GP(+)
        AND LPAD(TO_NUMBER(A.YD_STK_BED_NO) - 1, 2, '0') = B.YD_STK_BED_NO(+)   -- -1배드
        AND A.YD_STK_COL_GP = C.YD_STK_COL_GP(+)
        AND A.YD_STK_BED_NO = C.YD_STK_BED_NO(+)
        AND LPAD(TO_NUMBER(A.YD_STK_LYR_NO) + 1, 2, '0') = B.YD_STK_LYR_NO(+)   -- +1단
        AND LPAD(TO_NUMBER(A.YD_STK_LYR_NO) + 1, 2, '0') = C.YD_STK_LYR_NO(+)   -- +1단
    ) B,
    USRYDA.TB_YD_CARPOINT C
WHERE 1=1
AND A.STL_NO =B.STL_NO
AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DT
AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
AND B.YD_STK_COL_GP LIKE :V_YD_GP || :V_YD_BAY_GP ||'%'
AND C.YD_CARPNT_CD = :V_YD_CARPNT_CD
AND SUBSTR(B.YD_STK_COL_GP, 3, 2) BETWEEN '00' AND '99'
AND B.YD_STK_LYR_STAT IN ('C')
ORDER BY B.YD_STK_LYR_NO DESC, A.YD_CAR_UPP_LOC_CD ASC
 </pre> */
public final static String getYdStockTransOrdDTWbook2 = "com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStockTransOrdDTWbook2";

