/** <pre> 2022-09-29
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarYdCmbnCarldGP_PIDEV
WITH TEMP_TABLE AS
(
    SELECT
        A.TRANS_ORD_DATE,
        A.TRANS_ORD_SEQNO,
        A.YD_GP,
        A.COIL_GP
    FROM
        (
            SELECT
                B.YD_GP,
                A.STL_NO,
                A.TRANS_ORD_DATE,
                A.TRANS_ORD_SEQNO,
                B.COIL_GP
            FROM
                USRYDA.TB_YD_STOCK A,
                VW_YF_COILCOMM B
            WHERE 1=1
            AND A.STL_NO = B.COIL_NO 
            AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DATE
            AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
            
            UNION ALL
            
            SELECT
                B.YD_GP,
                A.STOCK_ID,
                A.TRANS_ORD_DATE2,
                A.TRANS_ORD_SEQNO2,
                B.COIL_GP
            FROM
                USRYMA.TB_YM_STOCK A,
                VW_YF_COILCOMM B
            WHERE 1=1
            AND A.STOCK_ID=B.COIL_NO 
            AND A.TRANS_ORD_DATE2=:V_TRANS_ORD_DATE
            AND A.TRANS_ORD_SEQNO2=:V_TRANS_ORD_SEQNO
            
            UNION ALL
            
            SELECT
                B.YD_GP,
                A.STL_NO,
                A.TRANS_ORD_DATE,
                A.TRANS_ORD_SEQNO,
                B.COIL_GP
            FROM
                USRYFA.TB_YF_STOCK A,
                VW_YF_COILCOMM B
            WHERE 1=1
            AND A.STL_NO = B.COIL_NO 
            AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DATE
            AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
        ) A
    GROUP BY A.TRANS_ORD_DATE, A.TRANS_ORD_SEQNO, A.YD_GP, A.COIL_GP
)
SELECT
    A.TRANS_ORD_DATE,
    A.TRANS_ORD_SEQNO,
    COUNT(YD_GP) AS CNT,
    (
        SELECT
            B.YD_GP
        FROM
            TEMP_TABLE B
        WHERE 1=1
        AND B.YD_GP <> :V_YD_GP
    ) AS NEXT_YD_GP,
    A.COIL_GP
FROM
    TEMP_TABLE A
GROUP BY A.TRANS_ORD_DATE ,A.TRANS_ORD_SEQNO, A.COIL_GP
HAVING COUNT(YD_GP) > 1
</pre> */
